pub const Store = struct {
    allocator: std.mem.Allocator,
    backend: Backend,
    agent_memory: agent_memory_runtime.Runtime = .native,
    agent_memory_stores: agent_memory_runtime.RuntimeRegistry,
    vector_backend: vector_runtime.Config = .{},
    vector_runtime: vector_runtime.Runtime = .{},
    vector_stores: vector_runtime.RuntimeRegistry,
    analytics_backend: analytics_runtime.Config = .{},
    graph_projection: graph_runtime.Runtime = .{},
    lucid_projection: lucid_runtime.Runtime = .{},

    pub const Backend = union(BackendKind) {
        sqlite: SQLiteStore,
        postgres: PostgresStore,
    };

    pub fn initSQLite(allocator: std.mem.Allocator, db_path: [:0]const u8) !Store {
        return initSQLiteWithOptions(allocator, db_path, .{});
    }

    pub fn initSQLiteWithOptions(allocator: std.mem.Allocator, db_path: [:0]const u8, options: StoreOptions) !Store {
        try options.analytics_backend.validateUsable();
        const graph_projection = try graph_runtime.Runtime.init(options.graph_projection);
        const lucid_projection = try lucid_runtime.Runtime.init(options.lucid_projection);
        var backend = try SQLiteStore.init(allocator, db_path);
        errdefer backend.deinit();
        backend.configureVectorAnn(options.vector_backend);
        var agent_memory = try agent_memory_runtime.Runtime.init(allocator, options.agent_memory);
        errdefer agent_memory.deinit();
        var agent_memory_stores = try agent_memory_runtime.RuntimeRegistry.init(allocator, options.agent_memory_stores);
        errdefer agent_memory_stores.deinit();
        var vector_stores = try vector_runtime.RuntimeRegistry.init(allocator, options.vector_stores);
        errdefer vector_stores.deinit();
        var vector_runtime_instance = try vector_runtime.Runtime.init(options.vector_backend);
        errdefer vector_runtime_instance.deinit();
        return .{
            .allocator = allocator,
            .backend = .{ .sqlite = backend },
            .agent_memory = agent_memory,
            .agent_memory_stores = agent_memory_stores,
            .vector_backend = options.vector_backend,
            .vector_runtime = vector_runtime_instance,
            .vector_stores = vector_stores,
            .analytics_backend = options.analytics_backend,
            .graph_projection = graph_projection,
            .lucid_projection = lucid_projection,
        };
    }

    pub fn initPostgres(allocator: std.mem.Allocator, url: []const u8) !Store {
        return initPostgresWithOptions(allocator, url, .{});
    }

    pub fn initPostgresWithOptions(allocator: std.mem.Allocator, url: []const u8, options: StoreOptions) !Store {
        try options.analytics_backend.validateUsable();
        const graph_projection = try graph_runtime.Runtime.init(options.graph_projection);
        const lucid_projection = try lucid_runtime.Runtime.init(options.lucid_projection);
        var backend = try PostgresStore.init(allocator, url);
        errdefer backend.deinit();
        if (options.run_legacy_compat_cleanup) try backend.runLegacyCompatCleanup();
        var agent_memory = try agent_memory_runtime.Runtime.init(allocator, options.agent_memory);
        errdefer agent_memory.deinit();
        var agent_memory_stores = try agent_memory_runtime.RuntimeRegistry.init(allocator, options.agent_memory_stores);
        errdefer agent_memory_stores.deinit();
        var vector_stores = try vector_runtime.RuntimeRegistry.init(allocator, options.vector_stores);
        errdefer vector_stores.deinit();
        var vector_runtime_instance = try vector_runtime.Runtime.init(options.vector_backend);
        errdefer vector_runtime_instance.deinit();
        return .{
            .allocator = allocator,
            .backend = .{ .postgres = backend },
            .agent_memory = agent_memory,
            .agent_memory_stores = agent_memory_stores,
            .vector_backend = options.vector_backend,
            .vector_runtime = vector_runtime_instance,
            .vector_stores = vector_stores,
            .analytics_backend = options.analytics_backend,
            .graph_projection = graph_projection,
            .lucid_projection = lucid_projection,
        };
    }

    pub fn deinit(self: *Store) void {
        self.vector_runtime.deinit();
        self.vector_stores.deinit();
        self.agent_memory.deinit();
        self.agent_memory_stores.deinit();
        switch (self.backend) {
            .sqlite => |*s| s.deinit(),
            .postgres => |*p| p.deinit(),
        }
    }

    fn beginLocalTransaction(self: *Store) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.beginTransaction(),
            .postgres => |*p| p.beginTransaction(),
        };
    }

    fn commitLocalTransaction(self: *Store) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.commitTransaction(),
            .postgres => |*p| p.commitTransaction(),
        };
    }

    fn rollbackLocalTransaction(self: *Store) void {
        switch (self.backend) {
            .sqlite => |*s| s.rollbackTransaction(),
            .postgres => |*p| p.rollbackTransaction(),
        }
    }

    pub fn health(self: *Store) bool {
        return switch (self.backend) {
            .sqlite => |*s| s.health(),
            .postgres => |*p| p.health(),
        };
    }

    pub fn backendName(self: *Store) []const u8 {
        return switch (self.backend) {
            .sqlite => "sqlite",
            .postgres => "postgres",
        };
    }

    pub fn agentMemoryBackendName(self: *Store) []const u8 {
        return self.agent_memory.backendName();
    }

    pub fn vectorBackendName(self: *Store) []const u8 {
        if (self.vectorExternalSinkCount() > 1) return "multi";
        return self.vector_backend.backend.name();
    }

    pub fn localVectorEngineName(self: *Store) []const u8 {
        return switch (self.backend) {
            .sqlite => "sqlite_local_vector",
            .postgres => "pgvector",
        };
    }

    pub fn effectiveVectorSearchEngineName(self: *Store) []const u8 {
        const external_count = self.vectorExternalSinkCount();
        if (external_count > 1) return "federated_vector";
        if (external_count == 1) {
            if (self.vector_backend.externalEnabled()) return self.vector_backend.backend.name();
            for (self.vector_stores.stores.items) |store| {
                if (store.config.externalEnabled()) return store.config.backend.name();
            }
        }
        return self.localVectorEngineName();
    }

    pub fn vectorExternalSinkCount(self: *Store) usize {
        var count: usize = 0;
        if (self.vector_backend.externalEnabled()) count += 1;
        for (self.vector_stores.stores.items) |store| {
            if (store.config.externalEnabled()) count += 1;
        }
        return count;
    }

    pub fn hasExternalVectorStores(self: *Store) bool {
        return self.vectorExternalSinkCount() > 0;
    }

    pub fn vectorExternalSinksJson(self: *Store, allocator: std.mem.Allocator) ![]u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        try out.append(allocator, '[');
        var first = true;
        if (self.vector_backend.externalEnabled()) {
            try appendVectorSinkJson(allocator, &out, &first, "primary", self.vector_backend, self.vector_runtime.stateName());
        }
        for (self.vector_stores.stores.items) |*store| {
            if (!store.config.externalEnabled()) continue;
            try appendVectorSinkJson(allocator, &out, &first, store.name, store.config, store.runtime.stateName());
        }
        try out.append(allocator, ']');
        return out.toOwnedSlice(allocator);
    }

    pub fn analyticsBackendName(self: *Store) []const u8 {
        return self.analytics_backend.backend.name();
    }

    pub fn lucidBackendName(self: *Store) []const u8 {
        return self.lucid_projection.backendName();
    }

    pub fn graphProjectionBackendName(self: *Store) []const u8 {
        return self.graph_projection.backendName();
    }

    fn enqueueLucidProjectionPut(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        if (!self.lucid_projection.canProject(scope, permissions_json)) return;
        const key = if (std.mem.eql(u8, object_type, "agent_memory"))
            try allocator.dupe(u8, object_id)
        else
            try lucidProjectionKey(allocator, object_type, object_id);
        defer allocator.free(key);
        const lucid_type = lucidTypeForPrimitive(object_type, title, text);
        const input_json = try lucidProjectionJobInputJson(allocator, "put", key, text, lucid_type);
        defer allocator.free(input_json);
        var job = try self.createJob(allocator, .{
            .job_type = "lucid_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
        defer freeCreatedJobResult(allocator, &job);
    }

    fn enqueueLucidProjectionDelete(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        if (!self.lucid_projection.canProject(scope, permissions_json)) return;
        const key = if (std.mem.eql(u8, object_type, "agent_memory"))
            try allocator.dupe(u8, object_id)
        else
            try lucidProjectionKey(allocator, object_type, object_id);
        defer allocator.free(key);
        const input_json = try lucidProjectionJobInputJson(allocator, "delete", key, "", "learning");
        defer allocator.free(input_json);
        var job = try self.createJob(allocator, .{
            .job_type = "lucid_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
        defer freeCreatedJobResult(allocator, &job);
    }

    fn enqueueGraphProjectionPut(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        from_entity_id: ?[]const u8,
        relation_type: ?[]const u8,
        to_entity_id: ?[]const u8,
    ) !void {
        if (!self.graph_projection.canProject(scope, permissions_json)) return;
        const input_json = try graph_runtime.projectionJobInputJson(allocator, "put", .{
            .object_type = object_type,
            .object_id = object_id,
            .title = title,
            .text = text,
            .scope = scope,
            .permissions_json = permissions_json,
            .from_entity_id = from_entity_id,
            .relation_type = relation_type,
            .to_entity_id = to_entity_id,
        });
        defer allocator.free(input_json);
        var job = try self.createJob(allocator, .{
            .job_type = "graph_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
        defer freeCreatedJobResult(allocator, &job);
    }

    fn enqueueGraphProjectionDelete(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        if (!self.graph_projection.canProject(scope, permissions_json)) return;
        const input_json = try graph_runtime.projectionJobInputJson(allocator, "delete", .{
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = permissions_json,
        });
        defer allocator.free(input_json);
        var job = try self.createJob(allocator, .{
            .job_type = "graph_projection",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
        defer freeCreatedJobResult(allocator, &job);
    }

    fn enqueueAgentMemoryLucidPut(self: *Store, allocator: std.mem.Allocator, entry: domain.AgentMemory, actor_id: ?[]const u8) !void {
        const projection_key = try agentMemoryProjectionKey(allocator, entry);
        defer allocator.free(projection_key);
        try self.enqueueLucidProjectionPut(allocator, "agent_memory", projection_key, entry.category, entry.content, entry.scope, entry.permissions_json, actor_id);
        try self.enqueueGraphProjectionPut(allocator, "agent_memory", projection_key, entry.category, entry.content, entry.scope, entry.permissions_json, actor_id, null, null, null);
    }

    fn enqueueAgentMemoryLucidDelete(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, scope: []const u8, permissions_json: []const u8, writer_actor_id: ?[]const u8) !void {
        const projection_key = try agentMemoryProjectionKeyFromParts(allocator, key, session_id, actor_id);
        defer allocator.free(projection_key);
        try self.enqueueLucidProjectionDelete(allocator, "agent_memory", projection_key, scope, permissions_json, writer_actor_id);
        try self.enqueueGraphProjectionDelete(allocator, "agent_memory", projection_key, scope, permissions_json, writer_actor_id);
    }

    fn syncMemoryAtomLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled() and !self.graph_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (domain.isDefaultVisibleStatus(status)) {
            if (try self.getMemoryAtom(temp, id)) |atom| {
                try self.enqueueLucidProjectionPut(temp, "memory_atom", atom.id, atom.predicate, atom.text, atom.scope, atom.permissions_json, actor_id);
                try self.enqueueGraphProjectionPut(temp, "memory_atom", atom.id, atom.predicate, atom.text, atom.scope, atom.permissions_json, actor_id, null, null, null);
            }
            return;
        }
        if (try self.getMemoryAtom(temp, id)) |atom| {
            try self.enqueueLucidProjectionDelete(temp, "memory_atom", atom.id, atom.scope, atom.permissions_json, actor_id);
            try self.enqueueGraphProjectionDelete(temp, "memory_atom", atom.id, atom.scope, atom.permissions_json, actor_id);
        }
    }

    fn syncArtifactLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled() and !self.graph_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (domain.isDefaultVisibleStatus(status)) {
            if (try self.getArtifact(temp, id)) |artifact| {
                try self.enqueueLucidProjectionPut(temp, "artifact", artifact.id, artifact.artifact_type, artifact.body, artifact.scope, artifact.permissions_json, actor_id);
                try self.enqueueGraphProjectionPut(temp, "artifact", artifact.id, artifact.artifact_type, artifact.body, artifact.scope, artifact.permissions_json, actor_id, null, null, null);
            }
            return;
        }
        if (try self.getArtifact(temp, id)) |artifact| {
            try self.enqueueLucidProjectionDelete(temp, "artifact", artifact.id, artifact.scope, artifact.permissions_json, actor_id);
            try self.enqueueGraphProjectionDelete(temp, "artifact", artifact.id, artifact.scope, artifact.permissions_json, actor_id);
        }
    }

    fn syncRelationLucidProjection(self: *Store, allocator: std.mem.Allocator, id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled() and !self.graph_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (try self.getRelation(temp, id)) |relation| {
            if (domain.isDefaultVisibleStatus(status)) {
                const relation_text = try std.fmt.allocPrint(temp, "{s} {s} {s}", .{ relation.from_entity_id, relation.relation_type, relation.to_entity_id });
                try self.enqueueLucidProjectionPut(temp, "relation", relation.id, relation.relation_type, relation_text, relation.scope, relation.permissions_json, actor_id);
                try self.enqueueGraphProjectionPut(temp, "relation", relation.id, relation.relation_type, relation_text, relation.scope, relation.permissions_json, actor_id, relation.from_entity_id, relation.relation_type, relation.to_entity_id);
            } else {
                try self.enqueueLucidProjectionDelete(temp, "relation", relation.id, relation.scope, relation.permissions_json, actor_id);
                try self.enqueueGraphProjectionDelete(temp, "relation", relation.id, relation.scope, relation.permissions_json, actor_id);
            }
        }
    }

    fn syncOverlayPrimitiveLucidProjection(self: *Store, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, status: []const u8, actor_id: ?[]const u8) !void {
        if (!self.lucid_projection.isEnabled() and !self.graph_projection.isEnabled()) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        if (std.mem.eql(u8, object_type, "source")) {
            if (try self.getSource(temp, object_id)) |source| {
                if (domain.isDefaultVisibleStatus(status)) {
                    try self.enqueueLucidProjectionPut(temp, "source", source.id, source.title, source.content, source.scope, source.permissions_json, actor_id);
                    try self.enqueueGraphProjectionPut(temp, "source", source.id, source.title, source.content, source.scope, source.permissions_json, actor_id, null, null, null);
                } else {
                    try self.enqueueLucidProjectionDelete(temp, "source", source.id, source.scope, source.permissions_json, actor_id);
                    try self.enqueueGraphProjectionDelete(temp, "source", source.id, source.scope, source.permissions_json, actor_id);
                }
            }
            return;
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            if (try self.getEntity(temp, object_id)) |entity| {
                const text = entity.description orelse entity.name;
                if (domain.isDefaultVisibleStatus(status)) {
                    try self.enqueueLucidProjectionPut(temp, "entity", entity.id, entity.name, text, entity.scope, entity.permissions_json, actor_id);
                    try self.enqueueGraphProjectionPut(temp, "entity", entity.id, entity.name, text, entity.scope, entity.permissions_json, actor_id, null, null, null);
                } else {
                    try self.enqueueLucidProjectionDelete(temp, "entity", entity.id, entity.scope, entity.permissions_json, actor_id);
                    try self.enqueueGraphProjectionDelete(temp, "entity", entity.id, entity.scope, entity.permissions_json, actor_id);
                }
            }
            return;
        }
        if (std.mem.eql(u8, object_type, "context_pack") and !domain.isDefaultVisibleStatus(status)) {
            try self.enqueueLucidProjectionDelete(temp, "context_pack", object_id, "public", "[]", actor_id);
            try self.enqueueGraphProjectionDelete(temp, "context_pack", object_id, "public", "[]", actor_id);
        }
    }

    fn mirrorKnowledgePrimitiveToRuntime(
        self: *Store,
        allocator: std.mem.Allocator,
        runtime: *agent_memory_runtime.Runtime,
        kind: PrimitiveMirrorKind,
        id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
    ) !void {
        _ = self;
        const key = try primitiveRuntimeKey(allocator, kind.resultType(), id);
        defer allocator.free(key);
        const content = try primitiveRuntimeContent(allocator, title, text);
        defer allocator.free(content);
        const category = try primitiveRuntimeCategory(allocator, kind.resultType());
        defer allocator.free(category);
        var entry = try runtime.store(allocator, .{
            .key = key,
            .content = content,
            .category = category,
            .scope = scope,
            .permissions_json = permissions_json,
            .actor_id = actor_id,
            .writer_actor_id = actor_id,
        });
        defer agent_memory_runtime.freeAgentMemory(allocator, &entry);
    }

    fn mirrorKnowledgePrimitive(
        self: *Store,
        allocator: std.mem.Allocator,
        kind: PrimitiveMirrorKind,
        id: []const u8,
        title: []const u8,
        text: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        route: AgentMemoryStorageRoute,
    ) !void {
        switch (route.target) {
            .primary => {
                if (self.agent_memory.isExternal() and !self.agent_memory.isNoop() and actor_id != null) {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id);
                }
            },
            .native => {},
            .runtime => {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                if (!self.agent_memory.isNoop()) {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id);
                }
            },
            .named => {
                const runtime = try self.namedAgentMemoryRuntime(route);
                if (!runtime.isNoop()) {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, runtime, kind, id, title, text, scope, permissions_json, actor_id);
                }
            },
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| {
                    try self.mirrorKnowledgePrimitive(allocator, kind, id, title, text, scope, permissions_json, actor_id, routeForSubsetStoreName(store_name));
                }
            },
            .all => {
                if (self.agent_memory.isExternal() and !self.agent_memory.isNoop()) {
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &self.agent_memory, kind, id, title, text, scope, permissions_json, actor_id);
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (named.runtime.isNoop()) continue;
                    try self.mirrorKnowledgePrimitiveToRuntime(allocator, &named.runtime, kind, id, title, text, scope, permissions_json, actor_id);
                }
            },
        }
    }

    fn primitiveMirrorJobInputJson(allocator: std.mem.Allocator, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) ![]const u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.appendSlice(allocator, "{\"actor_id\":");
        try json.appendNullableString(&out, allocator, actor_id);
        try out.append(allocator, '}');
        const base = try out.toOwnedSlice(allocator);
        defer allocator.free(base);
        return payloadWithStorageRouteJson(allocator, base, route);
    }

    fn primitiveMirrorJobNeeded(self: *Store, route: AgentMemoryStorageRoute, actor_id: ?[]const u8) bool {
        return switch (route.target) {
            .primary => self.agent_memory.isExternal() and !self.agent_memory.isNoop() and actor_id != null,
            .native => false,
            .runtime => self.agent_memory.isExternal() and !self.agent_memory.isNoop(),
            .named => blk: {
                const name = route.name orelse break :blk false;
                const named = self.agent_memory_stores.get(name) orelse break :blk true;
                break :blk !named.isNoop();
            },
            .subset => blk: {
                const stores = requireSubsetStores(route) catch break :blk true;
                for (stores) |store_name| {
                    if (self.primitiveMirrorJobNeeded(routeForSubsetStoreName(store_name), actor_id)) break :blk true;
                }
                break :blk false;
            },
            .all => blk: {
                if (self.primitiveMirrorJobNeeded(.{ .target = .primary }, actor_id)) break :blk true;
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (!named.runtime.isNoop()) break :blk true;
                }
                break :blk false;
            },
        };
    }

    fn enqueueKnowledgePrimitiveMirrorJob(
        self: *Store,
        allocator: std.mem.Allocator,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        route: AgentMemoryStorageRoute,
    ) !void {
        if (!self.primitiveMirrorJobNeeded(route, actor_id)) return;
        const input_json = try primitiveMirrorJobInputJson(allocator, actor_id, route);
        defer allocator.free(input_json);
        var job = try self.createJob(allocator, .{
            .job_type = "agent_memory_mirror",
            .scope = scope,
            .permissions_json = permissions_json,
            .object_type = object_type,
            .object_id = object_id,
            .input_json = input_json,
            .actor_id = actor_id,
        });
        defer freeCreatedJobResult(allocator, &job);
    }

    fn applyKnowledgeWriteProjectionEffects(self: *Store, allocator: std.mem.Allocator, effects: store_knowledge_write.PutEffects) !void {
        const lucid = effects.lucid;
        try self.enqueueLucidProjectionPut(
            allocator,
            lucid.object_type,
            lucid.object_id,
            lucid.title,
            lucid.text,
            lucid.scope,
            lucid.permissions_json,
            lucid.actor_id,
        );
        try self.enqueueGraphProjectionPut(
            allocator,
            lucid.object_type,
            lucid.object_id,
            lucid.title,
            lucid.text,
            lucid.scope,
            lucid.permissions_json,
            lucid.actor_id,
            null,
            null,
            null,
        );
        if (effects.mirror) |mirror| {
            try self.enqueueKnowledgePrimitiveMirrorJob(
                allocator,
                mirror.object_type,
                mirror.object_id,
                mirror.scope,
                mirror.permissions_json,
                mirror.actor_id,
                mirror.route,
            );
        }
    }

    pub fn runAgentMemoryMirrorJob(self: *Store, allocator: std.mem.Allocator, job: Job) ![]const u8 {
        var parsed = try std.json.parseFromSlice(std.json.Value, allocator, job.input_json, .{});
        defer parsed.deinit();
        if (parsed.value != .object) return error.InvalidPayload;
        var route = try storage_routes.fromObject(allocator, parsed.value.object);
        defer route.deinit(allocator);
        const actor_id = json.stringField(parsed.value.object, "actor_id");
        try self.ensureKnowledgePrimitiveMirrorRoute(route, actor_id);

        if (std.mem.eql(u8, job.object_type, "source")) {
            var source = (try self.getSource(allocator, job.object_id)) orelse return error.SourceNotFound;
            defer deinitSource(allocator, &source);
            try ensureJobAclDoesNotExceedTarget(allocator, job, source.scope, source.permissions_json);
            try self.mirrorKnowledgePrimitive(allocator, .source, source.id, source.title, source.content, source.scope, source.permissions_json, actor_id, route);
        } else if (std.mem.eql(u8, job.object_type, "artifact")) {
            var artifact = (try self.getArtifact(allocator, job.object_id)) orelse return error.ArtifactNotFound;
            defer deinitArtifact(allocator, &artifact);
            try ensureJobAclDoesNotExceedTarget(allocator, job, artifact.scope, artifact.permissions_json);
            try self.mirrorKnowledgePrimitive(allocator, .artifact, artifact.id, artifact.title, artifact.body, artifact.scope, artifact.permissions_json, actor_id, route);
        } else if (std.mem.eql(u8, job.object_type, "memory_atom")) {
            var atom = (try self.getMemoryAtom(allocator, job.object_id)) orelse return error.MemoryAtomNotFound;
            defer deinitMemoryAtom(allocator, &atom);
            try ensureJobAclDoesNotExceedTarget(allocator, job, atom.scope, atom.permissions_json);
            if (!std.mem.eql(u8, atom.predicate, "agent.memory")) {
                try self.mirrorKnowledgePrimitive(allocator, .memory_atom, atom.id, atom.predicate, atom.text, atom.scope, atom.permissions_json, actor_id, route);
            }
        } else if (std.mem.eql(u8, job.object_type, "entity")) {
            var entity = (try self.getEntity(allocator, job.object_id)) orelse return error.EntityNotFound;
            defer deinitEntity(allocator, &entity);
            try ensureJobAclDoesNotExceedTarget(allocator, job, entity.scope, entity.permissions_json);
            try self.mirrorKnowledgePrimitive(allocator, .entity, entity.id, entity.name, entity.description orelse entity.name, entity.scope, entity.permissions_json, actor_id, route);
        } else if (std.mem.eql(u8, job.object_type, "relation")) {
            var relation = (try self.getRelation(allocator, job.object_id)) orelse return error.RelationNotFound;
            defer deinitRelation(allocator, &relation);
            try ensureJobAclDoesNotExceedTarget(allocator, job, relation.scope, relation.permissions_json);
            const relation_text = try std.fmt.allocPrint(allocator, "{s} {s} {s}", .{ relation.from_entity_id, relation.relation_type, relation.to_entity_id });
            defer allocator.free(relation_text);
            try self.mirrorKnowledgePrimitive(allocator, .relation, relation.id, relation.relation_type, relation_text, relation.scope, relation.permissions_json, actor_id, route);
        } else if (std.mem.eql(u8, job.object_type, "context_pack")) {
            var pack = (try self.contextPackById(allocator, job.object_id)) orelse return error.ContextPackNotFound;
            defer deinitContextPackResult(allocator, &pack);
            var pack_acl = (try self.vectorObjectAcl(allocator, "context_pack", pack.id, actor_id)) orelse return error.ContextPackNotFound;
            defer freeVectorObjectAcl(allocator, &pack_acl);
            try ensureJobAclDoesNotExceedTarget(allocator, job, pack_acl.scope, pack_acl.permissions_json);
            try self.mirrorKnowledgePrimitive(allocator, .context_pack, pack.id, pack.query, pack.generated_summary, pack_acl.scope, pack_acl.permissions_json, actor_id, route);
        } else {
            return error.UnsupportedJob;
        }

        return try agentMemoryMirrorResultJson(allocator, job.object_type, job.object_id);
    }

    fn ensureJobAclDoesNotExceedTarget(allocator: std.mem.Allocator, job: Job, target_scope: []const u8, target_permissions_json: []const u8) !void {
        if (!aclCoversTarget(allocator, target_scope, target_permissions_json, job.scope, job.permissions_json)) return error.Forbidden;
    }

    fn agentMemoryMirrorResultJson(allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) ![]const u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.appendSlice(allocator, "{\"mirrored\":true,\"object_type\":");
        try json.appendString(&out, allocator, object_type);
        try out.appendSlice(allocator, ",\"object_id\":");
        try json.appendString(&out, allocator, object_id);
        try out.append(allocator, '}');
        return out.toOwnedSlice(allocator);
    }

    fn ensureKnowledgePrimitiveMirrorRoute(self: *Store, route: AgentMemoryStorageRoute, actor_id: ?[]const u8) !void {
        switch (route.target) {
            .primary, .native => {},
            .runtime => {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                if (!self.agent_memory.isNoop() and actor_id == null) return error.MissingActorId;
            },
            .named => {
                const runtime = try self.namedAgentMemoryRuntime(route);
                if (!runtime.isNoop() and actor_id == null) return error.MissingActorId;
            },
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.ensureKnowledgePrimitiveMirrorRoute(routeForSubsetStoreName(store_name), actor_id);
            },
            .all => {
                if (self.agent_memory.isExternal() and !self.agent_memory.isNoop() and actor_id == null) return error.MissingActorId;
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (!named.runtime.isNoop() and actor_id == null) return error.MissingActorId;
                }
            },
        }
    }

