    pub fn search(self: *Store, allocator: std.mem.Allocator, input: SearchInput) ![]domain.SearchResult {
        if (searchCandidateWindowLimit(input) == 0) return allocator.alloc(domain.SearchResult, 0);
        const retrieval_input = searchRetrievalWindowInput(input);
        var result_lists: std.ArrayListUnmanaged([]domain.SearchResult) = .empty;
        defer {
            for (result_lists.items) |list| allocator.free(list);
            result_lists.deinit(allocator);
        }
        try self.appendSearchResultListsForRoute(allocator, retrieval_input, input.agent_memory_route, &result_lists);

        if (self.lucid_projection.shouldAugment(searchResultListItemCount(result_lists.items)) and self.lucid_projection.resultVisible(allocator, retrieval_input.scopes_json, retrieval_input.actor_id)) {
            try self.appendLucidProjectionSearchResultList(allocator, retrieval_input, &result_lists);
        }
        return finalizeSearchResultLists(allocator, input, result_lists.items);
    }

    fn appendSearchResultListsForRoute(self: *Store, allocator: std.mem.Allocator, input: SearchInput, route: AgentMemoryStorageRoute, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        switch (route.target) {
            .primary => {
                try self.appendNativeSearchResultLists(allocator, input, lists);
                try self.appendAllRuntimeSearchResultLists(allocator, input, lists);
            },
            .native => try self.appendNativeSearchResultLists(allocator, input, lists),
            .runtime => try self.appendDefaultRuntimeSearchResultList(allocator, input, lists),
            .named => {
                const runtime = try self.namedAgentMemoryRuntime(route);
                try self.appendRuntimeSearchResultList(allocator, input, runtime, route.name orelse "named", lists);
            },
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.appendSearchResultListsForRoute(allocator, input, routeForSubsetStoreName(store_name), lists);
            },
            .all => {
                try self.appendNativeSearchResultLists(allocator, input, lists);
                try self.appendAllRuntimeSearchResultLists(allocator, input, lists);
            },
        }
    }

    fn appendNativeSearchResultLists(self: *Store, allocator: std.mem.Allocator, input: SearchInput, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        var native_input = input;
        const use_store_vector_path = self.hasExternalVectorStores() or input.strict_vector;
        if (use_store_vector_path) native_input.use_vector = false;
        const primary = try switch (self.backend) {
            .sqlite => |*s| s.search(allocator, native_input),
            .postgres => |*p| p.search(allocator, native_input),
        };
        try appendOwnedSearchResultList(allocator, lists, primary);

        if (use_store_vector_path and input.use_vector and input.query.len > 0) {
            var plan = try retrieval_mod.buildPlanWithAdaptive(allocator, input.query, input.use_vector, input.allow_reranker, adaptiveConfigFromSearchInput(input));
            defer plan.deinit(allocator);
            if (plan.use_vector or input.strict_vector) {
                var vector_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
                errdefer vector_results.deinit(allocator);
                try self.appendVectorSearchResults(allocator, input, plan.expanded_query, &vector_results);
                try appendCollectedSearchResultList(allocator, lists, &vector_results);
            }
        }
    }

    fn appendDefaultRuntimeSearchResultList(self: *Store, allocator: std.mem.Allocator, input: SearchInput, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        if (input.actor_id) |_| {
            if (self.agent_memory.isExternal()) {
                try self.appendRuntimeSearchResultList(allocator, input, &self.agent_memory, "runtime", lists);
                return;
            }
        }
        return error.AgentMemoryStorageUnavailable;
    }

    fn appendAllRuntimeSearchResultLists(self: *Store, allocator: std.mem.Allocator, input: SearchInput, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        if (input.actor_id == null) return;
        if (self.agent_memory.isExternal()) {
            try self.appendRuntimeSearchResultList(allocator, input, &self.agent_memory, "runtime", lists);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            try self.appendRuntimeSearchResultList(allocator, input, &named.runtime, named.name, lists);
        }
    }

    fn appendRuntimeSearchResultList(self: *Store, allocator: std.mem.Allocator, input: SearchInput, runtime: *agent_memory_runtime.Runtime, store_name: []const u8, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer results.deinit(allocator);
        try self.appendRuntimeSearchResults(allocator, input, runtime, store_name, &results);
        try appendCollectedSearchResultList(allocator, lists, &results);
    }

    fn appendLucidProjectionSearchResultList(self: *Store, allocator: std.mem.Allocator, input: SearchInput, lists: *std.ArrayListUnmanaged([]domain.SearchResult)) !void {
        const entries = try self.lucid_projection.context(allocator, input.query);
        defer lucid_runtime.freeEntries(allocator, entries);
        var results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer results.deinit(allocator);
        for (entries) |entry| {
            const id = try std.fmt.allocPrint(allocator, "lucid_projection:{s}", .{entry.id});
            const title = try std.fmt.allocPrint(allocator, "lucid:{s}", .{entry.label});
            const text = try allocator.dupe(u8, entry.content);
            const scope = try allocator.dupe(u8, self.lucid_projection.config.result_scope);
            const required_scopes = try requiredAccessJsonGlobal(allocator, self.lucid_projection.config.result_scope, self.lucid_projection.config.permissions_json, input.actor_id);
            try results.append(allocator, .{
                .id = id,
                .result_type = "lucid_projection",
                .title = title,
                .text = text,
                .scope = scope,
                .status = "active",
                .score = entry.score,
                .source_ids_json = "[]",
                .required_scopes_json = required_scopes,
                .actor_isolated = false,
                .created_at_ms = ids.nowMs(),
                .confidence = 0.55,
            });
        }
        try appendCollectedSearchResultList(allocator, lists, &results);
    }

    fn appendSearchResultsForRoute(self: *Store, allocator: std.mem.Allocator, input: SearchInput, route: AgentMemoryStorageRoute, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        switch (route.target) {
            .primary => {
                try self.appendNativeSearchResults(allocator, input, results);
                try self.appendAllRuntimeSearchResults(allocator, input, results);
            },
            .native => try self.appendNativeSearchResults(allocator, input, results),
            .runtime => try self.appendDefaultRuntimeSearchResults(allocator, input, results),
            .named => {
                const runtime = try self.namedAgentMemoryRuntime(route);
                try self.appendRuntimeSearchResults(allocator, input, runtime, route.name orelse "named", results);
            },
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.appendSearchResultsForRoute(allocator, input, routeForSubsetStoreName(store_name), results);
            },
            .all => {
                try self.appendNativeSearchResults(allocator, input, results);
                try self.appendAllRuntimeSearchResults(allocator, input, results);
            },
        }
    }

    fn appendNativeSearchResults(self: *Store, allocator: std.mem.Allocator, input: SearchInput, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        var native_input = input;
        const use_store_vector_path = self.hasExternalVectorStores() or input.strict_vector;
        if (use_store_vector_path) native_input.use_vector = false;
        const primary = try switch (self.backend) {
            .sqlite => |*s| s.search(allocator, native_input),
            .postgres => |*p| p.search(allocator, native_input),
        };
        defer allocator.free(primary);
        for (primary) |result| try results.append(allocator, result);

        if (use_store_vector_path and input.use_vector and input.query.len > 0) {
            var plan = try retrieval_mod.buildPlanWithAdaptive(allocator, input.query, input.use_vector, input.allow_reranker, adaptiveConfigFromSearchInput(input));
            defer plan.deinit(allocator);
            if (plan.use_vector or input.strict_vector) {
                try self.appendVectorSearchResults(allocator, input, plan.expanded_query, results);
            }
        }
    }

    fn appendVectorSearchResults(self: *Store, allocator: std.mem.Allocator, input: SearchInput, expanded_query: []const u8, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        var embedding_json_owned = false;
        const embedding_json = if (input.query_embedding_json) |value| value else blk: {
            embedding_json_owned = true;
            const dimensions = vector_mod.boundedEmbeddingDimensions(null, input.embedding_dimensions);
            const embedding = try vector_mod.deterministicEmbedding(allocator, expanded_query, dimensions);
            break :blk try vector_mod.embeddingToJson(allocator, embedding);
        };
        defer if (embedding_json_owned) allocator.free(embedding_json);
        const matches = try self.vectorSearch(allocator, .{
            .embedding_json = embedding_json,
            .scopes_json = input.scopes_json,
            .limit = @max(@as(usize, 20), input.limit),
            .include_deprecated = input.include_deprecated,
            .include_sessions = input.include_sessions,
            .session_id = input.session_id,
            .strict_external = input.strict_vector,
            .actor_id = input.actor_id,
        });
        defer vector_mod.freeMatches(allocator, matches);
        for (matches) |match| {
            if (try self.searchResultForVectorMatch(allocator, match, input)) |result| try results.append(allocator, result);
        }
    }

    fn searchResultForVectorMatch(self: *Store, allocator: std.mem.Allocator, match: vector_mod.VectorMatch, input: SearchInput) !?domain.SearchResult {
        return switch (self.backend) {
            .sqlite => |*s| s.searchResultForVectorMatch(allocator, match, input),
            .postgres => |*p| p.searchResultForVectorMatch(allocator, match, input),
        };
    }

    fn appendDefaultRuntimeSearchResults(self: *Store, allocator: std.mem.Allocator, input: SearchInput, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        if (input.actor_id) |_| {
            if (self.agent_memory.isExternal()) {
                try self.appendRuntimeSearchResults(allocator, input, &self.agent_memory, "runtime", results);
                return;
            }
        }
        return error.AgentMemoryStorageUnavailable;
    }

    fn appendAllRuntimeSearchResults(self: *Store, allocator: std.mem.Allocator, input: SearchInput, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        if (input.actor_id == null) return;
        if (self.agent_memory.isExternal()) {
            try self.appendRuntimeSearchResults(allocator, input, &self.agent_memory, "runtime", results);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            try self.appendRuntimeSearchResults(allocator, input, &named.runtime, named.name, results);
        }
    }

    fn appendRuntimeSearchResults(self: *Store, allocator: std.mem.Allocator, input: SearchInput, runtime: *agent_memory_runtime.Runtime, store_name: []const u8, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        return store_runtime_search.appendResults(self, allocator, input, runtime, store_name, results);
    }

