    fn validateVectorChunkAcl(self: *Store, allocator: std.mem.Allocator, input: VectorChunkInput) !void {
        var acl = (try self.vectorObjectAcl(allocator, input.object_type, input.object_id, input.actor_id)) orelse return error.InvalidVectorTarget;
        defer freeVectorObjectAcl(allocator, &acl);
        if (!aclCoversTarget(allocator, acl.scope, acl.permissions_json, input.scope, input.permissions_json)) return error.VectorAclBroaderThanObject;
