    pub fn vectorSearch(self: *Store, allocator: std.mem.Allocator, input: VectorSearchInput) ![]vector_mod.VectorMatch {
        if (self.hasExternalVectorStores()) {
            const candidate_limit = externalVectorCandidateLimit(input.limit);
            const candidates = self.searchExternalVectorStores(allocator, input, candidate_limit) catch |err| {
                if (input.strict_external) return err;
                return self.localVectorSearch(allocator, input);
            };
            defer vector_runtime.freeCandidates(allocator, candidates);
            return self.vectorSearchCandidates(allocator, input, candidates);
        }
        return self.localVectorSearch(allocator, input);
    }

    fn localVectorSearch(self: *Store, allocator: std.mem.Allocator, input: VectorSearchInput) ![]vector_mod.VectorMatch {
        return switch (self.backend) {
            .sqlite => |*s| s.vectorSearch(allocator, input),
            .postgres => |*p| p.vectorSearch(allocator, input),
        };
    }

    fn searchExternalVectorStores(self: *Store, allocator: std.mem.Allocator, input: VectorSearchInput, candidate_limit: usize) ![]vector_runtime.Candidate {
        var candidates: std.ArrayListUnmanaged(vector_runtime.Candidate) = .empty;
        errdefer freeCandidateList(allocator, &candidates);
        var successes: usize = 0;
        var last_error: ?anyerror = null;

        if (self.vector_backend.externalEnabled()) {
            if (vector_runtime.searchWithRuntime(allocator, self.vector_backend, &self.vector_runtime, input.embedding_json, candidate_limit)) |found| {
                defer vector_runtime.freeCandidates(allocator, found);
                try appendExternalVectorCandidates(allocator, &candidates, found, candidate_limit);
                successes += 1;
            } else |err| {
                if (input.strict_external) return err;
                last_error = err;
            }
        }

        for (self.vector_stores.stores.items) |*store| {
            if (!store.config.externalEnabled()) continue;
            if (vector_runtime.searchWithRuntime(allocator, store.config, &store.runtime, input.embedding_json, candidate_limit)) |found| {
                defer vector_runtime.freeCandidates(allocator, found);
                try appendExternalVectorCandidates(allocator, &candidates, found, candidate_limit);
                successes += 1;
            } else |err| {
                if (input.strict_external) return err;
                last_error = err;
            }
        }

        if (successes == 0 and last_error != null) return last_error.?;
        sortCandidateList(candidates.items);
        if (candidates.items.len > candidate_limit) {
            for (candidates.items[candidate_limit..]) |candidate| allocator.free(candidate.vector_id);
            candidates.items.len = candidate_limit;
        }
        return candidates.toOwnedSlice(allocator);
    }

    fn vectorSearchCandidates(self: *Store, allocator: std.mem.Allocator, input: VectorSearchInput, candidates: []const vector_runtime.Candidate) ![]vector_mod.VectorMatch {
        return switch (self.backend) {
            .sqlite => |*s| s.vectorSearchCandidates(allocator, input, candidates),
            .postgres => |*p| p.vectorSearchCandidates(allocator, input, candidates),
        };
    }

