    fn recordHygieneMarker(self: *Store, input: HygieneRunInput) !void {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now_ms = input.now_ms orelse ids.nowMs();
        const now_secs = @divFloor(now_ms, std.time.ms_per_s);
        const content = try std.fmt.allocPrint(allocator, "{d}", .{now_secs});
        var marker = try self.agentMemoryStore(allocator, .{
            .key = domain.last_hygiene_key,
            .content = content,
            .category = "core",
            .actor_id = input.actor_id orelse hygiene_marker_actor_id,
            .writer_actor_id = input.actor_id orelse hygiene_marker_actor_id,
            .metadata_json = "{\"system\":\"lifecycle_hygiene\"}",
            .suppress_feed = true,
        });
        agent_memory_runtime.freeAgentMemory(allocator, &marker);
    }

