    pub fn createContextPack(self: *Store, allocator: std.mem.Allocator, input: ContextPackInput) !ContextPackResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(input.agent_memory_route, input.actor_id);
        var owns_search_results = false;
        const search_results = if (input.preselected_results) |results|
            results
        else blk: {
            owns_search_results = true;
            break :blk try self.search(allocator, .{
                .query = input.query,
                .limit = input.retrieval_limit,
                .scopes_json = input.scopes_json,
                .include_deprecated = input.include_deprecated,
                .include_sessions = input.include_sessions,
                .session_id = input.session_id,
                .use_vector = input.use_vector,
                .adaptive_retrieval = input.adaptive_retrieval,
                .adaptive_keyword_max_tokens = input.adaptive_keyword_max_tokens,
                .adaptive_vector_min_tokens = input.adaptive_vector_min_tokens,
                .use_temporal_decay = input.use_temporal_decay,
                .use_mmr = input.use_mmr,
                .mmr_lambda = input.mmr_lambda,
                .mmr_candidate_multiplier = input.mmr_candidate_multiplier,
                .allow_reranker = input.allow_reranker,
                .rerank_candidate_limit = input.rerank_candidate_limit,
                .strict_reranker = input.strict_reranker,
                .min_relevance = input.min_relevance,
                .rrf_k = input.rrf_k,
                .rrf_weight = input.rrf_weight,
                .raw_score_weight = input.raw_score_weight,
                .rrf_window_multiplier = input.rrf_window_multiplier,
                .query_embedding_json = input.query_embedding_json,
                .query_embedding_provider = input.query_embedding_provider,
                .embedding_dimensions = input.embedding_dimensions,
                .actor_id = input.actor_id,
                .actor_capabilities_json = input.actor_capabilities_json,
                .agent_memory_route = input.agent_memory_route,
            });
        };
        defer if (owns_search_results) allocator.free(search_results);
        var routed_input = input;
        routed_input.preselected_results = search_results;
        try self.beginLocalTransaction();
        errdefer self.rollbackLocalTransaction();
        const pack = try switch (self.backend) {
            .sqlite => |*s| s.createContextPack(allocator, routed_input),
            .postgres => |*p| p.createContextPack(allocator, routed_input),
        };
        const scope = try contextPackFeedScope(allocator, pack);
        defer allocator.free(scope);
        const permissions = try contextPackFeedPermissions(allocator, pack);
        defer allocator.free(permissions);
        if (pack.persisted) {
            if (!input.suppress_feed) try self.appendContextPackPutFeedEvent(allocator, pack, scope, permissions, input.actor_id, input.agent_memory_route);
            try self.enqueueLucidProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id);
            try self.enqueueGraphProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id, null, null, null);
            try self.enqueueKnowledgePrimitiveMirrorJob(allocator, "context_pack", pack.id, scope, permissions, input.actor_id, input.agent_memory_route);
        }
        try self.commitLocalTransaction();
        return pack;
    }

    pub fn importContextPackSnapshot(self: *Store, allocator: std.mem.Allocator, input: ContextPackSnapshotInput) !ContextPackResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(.{}, input.actor_id);
        try self.validateContextPackSnapshotRefs(allocator, input);
        try self.beginLocalTransaction();
        errdefer self.rollbackLocalTransaction();
        const pack = try switch (self.backend) {
            .sqlite => |*s| s.importContextPackSnapshot(allocator, input),
            .postgres => |*p| p.importContextPackSnapshot(allocator, input),
        };
        if (!input.suppress_feed) {
            const scope = try contextPackFeedScope(allocator, pack);
            defer allocator.free(scope);
            const permissions = try contextPackFeedPermissions(allocator, pack);
            defer allocator.free(permissions);
            try self.appendContextPackPutFeedEvent(allocator, pack, scope, permissions, input.actor_id, .{});
            try self.enqueueLucidProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id);
            try self.enqueueGraphProjectionPut(allocator, "context_pack", pack.id, pack.query, pack.generated_summary, scope, permissions, input.actor_id, null, null, null);
            try self.enqueueKnowledgePrimitiveMirrorJob(allocator, "context_pack", pack.id, scope, permissions, input.actor_id, .{});
        }
        try self.commitLocalTransaction();
        return pack;
    }

    fn validateContextPackSnapshotRefs(self: *Store, allocator: std.mem.Allocator, input: ContextPackSnapshotInput) !void {
        const effective_required = if (input.actor_isolated) blk: {
            const actor = input.actor_id orelse return error.InvalidPayload;
            break :blk try domain.actorGrantJson(allocator, actor);
        } else input.required_scopes_json;
        defer if (input.actor_isolated) allocator.free(effective_required);

        try self.validateContextPackSourceRefs(allocator, input.included_sources_json, effective_required, input.actor_id);
        try self.validateContextPackArtifactRefs(allocator, input.included_artifacts_json, effective_required, input.actor_id);
        try self.validateContextPackMemoryAtomRefs(allocator, input.included_memory_atoms_json, effective_required, input.actor_id);
        try validateContextPackResultRefs(allocator, input.included_result_refs_json, effective_required, input.actor_isolated);
    }

    fn validateContextPackSourceRefs(self: *Store, allocator: std.mem.Allocator, ids_json: []const u8, required_scopes_json: []const u8, actor_id: ?[]const u8) !void {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, ids_json, .{}) catch return error.InvalidPayload;
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidPayload;
        for (parsed.value.array.items) |item| {
            if (item != .string) return error.InvalidPayload;
            var source = (try self.getSource(allocator, item.string)) orelse return error.ContextPackReferenceNotFound;
            defer deinitSource(allocator, &source);
            if (!try contextPackRequiredScopesCoverRecord(allocator, required_scopes_json, source.scope, source.permissions_json, actor_id)) return error.ContextPackAclBroaderThanRefs;
        }
    }

    fn validateContextPackArtifactRefs(self: *Store, allocator: std.mem.Allocator, ids_json: []const u8, required_scopes_json: []const u8, actor_id: ?[]const u8) !void {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, ids_json, .{}) catch return error.InvalidPayload;
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidPayload;
        for (parsed.value.array.items) |item| {
            if (item != .string) return error.InvalidPayload;
            var artifact = (try self.getArtifact(allocator, item.string)) orelse return error.ContextPackReferenceNotFound;
            defer deinitArtifact(allocator, &artifact);
            if (!try contextPackRequiredScopesCoverRecord(allocator, required_scopes_json, artifact.scope, artifact.permissions_json, actor_id)) return error.ContextPackAclBroaderThanRefs;
        }
    }

    fn validateContextPackMemoryAtomRefs(self: *Store, allocator: std.mem.Allocator, ids_json: []const u8, required_scopes_json: []const u8, actor_id: ?[]const u8) !void {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, ids_json, .{}) catch return error.InvalidPayload;
        defer parsed.deinit();
        if (parsed.value != .array) return error.InvalidPayload;
        for (parsed.value.array.items) |item| {
            if (item != .string) return error.InvalidPayload;
            var atom = (try self.getMemoryAtom(allocator, item.string)) orelse return error.ContextPackReferenceNotFound;
            defer deinitMemoryAtom(allocator, &atom);
            if (!try contextPackRequiredScopesCoverRecord(allocator, required_scopes_json, atom.scope, atom.permissions_json, actor_id)) return error.ContextPackAclBroaderThanRefs;
        }
    }

    pub fn importMemoryAtomsAtomic(self: *Store, allocator: std.mem.Allocator, inputs: []const PreparedMemoryImport) ![]domain.MemoryAtom {
        return switch (self.backend) {
            .sqlite => |*s| s.importMemoryAtomsAtomic(allocator, inputs),
            .postgres => |*p| p.importMemoryAtomsAtomic(allocator, inputs),
        };
    }

    pub fn applyFeedMemoryAtomAtomic(self: *Store, allocator: std.mem.Allocator, input: FeedMemoryApplyInput) !FeedMemoryApplyResult {
        try self.ensureKnowledgePrimitiveMirrorRoute(input.prepared.atom.storage_route, input.prepared.atom.actor_id);
        var routed_input = input;
        var routed_event = input.event;
        const event_payload_json = try payloadWithStorageRouteJson(allocator, input.event.payload_json, input.prepared.atom.storage_route);
        defer allocator.free(event_payload_json);
        routed_event.payload_json = event_payload_json;
        routed_input.event = routed_event;
        var mirror_job_input_json: ?[]const u8 = null;
        defer if (mirror_job_input_json) |payload| allocator.free(payload);
        if (input.prepared.atom.storage_route.target != .primary and
            !std.mem.eql(u8, input.prepared.atom.predicate, "agent.memory") and
            self.primitiveMirrorJobNeeded(input.prepared.atom.storage_route, input.prepared.atom.actor_id))
        {
            mirror_job_input_json = try primitiveMirrorJobInputJson(allocator, input.prepared.atom.actor_id, input.prepared.atom.storage_route);
            routed_input.mirror_job_input_json = mirror_job_input_json;
        }
        const result = try switch (self.backend) {
            .sqlite => |*s| s.applyFeedMemoryAtomAtomic(allocator, routed_input),
            .postgres => |*p| p.applyFeedMemoryAtomAtomic(allocator, routed_input),
        };
        return result;
    }

    pub fn applyFeedAgentMemoryAtomic(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput) !FeedAgentMemoryApplyResult {
        return switch (self.backend) {
            .sqlite => |*s| s.applyFeedAgentMemoryAtomic(allocator, input),
            .postgres => |*p| p.applyFeedAgentMemoryAtomic(allocator, input),
        };
    }

    pub fn effectiveAgentMemoryEventRoute(self: *Store, route: AgentMemoryStorageRoute) AgentMemoryStorageRoute {
        if (route.target == .primary and self.agent_memory.isExternal()) return .{ .target = .runtime };
        return route;
    }

    pub fn applyFeedAgentMemoryRouted(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        return switch (effective_route.target) {
            .primary, .native => self.applyFeedAgentMemoryAtomic(allocator, input),
            .runtime, .named, .subset, .all => self.applyFeedAgentMemoryRuntime(allocator, input, effective_route),
        };
    }

    fn applyFeedAgentMemoryRuntime(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        return switch (effective_route.target) {
            .primary, .native => self.applyFeedAgentMemoryAtomic(allocator, input),
            .runtime, .named, .subset, .all => self.applyFeedAgentMemoryRuntimeInner(allocator, input, effective_route),
        };
    }

    fn applyFeedAgentMemoryRuntimeInner(self: *Store, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput, route: AgentMemoryStorageRoute) !FeedAgentMemoryApplyResult {
        var object_id: []const u8 = input.delete_key orelse "agent_memory";
        var entry: ?domain.AgentMemory = null;
        var deleted = false;
        const event_payload_json = try payloadWithStorageRouteJson(allocator, input.event.payload_json, route);
        defer allocator.free(event_payload_json);
        if (input.input) |memory_input| {
            var auditable = memory_input;
            if (auditable.writer_actor_id == null) auditable.writer_actor_id = input.writer_actor_id orelse input.event.actor_id;
            if (auditable.actor_scopes_json == null) auditable.actor_scopes_json = input.actor_scopes_json;
            if (auditable.actor_capabilities_json == null) auditable.actor_capabilities_json = input.actor_capabilities_json;
            auditable.suppress_feed = true;
            const saved = try self.agentMemoryStoreRouted(allocator, auditable, route);
            object_id = saved.id;
            entry = saved;
        } else if (input.delete_key) |key| {
            deleted = if (input.delete_all)
                try self.agentMemoryDeleteAllRoutedInner(key, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, input.actor_scopes_json, input.actor_capabilities_json, route, true, input.event_order)
            else
                try self.agentMemoryDeleteRoutedInner(key, input.delete_session_id, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, input.actor_scopes_json, input.actor_capabilities_json, route, true, input.event_order);
            object_id = key;
        }

        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, object_id, event_payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = object_id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        });
        return .{ .event_id = event_id, .object_id = object_id, .entry = entry, .deleted = deleted };
    }

    pub fn applyExtractedKnowledge(self: *Store, allocator: std.mem.Allocator, input: ExtractedKnowledgeInput) !ExtractedKnowledgeResult {
        const result = try switch (self.backend) {
            .sqlite => |*s| s.applyExtractedKnowledge(allocator, input),
            .postgres => |*p| p.applyExtractedKnowledge(allocator, input),
        };
        if (result.artifact) |artifact| try self.appendArtifactPutFeedEvent(allocator, artifact, input.actor_id, .{});
        for (result.entities) |entity| try self.appendEntityPutFeedEvent(allocator, entity, input.actor_id, .{});
        for (result.relations) |relation| try self.appendRelationPutFeedEvent(allocator, relation, input.actor_id, .{});
        for (result.atoms) |atom| {
            if (!std.mem.eql(u8, atom.predicate, "agent.memory")) try self.appendMemoryAtomPutFeedEvent(allocator, atom, input.actor_id, .{});
        }
        return result;
    }

    pub fn agentMemoryStore(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        const normalized = normalizeAgentMemoryInput(input);
        if (self.agent_memory.isExternal()) return self.agentMemoryStoreRuntime(allocator, normalized);
        return self.agentMemoryStoreNative(allocator, normalized);
    }

    pub fn agentMemoryStoreRouted(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput, route: AgentMemoryStorageRoute) !domain.AgentMemory {
        const normalized = normalizeAgentMemoryInput(input);
        return switch (route.target) {
            .primary => self.agentMemoryStore(allocator, normalized),
            .native => self.agentMemoryStoreNative(allocator, normalized),
            .runtime => self.agentMemoryStoreRuntime(allocator, normalized),
            .named => self.agentMemoryStoreNamed(allocator, normalized, route),
            .subset => self.agentMemoryStoreSubset(allocator, normalized, route),
            .all => blk: {
                var result = try self.agentMemoryStoreNative(allocator, normalized);
                errdefer agent_memory_runtime.freeAgentMemory(allocator, &result);
                if (self.agent_memory.isExternal() and !self.agent_memory.isNoop()) {
                    const next = try self.agentMemoryStoreRuntime(allocator, normalized);
                    agent_memory_runtime.freeAgentMemory(allocator, &result);
                    result = next;
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (named.runtime.isNoop()) continue;
                    const next = try self.agentMemoryStoreInRuntime(allocator, &named.runtime, normalized, named.name);
                    agent_memory_runtime.freeAgentMemory(allocator, &result);
                    result = next;
                }
                break :blk result;
            },
        };
    }

    fn namedAgentMemoryRuntime(self: *Store, route: AgentMemoryStorageRoute) !*agent_memory_runtime.Runtime {
        const name = route.name orelse return error.AgentMemoryStorageUnavailable;
        return self.agent_memory_stores.get(name) orelse error.AgentMemoryStorageUnavailable;
    }

    fn agentMemoryStoreRuntime(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
        return self.agentMemoryStoreInRuntime(allocator, &self.agent_memory, normalizeAgentMemoryInput(input), "runtime");
    }

    fn agentMemoryStoreNamed(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput, route: AgentMemoryStorageRoute) !domain.AgentMemory {
        const runtime = try self.namedAgentMemoryRuntime(route);
        return self.agentMemoryStoreInRuntime(allocator, runtime, input, route.name orelse "named");
    }

    fn agentMemoryStoreInRuntime(self: *Store, allocator: std.mem.Allocator, runtime: *agent_memory_runtime.Runtime, input: AgentMemoryInput, store_name: []const u8) !domain.AgentMemory {
        const normalized = normalizeAgentMemoryInput(input);
        const runtime_input: agent_memory_runtime.Input = .{
            .key = normalized.key,
            .content = normalized.content,
            .category = normalized.category,
            .session_id = normalized.session_id,
            .scope = normalized.scope,
            .permissions_json = normalized.permissions_json,
            .metadata_json = normalized.metadata_json,
            .actor_id = normalized.actor_id,
            .writer_actor_id = normalized.writer_actor_id,
            .actor_scopes_json = normalized.actor_scopes_json,
            .actor_capabilities_json = normalized.actor_capabilities_json,
            .operation = normalized.operation,
            .suppress_feed = normalized.suppress_runtime_feed,
            .event_order = runtimeAgentMemoryEventOrder(normalized.event_order),
        };
        var entry = try runtime.store(allocator, runtime_input);
        try tagAgentMemoryStore(allocator, &entry, store_name);
        errdefer {
            var cleanup = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &cleanup);
        }
        if (std.mem.eql(u8, entry.status, "ignored")) return entry;
        if (runtime.isNoop()) return entry;
        if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) return entry;
        try self.materializeRuntimeAgentMemory(allocator, entry, store_name);
        if (!normalized.suppress_feed) try self.appendAgentMemoryFeedEvent(allocator, entry, store_name, normalized.operation, normalized.content);
        try self.enqueueAgentMemoryLucidPut(allocator, entry, normalized.writer_actor_id orelse normalized.actor_id);
        return entry;
    }

    fn agentMemoryStoreNative(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        const normalized = normalizeAgentMemoryInput(input);
        var entry = try switch (self.backend) {
            .sqlite => |*s| s.agentMemoryStore(allocator, normalized),
            .postgres => |*p| p.agentMemoryStore(allocator, normalized),
        };
        try tagAgentMemoryStore(allocator, &entry, "native");
        errdefer {
            var cleanup = entry;
            agent_memory_runtime.freeAgentMemory(allocator, &cleanup);
        }
        if (!normalized.suppress_feed) try self.appendAgentMemoryFeedEvent(allocator, entry, "native", normalized.operation, normalized.content);
        try self.enqueueAgentMemoryLucidPut(allocator, entry, normalized.writer_actor_id orelse normalized.actor_id);
        return entry;
    }

    fn materializeRuntimeAgentMemory(self: *Store, allocator: std.mem.Allocator, entry: domain.AgentMemory, store_name: []const u8) !void {
        try self.deprecateRuntimeAgentMemoryMirrors(allocator, store_name, entry.key, entry.session_id, entry.actor_id, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
        const source_title = try std.fmt.allocPrint(allocator, "Runtime agent memory: {s}:{s}", .{ store_name, entry.key });
        defer allocator.free(source_title);
        const metadata = try agentMemoryRuntimeMetadataJson(allocator, store_name, entry);
        defer allocator.free(metadata);
        const source = try self.createRuntimeAgentMemorySource(allocator, .{
            .source_type = "agent_observation",
            .title = source_title,
            .content = entry.content,
            .scope = entry.scope,
            .permissions_json = entry.permissions_json,
            .metadata_json = metadata,
            .actor_id = if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
        });
        defer allocator.free(source.id);
        const source_ids = try singleJsonString(allocator, source.id);
        defer allocator.free(source_ids);
        const evidence = try evidenceRangeJson(allocator, source.id, entry.content.len, "agent_memory_runtime");
        defer allocator.free(evidence);
        const atom = try self.createMemoryAtom(allocator, .{
            .predicate = "agent.memory",
            .object = entry.key,
            .text = entry.content,
            .scope = entry.scope,
            .confidence = 0.8,
            .status = domain.defaultMemoryStatus("agent", entry.scope),
            .source_ids_json = source_ids,
            .evidence_ranges_json = evidence,
            .created_by = "agent",
            .permissions_json = entry.permissions_json,
            .tags_json = "[\"agent_memory\",\"runtime\"]",
            .actor_id = if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
        });
        defer allocator.free(atom.id);
    }

    fn deprecateRuntimeAgentMemoryMirrors(self: *Store, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: ?[]const u8) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.deprecateRuntimeAgentMemoryMirrors(store_name, key, session_id, owner_actor_id, writer_actor_id),
            .postgres => |*p| p.deprecateRuntimeAgentMemoryMirrors(allocator, store_name, key, session_id, owner_actor_id, writer_actor_id),
        };
    }

    fn deprecateRuntimeAgentMemoryMirrorsAllSessions(self: *Store, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, owner_actor_id: []const u8, writer_actor_id: ?[]const u8) !void {
        return switch (self.backend) {
            .sqlite => |*s| s.deprecateRuntimeAgentMemoryMirrorsAllSessions(store_name, key, owner_actor_id, writer_actor_id),
            .postgres => |*p| p.deprecateRuntimeAgentMemoryMirrorsAllSessions(allocator, store_name, key, owner_actor_id, writer_actor_id),
        };
    }

    fn patchRuntimeAgentMemoryMirrorsStatus(self: *Store, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.patchRuntimeAgentMemoryMirrorsStatus(store_name, key, session_id, owner_actor_id, status, writer_actor_id),
            .postgres => |*p| p.patchRuntimeAgentMemoryMirrorsStatus(allocator, store_name, key, session_id, owner_actor_id, status, writer_actor_id),
        };
    }

    fn patchAgentMemoryStatusNative(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.patchAgentMemoryStatusOrdered(allocator, key, session_id, owner_actor_id, status, writer_actor_id, event_order),
            .postgres => |*p| p.patchAgentMemoryStatusOrdered(allocator, key, session_id, owner_actor_id, status, writer_actor_id, event_order),
        };
    }

    fn patchAgentMemoryRuntimeStatus(self: *Store, allocator: std.mem.Allocator, runtime: *agent_memory_runtime.Runtime, store_name: []const u8, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (!domain.isDefaultVisibleStatus(status)) {
            const deleted = try runtime.deleteByInput(.{
                .key = key,
                .session_id = session_id,
                .actor_id = owner_actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
            });
            if (deleted) {
                _ = try self.patchRuntimeAgentMemoryMirrorsStatus(allocator, store_name, key, session_id, owner_actor_id, status, writer_actor_id);
                return true;
            }
            var existing_after_delete = try runtime.getByInput(allocator, .{
                .key = key,
                .session_id = session_id,
                .actor_id = owner_actor_id,
                .capabilities_json = actor_capabilities_json,
            });
            defer if (existing_after_delete) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            return existing_after_delete != null;
        }
        const changed = try runtime.patchStatusByInput(allocator, .{
            .key = key,
            .status = status,
            .session_id = session_id,
            .actor_id = owner_actor_id,
            .writer_actor_id = writer_actor_id,
            .actor_scopes_json = actor_scopes_json,
            .actor_capabilities_json = actor_capabilities_json,
            .event_order = runtimeAgentMemoryEventOrder(event_order),
        });
        if (changed) {
            _ = try self.patchRuntimeAgentMemoryMirrorsStatus(allocator, store_name, key, session_id, owner_actor_id, status, writer_actor_id);
            return true;
        }
        var existing = try runtime.getByInput(allocator, .{
            .key = key,
            .session_id = session_id,
            .actor_id = owner_actor_id,
            .capabilities_json = actor_capabilities_json,
        });
        defer if (existing) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
        return existing != null;
    }

    pub fn patchAgentMemoryStatusRouted(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.patchAgentMemoryStatusRoutedOrdered(allocator, key, session_id, owner_actor_id, status, writer_actor_id, route, null);
    }

    pub fn patchAgentMemoryStatusRoutedWithScopes(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.patchAgentMemoryStatusRoutedOrderedWithScopes(allocator, key, session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, route, null);
    }

    pub fn patchAgentMemoryStatusRoutedOrderedWithAuth(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, event_order: ?AgentMemoryEventOrder) !bool {
        const normalized_session_id = access.normalizeSessionId(session_id);
        return switch (route.target) {
            .primary => if (self.agent_memory.isExternal())
                self.patchAgentMemoryRuntimeStatus(allocator, &self.agent_memory, "runtime", key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order)
            else
                self.patchAgentMemoryStatusNative(allocator, key, normalized_session_id, owner_actor_id, status, writer_actor_id, event_order),
            .native => self.patchAgentMemoryStatusNative(allocator, key, normalized_session_id, owner_actor_id, status, writer_actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal())
                self.patchAgentMemoryRuntimeStatus(allocator, &self.agent_memory, "runtime", key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order)
            else
                error.AgentMemoryStorageUnavailable,
            .named => self.patchAgentMemoryRuntimeStatus(allocator, try self.namedAgentMemoryRuntime(route), route.name orelse "named", key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order),
            .subset => blk: {
                const stores = try requireSubsetStores(route);
                var changed = false;
                for (stores) |store_name| {
                    changed = (try self.patchAgentMemoryStatusRoutedOrderedWithAuth(allocator, key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, routeForSubsetStoreName(store_name), event_order)) or changed;
                }
                break :blk changed;
            },
            .all => blk: {
                var changed = try self.patchAgentMemoryStatusNative(allocator, key, normalized_session_id, owner_actor_id, status, writer_actor_id, event_order);
                if (self.agent_memory.isExternal()) {
                    changed = (try self.patchAgentMemoryRuntimeStatus(allocator, &self.agent_memory, "runtime", key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order)) or changed;
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    changed = (try self.patchAgentMemoryRuntimeStatus(allocator, &named.runtime, named.name, key, normalized_session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order)) or changed;
                }
                break :blk changed;
            },
        };
    }

    fn agentMemoryReplayBlockedByTombstoneNative(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.agentMemoryTombstoneBlocksReplay(key, session_id, owner_actor_id, event_order),
            .postgres => |*p| p.agentMemoryTombstoneBlocksReplay(allocator, key, session_id, owner_actor_id, event_order),
        };
    }

    fn agentMemoryReplayBlockedByTombstoneRuntime(_: *Store, allocator: std.mem.Allocator, runtime: *agent_memory_runtime.Runtime, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        return runtime.tombstoneBlocksReplayByInput(allocator, .{
            .key = key,
            .session_id = session_id,
            .actor_id = owner_actor_id,
            .event_order = runtimeAgentMemoryEventOrder(event_order).?,
        });
    }

    pub fn agentMemoryReplayBlockedByTombstoneRouted(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, route: AgentMemoryStorageRoute, event_order: AgentMemoryEventOrder) !bool {
        const normalized_session_id = access.normalizeSessionId(session_id);
        return switch (route.target) {
            .primary => if (self.agent_memory.isExternal())
                self.agentMemoryReplayBlockedByTombstoneRuntime(allocator, &self.agent_memory, key, normalized_session_id, owner_actor_id, event_order)
            else
                self.agentMemoryReplayBlockedByTombstoneNative(allocator, key, normalized_session_id, owner_actor_id, event_order),
            .native => self.agentMemoryReplayBlockedByTombstoneNative(allocator, key, normalized_session_id, owner_actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal())
                self.agentMemoryReplayBlockedByTombstoneRuntime(allocator, &self.agent_memory, key, normalized_session_id, owner_actor_id, event_order)
            else
                false,
            .named => self.agentMemoryReplayBlockedByTombstoneRuntime(allocator, try self.namedAgentMemoryRuntime(route), key, normalized_session_id, owner_actor_id, event_order),
            .subset => blk: {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| {
                    if (try self.agentMemoryReplayBlockedByTombstoneRouted(allocator, key, normalized_session_id, owner_actor_id, routeForSubsetStoreName(store_name), event_order)) break :blk true;
                }
                break :blk false;
            },
            .all => blk: {
                if (try self.agentMemoryReplayBlockedByTombstoneNative(allocator, key, normalized_session_id, owner_actor_id, event_order)) break :blk true;
                if (self.agent_memory.isExternal()) {
                    if (try self.agentMemoryReplayBlockedByTombstoneRuntime(allocator, &self.agent_memory, key, normalized_session_id, owner_actor_id, event_order)) break :blk true;
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (try self.agentMemoryReplayBlockedByTombstoneRuntime(allocator, &named.runtime, key, normalized_session_id, owner_actor_id, event_order)) break :blk true;
                }
                break :blk false;
            },
        };
    }

    pub fn agentMemoryLifecycleCanDelegateMissingTargetRouted(self: *Store, route: AgentMemoryStorageRoute) !bool {
        return switch (route.target) {
            .primary => self.agent_memory.isExternal() and self.agent_memory.delegatesMissingLifecycleTarget(),
            .native => false,
            .runtime => self.agent_memory.isExternal() and self.agent_memory.delegatesMissingLifecycleTarget(),
            .named => (try self.namedAgentMemoryRuntime(route)).delegatesMissingLifecycleTarget(),
            .subset => blk: {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| {
                    if (try self.agentMemoryLifecycleCanDelegateMissingTargetRouted(routeForSubsetStoreName(store_name))) break :blk true;
                }
                break :blk false;
            },
            .all => blk: {
                if (self.agent_memory.isExternal() and self.agent_memory.delegatesMissingLifecycleTarget()) break :blk true;
                for (self.agent_memory_stores.stores.items) |*named| {
                    if (named.runtime.delegatesMissingLifecycleTarget()) break :blk true;
                }
                break :blk false;
            },
        };
    }

    pub fn agentMemoryLifecycleRequiresRemoteTargetLookupRouted(self: *Store, route: AgentMemoryStorageRoute) !bool {
        return switch (route.target) {
            .primary => self.agent_memory.isExternal() and self.agent_memory.delegatesMissingLifecycleTarget(),
            .native => false,
            .runtime => self.agent_memory.isExternal() and self.agent_memory.delegatesMissingLifecycleTarget(),
            .named => (try self.namedAgentMemoryRuntime(route)).delegatesMissingLifecycleTarget(),
            .subset => blk: {
                const stores = try requireSubsetStores(route);
                var saw_store = false;
                for (stores) |store_name| {
                    saw_store = true;
                    if (!try self.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(routeForSubsetStoreName(store_name))) break :blk false;
                }
                break :blk saw_store;
            },
            .all => false,
        };
    }

    pub fn patchAgentMemoryStatusRoutedOrdered(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute, event_order: ?AgentMemoryEventOrder) !bool {
        return self.patchAgentMemoryStatusRoutedOrderedWithScopes(allocator, key, session_id, owner_actor_id, status, writer_actor_id, null, route, event_order);
    }

    pub fn patchAgentMemoryStatusRoutedOrderedWithScopes(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, route: AgentMemoryStorageRoute, event_order: ?AgentMemoryEventOrder) !bool {
        return self.patchAgentMemoryStatusRoutedOrderedWithAuth(allocator, key, session_id, owner_actor_id, status, writer_actor_id, actor_scopes_json, null, route, event_order);
    }

    fn deprecateRuntimeAgentMemoryMirrorsForDelete(self: *Store, key: []const u8, session_id: ?[]const u8, owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const owner = owner_actor_id orelse return;
        switch (route.target) {
            .primary => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id),
            .native => {},
            .runtime => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id),
            .named => try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, route.name orelse "named", key, session_id, owner, writer_actor_id),
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.deprecateRuntimeAgentMemoryMirrorsForDelete(key, session_id, owner, writer_actor_id, routeForSubsetStoreName(store_name));
            },
            .all => {
                if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, "runtime", key, session_id, owner, writer_actor_id);
                for (self.agent_memory_stores.stores.items) |named| {
                    try self.deprecateRuntimeAgentMemoryMirrors(self.allocator, named.name, key, session_id, owner, writer_actor_id);
                }
            },
        }
    }

    fn deprecateRuntimeAgentMemoryMirrorsForDeleteAll(self: *Store, key: []const u8, owner_actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const owner = owner_actor_id orelse return;
        switch (route.target) {
            .primary => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id),
            .native => {},
            .runtime => if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id),
            .named => try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, route.name orelse "named", key, owner, writer_actor_id),
            .subset => {
                const stores = try requireSubsetStores(route);
                for (stores) |store_name| try self.deprecateRuntimeAgentMemoryMirrorsForDeleteAll(key, owner, writer_actor_id, routeForSubsetStoreName(store_name));
            },
            .all => {
                if (self.agent_memory.isExternal()) try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, "runtime", key, owner, writer_actor_id);
                for (self.agent_memory_stores.stores.items) |named| {
                    try self.deprecateRuntimeAgentMemoryMirrorsAllSessions(self.allocator, named.name, key, owner, writer_actor_id);
                }
            },
        }
    }

