    fn routeForSubsetStoreName(name: []const u8) AgentMemoryStorageRoute {
        return store_agent_memory_subset.routeForStoreName(name);
    }

    pub fn agentMemoryRouteIncludesNative(self: *Store, route: AgentMemoryStorageRoute) bool {
        return switch (route.target) {
            .primary => !self.agent_memory.isExternal(),
            .native => true,
            .runtime, .named => false,
            .all => true,
            .subset => blk: {
                for (route.stores) |store_name| {
                    if (self.agentMemoryRouteIncludesNative(routeForSubsetStoreName(store_name))) break :blk true;
                }
                break :blk false;
            },
        };
    }

    fn routeForAgentMemoryStoreTag(store_name: []const u8) AgentMemoryStorageRoute {
        if (std.mem.eql(u8, store_name, "native")) return .{ .target = .native };
        if (std.mem.eql(u8, store_name, "runtime")) return .{ .target = .runtime };
        return .{ .target = .named, .name = store_name };
    }

    fn requireSubsetStores(route: AgentMemoryStorageRoute) anyerror![]const []const u8 {
        return store_agent_memory_subset.requireStores(route);
    }

    fn agentMemoryStoreSubset(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryInput, route: AgentMemoryStorageRoute) anyerror!domain.AgentMemory {
        const stores = try requireSubsetStores(route);
        var result: ?domain.AgentMemory = null;
        errdefer if (result) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
        var noop_result: ?domain.AgentMemory = null;
        errdefer if (noop_result) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);

        for (stores) |store_name| {
            const store_route = routeForSubsetStoreName(store_name);
            const next = try self.agentMemoryStoreRouted(allocator, input, store_route);
            if (try self.agentMemoryRouteIsNoop(store_route)) {
                if (noop_result) |*previous| agent_memory_runtime.freeAgentMemory(allocator, previous);
                noop_result = next;
                continue;
            }
            if (result) |*previous| agent_memory_runtime.freeAgentMemory(allocator, previous);
            result = next;
        }
        if (result) |entry| {
            if (noop_result) |*previous| agent_memory_runtime.freeAgentMemory(allocator, previous);
            return entry;
        }
        return noop_result orelse error.AgentMemoryStorageUnavailable;
    }

    fn agentMemoryRouteIsNoop(self: *Store, route: AgentMemoryStorageRoute) !bool {
        return switch (route.target) {
            .primary => self.agent_memory.isExternal() and self.agent_memory.isNoop(),
            .native => false,
            .runtime => if (self.agent_memory.isExternal()) self.agent_memory.isNoop() else error.AgentMemoryStorageUnavailable,
            .named => (try self.namedAgentMemoryRuntime(route)).isNoop(),
            .subset, .all => false,
        };
    }

    fn agentMemoryDeleteSubset(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) anyerror!bool {
        return self.agentMemoryDeleteSubsetInner(key, session_id, actor_id, writer_actor_id, null, null, route, false, null);
    }

    fn agentMemoryDeleteSubsetInner(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, suppress_feed: bool, event_order: ?AgentMemoryEventOrder) anyerror!bool {
        const stores = try requireSubsetStores(route);
        var deleted = false;
        for (stores) |store_name| {
            deleted = (try self.agentMemoryDeleteRoutedInner(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, routeForSubsetStoreName(store_name), suppress_feed, event_order)) or deleted;
        }
        return deleted;
    }

