    fn loadMessagesSubset(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) anyerror![]Message {
        return self.loadMessagesSubsetWithAuth(allocator, session_id, actor_id, null, route);
    }

    fn loadMessagesSubsetWithAuth(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) anyerror![]Message {
        const stores = try requireSubsetStores(route);
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessageOwned(allocator, message);
            out.deinit(allocator);
        }
        for (stores) |store_name| {
            const messages = try self.loadMessagesRoutedWithAuth(allocator, session_id, actor_id, actor_capabilities_json, routeForSubsetStoreName(store_name));
            defer allocator.free(messages);
            if (out.items.len == 0) {
                try appendMessageSlice(allocator, &out, messages);
            } else {
                try appendMissingMessageSlice(allocator, &out, messages);
            }
        }
        sortMessages(out.items);
        return out.toOwnedSlice(allocator);
    }

