    fn agentMemoryGetWithAuth(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(session_id);
        if (self.agent_memory.isExternal()) {
            var entry = try self.agent_memory.getByInput(allocator, .{
                .key = key,
                .session_id = normalized_session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            });
            if (entry) |*value| try tagAgentMemoryStore(allocator, value, "runtime");
            return entry;
        }
        return self.agentMemoryGetNative(allocator, key, normalized_session_id, actor_id);
    }

