    pub fn agentMemoryGetByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryGetInput) !?domain.AgentMemory {
        const normalized = normalizeAgentMemoryGetInput(input);
        return switch (normalized.route.target) {
            .primary => self.agentMemoryGetPrimaryByInput(allocator, normalized),
            .native => self.agentMemoryGetNativeByInput(allocator, normalized),
            .runtime => blk: {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                break :blk try agentMemoryGetRuntimeByInput(allocator, &self.agent_memory, normalized, "runtime");
            },
            .named => self.agentMemoryGetNamedByInput(allocator, normalized),
            .subset => store_agent_memory_subset.getByInput(self, allocator, normalized),
            .all => self.agentMemoryGetAllByInput(allocator, normalized),
        };
    }

    fn normalizeAgentMemoryGetInput(input: AgentMemoryGetInput) AgentMemoryGetInput {
        var normalized = input;
        normalized.session_id = access.normalizeSessionId(input.session_id);
        return normalized;
    }

    fn agentMemoryRuntimeGetInput(input: AgentMemoryGetInput) agent_memory_runtime.GetInput {
        return .{
            .key = input.key,
            .session_id = if (input.access == .any_visible) null else input.session_id,
            .actor_id = input.actor_id,
            .scopes_json = if (input.access == .exact_owner) null else input.scopes_json,
            .capabilities_json = input.capabilities_json,
            .any_session = input.access == .any_visible,
        };
    }

    fn agentMemoryGetRuntimeByInput(allocator: std.mem.Allocator, runtime: *agent_memory_runtime.Runtime, input: AgentMemoryGetInput, store_name: []const u8) !?domain.AgentMemory {
        var entry = try runtime.getByInput(allocator, agentMemoryRuntimeGetInput(input));
        if (entry) |*value| try tagAgentMemoryStore(allocator, value, store_name);
        return entry;
    }

    fn agentMemoryGetNativeByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryGetInput) !?domain.AgentMemory {
        return switch (input.access) {
            .exact_owner => self.agentMemoryGetNative(allocator, input.key, input.session_id, input.actor_id),
            .visible => self.agentMemoryGetVisibleNative(allocator, input.key, input.session_id, try requiredActorId(input.actor_id), input.scopes_json),
            .any_visible => self.agentMemoryGetAnyVisibleNative(allocator, input.key, try requiredActorId(input.actor_id), input.scopes_json),
        };
    }

    fn agentMemoryGetPrimaryByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryGetInput) !?domain.AgentMemory {
        if (self.agent_memory.isExternal()) {
            const runtime_entry = try agentMemoryGetRuntimeByInput(allocator, &self.agent_memory, input, "runtime");
            if (input.access != .any_visible or runtime_entry != null) return runtime_entry;
        }
        return self.agentMemoryGetNativeByInput(allocator, input);
    }

    fn agentMemoryGetNamedByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryGetInput) !?domain.AgentMemory {
        return agentMemoryGetRuntimeByInput(allocator, try self.namedAgentMemoryRuntime(input.route), input, input.route.name orelse "named");
    }

    fn agentMemoryGetAllByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryGetInput) !?domain.AgentMemory {
        if (self.agent_memory.isExternal()) {
            if (try agentMemoryGetRuntimeByInput(allocator, &self.agent_memory, input, "runtime")) |entry| return entry;
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            if (try agentMemoryGetRuntimeByInput(allocator, &named.runtime, input, named.name)) |entry| return entry;
        }
        return self.agentMemoryGetNativeByInput(allocator, input);
    }

    fn agentMemoryGetVisibleNative(self: *Store, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var entry = try switch (self.backend) {
            .sqlite => |*s| s.agentMemoryGetVisible(allocator, key, session_id, actor_id, scopes_json),
            .postgres => |*p| p.agentMemoryGetVisible(allocator, key, session_id, actor_id, scopes_json),
        };
        if (entry) |*value| try tagAgentMemoryStore(allocator, value, "native");
        return entry;
    }

    fn agentMemoryGetAnyVisibleNative(self: *Store, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
