    fn agentMemoryListRoutedWithAuth(self: *Store, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(session_id);
        return switch (route.target) {
            .primary => self.agentMemoryListWithAuth(allocator, category, normalized_session_id, actor_id, actor_capabilities_json),
            .native => self.agentMemoryListNative(allocator, category, normalized_session_id, actor_id),
            .runtime => blk: {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                const entries = try self.agent_memory.listByInput(allocator, .{
                    .category = category,
                    .session_id = normalized_session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                });
                try tagAgentMemorySliceStore(allocator, entries, "runtime");
                break :blk entries;
            },
            .named => blk: {
                const entries = try (try self.namedAgentMemoryRuntime(route)).listByInput(allocator, .{
                    .category = category,
                    .session_id = normalized_session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                });
                try tagAgentMemorySliceStore(allocator, entries, route.name orelse "named");
                break :blk entries;
            },
            .subset => store_agent_memory_subset.listByInput(self, allocator, .{
                .category = category,
                .session_id = normalized_session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
                .route = route,
                .access = .exact_owner,
            }),
            .all => self.agentMemoryListAllByInput(allocator, .{
                .category = category,
                .session_id = normalized_session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
                .route = route,
                .access = .exact_owner,
            }),
        };
    }

