    pub fn agentMemoryListByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryListInput) ![]domain.AgentMemory {
        if (input.limit) |limit| {
            return switch (input.access) {
                .exact_owner => self.agentMemoryListRoutedWindowWithAuth(allocator, input.category, input.session_id, input.actor_id, input.capabilities_json, input.route, limit, input.offset),
                .visible => self.agentMemoryListVisibleRoutedWindowWithAuth(allocator, input.category, input.session_id, try requiredActorId(input.actor_id), input.scopes_json, input.capabilities_json, input.route, limit, input.offset),
                .any_visible => self.agentMemoryListAnyVisibleRoutedWindowWithAuth(allocator, input.category, try requiredActorId(input.actor_id), input.scopes_json, input.capabilities_json, input.route, limit, input.offset),
            };
        }
        return switch (input.access) {
            .exact_owner => self.agentMemoryListRoutedWithAuth(allocator, input.category, input.session_id, input.actor_id, input.capabilities_json, input.route),
            .visible => self.agentMemoryListVisibleRoutedWithAuth(allocator, input.category, input.session_id, try requiredActorId(input.actor_id), input.scopes_json, input.capabilities_json, input.route),
            .any_visible => self.agentMemoryListAnyVisibleRoutedWithAuth(allocator, input.category, try requiredActorId(input.actor_id), input.scopes_json, input.capabilities_json, input.route),
        };
    }

    pub fn runRoutedAgentMemoryDedupe(self: *Store, allocator: std.mem.Allocator, input: HygieneRunInput, route: AgentMemoryStorageRoute, options: RoutedAgentMemoryDedupeInput, result: *HygieneRunResult) !void {
        const actor_id = input.actor_id orelse return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const scratch = arena.allocator();
        const limit = @max(@as(usize, 1), @min(input.dedupe_limit, @as(usize, 20_000)));
        const session_id = access.normalizeSessionId(options.session_id);
        const entries = if (session_id) |sid|
            try self.agentMemoryListVisibleRoutedWithAuth(scratch, options.category, sid, actor_id, input.scopes_json, input.capabilities_json, route)
        else
            try self.agentMemoryListAnyVisibleRoutedWithAuth(scratch, options.category, actor_id, input.scopes_json, input.capabilities_json, route);
        defer freeAgentMemorySlice(scratch, entries);

        var winners: std.StringHashMapUnmanaged(RoutedAgentMemoryDedupeWinner) = .{};
        defer winners.deinit(scratch);

        var scanned: usize = 0;
        for (entries) |entry| {
            const store_name = if (entry.store.len > 0) entry.store else "native";
            if (std.mem.eql(u8, store_name, "native")) continue;
            if (scanned >= limit) break;
            if (std.mem.eql(u8, entry.status, "rejected") or
                std.mem.eql(u8, entry.status, "deprecated") or
                std.mem.eql(u8, entry.status, "superseded")) continue;
            if (!options.include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) continue;

            scanned += 1;
            result.agent_memory_dedupe_checked += 1;
            const dedupe_key = (try hygieneRoutedAgentMemoryDedupeKey(scratch, store_name, entry.scope, entry.permissions_json, entry.category, entry.session_id, entry.content, input.dedupe_normalized)) orelse continue;
            const created = std.fmt.parseInt(i64, entry.timestamp, 10) catch 0;
            const map_entry = try winners.getOrPut(scratch, dedupe_key);
            if (!map_entry.found_existing) {
                map_entry.key_ptr.* = dedupe_key;
                map_entry.value_ptr.* = .{
                    .key = entry.key,
                    .session_id = entry.session_id,
                    .actor_id = entry.actor_id,
                    .store = store_name,
                    .status = entry.status,
                    .scope = entry.scope,
                    .permissions_json = entry.permissions_json,
                    .created_at_ms = created,
                };
                continue;
            }
            if (!map_entry.value_ptr.seen_duplicate) {
                result.agent_memory_dedupe_groups += 1;
                map_entry.value_ptr.seen_duplicate = true;
            }
            const winner = map_entry.value_ptr.*;
            const replace_winner = blk: {
                const current_rank = hygieneAtomDedupeRank(entry.status);
                const winner_rank = hygieneAtomDedupeRank(winner.status);
                if (current_rank != winner_rank) break :blk current_rank > winner_rank;
                break :blk created > winner.created_at_ms;
            };
            if (replace_winner) {
                if (try self.deleteRoutedAgentMemoryDuplicate(input, winner)) {
                    if (input.hard_delete) result.agent_memory_dedupe_purged += 1 else result.agent_memory_dedupe_deprecated += 1;
                }
                map_entry.value_ptr.* = .{
                    .key = entry.key,
                    .session_id = entry.session_id,
                    .actor_id = entry.actor_id,
                    .store = store_name,
                    .status = entry.status,
                    .scope = entry.scope,
                    .permissions_json = entry.permissions_json,
                    .created_at_ms = created,
                    .seen_duplicate = true,
                };
            } else if (try self.deleteRoutedAgentMemoryDuplicate(input, .{
                .key = entry.key,
                .session_id = entry.session_id,
                .actor_id = entry.actor_id,
                .store = store_name,
                .status = entry.status,
                .scope = entry.scope,
                .permissions_json = entry.permissions_json,
                .created_at_ms = created,
            })) {
                if (input.hard_delete) result.agent_memory_dedupe_purged += 1 else result.agent_memory_dedupe_deprecated += 1;
            }
        }
    }

    fn deleteRoutedAgentMemoryDuplicate(self: *Store, input: HygieneRunInput, duplicate: RoutedAgentMemoryDedupeWinner) !bool {
        if (!hygieneCanDeprecateAtom(input, duplicate.status, duplicate.scope, duplicate.permissions_json)) return false;
        return self.agentMemoryDeleteRoutedWithAuth(duplicate.key, duplicate.session_id, duplicate.actor_id, input.actor_id, input.scopes_json, input.capabilities_json, routeForAgentMemoryStoreTag(duplicate.store));
    }

