        const entries = try switch (self.backend) {
            .sqlite => |*s| s.agentMemoryListAnyVisibleWindow(allocator, category, actor_id, scopes_json, limit, offset),
            .postgres => |*p| p.agentMemoryListAnyVisibleWindow(allocator, category, actor_id, scopes_json, limit, offset),
        };
        try tagAgentMemorySliceStore(allocator, entries, "native");
        return entries;
    }

    fn agentMemorySearch(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
