    fn agentMemorySearchWithAuth(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(session_id);
        if (self.agent_memory.isExternal()) {
            const entries = try self.agent_memory.searchByInput(allocator, .{
                .query = query,
                .limit = limit,
                .session_id = normalized_session_id,
                .scopes_json = scopes_json,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
