    }

    fn agentMemorySearchRouted(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) ![]domain.AgentMemory {
