    }

    fn agentMemorySearchRoutedWithAuth(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(session_id);
        return switch (route.target) {
            .primary => self.agentMemorySearchWithAuth(allocator, query, limit, normalized_session_id, scopes_json, actor_id, actor_capabilities_json),
            .native => self.agentMemorySearchNative(allocator, query, limit, normalized_session_id, scopes_json, actor_id),
            .runtime => blk: {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                const entries = try self.agent_memory.searchByInput(allocator, .{
                    .query = query,
                    .limit = limit,
                    .session_id = normalized_session_id,
                    .scopes_json = scopes_json,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                });
                try tagAgentMemorySliceStore(allocator, entries, "runtime");
                break :blk entries;
            },
            .named => blk: {
                const entries = try (try self.namedAgentMemoryRuntime(route)).searchByInput(allocator, .{
                    .query = query,
                    .limit = limit,
                    .session_id = normalized_session_id,
                    .scopes_json = scopes_json,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                });
                try tagAgentMemorySliceStore(allocator, entries, route.name orelse "named");
                break :blk entries;
            },
            .subset => store_agent_memory_subset.searchByInput(self, allocator, .{
                .query = query,
                .limit = limit,
                .session_id = normalized_session_id,
                .scopes_json = scopes_json,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
                .route = route,
            }),
            .all => self.agentMemorySearchAllByInput(allocator, .{
                .query = query,
                .limit = limit,
                .session_id = normalized_session_id,
                .scopes_json = scopes_json,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
                .route = route,
            }),
        };
    }

    fn agentMemorySearchAnyVisibleRouted(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, scopes_json: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) ![]domain.AgentMemory {
