            .named => blk: {
                const entries = try (try self.namedAgentMemoryRuntime(route)).searchByInput(allocator, .{
                    .query = query,
                    .limit = limit,
                    .scopes_json = scopes_json,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .any_session = true,
                });
                try tagAgentMemorySliceStore(allocator, entries, route.name orelse "named");
                break :blk entries;
            },
            .subset => store_agent_memory_subset.searchByInput(self, allocator, .{
                .query = query,
                .limit = limit,
                .scopes_json = scopes_json,
