            .all => self.agentMemorySearchAllByInput(allocator, .{
                .query = query,
                .limit = limit,
                .scopes_json = scopes_json,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
                .route = route,
                .access = .any_visible,
