    pub fn agentMemorySearchByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemorySearchInput) ![]domain.AgentMemory {
        return switch (input.access) {
            .exact_owner, .visible => self.agentMemorySearchRoutedWithAuth(allocator, input.query, input.limit, input.session_id, input.scopes_json, input.actor_id, input.capabilities_json, input.route),
            .any_visible => self.agentMemorySearchAnyVisibleRoutedWithAuth(allocator, input.query, input.limit, input.scopes_json, input.actor_id, input.capabilities_json, input.route),
        };
    }

    fn agentMemorySearchNative(self: *Store, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const entries = try switch (self.backend) {
            .sqlite => |*s| s.agentMemorySearch(allocator, query, limit, session_id, scopes_json, actor_id),
            .postgres => |*p| p.agentMemorySearch(allocator, query, limit, session_id, scopes_json, actor_id),
