    fn runtimeListInputForStoreInput(input: AgentMemoryListInput, limit: ?usize) agent_memory_runtime.ListInput {
        return .{
            .category = input.category,
            .session_id = if (input.access == .any_visible) null else input.session_id,
            .actor_id = input.actor_id,
            .scopes_json = if (input.access == .exact_owner) null else input.scopes_json,
            .capabilities_json = input.capabilities_json,
            .any_session = input.access == .any_visible,
            .limit = limit,
        };
    }

    fn agentMemoryListNativeByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryListInput, limit: ?usize) ![]domain.AgentMemory {
        return switch (input.access) {
            .exact_owner => if (limit) |fetch_limit|
                self.agentMemoryListNativeWindow(allocator, input.category, input.session_id, input.actor_id, fetch_limit, 0)
            else
                self.agentMemoryListNative(allocator, input.category, input.session_id, input.actor_id),
            .visible => if (limit) |fetch_limit|
                self.agentMemoryListVisibleNativeWindow(allocator, input.category, input.session_id, try requiredActorId(input.actor_id), input.scopes_json, fetch_limit, 0)
            else
                self.agentMemoryListVisibleNative(allocator, input.category, input.session_id, try requiredActorId(input.actor_id), input.scopes_json),
            .any_visible => if (limit) |fetch_limit|
                self.agentMemoryListAnyVisibleNativeWindow(allocator, input.category, try requiredActorId(input.actor_id), input.scopes_json, fetch_limit, 0)
            else
                self.agentMemoryListAnyVisibleNative(allocator, input.category, try requiredActorId(input.actor_id), input.scopes_json),
        };
    }

    fn agentMemoryListAllByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryListInput) ![]domain.AgentMemory {
        if (input.limit) |limit| {
            if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
            return self.agentMemoryListAllWindowByInput(allocator, input, limit);
        }

        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer freeAgentMemoryArrayList(allocator, &out);
        if (self.agent_memory.isExternal()) {
            const runtime = try self.agent_memory.listByInput(allocator, runtimeListInputForStoreInput(input, null));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, "runtime");
            try appendAgentMemorySlice(allocator, &out, runtime);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            const runtime = try named.runtime.listByInput(allocator, runtimeListInputForStoreInput(input, null));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, named.name);
            try appendMissingAgentMemorySlice(allocator, &out, runtime);
        }
        const native = try self.agentMemoryListNativeByInput(allocator, input, null);
        defer freeAgentMemorySlice(allocator, native);
        try appendMissingAgentMemorySlice(allocator, &out, native);
        return out.toOwnedSlice(allocator);
    }

    fn agentMemoryListAllWindowByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemoryListInput, limit: usize) ![]domain.AgentMemory {
        const fetch_limit = agentMemoryWindowPrefetchLimit(limit, input.offset);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer freeAgentMemoryArrayList(allocator, &out);
        if (self.agent_memory.isExternal()) {
            const runtime = try self.agent_memory.listByInput(allocator, runtimeListInputForStoreInput(input, fetch_limit));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, "runtime");
            try appendAgentMemorySlice(allocator, &out, runtime);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            const runtime = try named.runtime.listByInput(allocator, runtimeListInputForStoreInput(input, fetch_limit));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, named.name);
            try appendMissingAgentMemorySlice(allocator, &out, runtime);
        }
        const native = try self.agentMemoryListNativeByInput(allocator, input, fetch_limit);
        defer freeAgentMemorySlice(allocator, native);
        try appendMissingAgentMemorySlice(allocator, &out, native);
        return pageAgentMemoryArrayList(allocator, &out, limit, input.offset);
    }

    fn runtimeSearchInputForStoreInput(input: AgentMemorySearchInput) agent_memory_runtime.SearchInput {
        return .{
            .query = input.query,
            .limit = input.limit,
            .session_id = if (input.access == .any_visible) null else input.session_id,
            .scopes_json = input.scopes_json,
            .actor_id = input.actor_id,
            .capabilities_json = input.capabilities_json,
            .any_session = input.access == .any_visible,
        };
    }

    fn agentMemorySearchNativeByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemorySearchInput) ![]domain.AgentMemory {
        return switch (input.access) {
            .exact_owner, .visible => self.agentMemorySearchNative(allocator, input.query, input.limit, input.session_id, input.scopes_json, input.actor_id),
            .any_visible => self.agentMemorySearchAnyVisibleNative(allocator, input.query, input.limit, input.scopes_json, input.actor_id),
        };
    }

    fn agentMemorySearchAllByInput(self: *Store, allocator: std.mem.Allocator, input: AgentMemorySearchInput) ![]domain.AgentMemory {
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer freeAgentMemoryArrayList(allocator, &out);
        if (self.agent_memory.isExternal()) {
            const runtime = try self.agent_memory.searchByInput(allocator, runtimeSearchInputForStoreInput(input));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, "runtime");
            try appendAgentMemorySlice(allocator, &out, runtime);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            const runtime = try named.runtime.searchByInput(allocator, runtimeSearchInputForStoreInput(input));
            defer freeAgentMemorySlice(allocator, runtime);
            try tagAgentMemorySliceStore(allocator, runtime, named.name);
            try appendMissingAgentMemorySlice(allocator, &out, runtime);
        }
        const native = try self.agentMemorySearchNativeByInput(allocator, input);
        defer freeAgentMemorySlice(allocator, native);
        try appendMissingAgentMemorySlice(allocator, &out, native);
        sortAgentMemoryResults(out.items);
        trimAgentMemoryResults(allocator, &out, input.limit);
        return out.toOwnedSlice(allocator);
    }

    fn agentMemoryCountAllByInput(self: *Store, input: AgentMemoryCountInput) !usize {
        var count: usize = 0;
        if (self.agent_memory.isExternal()) {
            count += try self.agent_memory.countByInput(.{
                .scopes_json = input.scopes_json,
                .actor_id = input.actor_id,
                .capabilities_json = input.capabilities_json,
            });
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            count += try named.runtime.countByInput(.{
                .scopes_json = input.scopes_json,
                .actor_id = input.actor_id,
                .capabilities_json = input.capabilities_json,
            });
        }
        count += try self.agentMemoryCountNative(input.actor_id, input.scopes_json);
        return count;
    }

    fn agentMemoryDelete(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        const normalized_session_id = access.normalizeSessionId(session_id);
        if (self.agent_memory.isExternal()) return self.agent_memory.deleteByInput(.{
            .key = key,
            .session_id = normalized_session_id,
            .actor_id = actor_id,
            .writer_actor_id = writer_actor_id,
        });
        return self.agentMemoryDeleteNative(key, normalized_session_id, actor_id, writer_actor_id);
    }

    fn agentMemoryDeleteRouted(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteRoutedWithScopes(key, session_id, actor_id, writer_actor_id, null, route);
    }

    fn agentMemoryDeleteRoutedWithScopes(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteRoutedWithAuth(key, session_id, actor_id, writer_actor_id, actor_scopes_json, null, route);
    }

    fn agentMemoryDeleteRoutedWithAuth(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteRoutedInner(key, access.normalizeSessionId(session_id), actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, route, false, null);
    }

    fn agentMemoryDeleteAllRouted(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteAllRoutedWithScopes(key, actor_id, writer_actor_id, null, route);
    }

    fn agentMemoryDeleteAllRoutedWithScopes(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteAllRoutedWithAuth(key, actor_id, writer_actor_id, actor_scopes_json, null, route);
    }

    fn agentMemoryDeleteAllRoutedWithAuth(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !bool {
        return self.agentMemoryDeleteAllRoutedInner(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, route, false, null);
    }

    pub fn agentMemoryDeleteByInput(self: *Store, input: AgentMemoryDeleteInput) !bool {
        if (input.all_owners) {
            return self.agentMemoryDeleteAllRoutedInner(input.key, input.actor_id, input.writer_actor_id, input.actor_scopes_json, input.actor_capabilities_json, input.route, input.suppress_feed, input.event_order);
        }
        return self.agentMemoryDeleteRoutedInner(input.key, input.session_id, input.actor_id, input.writer_actor_id, input.actor_scopes_json, input.actor_capabilities_json, input.route, input.suppress_feed, input.event_order);
    }

    fn agentMemoryDeleteAllRoutedInner(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, suppress_feed: bool, event_order: ?AgentMemoryEventOrder) !bool {
        switch (route.target) {
            .subset => return self.agentMemoryDeleteAllSubsetInner(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, route, suppress_feed, event_order),
            .all => {
                var deleted = try self.agentMemoryDeleteAllRoutedInner(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .native }, suppress_feed, event_order);
                if (self.agent_memory.isExternal()) {
                    deleted = (try self.agentMemoryDeleteAllRoutedInner(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .runtime }, suppress_feed, event_order)) or deleted;
                }
                for (self.agent_memory_stores.stores.items) |named| {
                    deleted = (try self.agentMemoryDeleteAllRoutedInner(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .named, .name = named.name }, suppress_feed, event_order)) or deleted;
                }
                return deleted;
            },
            else => {},
        }

        var feed_candidate = if (!suppress_feed)
            try self.agentMemoryDeleteAllFeedCandidate(self.allocator, key, actor_id, actor_scopes_json, actor_capabilities_json, route)
        else
            null;
        defer if (feed_candidate) |*entry| agent_memory_runtime.freeAgentMemory(self.allocator, entry);

        const deleted = try switch (route.target) {
            .primary => self.agentMemoryDeleteAllPrimaryOrderedWithAuth(key, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order),
            .native => self.agentMemoryDeleteAllNativeOrdered(key, actor_id, writer_actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal()) self.agent_memory.deleteByInput(.{
                .key = key,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
                .all_owners = true,
            }) else error.AgentMemoryStorageUnavailable,
            .named => (try self.namedAgentMemoryRuntime(route)).deleteByInput(.{
                .key = key,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
                .all_owners = true,
            }),
            .subset, .all => error.AgentMemoryStorageUnavailable,
        };
        if (deleted) {
            try self.deprecateRuntimeAgentMemoryMirrorsForDeleteAll(key, actor_id, writer_actor_id, route);
            if (!suppress_feed) {
                try self.appendAgentMemoryDeleteAllFeedEvent(self.allocator, route, key, actor_id, writer_actor_id, feed_candidate);
            }
        }
        return deleted;
    }

    fn agentMemoryDeleteAllFeedCandidate(self: *Store, allocator: std.mem.Allocator, key: []const u8, actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !?domain.AgentMemory {
        const actor = actor_id orelse return null;
        const scopes_json = actor_scopes_json orelse "[]";
        return self.agentMemoryGetAnyVisibleRoutedWithAuth(allocator, key, actor, scopes_json, actor_capabilities_json, route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => null,
            else => return err,
        };
    }

    fn agentMemoryDeleteRoutedInner(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, suppress_feed: bool, event_order: ?AgentMemoryEventOrder) !bool {
        const normalized_session_id = access.normalizeSessionId(session_id);
        switch (route.target) {
            .subset => return self.agentMemoryDeleteSubsetInner(key, normalized_session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, route, suppress_feed, event_order),
            .all => {
                var deleted = try self.agentMemoryDeleteRoutedInner(key, normalized_session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .native }, suppress_feed, event_order);
                if (self.agent_memory.isExternal()) {
                    deleted = (try self.agentMemoryDeleteRoutedInner(key, normalized_session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .runtime }, suppress_feed, event_order)) or deleted;
                }
                for (self.agent_memory_stores.stores.items) |named| {
                    deleted = (try self.agentMemoryDeleteRoutedInner(key, normalized_session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, .{ .target = .named, .name = named.name }, suppress_feed, event_order)) or deleted;
                }
                return deleted;
            },
            else => {},
        }

        var existing = try self.agentMemoryGetRoutedWithAuth(self.allocator, key, normalized_session_id, actor_id, actor_capabilities_json, route);
        defer if (existing) |*entry| agent_memory_runtime.freeAgentMemory(self.allocator, entry);
        const deleted = try switch (route.target) {
            .primary => self.agentMemoryDeletePrimaryOrderedWithAuth(key, normalized_session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json, event_order),
            .native => self.agentMemoryDeleteNativeOrdered(key, normalized_session_id, actor_id, writer_actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal()) self.agent_memory.deleteByInput(.{
                .key = key,
                .session_id = normalized_session_id,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
            }) else error.AgentMemoryStorageUnavailable,
            .named => (try self.namedAgentMemoryRuntime(route)).deleteByInput(.{
                .key = key,
                .session_id = normalized_session_id,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
            }),
            .subset, .all => error.AgentMemoryStorageUnavailable,
        };
        if (deleted) {
            try self.deprecateRuntimeAgentMemoryMirrorsForDelete(key, normalized_session_id, actor_id, writer_actor_id, route);
            if (!suppress_feed) {
                try self.appendAgentMemoryDeleteFeedEvent(self.allocator, route, key, normalized_session_id, actor_id, writer_actor_id, existing);
            }
            if (existing) |entry| {
                const owner_actor_id: ?[]const u8 = if (actor_id) |owner| owner else entry.actor_id;
                try self.enqueueAgentMemoryLucidDelete(self.allocator, key, normalized_session_id, owner_actor_id, entry.scope, entry.permissions_json, writer_actor_id);
            }
        }
        return deleted;
    }

    fn agentMemoryDeleteNative(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.agentMemoryDelete(key, session_id, actor_id, writer_actor_id),
            .postgres => |*p| p.agentMemoryDelete(key, session_id, actor_id, writer_actor_id),
        };
    }

    fn agentMemoryDeletePrimaryOrderedWithAuth(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (self.agent_memory.isExternal()) {
            return self.agent_memory.deleteByInput(.{
                .key = key,
                .session_id = session_id,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
            });
        }
        if (event_order == null) return self.agentMemoryDeleteNative(key, session_id, actor_id, writer_actor_id);
        return self.agentMemoryDeleteNativeOrdered(key, session_id, actor_id, writer_actor_id, event_order);
    }

    fn agentMemoryDeleteNativeOrdered(self: *Store, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (event_order == null) return self.agentMemoryDeleteNative(key, session_id, actor_id, writer_actor_id);
        return switch (self.backend) {
            .sqlite => |*s| blk: {
                s.tx_mutex.lockUncancelable(compat.io());
                defer s.tx_mutex.unlock(compat.io());
                try s.exec("BEGIN IMMEDIATE");
                errdefer s.exec("ROLLBACK") catch {};
                const changed = try s.agentMemoryDeleteInTxOrdered(key, session_id, actor_id, writer_actor_id, event_order);
                try s.exec("COMMIT");
                break :blk changed;
            },
            .postgres => |*p| p.agentMemoryDeleteOrdered(self.allocator, key, session_id, actor_id, writer_actor_id, event_order),
        };
    }

    fn agentMemoryDeleteAll(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        if (self.agent_memory.isExternal()) return self.agent_memory.deleteByInput(.{
            .key = key,
            .actor_id = actor_id,
            .writer_actor_id = writer_actor_id,
            .all_owners = true,
        });
        return self.agentMemoryDeleteAllNative(key, actor_id, writer_actor_id);
    }

    fn agentMemoryDeleteAllNative(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        return switch (self.backend) {
            .sqlite => |*s| s.agentMemoryDeleteAll(key, actor_id, writer_actor_id),
            .postgres => |*p| p.agentMemoryDeleteAll(key, actor_id, writer_actor_id),
        };
    }

    fn agentMemoryDeleteAllPrimaryOrderedWithAuth(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (self.agent_memory.isExternal()) {
            return self.agent_memory.deleteByInput(.{
                .key = key,
                .actor_id = actor_id,
                .writer_actor_id = writer_actor_id,
                .actor_scopes_json = actor_scopes_json,
                .actor_capabilities_json = actor_capabilities_json,
                .event_order = runtimeAgentMemoryEventOrder(event_order),
                .all_owners = true,
            });
        }
        if (event_order == null) return self.agentMemoryDeleteAllNative(key, actor_id, writer_actor_id);
        return self.agentMemoryDeleteAllNativeOrdered(key, actor_id, writer_actor_id, event_order);
    }

    fn agentMemoryDeleteAllNativeOrdered(self: *Store, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (event_order == null) return self.agentMemoryDeleteAllNative(key, actor_id, writer_actor_id);
        return switch (self.backend) {
            .sqlite => |*s| blk: {
                s.tx_mutex.lockUncancelable(compat.io());
                defer s.tx_mutex.unlock(compat.io());
                try s.exec("BEGIN IMMEDIATE");
                errdefer s.exec("ROLLBACK") catch {};
                const changed = try s.agentMemoryDeleteAllInTxOrdered(key, actor_id, writer_actor_id, event_order);
                try s.exec("COMMIT");
                break :blk changed;
            },
            .postgres => |*p| p.agentMemoryDeleteAllOrdered(self.allocator, key, actor_id, writer_actor_id, event_order),
        };
    }

