    pub fn agentMemoryCountByInput(self: *Store, input: AgentMemoryCountInput) !usize {
        return switch (input.route.target) {
            .primary => self.agentMemoryCountWithAuth(input.actor_id, input.scopes_json, input.capabilities_json),
            .native => self.agentMemoryCountNative(input.actor_id, input.scopes_json),
            .runtime => blk: {
                if (!self.agent_memory.isExternal()) return error.AgentMemoryStorageUnavailable;
                break :blk try self.agent_memory.countByInput(.{
                    .scopes_json = input.scopes_json,
                    .actor_id = input.actor_id,
                    .capabilities_json = input.capabilities_json,
                });
            },
            .named => (try self.namedAgentMemoryRuntime(input.route)).countByInput(.{
                .scopes_json = input.scopes_json,
                .actor_id = input.actor_id,
                .capabilities_json = input.capabilities_json,
            }),
            .subset => store_agent_memory_subset.countByInput(self, .{
                .actor_id = input.actor_id,
                .scopes_json = input.scopes_json,
                .capabilities_json = input.capabilities_json,
                .route = input.route,
            }),
            .all => self.agentMemoryCountAllByInput(input),
        };
    }

