    pub fn saveMessageRoutedAtSuppressFeedOrderedWithAuth(self: *Store, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, event_order: ?AgentMemoryEventOrder) !void {
        return self.saveMessageRoutedAtInner(session_id, role, content, created_at_ms, actor_id, actor_capabilities_json, route, true, event_order);
    }

    fn saveMessageRoutedAtInner(self: *Store, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, suppress_feed: bool, event_order: ?AgentMemoryEventOrder) !void {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        try switch (effective_route.target) {
            .primary => self.saveMessagePrimaryOrderedWithAuth(session_id, role, content, created_at_ms, actor_id, actor_capabilities_json, event_order),
            .native => self.saveMessageNativeAtOrdered(session_id, role, content, created_at_ms, actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal()) blk: {
                const runtime_order = runtimeAgentMemoryEventOrder(event_order);
                break :blk self.agent_memory.saveMessageByInput(.{
                    .session_id = session_id,
                    .role = role,
                    .content = content,
                    .created_at_ms = created_at_ms,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .event_order = runtime_order,
                    .suppress_feed = suppress_feed,
                });
            } else error.AgentMemoryStorageUnavailable,
            .named => blk: {
                const runtime = try self.namedAgentMemoryRuntime(effective_route);
                const runtime_order = runtimeAgentMemoryEventOrder(event_order);
                break :blk runtime.saveMessageByInput(.{
                    .session_id = session_id,
                    .role = role,
                    .content = content,
                    .created_at_ms = created_at_ms,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .event_order = runtime_order,
                    .suppress_feed = suppress_feed,
                });
            },
            .subset => self.saveMessageSubsetAtWithAuth(session_id, role, content, created_at_ms, actor_id, actor_capabilities_json, effective_route, event_order),
            .all => {
                try self.saveMessageNativeAtOrdered(session_id, role, content, created_at_ms, actor_id, event_order);
                const runtime_order = runtimeAgentMemoryEventOrder(event_order);
                if (self.agent_memory.isExternal()) {
                    try self.agent_memory.saveMessageByInput(.{
                        .session_id = session_id,
                        .role = role,
                        .content = content,
                        .created_at_ms = created_at_ms,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .event_order = runtime_order,
                        .suppress_feed = suppress_feed,
                    });
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    try named.runtime.saveMessageByInput(.{
                        .session_id = session_id,
                        .role = role,
                        .content = content,
                        .created_at_ms = created_at_ms,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .event_order = runtime_order,
                        .suppress_feed = suppress_feed,
                    });
                }
            },
        };
        if (!suppress_feed) try self.appendAgentSessionMessagePutFeedEvent(self.allocator, session_id, role, content, created_at_ms, actor_id, effective_route);
    }

    fn saveMessagePrimaryOrdered(self: *Store, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !void {
