    }

    pub fn loadMessagesWithAuth(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) ![]Message {
        if (self.agent_memory.isExternal()) return self.agent_memory.loadMessagesByInput(allocator, .{
            .session_id = session_id,
            .actor_id = actor_id,
            .capabilities_json = actor_capabilities_json,
        });
        return self.loadMessagesNative(allocator, session_id, actor_id);
    }

    pub fn loadMessagesRouted(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) ![]Message {
        return self.loadMessagesRoutedWithAuth(allocator, session_id, actor_id, null, route);
    }

    pub fn loadMessagesRoutedWithAuth(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) ![]Message {
        return switch (route.target) {
            .primary => self.loadMessagesWithAuth(allocator, session_id, actor_id, actor_capabilities_json),
            .native => self.loadMessagesNative(allocator, session_id, actor_id),
            .runtime => if (self.agent_memory.isExternal()) self.agent_memory.loadMessagesByInput(allocator, .{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            }) else error.AgentMemoryStorageUnavailable,
            .named => (try self.namedAgentMemoryRuntime(route)).loadMessagesByInput(allocator, .{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            }),
            .subset => self.loadMessagesSubsetWithAuth(allocator, session_id, actor_id, actor_capabilities_json, route),
            .all => self.loadMessagesAllWithAuth(allocator, session_id, actor_id, actor_capabilities_json),
        };
    }

    fn loadMessagesNative(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        return switch (self.backend) {
            .sqlite => |*s| s.loadMessages(allocator, session_id, actor_id),
            .postgres => |*p| p.loadMessages(allocator, session_id, actor_id),
        };
    }

    fn loadMessagesAll(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        return self.loadMessagesAllWithAuth(allocator, session_id, actor_id, null);
    }

    fn loadMessagesAllWithAuth(self: *Store, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) ![]Message {
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessageOwned(allocator, message);
            out.deinit(allocator);
        }
        if (self.agent_memory.isExternal()) {
            const runtime = try self.agent_memory.loadMessagesByInput(allocator, .{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            });
            defer allocator.free(runtime);
            try appendMessageSlice(allocator, &out, runtime);
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            const runtime = try named.runtime.loadMessagesByInput(allocator, .{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            });
            defer allocator.free(runtime);
            try appendMissingMessageSlice(allocator, &out, runtime);
        }
        const native = try self.loadMessagesNative(allocator, session_id, actor_id);
        defer allocator.free(native);
        try appendMissingMessageSlice(allocator, &out, native);
        sortMessages(out.items);
        return out.toOwnedSlice(allocator);
    }

