    fn clearAutoSavedRoutedInner(self: *Store, session_id: ?[]const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, suppress_feed: bool) !void {
        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        try switch (effective_route.target) {
            .primary => self.clearAutoSavedPrimaryMessagesWithAuth(session_id, actor_id, actor_capabilities_json),
            .native => self.clearAutoSavedNative(session_id, actor_id),
            .runtime => if (self.agent_memory.isExternal()) blk: {
                break :blk self.agent_memory.clearAutoSavedByInput(.{
                    .session_id = session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .suppress_feed = suppress_feed,
                });
            } else error.AgentMemoryStorageUnavailable,
            .named => blk: {
                const runtime = try self.namedAgentMemoryRuntime(effective_route);
                break :blk runtime.clearAutoSavedByInput(.{
                    .session_id = session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .suppress_feed = suppress_feed,
                });
            },
            .subset => self.clearAutoSavedSubsetWithAuth(session_id, actor_id, actor_capabilities_json, effective_route),
            .all => {
                try self.clearAutoSavedNative(session_id, actor_id);
                if (self.agent_memory.isExternal()) {
                    try self.agent_memory.clearAutoSavedByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .suppress_feed = suppress_feed,
                    });
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    try named.runtime.clearAutoSavedByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .suppress_feed = suppress_feed,
                    });
                }
            },
        };
        try self.clearAutoSavedAgentMemoryEntriesRoutedWithAuth(session_id, actor_id, actor_capabilities_json, effective_route);
        if (!suppress_feed) try self.appendAgentSessionAutosaveDeleteFeedEvent(self.allocator, session_id, actor_id, effective_route);
    }

    fn clearAutoSavedAgentMemoryEntriesRouted(self: *Store, session_id: ?[]const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        return self.clearAutoSavedAgentMemoryEntriesRoutedWithAuth(session_id, actor_id, null, route);
    }

    fn clearAutoSavedAgentMemoryEntriesRoutedWithAuth(self: *Store, session_id: ?[]const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const entries = try self.agentMemoryListRoutedWithAuth(self.allocator, null, session_id, actor_id, actor_capabilities_json, route);
        defer freeAgentMemorySlice(self.allocator, entries);

        for (entries) |entry| {
            if (!domain.isAutosaveMemoryKey(entry.key)) continue;
            const delete_route = switch (route.target) {
                .subset, .all => route,
                else => if (entry.store.len > 0) routeForAgentMemoryStoreTag(entry.store) else route,
            };
            _ = try self.agentMemoryDeleteRoutedInner(
                entry.key,
                entry.session_id,
                entry.actor_id,
                actor_id orelse entry.actor_id,
                null,
                actor_capabilities_json,
                delete_route,
                true,
                null,
            );
        }
    }

