        const effective_route = self.effectiveAgentMemoryEventRoute(route);
        const deleted = try switch (effective_route.target) {
            .primary => self.deleteUsagePrimaryOrderedWithAuth(session_id, actor_id, actor_capabilities_json, event_order),
            .native => self.deleteUsageNativeOrdered(session_id, actor_id, event_order),
            .runtime => if (self.agent_memory.isExternal()) blk: {
                const runtime_order = runtimeAgentMemoryEventOrder(event_order);
                break :blk self.agent_memory.deleteUsageByInput(.{
                    .session_id = session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .event_order = runtime_order,
                    .suppress_feed = suppress_feed,
                });
