                    .session_id = session_id,
                    .actor_id = actor_id,
                    .capabilities_json = actor_capabilities_json,
                    .event_order = runtime_order,
                    .suppress_feed = suppress_feed,
                });
            },
            .subset => self.deleteUsageSubsetWithAuth(session_id, actor_id, actor_capabilities_json, effective_route, event_order),
            .all => blk: {
                var deleted = try self.deleteUsageNativeOrdered(session_id, actor_id, event_order);
                const runtime_order = runtimeAgentMemoryEventOrder(event_order);
                if (self.agent_memory.isExternal()) {
                    deleted = (try self.agent_memory.deleteUsageByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .event_order = runtime_order,
                        .suppress_feed = suppress_feed,
                    })) or deleted;
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    deleted = (try named.runtime.deleteUsageByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                        .event_order = runtime_order,
                        .suppress_feed = suppress_feed,
                    })) or deleted;
                }
                break :blk deleted;
            },
        };
        if (deleted and !suppress_feed) try self.appendAgentSessionUsageDeleteFeedEvent(self.allocator, session_id, actor_id, effective_route);
        return deleted;
    }

