    fn deleteUsageNativeOrdered(self: *Store, session_id: []const u8, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        if (event_order == null) return self.deleteUsageNative(session_id, actor_id);
        return switch (self.backend) {
            .sqlite => |*s| s.deleteUsageOrdered(session_id, actor_id, event_order),
            .postgres => |*p| p.deleteUsageOrdered(session_id, actor_id, event_order),
        };
    }

