        return self.loadUsageWithAuth(session_id, actor_id, null);
    }

    pub fn loadUsageWithAuth(self: *Store, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) !?u64 {
        if (self.agent_memory.isExternal()) return self.agent_memory.loadUsageByInput(.{
            .session_id = session_id,
            .actor_id = actor_id,
            .capabilities_json = actor_capabilities_json,
        });
        return self.loadUsageNative(session_id, actor_id);
    }

    pub fn loadUsageRouted(self: *Store, session_id: []const u8, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !?u64 {
        return self.loadUsageRoutedWithAuth(session_id, actor_id, null, route);
    }

    pub fn loadUsageRoutedWithAuth(self: *Store, session_id: []const u8, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !?u64 {
        return switch (route.target) {
            .primary => self.loadUsageWithAuth(session_id, actor_id, actor_capabilities_json),
            .native => self.loadUsageNative(session_id, actor_id),
            .runtime => if (self.agent_memory.isExternal()) self.agent_memory.loadUsageByInput(.{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            }) else error.AgentMemoryStorageUnavailable,
            .named => (try self.namedAgentMemoryRuntime(route)).loadUsageByInput(.{
                .session_id = session_id,
                .actor_id = actor_id,
                .capabilities_json = actor_capabilities_json,
            }),
            .subset => self.loadUsageSubsetWithAuth(session_id, actor_id, actor_capabilities_json, route),
            .all => blk: {
                var max_total: ?u64 = null;
                if (self.agent_memory.isExternal()) {
                    max_total = maxUsageTotal(max_total, try self.agent_memory.loadUsageByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                    }));
                }
                for (self.agent_memory_stores.stores.items) |*named| {
                    max_total = maxUsageTotal(max_total, try named.runtime.loadUsageByInput(.{
                        .session_id = session_id,
                        .actor_id = actor_id,
                        .capabilities_json = actor_capabilities_json,
                    }));
                }
                max_total = maxUsageTotal(max_total, try self.loadUsageNative(session_id, actor_id));
                break :blk max_total;
            },
        };
    }

    fn loadUsageNative(self: *Store, session_id: []const u8, actor_id: ?[]const u8) !?u64 {
        return switch (self.backend) {
            .sqlite => |*s| s.loadUsage(session_id, actor_id),
            .postgres => |*p| p.loadUsage(session_id, actor_id),
        };
    }

