    fn listSessionsAllWithAuth(self: *Store, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8) !HistoryList {
        var routes: std.ArrayListUnmanaged(AgentMemoryStorageRoute) = .empty;
        defer routes.deinit(allocator);
        if (self.agent_memory.isExternal()) {
            try routes.append(allocator, .{ .target = .runtime });
        }
        for (self.agent_memory_stores.stores.items) |*named| {
            try routes.append(allocator, AgentMemoryStorageRoute.parse(named.name));
        }
        try routes.append(allocator, .{ .target = .native });
        return self.listSessionsFanInWithAuth(allocator, limit, offset, actor_id, actor_capabilities_json, routes.items, .{ .target = .all });
    }

    fn listSessionsFanInWithAuth(self: *Store, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, routes: []const AgentMemoryStorageRoute, refresh_route: AgentMemoryStorageRoute) !HistoryList {
        var out: std.ArrayListUnmanaged(SessionInfo) = .empty;
        errdefer {
            for (out.items) |*session| freeSessionInfoOwned(allocator, session);
            out.deinit(allocator);
        }
        const candidate_limit = sessionFanInCandidateLimit(limit, offset);
        var stats = SessionFanInStats{};
        for (routes) |child_route| {
            try self.appendSessionCandidatePageFromRouteWithAuth(allocator, &out, &stats, actor_id, actor_capabilities_json, child_route, candidate_limit);
        }
        const exact_total = if (stats.non_empty_routes <= 1)
            stats.total_sum
        else if (stats.all_fetched)
            @as(u64, @intCast(out.items.len))
        else blk: {
            for (out.items) |*session| freeSessionInfoOwned(allocator, session);
            out.clearRetainingCapacity();
            for (routes) |child_route| {
                try self.appendAllSessionPagesFromRouteWithAuth(allocator, &out, actor_id, actor_capabilities_json, child_route);
            }
            break :blk @as(u64, @intCast(out.items.len));
        };
        const result = try takeSessionInfoPageWithTotal(allocator, &out, limit, offset, exact_total);
        errdefer {
            for (result.sessions) |*session| freeSessionInfoOwned(allocator, session);
            allocator.free(result.sessions);
        }
        try self.refreshSessionInfoPageFromRouteWithAuth(allocator, result.sessions, actor_id, actor_capabilities_json, refresh_route);
        return result;
    }

    fn appendSessionCandidatePageFromRouteWithAuth(self: *Store, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(SessionInfo), stats: *SessionFanInStats, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute, candidate_limit: usize) !void {
        const page = try self.listSessionsRoutedWithAuth(allocator, candidate_limit, 0, actor_id, actor_capabilities_json, route);
        defer allocator.free(page.sessions);
        errdefer {
            for (page.sessions) |*session| freeSessionInfoOwned(allocator, session);
        }
        stats.observe(page.total, page.sessions.len);
        try appendOrMergeSessionInfoSlice(allocator, out, page.sessions);
    }

    fn appendAllSessionPagesFromRoute(self: *Store, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(SessionInfo), actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        return self.appendAllSessionPagesFromRouteWithAuth(allocator, out, actor_id, null, route);
    }

    fn appendAllSessionPagesFromRouteWithAuth(self: *Store, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(SessionInfo), actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        var page_offset: usize = 0;
        while (true) {
            const page = try self.listSessionsRoutedWithAuth(allocator, sessionRouteFanInPageSize(), page_offset, actor_id, actor_capabilities_json, route);
            defer allocator.free(page.sessions);
            errdefer {
                for (page.sessions) |*session| freeSessionInfoOwned(allocator, session);
            }
            const fetched = page.sessions.len;
            try appendOrMergeSessionInfoSlice(allocator, out, page.sessions);
            if (fetched == 0 or fetched < sessionRouteFanInPageSize()) break;
            page_offset = sessionFanInOffsetAfterFetch(page_offset, fetched) orelse break;
            if (sessionFanInOffsetReachedTotal(page_offset, page.total)) break;
        }
    }

    fn refreshSessionInfoPageFromRoute(self: *Store, allocator: std.mem.Allocator, page: []SessionInfo, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        return self.refreshSessionInfoPageFromRouteWithAuth(allocator, page, actor_id, null, route);
    }

    fn refreshSessionInfoPageFromRouteWithAuth(self: *Store, allocator: std.mem.Allocator, page: []SessionInfo, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        for (page) |*session| {
            try self.refreshSessionInfoFromRouteWithAuth(allocator, session, actor_id, actor_capabilities_json, route);
        }
    }

    fn refreshSessionInfoFromRoute(self: *Store, allocator: std.mem.Allocator, session: *SessionInfo, actor_id: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        return self.refreshSessionInfoFromRouteWithAuth(allocator, session, actor_id, null, route);
    }

    fn refreshSessionInfoFromRouteWithAuth(self: *Store, allocator: std.mem.Allocator, session: *SessionInfo, actor_id: ?[]const u8, actor_capabilities_json: ?[]const u8, route: AgentMemoryStorageRoute) !void {
        const messages = try self.loadMessagesRoutedWithAuth(allocator, session.session_id, actor_id, actor_capabilities_json, route);
        defer {
            for (messages) |*message| freeMessageOwned(allocator, message);
            allocator.free(messages);
        }
        var count: u64 = 0;
        var first: i64 = 0;
        var last: i64 = 0;
        for (messages) |message| {
            if (!domain.sessionMessageVisibleInHistory(message.role)) continue;
            count += 1;
            if (first == 0 or message.created_at_ms < first) first = message.created_at_ms;
            if (message.created_at_ms > last) last = message.created_at_ms;
        }
        session.message_count = count;
        session.first_message_at = first;
        session.last_message_at = last;
    }

