const external_vector_candidate_multiplier: usize = 4;

fn externalVectorCandidateLimit(limit: usize) usize {
    const expanded = bounded_int.saturatingUsizeMul(limit, external_vector_candidate_multiplier);
    return vector_runtime.externalVectorSearchLimit(expanded);
}

fn appendExternalVectorCandidates(
    allocator: std.mem.Allocator,
    out: *std.ArrayListUnmanaged(vector_runtime.Candidate),
    candidates: []const vector_runtime.Candidate,
    candidate_limit: usize,
) !void {
    for (candidates) |candidate| {
        if (!std.math.isFinite(candidate.score)) continue;
        var found_existing = false;
        for (out.items) |*existing| {
            if (std.mem.eql(u8, existing.vector_id, candidate.vector_id)) {
                if (candidate.score > existing.score) existing.score = candidate.score;
                found_existing = true;
                break;
            }
        }
        if (found_existing) continue;
        try out.append(allocator, .{
            .vector_id = try allocator.dupe(u8, candidate.vector_id),
            .score = candidate.score,
        });
    }
    sortCandidateList(out.items);
    if (out.items.len > candidate_limit) {
        for (out.items[candidate_limit..]) |candidate| allocator.free(candidate.vector_id);
        out.items.len = candidate_limit;
    }
}

fn sortCandidateList(candidates: []vector_runtime.Candidate) void {
    std.mem.sort(vector_runtime.Candidate, candidates, {}, candidateScoreDesc);
}

fn candidateScoreDesc(_: void, a: vector_runtime.Candidate, b: vector_runtime.Candidate) bool {
    if (a.score == b.score) return std.mem.lessThan(u8, a.vector_id, b.vector_id);
    return a.score > b.score;
}

fn freeCandidateList(allocator: std.mem.Allocator, candidates: *std.ArrayListUnmanaged(vector_runtime.Candidate)) void {
    for (candidates.items) |candidate| allocator.free(candidate.vector_id);
    candidates.deinit(allocator);
}

fn appendVectorSinkJson(
    allocator: std.mem.Allocator,
    out: *std.ArrayListUnmanaged(u8),
    first: *bool,
    name: []const u8,
    cfg: vector_runtime.Config,
    state: []const u8,
) !void {
    if (!first.*) try out.append(allocator, ',');
    first.* = false;
    try out.appendSlice(allocator, "{\"name\":");
    try json.appendString(out, allocator, name);
    try out.appendSlice(allocator, ",\"backend\":");
    try json.appendString(out, allocator, cfg.backend.name());
    try out.appendSlice(allocator, ",\"collection\":");
    try json.appendString(out, allocator, cfg.collection);
    try out.appendSlice(allocator, ",\"enabled\":");
    try out.appendSlice(allocator, if (cfg.externalEnabled()) "true" else "false");
    try out.appendSlice(allocator, ",\"state\":");
    try json.appendString(out, allocator, state);
    try out.appendSlice(allocator, ",\"base_url_configured\":");
    try out.appendSlice(allocator, if (cfg.base_url != null) "true" else "false");
    try out.appendSlice(allocator, ",\"postgres_url_configured\":");
    try out.appendSlice(allocator, if (cfg.postgres_url != null) "true" else "false");
    try out.appendSlice(allocator, ",\"lancedb_uri_configured\":");
    try out.appendSlice(allocator, if (cfg.lancedb_uri != null) "true" else "false");
    try out.appendSlice(allocator, "}");
}

fn filterVectorMatchesByMinScore(allocator: std.mem.Allocator, matches: []vector_mod.VectorMatch, input: VectorSearchInput) ![]vector_mod.VectorMatch {
    const min_score = normalizedVectorMinScore(input.min_score);
    if (min_score <= 0) return matches;
    var keep: usize = 0;
    var changed = false;
    for (matches, 0..) |*match, i| {
        if (vectorScoreAllowed(match.score, min_score)) {
            if (keep != i) {
                matches[keep] = match.*;
                match.* = undefined;
                changed = true;
            }
            keep += 1;
        } else {
            vector_mod.deinitMatch(allocator, match);
            changed = true;
        }
    }
    if (!changed) return matches;
    if (keep == 0) {
        allocator.free(matches);
        return allocator.alloc(vector_mod.VectorMatch, 0);
    }
    return allocator.realloc(matches, keep);
}

