pub const SQLiteStore = struct {
    allocator: std.mem.Allocator,
    db: *c.sqlite3,
    tx_mutex: std.Io.Mutex = .init,
    vector_ann_candidate_multiplier: u32 = vector_runtime.default_sqlite_ann_candidate_multiplier,
    vector_ann_min_candidates: u32 = vector_runtime.default_sqlite_ann_min_candidates,

    const Self = @This();

    pub fn init(allocator: std.mem.Allocator, db_path: [:0]const u8) !Self {
        var db: ?*c.sqlite3 = null;
        const flags = c.SQLITE_OPEN_READWRITE | c.SQLITE_OPEN_CREATE | c.SQLITE_OPEN_FULLMUTEX;
        if (c.sqlite3_open_v2(db_path.ptr, &db, flags, null) != c.SQLITE_OK) {
            if (db) |handle| _ = c.sqlite3_close(handle);
            return error.OpenDatabaseFailed;
        }
        errdefer _ = c.sqlite3_close(db.?);
        _ = c.sqlite3_busy_timeout(db.?, 5000);
        var self = Self{ .allocator = allocator, .db = db.? };
        try self.prepareExistingTablesForSchema();
        try self.exec(migrations.sqlite_schema);
        try self.applySchemaMigrations();
        try self.assertSchemaCurrent();
        return self;
    }

    pub fn deinit(self: *Self) void {
        _ = c.sqlite3_close(self.db);
    }

    pub fn configureVectorAnn(self: *Self, cfg: vector_runtime.Config) void {
        self.vector_ann_candidate_multiplier = cfg.sqliteAnnCandidateMultiplier();
        self.vector_ann_min_candidates = cfg.sqliteAnnMinCandidates();
    }

    pub fn health(_: *Self) bool {
        return true;
    }

    pub fn schemaVersion(self: *Self) !i64 {
        return self.countSql("SELECT coalesce(max(version), 0) FROM schema_migrations");
    }

    fn assertSchemaCurrent(self: *Self) !void {
        var version: i64 = 1;
        while (version <= migrations.expected_schema_version) : (version += 1) {
            if (!try self.schemaMigrationPresent(version)) return error.SchemaMigrationIncomplete;
        }
        if (try self.schemaVersion() != migrations.expected_schema_version) return error.SchemaMigrationIncomplete;
    }

    fn schemaMigrationPresent(self: *Self, version: i64) !bool {
        const expected = migrations.expectedMigration(version) orelse return false;
        const stmt = try self.prepare("SELECT name, checksum FROM schema_migrations WHERE version = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        _ = c.sqlite3_bind_int64(stmt, 1, version);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return false;
        const name = try columnText(self.allocator, stmt, 0);
        defer self.allocator.free(name);
        const checksum = try columnText(self.allocator, stmt, 1);
        defer self.allocator.free(checksum);
        return std.mem.eql(u8, name, expected.name) and std.mem.eql(u8, checksum, expected.checksum);
    }

    fn prepareExistingTablesForSchema(self: *Self) !void {
        if (try self.tableExists("session_messages")) {
            if (!try self.columnExists("session_messages", "actor_id")) {
                try self.exec("ALTER TABLE session_messages ADD COLUMN actor_id TEXT");
            }
        }
        if (try self.tableExists("session_usage")) {
            if (!try self.columnExists("session_usage", "actor_id")) {
                try self.exec("ALTER TABLE session_usage ADD COLUMN actor_id TEXT");
            }
        }
    }

    fn tableExists(self: *Self, comptime table: []const u8) !bool {
        return (try self.countSql("SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='" ++ table ++ "'")) > 0;
    }

    fn exec(self: *Self, sql: [*:0]const u8) !void {
        var err_msg: [*c]u8 = null;
        const rc = c.sqlite3_exec(self.db, sql, null, null, &err_msg);
        if (rc != c.SQLITE_OK) {
            std.log.err("sqlite exec failed: {s}", .{if (err_msg != null) std.mem.span(err_msg) else std.mem.span(c.sqlite3_errmsg(self.db))});
            if (err_msg) |msg| c.sqlite3_free(msg);
            return error.SqlExecFailed;
        }
    }

    fn prepare(self: *Self, sql: [*:0]const u8) !*c.sqlite3_stmt {
        var stmt: ?*c.sqlite3_stmt = null;
        if (c.sqlite3_prepare_v2(self.db, sql, -1, &stmt, null) != c.SQLITE_OK) {
            return error.SqlPrepareFailed;
        }
        return stmt.?;
    }

    fn beginTransaction(self: *Self) !void {
        self.tx_mutex.lockUncancelable(compat.io());
        errdefer self.tx_mutex.unlock(compat.io());
        try self.exec("BEGIN IMMEDIATE");
    }

    fn commitTransaction(self: *Self) !void {
        try self.exec("COMMIT");
        self.tx_mutex.unlock(compat.io());
    }

    fn rollbackTransaction(self: *Self) void {
        self.exec("ROLLBACK") catch {};
        self.tx_mutex.unlock(compat.io());
    }

    fn applySchemaMigrations(self: *Self) !void {
        try self.exec("BEGIN IMMEDIATE");
        errdefer self.exec("ROLLBACK") catch {};
        if (!try self.columnExists("schema_migrations", "checksum")) {
            try self.exec("ALTER TABLE schema_migrations ADD COLUMN checksum TEXT NOT NULL DEFAULT ''");
        }
        try self.exec("UPDATE schema_migrations SET name = 'core_primitives', checksum = 'np-001-core-primitives' WHERE version = 1");
        if (!try self.columnExists("vector_chunks", "permissions_json")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN permissions_json TEXT NOT NULL DEFAULT '[]'");
        }
        if (!try self.columnExists("vector_chunks", "heading_path_json")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN heading_path_json TEXT NOT NULL DEFAULT '[]'");
        }
        if (!try self.columnExists("vector_chunks", "start_byte")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN start_byte INTEGER NOT NULL DEFAULT 0");
        }
        if (!try self.columnExists("vector_chunks", "end_byte")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN end_byte INTEGER NOT NULL DEFAULT 0");
        }
        if (!try self.columnExists("vector_chunks", "content_hash")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN content_hash TEXT NOT NULL DEFAULT ''");
        }
        if (!try self.columnExists("vector_chunks", "chunk_strategy")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN chunk_strategy TEXT NOT NULL DEFAULT 'plain'");
        }
        if (!try self.columnExists("vector_chunks", "estimated_tokens")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN estimated_tokens INTEGER NOT NULL DEFAULT 0");
        }
        if (!try self.columnExists("vector_chunks", "transcript_timestamp")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN transcript_timestamp TEXT");
        }
        if (!try self.columnExists("vector_chunks", "transcript_speaker")) {
            try self.exec("ALTER TABLE vector_chunks ADD COLUMN transcript_speaker TEXT");
        }
        try self.exec("DELETE FROM vector_chunks WHERE rowid NOT IN (SELECT max(rowid) FROM vector_chunks GROUP BY object_type, object_id, chunk_ordinal)");
        try self.exec("CREATE INDEX IF NOT EXISTS idx_vector_chunks_content_hash ON vector_chunks(object_type, object_id, content_hash)");
        try self.exec("CREATE UNIQUE INDEX IF NOT EXISTS idx_vector_chunks_object_ordinal ON vector_chunks(object_type, object_id, chunk_ordinal)");
        try self.ensureSqliteVectorAnnIndex();
        if (!try self.columnExists("memory_feed_events", "dedupe_key")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN dedupe_key TEXT");
        }
        if (!try self.columnExists("memory_feed_events", "permissions_json")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN permissions_json TEXT NOT NULL DEFAULT '[]'");
        }
        if (!try self.columnExists("memory_feed_events", "operation")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN operation TEXT NOT NULL DEFAULT 'put'");
        }
        if (!try self.columnExists("memory_feed_events", "actor_id")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN actor_id TEXT");
        }
        if (!try self.columnExists("memory_feed_events", "causality_json")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN causality_json TEXT NOT NULL DEFAULT '{}'");
        }
        if (!try self.columnExists("memory_feed_events", "compacted_at_ms")) {
            try self.exec("ALTER TABLE memory_feed_events ADD COLUMN compacted_at_ms INTEGER");
        }
        if (try self.tableExists("agent_memory_items")) {
            if (!try self.columnExists("agent_memory_items", "writer_actor_id")) {
                try self.exec("ALTER TABLE agent_memory_items ADD COLUMN writer_actor_id TEXT NOT NULL DEFAULT ''");
            }
            try self.exec("UPDATE agent_memory_items SET writer_actor_id = actor_id WHERE writer_actor_id = ''");
            try self.exec("CREATE INDEX IF NOT EXISTS idx_agent_memory_writer ON agent_memory_items(writer_actor_id, timestamp_ms)");
        }
        if (!try self.columnExists("jobs", "locked_until_ms")) {
            try self.exec("ALTER TABLE jobs ADD COLUMN locked_until_ms INTEGER");
        }
        if (!try self.columnExists("jobs", "worker_id")) {
            try self.exec("ALTER TABLE jobs ADD COLUMN worker_id TEXT");
        }
        try self.exec("CREATE INDEX IF NOT EXISTS idx_jobs_status_locked ON jobs(status, locked_until_ms)");
        if (!try self.columnExists("vector_outbox", "locked_until_ms")) {
            try self.exec("ALTER TABLE vector_outbox ADD COLUMN locked_until_ms INTEGER");
        }
        if (!try self.columnExists("vector_outbox", "worker_id")) {
            try self.exec("ALTER TABLE vector_outbox ADD COLUMN worker_id TEXT");
        }
        try self.exec("CREATE INDEX IF NOT EXISTS idx_vector_outbox_status_locked ON vector_outbox(status, locked_until_ms)");
        try self.exec("CREATE TABLE IF NOT EXISTS memory_feed_state (id INTEGER PRIMARY KEY CHECK (id = 1), cursor_floor INTEGER NOT NULL DEFAULT 0, updated_at_ms INTEGER NOT NULL)");
        try self.exec("INSERT OR IGNORE INTO memory_feed_state (id, cursor_floor, updated_at_ms) VALUES (1, 0, strftime('%s','now') * 1000)");
        try self.exec("CREATE TABLE IF NOT EXISTS memory_feed_cursors (name TEXT PRIMARY KEY, cursor_floor INTEGER NOT NULL DEFAULT 0, updated_at_ms INTEGER NOT NULL)");
        try self.exec("CREATE TABLE IF NOT EXISTS memory_feed_origin_frontiers (projection TEXT NOT NULL, origin_instance_id TEXT NOT NULL, origin_sequence INTEGER NOT NULL DEFAULT 0, updated_at_ms INTEGER NOT NULL, PRIMARY KEY (projection, origin_instance_id))");
        try self.exec("CREATE TABLE IF NOT EXISTS primitive_lifecycle (object_type TEXT NOT NULL, object_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'active', actor_id TEXT, payload_json TEXT NOT NULL DEFAULT '{}', updated_at_ms INTEGER NOT NULL, PRIMARY KEY (object_type, object_id))");
        try self.exec("CREATE INDEX IF NOT EXISTS idx_primitive_lifecycle_type_status ON primitive_lifecycle(object_type, status)");
        if (!try self.columnExists("response_cache", "response_json")) {
