    fn ensureSqliteVectorAnnIndex(self: *Self) !void {
        try self.exec(
            \\CREATE TABLE IF NOT EXISTS vector_chunk_ann (
            \\  id TEXT PRIMARY KEY,
            \\  dimensions INTEGER NOT NULL,
            \\  band0 INTEGER NOT NULL,
            \\  band1 INTEGER NOT NULL,
            \\  band2 INTEGER NOT NULL,
            \\  band3 INTEGER NOT NULL,
            \\  source_updated_at_ms INTEGER NOT NULL
            \\);
            \\CREATE INDEX IF NOT EXISTS idx_vector_chunk_ann_band0 ON vector_chunk_ann(dimensions, band0);
            \\CREATE INDEX IF NOT EXISTS idx_vector_chunk_ann_band1 ON vector_chunk_ann(dimensions, band1);
            \\CREATE INDEX IF NOT EXISTS idx_vector_chunk_ann_band2 ON vector_chunk_ann(dimensions, band2);
            \\CREATE INDEX IF NOT EXISTS idx_vector_chunk_ann_band3 ON vector_chunk_ann(dimensions, band3);
        );
    }

    fn rebuildSqliteVectorAnnIndex(self: *Self) !void {
        try self.ensureSqliteVectorAnnIndex();
        try self.exec("DELETE FROM vector_chunk_ann WHERE id NOT IN (SELECT id FROM vector_chunks)");
        const stmt = try self.prepare(
            \\SELECT vc.id, vc.embedding_json, vc.dimensions, vc.updated_at_ms
            \\FROM vector_chunks vc
            \\LEFT JOIN vector_chunk_ann ann ON ann.id = vc.id
            \\WHERE ann.id IS NULL
            \\   OR ann.source_updated_at_ms <> vc.updated_at_ms
            \\   OR ann.dimensions <> vc.dimensions
        );
        defer _ = c.sqlite3_finalize(stmt);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const id_text = try columnText(self.allocator, stmt, 0);
            defer self.allocator.free(id_text);
            const embedding_json = try columnText(self.allocator, stmt, 1);
            defer self.allocator.free(embedding_json);
            const dimensions = c.sqlite3_column_int64(stmt, 2);
            const updated_at_ms = c.sqlite3_column_int64(stmt, 3);
            const embedding = vector_mod.embeddingFromJson(self.allocator, embedding_json) catch {
                try self.deleteSqliteVectorAnn(id_text);
                continue;
            };
            defer self.allocator.free(embedding);
            try self.upsertSqliteVectorAnnFromEmbedding(id_text, embedding, dimensions, updated_at_ms);
        }
    }

    fn upsertSqliteVectorAnnFromEmbedding(self: *Self, id: []const u8, embedding: []const f32, dimensions: i64, source_updated_at_ms: i64) !void {
        if (embedding.len == 0) {
            try self.deleteSqliteVectorAnn(id);
            return;
        }
        const bands = vector_mod.signatureBands(vector_mod.simhashSignature(embedding));
        const stmt = try self.prepare(
            \\INSERT INTO vector_chunk_ann (id, dimensions, band0, band1, band2, band3, source_updated_at_ms)
            \\VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)
            \\ON CONFLICT(id) DO UPDATE SET
            \\  dimensions = excluded.dimensions,
            \\  band0 = excluded.band0,
            \\  band1 = excluded.band1,
            \\  band2 = excluded.band2,
            \\  band3 = excluded.band3,
            \\  source_updated_at_ms = excluded.source_updated_at_ms
        );
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        _ = c.sqlite3_bind_int64(stmt, 2, dimensions);
        _ = c.sqlite3_bind_int64(stmt, 3, @intCast(bands[0]));
        _ = c.sqlite3_bind_int64(stmt, 4, @intCast(bands[1]));
        _ = c.sqlite3_bind_int64(stmt, 5, @intCast(bands[2]));
        _ = c.sqlite3_bind_int64(stmt, 6, @intCast(bands[3]));
        _ = c.sqlite3_bind_int64(stmt, 7, source_updated_at_ms);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
    }

    fn deleteSqliteVectorAnn(self: *Self, id: []const u8) !void {
        const stmt = try self.prepare("DELETE FROM vector_chunk_ann WHERE id = ?1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.DeleteFailed;
    }

