            \\  expires_at_ms INTEGER NOT NULL DEFAULT 0,
            \\  hit_count INTEGER NOT NULL DEFAULT 0,
            \\  token_count INTEGER NOT NULL DEFAULT 0,
            \\  PRIMARY KEY (actor_id, cache_key)
            \\);
            \\INSERT OR REPLACE INTO semantic_cache_v10 (cache_key,query,response_json,embedding_json,embedding_provider,embedding_model,embedding_dimensions,scopes_json,actor_id,created_at_ms,accessed_at_ms,expires_at_ms,hit_count,token_count)
            \\  SELECT cache_key,query,response_json,embedding_json,coalesce(nullif(embedding_provider,''),'provided'),coalesce(embedding_model,''),coalesce(embedding_dimensions,0),scopes_json,coalesce(actor_id,''),created_at_ms,coalesce(nullif(accessed_at_ms,0),created_at_ms),expires_at_ms,hit_count,token_count FROM semantic_cache;
