        );
    }

    fn cacheActorPrimaryKeyPresent(self: *Self, comptime table: []const u8) !bool {
        const stmt = try self.prepare("PRAGMA table_info(" ++ table ++ ")");
        defer _ = c.sqlite3_finalize(stmt);
        var actor_pk: c_int = 0;
        var key_pk: c_int = 0;
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const name = try columnText(self.allocator, stmt, 1);
            defer self.allocator.free(name);
            const pk = c.sqlite3_column_int(stmt, 5);
            if (std.mem.eql(u8, name, "actor_id")) actor_pk = pk;
            if (std.mem.eql(u8, name, "cache_key")) key_pk = pk;
        }
        return actor_pk > 0 and key_pk > 0;
    }

    fn columnExists(self: *Self, comptime table: []const u8, column: []const u8) !bool {
        const stmt = try self.prepare("PRAGMA table_info(" ++ table ++ ")");
        defer _ = c.sqlite3_finalize(stmt);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            const name = try columnText(self.allocator, stmt, 1);
            defer self.allocator.free(name);
            if (std.mem.eql(u8, name, column)) return true;
        }
        return false;
    }

    fn bindText(stmt: *c.sqlite3_stmt, index: c_int, value: []const u8) void {
        _ = c.sqlite3_bind_text64(stmt, index, value.ptr, @intCast(bounded_int.usizeToU64Saturating(value.len)), SQLITE_STATIC, c.SQLITE_UTF8);
    }

    fn bindNullableText(stmt: *c.sqlite3_stmt, index: c_int, value: ?[]const u8) void {
        if (value) |v| bindText(stmt, index, v) else _ = c.sqlite3_bind_null(stmt, index);
    }

    fn sqliteLimitParam(value: usize) i64 {
        return bounded_int.usizeToI64Saturating(value);
    }

    fn bindOptionalLimit(stmt: *c.sqlite3_stmt, index: c_int, limit: ?usize) void {
        if (limit) |value| _ = c.sqlite3_bind_int64(stmt, index, sqliteLimitParam(value));
    }

    fn columnBytes(stmt: *c.sqlite3_stmt, index: c_int) usize {
        return bounded_int.nonNegativeCIntToUsize(c.sqlite3_column_bytes(stmt, index));
    }

    fn columnText(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, index: c_int) ![]u8 {
        const ptr = c.sqlite3_column_text(stmt, index) orelse return allocator.dupe(u8, "");
        const len = columnBytes(stmt, index);
        const bytes: [*]const u8 = @ptrCast(ptr);
        return allocator.dupe(u8, bytes[0..len]);
    }

    fn columnTextNullable(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt, index: c_int) !?[]u8 {
        if (c.sqlite3_column_type(stmt, index) == c.SQLITE_NULL) return null;
        const value = try columnText(allocator, stmt, index);
        return value;
    }

    fn columnIntNullable(stmt: *c.sqlite3_stmt, index: c_int) ?i64 {
        if (c.sqlite3_column_type(stmt, index) == c.SQLITE_NULL) return null;
        return c.sqlite3_column_int64(stmt, index);
    }

    fn insertAudit(self: *Self, event_type: []const u8, object_type: []const u8, object_id: []const u8) !void {
        try self.insertAuditActor(event_type, null, object_type, object_id);
    }

    fn insertAuditActor(self: *Self, event_type: []const u8, actor_id: ?[]const u8, object_type: []const u8, object_id: []const u8) !void {
        try self.insertAuditActorPayload(event_type, actor_id, object_type, object_id, "{}");
    }

    fn insertAuditActorPayload(self: *Self, event_type: []const u8, actor_id: ?[]const u8, object_type: []const u8, object_id: []const u8, payload_json: []const u8) !void {
        const stmt = try self.prepare("INSERT INTO audit_events (event_type, actor, object_type, object_id, payload_json, created_at_ms) VALUES (?1, ?2, ?3, ?4, ?5, ?6)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, event_type);
        bindNullableText(stmt, 2, actor_id);
        bindText(stmt, 3, object_type);
        bindText(stmt, 4, object_id);
        bindText(stmt, 5, payload_json);
        _ = c.sqlite3_bind_int64(stmt, 6, ids.nowMs());
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
    }

    pub fn listAuditEvents(self: *Self, allocator: std.mem.Allocator, since_id: i64, limit: usize) ![]AuditEvent {
        const capped = @max(@as(usize, 1), @min(limit, 5000));
        const stmt = try self.prepare("SELECT id,event_type,actor,object_type,object_id,payload_json,created_at_ms FROM audit_events WHERE id > ?1 ORDER BY id LIMIT ?2");
        defer _ = c.sqlite3_finalize(stmt);
        _ = c.sqlite3_bind_int64(stmt, 1, since_id);
        _ = c.sqlite3_bind_int64(stmt, 2, @intCast(capped));
        var out: std.ArrayListUnmanaged(AuditEvent) = .empty;
        errdefer out.deinit(allocator);
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            try out.append(allocator, .{
                .id = c.sqlite3_column_int64(stmt, 0),
                .event_type = try columnText(allocator, stmt, 1),
                .actor = try columnTextNullable(allocator, stmt, 2),
                .object_type = try columnText(allocator, stmt, 3),
                .object_id = try columnText(allocator, stmt, 4),
                .payload_json = try columnText(allocator, stmt, 5),
                .created_at_ms = c.sqlite3_column_int64(stmt, 6),
            });
        }
        return out.toOwnedSlice(allocator);
    }

    fn deleteSqliteByTextColumnBestEffort(self: *Self, comptime table: []const u8, comptime column: []const u8, value: []const u8) void {
        const stmt = self.prepare("DELETE FROM " ++ table ++ " WHERE " ++ column ++ " = ?1") catch return;
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, value);
        _ = c.sqlite3_step(stmt);
    }

    fn deleteVectorChunksForObjectBestEffort(self: *Self, object_type: []const u8, object_id: []const u8) void {
        const stmt = self.prepare("DELETE FROM vector_chunks WHERE object_type = ?1 AND object_id = ?2") catch return;
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, object_type);
        bindText(stmt, 2, object_id);
        _ = c.sqlite3_step(stmt);
    }

    fn deleteVectorChunksForObject(self: *Self, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, actor_id: ?[]const u8) !usize {
        var ids_to_delete: std.ArrayListUnmanaged([]const u8) = .empty;
        defer {
            for (ids_to_delete.items) |chunk_id| allocator.free(chunk_id);
            ids_to_delete.deinit(allocator);
        }
        {
            const stmt = try self.prepare("SELECT id FROM vector_chunks WHERE object_type = ?1 AND object_id = ?2 ORDER BY id");
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, object_type);
            bindText(stmt, 2, object_id);
            while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
                try ids_to_delete.append(allocator, try columnText(allocator, stmt, 0));
            }
        }
        var deleted: usize = 0;
        for (ids_to_delete.items) |chunk_id| {
            if (try self.deleteVectorChunk(allocator, chunk_id, actor_id)) deleted += 1;
        }
        return deleted;
    }

    fn cleanupCreatedSourceBestEffort(self: *Self, id: []const u8) void {
        self.deleteSqliteByTextColumnBestEffort("sources_fts", "id", id);
        self.deleteVectorChunksForObjectBestEffort("source", id);
        self.deleteSqliteByTextColumnBestEffort("sources", "id", id);
    }

    fn cleanupCreatedArtifactBestEffort(self: *Self, id: []const u8) void {
        self.deleteSqliteByTextColumnBestEffort("artifacts_fts", "id", id);
        self.deleteVectorChunksForObjectBestEffort("artifact", id);
        self.deleteSqliteByTextColumnBestEffort("artifacts", "id", id);
    }

    fn cleanupCreatedMemoryAtomBestEffort(self: *Self, id: []const u8) void {
        self.deleteSqliteByTextColumnBestEffort("memory_atoms_fts", "id", id);
        self.deleteSqliteByTextColumnBestEffort("agent_memory_items", "memory_atom_id", id);
        self.deleteVectorChunksForObjectBestEffort("memory_atom", id);
        self.deleteSqliteByTextColumnBestEffort("memory_atoms", "id", id);
    }

    fn cleanupCreatedEntityBestEffort(self: *Self, id: []const u8) void {
        self.deleteSqliteByTextColumnBestEffort("entities_fts", "id", id);
        self.deleteSqliteByTextColumnBestEffort("entities", "id", id);
    }

    fn cleanupCreatedRelationBestEffort(self: *Self, id: []const u8) void {
        self.deleteSqliteByTextColumnBestEffort("relations_fts", "id", id);
        self.deleteSqliteByTextColumnBestEffort("relations", "id", id);
    }

    pub fn createSpace(self: *Self, allocator: std.mem.Allocator, input: SpaceInput) !Space {
        const id = try idOrMake(allocator, input.id, "spc_");
        const now = ids.nowMs();
        const stmt = try self.prepare("INSERT INTO spaces (id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms) VALUES (?1,?2,?3,?4,?5,?6,?7,?8,?9)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        bindText(stmt, 2, input.name);
        bindText(stmt, 3, input.title);
        bindNullableText(stmt, 4, input.description);
        bindText(stmt, 5, input.scope);
        bindText(stmt, 6, input.permissions_json);
        bindText(stmt, 7, input.metadata_json);
        _ = c.sqlite3_bind_int64(stmt, 8, now);
        _ = c.sqlite3_bind_int64(stmt, 9, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        const space = Space{ .id = id, .name = input.name, .title = input.title, .description = input.description, .scope = input.scope, .permissions_json = input.permissions_json, .metadata_json = input.metadata_json, .created_at_ms = now, .updated_at_ms = now };
        try self.upsertSpaceFts(space);
        try self.insertAuditActor("space.created", input.actor_id, "space", id);
        return space;
    }

    pub fn getSpace(self: *Self, allocator: std.mem.Allocator, id: []const u8) !?Space {
        const stmt = try self.prepare("SELECT id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms FROM spaces WHERE id = ?1 OR name = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        if (c.sqlite3_step(stmt) != c.SQLITE_ROW) return null;
        return try readSqliteSpace(allocator, stmt);
    }

    pub fn listSpaces(self: *Self, allocator: std.mem.Allocator, scopes_json: []const u8, limit_raw: usize) ![]Space {
        const stmt = try self.prepare("SELECT id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms FROM spaces ORDER BY updated_at_ms DESC LIMIT ?1");
        defer _ = c.sqlite3_finalize(stmt);
        _ = c.sqlite3_bind_int64(stmt, 1, bounded_int.usizeToI64Saturating(@max(@as(usize, 1), @min(limit_raw, 200))));
        var out: std.ArrayListUnmanaged(Space) = .empty;
        errdefer {
            for (out.items) |*space| deinitSpace(allocator, space);
            out.deinit(allocator);
        }
        while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
            var space = try readSqliteSpace(allocator, stmt);
            errdefer deinitSpace(allocator, &space);
            if (!try self.recordVisibleWithPolicy(allocator, space.scope, space.permissions_json, scopes_json)) {
                deinitSpace(allocator, &space);
                continue;
            }
            const status = try self.primitiveLifecycleStatus(allocator, "space", space.id);
            if (!domain.isDefaultVisibleStatus(status)) {
                deinitSpace(allocator, &space);
                continue;
            }
            try out.ensureUnusedCapacity(allocator, 1);
            out.appendAssumeCapacity(space);
        }
        return out.toOwnedSlice(allocator);
    }

    fn readSqliteSpace(allocator: std.mem.Allocator, stmt: *c.sqlite3_stmt) !Space {
        return .{
            .id = try columnText(allocator, stmt, 0),
            .name = try columnText(allocator, stmt, 1),
            .title = try columnText(allocator, stmt, 2),
            .description = try columnTextNullable(allocator, stmt, 3),
            .scope = try columnText(allocator, stmt, 4),
            .permissions_json = try columnText(allocator, stmt, 5),
            .metadata_json = try columnText(allocator, stmt, 6),
            .created_at_ms = c.sqlite3_column_int64(stmt, 7),
            .updated_at_ms = c.sqlite3_column_int64(stmt, 8),
        };
    }

    pub fn upsertPolicyScope(self: *Self, allocator: std.mem.Allocator, input: PolicyScopeInput) !PolicyScope {
        const now = ids.nowMs();
        const stmt = try self.prepare("INSERT INTO policy_scopes (scope,visibility,permissions_json,owner,ttl_ms,review_after_ms,metadata_json,created_at_ms,updated_at_ms) VALUES (?1,?2,?3,?4,?5,?6,?7,?8,?9) ON CONFLICT(scope) DO UPDATE SET visibility=excluded.visibility, permissions_json=excluded.permissions_json, owner=excluded.owner, ttl_ms=excluded.ttl_ms, review_after_ms=excluded.review_after_ms, metadata_json=excluded.metadata_json, updated_at_ms=excluded.updated_at_ms");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, input.scope);
        bindText(stmt, 2, input.visibility);
        bindText(stmt, 3, input.permissions_json);
        bindNullableText(stmt, 4, input.owner);
        if (input.ttl_ms) |v| _ = c.sqlite3_bind_int64(stmt, 5, v) else _ = c.sqlite3_bind_null(stmt, 5);
        if (input.review_after_ms) |v| _ = c.sqlite3_bind_int64(stmt, 6, v) else _ = c.sqlite3_bind_null(stmt, 6);
        bindText(stmt, 7, input.metadata_json);
        _ = c.sqlite3_bind_int64(stmt, 8, now);
        _ = c.sqlite3_bind_int64(stmt, 9, now);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        const policy = (try self.getPolicyScope(allocator, input.scope)).?;
        try self.upsertPolicyScopeFts(policy);
        try self.insertAuditActor("policy_scope.upserted", input.actor_id, "policy_scope", input.scope);
        return policy;
    }

    pub fn getPolicyScope(self: *Self, allocator: std.mem.Allocator, scope: []const u8) !?PolicyScope {
        const stmt = try self.prepare("SELECT scope,visibility,permissions_json,owner,ttl_ms,review_after_ms,metadata_json,created_at_ms,updated_at_ms FROM policy_scopes WHERE scope = ?1 LIMIT 1");
        defer _ = c.sqlite3_finalize(stmt);
