    pub fn createArtifact(self: *Self, allocator: std.mem.Allocator, input: ArtifactInput) !domain.Artifact {
        const id = try idOrMake(allocator, input.id, "art_");
        const now = ids.nowMs();
        var committed = false;
        errdefer if (!committed) self.cleanupCreatedArtifactBestEffort(id);
        {
            const stmt = try self.prepare("INSERT INTO artifacts (id,type,title,body,status,owner,space_id,version,created_at_ms,updated_at_ms,last_verified_at_ms,scope,source_ids_json,related_entities_json,permissions_json,fields_json,summary,agent_summary) VALUES (?1,?2,?3,?4,?5,?6,?7,1,?8,?9,NULL,?10,?11,?12,?13,?14,?15,?16)");
            defer _ = c.sqlite3_finalize(stmt);
            bindText(stmt, 1, id);
            bindText(stmt, 2, input.artifact_type);
            bindText(stmt, 3, input.title);
            bindText(stmt, 4, input.body);
            bindText(stmt, 5, input.status);
            bindNullableText(stmt, 6, input.owner);
            bindNullableText(stmt, 7, input.space_id);
            _ = c.sqlite3_bind_int64(stmt, 8, now);
            _ = c.sqlite3_bind_int64(stmt, 9, now);
            bindText(stmt, 10, input.scope);
            bindText(stmt, 11, input.source_ids_json);
            bindText(stmt, 12, input.related_entities_json);
            bindText(stmt, 13, input.permissions_json);
            bindText(stmt, 14, input.fields_json);
            bindNullableText(stmt, 15, input.summary);
            bindNullableText(stmt, 16, input.agent_summary);
            if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        }
        try self.upsertArtifactFts(allocator, id, input.title, input.body, input.fields_json);
        try self.insertAuditActor("artifact.created", input.actor_id, "artifact", id);
        committed = true;
        return .{
            .id = id,
            .artifact_type = input.artifact_type,
            .title = input.title,
            .body = input.body,
            .status = input.status,
            .owner = input.owner,
            .space_id = input.space_id,
            .version = 1,
            .created_at_ms = now,
            .updated_at_ms = now,
            .last_verified_at_ms = null,
            .scope = input.scope,
            .source_ids_json = input.source_ids_json,
            .related_entities_json = input.related_entities_json,
            .permissions_json = input.permissions_json,
            .fields_json = input.fields_json,
            .summary = input.summary,
            .agent_summary = input.agent_summary,
        };
    }

    pub fn upsertArtifact(self: *Self, allocator: std.mem.Allocator, input: ArtifactInput) !domain.Artifact {
        const id = try idOrMake(allocator, input.id, "art_");
        const now = ids.nowMs();
        const stmt = try self.prepare(
            "INSERT INTO artifacts (id,type,title,body,status,owner,space_id,version,created_at_ms,updated_at_ms,last_verified_at_ms,scope,source_ids_json,related_entities_json,permissions_json,fields_json,summary,agent_summary) " ++
                "VALUES (?1,?2,?3,?4,?5,?6,?7,1,?8,?9,NULL,?10,?11,?12,?13,?14,?15,?16) " ++
                "ON CONFLICT(id) DO UPDATE SET type=excluded.type,title=excluded.title,body=excluded.body,status=excluded.status,owner=excluded.owner,space_id=excluded.space_id,version=artifacts.version+1,updated_at_ms=excluded.updated_at_ms,scope=excluded.scope,source_ids_json=excluded.source_ids_json,related_entities_json=excluded.related_entities_json,permissions_json=excluded.permissions_json,fields_json=excluded.fields_json,summary=excluded.summary,agent_summary=excluded.agent_summary",
        );
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        bindText(stmt, 2, input.artifact_type);
        bindText(stmt, 3, input.title);
        bindText(stmt, 4, input.body);
        bindText(stmt, 5, input.status);
        bindNullableText(stmt, 6, input.owner);
        bindNullableText(stmt, 7, input.space_id);
        _ = c.sqlite3_bind_int64(stmt, 8, now);
        _ = c.sqlite3_bind_int64(stmt, 9, now);
        bindText(stmt, 10, input.scope);
        bindText(stmt, 11, input.source_ids_json);
        bindText(stmt, 12, input.related_entities_json);
        bindText(stmt, 13, input.permissions_json);
        bindText(stmt, 14, input.fields_json);
        bindNullableText(stmt, 15, input.summary);
        bindNullableText(stmt, 16, input.agent_summary);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
        const artifact = (try self.getArtifact(allocator, id)).?;
        try self.upsertArtifactFts(allocator, artifact.id, artifact.title, artifact.body, artifact.fields_json);
        try self.insertAuditActor("artifact.upserted", input.actor_id, "artifact", artifact.id);
        return artifact;
    }

    fn upsertArtifactFts(self: *Self, allocator: std.mem.Allocator, id: []const u8, title: []const u8, body: []const u8, fields_json: []const u8) !void {
        const del = try self.prepare("DELETE FROM artifacts_fts WHERE id = ?1");
        defer _ = c.sqlite3_finalize(del);
        bindText(del, 1, id);
        _ = c.sqlite3_step(del);
        const fts_body = try artifactTextWithFields(allocator, body, fields_json);
        defer allocator.free(fts_body);
        const stmt = try self.prepare("INSERT INTO artifacts_fts (id,title,body) VALUES (?1,?2,?3)");
        defer _ = c.sqlite3_finalize(stmt);
        bindText(stmt, 1, id);
        bindText(stmt, 2, title);
        bindText(stmt, 3, fts_body);
        if (c.sqlite3_step(stmt) != c.SQLITE_DONE) return error.InsertFailed;
    }

