        else
            agentMemoryVisibleSelectSql("", "ORDER BY CASE WHEN ami.actor_id = ?3 THEN 0 WHEN ami.actor_id LIKE 'shared:%' THEN 1 ELSE 2 END, ami.timestamp_ms DESC LIMIT ?4 OFFSET ?5");
        const fetch_limit = agentMemoryBackendWindowFetchLimit(limit);
        var raw_offset: usize = 0;
        var visible_seen: usize = 0;
        var list: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (list.items) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            list.deinit(allocator);
        }
        while (true) {
            var fetched: usize = 0;
            {
                const stmt = try self.prepare(sql);
                defer _ = c.sqlite3_finalize(stmt);
                if (category) |cat| bindText(stmt, 1, cat);
                bindNullableText(stmt, 2, session_id);
                bindText(stmt, 3, actor_id);
                _ = c.sqlite3_bind_int64(stmt, 4, bounded_int.usizeToI64Saturating(fetch_limit));
                _ = c.sqlite3_bind_int64(stmt, 5, agentMemoryBackendWindowOffsetI64(raw_offset));
                while (c.sqlite3_step(stmt) == c.SQLITE_ROW) {
                    fetched += 1;
                    if (!try self.agentMemoryStmtVisible(allocator, stmt, scopes_json, actor_id)) continue;
                    if (visible_seen < offset) {
                        visible_seen += 1;
                        continue;
                    }
                    if (list.items.len >= limit) continue;
                    try list.append(allocator, try readAgentMemory(allocator, stmt));
                }
            }
            if (list.items.len >= limit or fetched < fetch_limit) break;
            raw_offset = agentMemoryBackendWindowOffsetAfterFetch(raw_offset, fetched);
        }
        return list.toOwnedSlice(allocator);
    }

