    fn runLegacyCompatCleanup(self: *PostgresStore) !void {
        try self.runSql(
            \\BEGIN;
            \\DO $$
            \\BEGIN
            \\  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'compat_memories') THEN
            \\    EXECUTE 'DELETE FROM vector_chunks WHERE object_type = ''memory_atom'' AND object_id IN (SELECT memory_atom_id FROM compat_memories)';
            \\    EXECUTE 'DELETE FROM memory_atoms WHERE id IN (SELECT memory_atom_id FROM compat_memories)';
            \\  END IF;
            \\END $$;
            \\DELETE FROM vector_chunks WHERE object_type = 'memory_atom' AND object_id IN (SELECT id FROM memory_atoms WHERE predicate = 'compat.memory');
            \\DELETE FROM memory_atoms WHERE predicate = 'compat.memory';
            \\DELETE FROM vector_chunks WHERE object_type = 'source' AND object_id IN (SELECT id FROM sources WHERE metadata_json::text LIKE '%"compat"%nullclaw%');
            \\DELETE FROM sources WHERE metadata_json::text LIKE '%"compat"%nullclaw%';
            \\DROP INDEX IF EXISTS compat_memories_key_session_idx;
            \\DROP INDEX IF EXISTS compat_memories_key_session_actor_idx;
            \\DROP TABLE IF EXISTS compat_memories;
            \\COMMIT;
        );
    }

    fn queryJson(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8) !std.json.Parsed(std.json.Value) {
        const text = try self.queryText(allocator, sql);
        defer allocator.free(text);
        if (text.len == 0) return std.json.parseFromSlice(std.json.Value, allocator, "null", .{});
        return std.json.parseFromSlice(std.json.Value, allocator, text, .{});
    }

    fn queryParamsJson(self: *PostgresStore, allocator: std.mem.Allocator, sql: []const u8, params: []const ?[]const u8) !std.json.Parsed(std.json.Value) {
        const text = try self.queryParamsText(allocator, sql, params);
        defer allocator.free(text);
        if (text.len == 0) return std.json.parseFromSlice(std.json.Value, allocator, "null", .{});
        return std.json.parseFromSlice(std.json.Value, allocator, text, .{});
    }

    fn queryRowParamsJson(self: *PostgresStore, allocator: std.mem.Allocator, inner_sql: []const u8, params: []const ?[]const u8) !std.json.Parsed(std.json.Value) {
        const sql = try rowJsonSql(allocator, inner_sql);
        defer allocator.free(sql);
        return self.queryParamsJson(allocator, sql, params);
    }

    fn queryArrayParamsJson(self: *PostgresStore, allocator: std.mem.Allocator, inner_sql: []const u8, params: []const ?[]const u8) !std.json.Parsed(std.json.Value) {
        const sql = try arrayJsonSql(allocator, inner_sql);
        defer allocator.free(sql);
        return self.queryParamsJson(allocator, sql, params);
    }

    fn rowJsonSql(allocator: std.mem.Allocator, inner_sql: []const u8) ![]u8 {
        return std.fmt.allocPrint(allocator, "SELECT coalesce((SELECT row_to_json(t)::text FROM ({s}) t), 'null')", .{inner_sql});
    }

    fn arrayJsonSql(allocator: std.mem.Allocator, inner_sql: []const u8) ![]u8 {
        return std.fmt.allocPrint(allocator, "SELECT coalesce((SELECT json_agg(row_to_json(t))::text FROM ({s}) t), '[]')", .{inner_sql});
    }

    fn pgSearchCandidateLimit(limit: usize, multiplier: usize, max_limit: usize) usize {
        const base = @max(@as(usize, 1), @min(limit, 1000));
        const expanded = bounded_int.saturatingUsizeMul(base, multiplier);
        return @min(@max(expanded, @as(usize, 200)), max_limit);
    }

    fn sqlString(allocator: std.mem.Allocator, value: []const u8) ![]u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        try out.append(allocator, '\'');
        for (value) |ch| {
            if (ch == '\'') try out.append(allocator, '\'');
            try out.append(allocator, ch);
        }
        try out.append(allocator, '\'');
        return out.toOwnedSlice(allocator);
    }

    fn appendPgTextArrayItem(out: *std.ArrayListUnmanaged(u8), allocator: std.mem.Allocator, value: []const u8) !void {
        try out.append(allocator, '\'');
        for (value) |ch| {
            if (ch == '\'') try out.append(allocator, '\'');
            try out.append(allocator, ch);
        }
        try out.append(allocator, '\'');
    }

    fn appendPgVisibleScopes(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), scopes: []const []const u8, scope_expr: []const u8) !void {
        var exact_count: usize = 0;
        for (scopes) |scope| {
            if (scope.len == 0 or std.mem.eql(u8, scope, "admin")) continue;
            if (scope[scope.len - 1] == '*') continue;
            if (exact_count == 0) try out.print(allocator, " OR {s} IN (", .{scope_expr}) else try out.append(allocator, ',');
            try appendPgTextArrayItem(out, allocator, scope);
            exact_count += 1;
        }
        if (exact_count > 0) try out.append(allocator, ')');

        for (scopes) |scope| {
            if (scope.len < 2 or scope[scope.len - 1] != '*') continue;
            const prefix = scope[0 .. scope.len - 1];
            try out.print(allocator, " OR substr({s}, 1, {d}) = ", .{ scope_expr, prefix.len });
            try appendPgTextArrayItem(out, allocator, prefix);
        }
    }

    fn appendPgVisiblePermissions(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), scopes: []const []const u8, actor_id: ?[]const u8, permissions_expr: []const u8) !void {
        try out.print(allocator, "(coalesce(jsonb_array_length({s}), 0) = 0 OR {s} ? 'public'", .{ permissions_expr, permissions_expr });
        var item_count: usize = 0;
        for (scopes) |scope| {
            if (scope.len == 0 or std.mem.eql(u8, scope, "admin")) continue;
            if (item_count == 0) {
                try out.print(allocator, " OR {s} ?| ARRAY[", .{permissions_expr});
            } else {
                try out.append(allocator, ',');
            }
            try appendPgTextArrayItem(out, allocator, scope);
            item_count += 1;
        }
        if (actor_id) |actor| {
            if (actor.len > 0) {
                const grant = try domain.actorGrant(allocator, actor);
                if (item_count == 0) {
                    try out.print(allocator, " OR {s} ?| ARRAY[", .{permissions_expr});
                } else {
                    try out.append(allocator, ',');
                }
                try appendPgTextArrayItem(out, allocator, grant);
                item_count += 1;
            }
        }
        if (item_count > 0) try out.append(allocator, ']');
        try out.append(allocator, ')');
    }

    fn pgRecordVisibleSql(allocator: std.mem.Allocator, scope_expr: []const u8, permissions_expr: []const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]const u8 {
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, scopes_json, .{}) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => return try std.fmt.allocPrint(allocator, "({s} = 'public' AND (coalesce(jsonb_array_length({s}), 0) = 0 OR {s} ? 'public'))", .{ scope_expr, permissions_expr, permissions_expr }),
        };
        defer parsed.deinit();
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item == .string and std.mem.eql(u8, item.string, "admin")) return allocator.dupe(u8, "TRUE");
            }
        }

        var scopes: std.ArrayListUnmanaged([]const u8) = .empty;
        defer scopes.deinit(allocator);
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .string) continue;
                try scopes.append(allocator, item.string);
            }
        }

        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.append(allocator, '(');
        try out.print(allocator, "({s} = 'public'", .{scope_expr});
        try appendPgVisibleScopes(allocator, &out, scopes.items, scope_expr);
        if (actor_id) |actor| {
            if (actor.len > 0) {
                const actor_scope = try domain.defaultAgentMemoryScope(allocator, actor);
                try out.print(allocator, " OR {s} = ", .{scope_expr});
                try appendPgTextArrayItem(&out, allocator, actor);
                try out.print(allocator, " OR {s} = ", .{scope_expr});
                try appendPgTextArrayItem(&out, allocator, actor_scope);
            }
        }
        try out.append(allocator, ')');
        try out.append(allocator, ' ');
        try out.appendSlice(allocator, "AND ");
        try appendPgVisiblePermissions(allocator, &out, scopes.items, actor_id, permissions_expr);
        try out.append(allocator, ')');
        return out.toOwnedSlice(allocator);
    }

    fn sqlNullableString(allocator: std.mem.Allocator, value: ?[]const u8) ![]u8 {
        if (value) |v| return sqlString(allocator, v);
        return allocator.dupe(u8, "NULL");
    }

    fn pgAgentMemorySessionFilter(allocator: std.mem.Allocator, session_id: ?[]const u8, actor_id: ?[]const u8) ![]u8 {
        return pgAgentMemorySessionFilterQualified(allocator, "", session_id, actor_id);
    }

    fn pgAgentMemoryVisibleSessionFilter(allocator: std.mem.Allocator, comptime prefix: []const u8, session_id: ?[]const u8) ![]u8 {
        if (session_id) |sid| {
            return std.fmt.allocPrint(allocator, "{s}session_id = {s}", .{ prefix, try sqlString(allocator, sid) });
        }
        return std.fmt.allocPrint(allocator, "{s}session_id IS NULL", .{prefix});
    }

    fn pgSessionActorFilter(allocator: std.mem.Allocator, comptime prefix: []const u8, actor_id: ?[]const u8) ![]const u8 {
        if (actor_id) |actor| {
            if (actor.len == 0) return "FALSE";
            return std.fmt.allocPrint(allocator, "{s}actor_id = {s}", .{ prefix, try sqlString(allocator, actor) });
        }
        return "TRUE";
    }

    fn pgAgentMemorySessionFilterQualified(allocator: std.mem.Allocator, comptime prefix: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]u8 {
        const actor_filter = if (actor_id) |actor| blk: {
            if (actor.len == 0) break :blk try allocator.dupe(u8, "FALSE");
            break :blk try std.fmt.allocPrint(allocator, "{s}actor_id = {s}", .{ prefix, try sqlString(allocator, actor) });
        } else try allocator.dupe(u8, "FALSE");
        if (session_id) |sid| {
            return std.fmt.allocPrint(allocator, "{s}session_id = {s} AND {s}", .{ prefix, try sqlString(allocator, sid), actor_filter });
        }
        return std.fmt.allocPrint(allocator, "{s}session_id IS NULL AND {s}", .{ prefix, actor_filter });
    }

    fn sqlJsonb(allocator: std.mem.Allocator, value: []const u8) ![]u8 {
        const quoted = try sqlString(allocator, value);
        defer allocator.free(quoted);
        return std.fmt.allocPrint(allocator, "{s}::jsonb", .{quoted});
    }

    fn sqlNullableInt(allocator: std.mem.Allocator, value: ?i64) ![]u8 {
        if (value) |v| return std.fmt.allocPrint(allocator, "{d}", .{v});
        return allocator.dupe(u8, "NULL");
    }

    pub fn createSpace(self: *PostgresStore, allocator: std.mem.Allocator, input: SpaceInput) !Space {
        const id = try idOrMake(allocator, input.id, "spc_");
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "WITH inserted AS (" ++
                "INSERT INTO spaces (id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms) VALUES ($1,$2,$3,$4,$5,$6::jsonb,$7::jsonb,$8::bigint,$9::bigint) RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'space.created',$10,'space',id,'{}'::jsonb,$11::bigint FROM inserted RETURNING 1" ++
                ") SELECT count(*)::text FROM inserted",
            &.{ id, input.name, input.title, input.description, input.scope, input.permissions_json, input.metadata_json, now_text, now_text, input.actor_id, now_text },
        );
        return .{ .id = id, .name = input.name, .title = input.title, .description = input.description, .scope = input.scope, .permissions_json = input.permissions_json, .metadata_json = input.metadata_json, .created_at_ms = now, .updated_at_ms = now };
    }

    pub fn getSpace(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?Space {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms FROM spaces WHERE id = $1 OR name = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgSpace(allocator, parsed.value.object);
    }

    pub fn listSpaces(self: *PostgresStore, allocator: std.mem.Allocator, scopes_json: []const u8, limit_raw: usize) ![]Space {
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{@max(@as(usize, 1), @min(limit_raw, 200))});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,name,title,description,scope,permissions_json,metadata_json,created_at_ms,updated_at_ms FROM spaces ORDER BY updated_at_ms DESC LIMIT $1::bigint",
            &.{limit_text},
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(Space) = .empty;
        errdefer {
            for (out.items) |*space| deinitSpace(allocator, space);
            out.deinit(allocator);
        }
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            var space = try readPgSpace(allocator, item.object);
            errdefer deinitSpace(allocator, &space);
            if (!try self.recordVisibleWithPolicy(allocator, space.scope, space.permissions_json, scopes_json)) {
                deinitSpace(allocator, &space);
                continue;
            }
            const status = try self.primitiveLifecycleStatus(allocator, "space", space.id);
            if (!domain.isDefaultVisibleStatus(status)) {
                deinitSpace(allocator, &space);
                continue;
            }
            try out.ensureUnusedCapacity(allocator, 1);
            out.appendAssumeCapacity(space);
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn upsertPolicyScope(self: *PostgresStore, allocator: std.mem.Allocator, input: PolicyScopeInput) !PolicyScope {
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        const ttl_text: ?[]const u8 = if (input.ttl_ms) |ttl| try std.fmt.allocPrint(allocator, "{d}", .{ttl}) else null;
        defer if (ttl_text) |value| allocator.free(value);
        const review_text: ?[]const u8 = if (input.review_after_ms) |review| try std.fmt.allocPrint(allocator, "{d}", .{review}) else null;
        defer if (review_text) |value| allocator.free(value);
        try self.runParams(
            allocator,
            "WITH upserted AS (" ++
                "INSERT INTO policy_scopes (scope,visibility,permissions_json,owner,ttl_ms,review_after_ms,metadata_json,created_at_ms,updated_at_ms) VALUES ($1,$2,$3::jsonb,$4,$5::bigint,$6::bigint,$7::jsonb,$8::bigint,$9::bigint) " ++
                "ON CONFLICT(scope) DO UPDATE SET visibility=excluded.visibility, permissions_json=excluded.permissions_json, owner=excluded.owner, ttl_ms=excluded.ttl_ms, review_after_ms=excluded.review_after_ms, metadata_json=excluded.metadata_json, updated_at_ms=excluded.updated_at_ms RETURNING scope" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'policy_scope.upserted',$10,'policy_scope',scope,'{}'::jsonb,$11::bigint FROM upserted RETURNING 1" ++
                ") SELECT count(*)::text FROM upserted",
            &.{ input.scope, input.visibility, input.permissions_json, input.owner, ttl_text, review_text, input.metadata_json, now_text, now_text, input.actor_id, now_text },
        );
        return (try self.getPolicyScope(allocator, input.scope)).?;
    }

    pub fn getPolicyScope(self: *PostgresStore, allocator: std.mem.Allocator, scope: []const u8) !?PolicyScope {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT scope,visibility,permissions_json,owner,ttl_ms,review_after_ms,metadata_json,created_at_ms,updated_at_ms FROM policy_scopes WHERE scope = $1 LIMIT 1",
            &.{scope},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgPolicyScope(allocator, parsed.value.object);
    }

    pub fn listPolicyScopes(self: *PostgresStore, allocator: std.mem.Allocator, scopes_json: []const u8, limit_raw: usize) ![]PolicyScope {
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{@max(@as(usize, 1), @min(limit_raw, 200))});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT scope,visibility,permissions_json,owner,ttl_ms,review_after_ms,metadata_json,created_at_ms,updated_at_ms FROM policy_scopes ORDER BY updated_at_ms DESC LIMIT $1::bigint",
            &.{limit_text},
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(PolicyScope) = .empty;
        errdefer {
            for (out.items) |*policy| deinitPolicyScope(allocator, policy);
            out.deinit(allocator);
        }
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            var policy = try readPgPolicyScope(allocator, item.object);
            errdefer deinitPolicyScope(allocator, &policy);
            if (!try self.recordVisibleWithPolicy(allocator, policy.scope, policy.permissions_json, scopes_json)) {
                deinitPolicyScope(allocator, &policy);
                continue;
            }
            const status = try self.primitiveLifecycleStatus(allocator, "policy_scope", policy.scope);
            if (!domain.isDefaultVisibleStatus(status)) {
                deinitPolicyScope(allocator, &policy);
                continue;
            }
            try out.ensureUnusedCapacity(allocator, 1);
            out.appendAssumeCapacity(policy);
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn createSource(self: *PostgresStore, allocator: std.mem.Allocator, input: SourceInput) !domain.Source {
