    pub fn listSources(self: *PostgresStore, allocator: std.mem.Allocator, limit: ?usize) ![]domain.Source {
        const parsed = if (limit) |value| blk: {
            const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{value});
