                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'memory_atom.created',$18,'memory_atom',id,'{}'::jsonb,$19::bigint FROM inserted RETURNING 1" ++
                ") SELECT count(*)::text FROM inserted",
            &.{ id, input.subject_entity_id, input.predicate, input.object, input.text, input.scope, confidence_text, status, input.source_ids_json, input.evidence_ranges_json, input.created_by, now_text, valid_from_text, valid_until_text, input.owner, input.permissions_json, input.tags_json, input.actor_id, now_text },
        );
        return .{ .id = id, .subject_entity_id = input.subject_entity_id, .predicate = input.predicate, .object = input.object, .text = input.text, .scope = input.scope, .confidence = input.confidence, .status = status, .source_ids_json = input.source_ids_json, .evidence_ranges_json = input.evidence_ranges_json, .created_by = input.created_by, .created_at_ms = now, .valid_from_ms = input.valid_from_ms, .valid_until_ms = input.valid_until_ms, .last_verified_at_ms = null, .owner = input.owner, .permissions_json = input.permissions_json, .tags_json = input.tags_json };
    }

    pub fn importMemoryAtomsAtomic(self: *PostgresStore, allocator: std.mem.Allocator, inputs: []const PreparedMemoryImport) ![]domain.MemoryAtom {
        try self.beginTransaction();
        errdefer self.rollbackTransaction();

        var out: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        errdefer out.deinit(allocator);

        for (inputs) |prepared| {
            var atom_input = prepared.atom;
            if (prepared.generated_source) |source_input| {
                const source = try self.createSource(allocator, source_input);
                atom_input.source_ids_json = try singleJsonString(allocator, source.id);
                atom_input.evidence_ranges_json = try evidenceRangeJson(allocator, source.id, atom_input.text.len, "snapshot_import");
            }

            const atom = try self.createMemoryAtom(allocator, atom_input);
            try out.append(allocator, atom);
        }

        try self.commitTransaction();
        return out.toOwnedSlice(allocator);
    }

    pub fn applyFeedMemoryAtomAtomic(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedMemoryApplyInput) !FeedMemoryApplyResult {
        try self.beginTransaction();
        errdefer self.rollbackTransaction();

        var atom_input = input.prepared.atom;
        if (input.prepared.generated_source) |source_input| {
            const source = try self.createSource(allocator, source_input);
            atom_input.source_ids_json = try singleJsonString(allocator, source.id);
            atom_input.evidence_ranges_json = try evidenceRangeJson(allocator, source.id, atom_input.text.len, "generated_source");
        }

        const atom = try self.createMemoryAtom(allocator, atom_input);
        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, atom.id, input.event.payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = atom.id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = input.event.payload_json,
            .status = "applied",
        });
        if (input.mirror_job_input_json) |job_input_json| {
            var job = try self.createJob(allocator, .{
                .job_type = "agent_memory_mirror",
                .scope = atom.scope,
                .permissions_json = atom.permissions_json,
                .object_type = "memory_atom",
                .object_id = atom.id,
                .input_json = job_input_json,
                .actor_id = input.prepared.atom.actor_id,
            });
            defer freeCreatedJobResult(allocator, &job);
        }

        try self.commitTransaction();
        return .{ .event_id = event_id, .atom = atom };
    }

    pub fn applyFeedAgentMemoryAtomic(self: *PostgresStore, allocator: std.mem.Allocator, input: FeedAgentMemoryApplyInput) !FeedAgentMemoryApplyResult {
        try self.beginTransaction();
        errdefer self.rollbackTransaction();

        var object_id: []const u8 = input.delete_key orelse "agent_memory";
        var entry: ?domain.AgentMemory = null;
        var deleted = false;
        if (input.input) |memory_input| {
            var auditable = memory_input;
            if (auditable.writer_actor_id == null) auditable.writer_actor_id = input.writer_actor_id orelse input.event.actor_id;
            const saved = try self.agentMemoryStore(allocator, auditable);
            object_id = saved.id;
            entry = saved;
        } else if (input.delete_key) |key| {
            deleted = if (input.delete_all)
                try self.agentMemoryDeleteAllOrdered(allocator, key, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, input.event_order)
            else
                try self.agentMemoryDeleteOrdered(allocator, key, input.delete_session_id, input.delete_owner_actor_id, input.writer_actor_id orelse input.event.actor_id, input.event_order);
            object_id = key;
        }

        const event_id = if (input.reserved_event_id) |reserved| blk: {
            if (!try self.markFeedEventApplied(reserved, input.event.object_type, object_id, input.event.payload_json)) return error.FeedReservationConsumed;
            break :blk reserved;
        } else try self.appendFeedEvent(.{
            .event_type = input.event.event_type,
            .operation = input.event.operation,
            .object_type = input.event.object_type,
            .object_id = object_id,
            .scope = input.event.scope,
            .permissions_json = input.event.permissions_json,
            .actor_id = input.event.actor_id,
            .dedupe_key = input.event.dedupe_key,
            .causality_json = input.event.causality_json,
            .payload_json = input.event.payload_json,
            .status = "applied",
        });

        try self.commitTransaction();
        return .{ .event_id = event_id, .object_id = object_id, .entry = entry, .deleted = deleted };
    }

    pub fn applyExtractedKnowledge(self: *PostgresStore, allocator: std.mem.Allocator, input: ExtractedKnowledgeInput) !ExtractedKnowledgeResult {
        const ResolvedRelation = struct {
            input: ExtractedRelationInput,
            from_entity: domain.Entity,
            to_entity: domain.Entity,
        };

        try self.beginTransaction();
        errdefer self.rollbackTransaction();

        var entity_list: std.ArrayListUnmanaged(domain.Entity) = .empty;
        errdefer entity_list.deinit(allocator);
        const base_entities = try self.resolveExtractedEntitiesPg(allocator, input.entity_names_json, input.source.scope, input.source.permissions_json, input.actor_id);
        for (base_entities) |entity| try appendUniqueEntity(allocator, &entity_list, entity);

        var resolved_relations: std.ArrayListUnmanaged(ResolvedRelation) = .empty;
        errdefer resolved_relations.deinit(allocator);
        for (input.relations) |relation_input| {
            const from_entity = try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = relation_input.from_entity_name,
                .scope = input.source.scope,
                .permissions_json = input.source.permissions_json,
                .actor_id = input.actor_id,
            });
            const to_entity = try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = relation_input.to_entity_name,
                .scope = input.source.scope,
                .permissions_json = input.source.permissions_json,
                .actor_id = input.actor_id,
            });
            try appendUniqueEntity(allocator, &entity_list, from_entity);
            try appendUniqueEntity(allocator, &entity_list, to_entity);
            try resolved_relations.append(allocator, .{ .input = relation_input, .from_entity = from_entity, .to_entity = to_entity });
        }

        const entities = try entity_list.toOwnedSlice(allocator);
        const related_entity_ids_json = try entityIdsJson(allocator, entities);

        try self.runParams(
            allocator,
            "UPDATE sources SET related_entities_json = $1::jsonb WHERE id = $2",
            &.{ related_entity_ids_json, input.source.id },
        );

        var artifact: ?domain.Artifact = null;
        if (input.artifact) |base_artifact_input| {
            var artifact_input = base_artifact_input;
            artifact_input.related_entities_json = related_entity_ids_json;
            artifact = try self.createArtifact(allocator, artifact_input);
        }

        var atoms: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        errdefer atoms.deinit(allocator);
        const subject_entity_id = if (entities.len > 0) entities[0].id else null;
        for (input.atoms) |base_atom_input| {
            var atom_input = base_atom_input;
            if (atom_input.subject_entity_id == null) atom_input.subject_entity_id = subject_entity_id;
            try atoms.append(allocator, try self.createMemoryAtom(allocator, atom_input));
        }

        var relations: std.ArrayListUnmanaged(domain.Relation) = .empty;
        errdefer relations.deinit(allocator);
        for (resolved_relations.items) |resolved| {
            try relations.append(allocator, try self.createRelation(allocator, .{
                .from_entity_id = resolved.from_entity.id,
                .relation_type = resolved.input.relation_type,
                .to_entity_id = resolved.to_entity.id,
                .source_ids_json = resolved.input.source_ids_json,
                .scope = resolved.input.scope,
                .permissions_json = resolved.input.permissions_json,
                .confidence = resolved.input.confidence,
                .status = resolved.input.status,
                .actor_id = resolved.input.actor_id,
            }));
        }

        try self.commitTransaction();
        return .{ .artifact = artifact, .entities = entities, .relations = try relations.toOwnedSlice(allocator), .atoms = try atoms.toOwnedSlice(allocator) };
    }

    fn resolveExtractedEntitiesPg(self: *PostgresStore, allocator: std.mem.Allocator, names_json: []const u8, scope: []const u8, permissions_json: []const u8, actor_id: ?[]const u8) ![]domain.Entity {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, names_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return allocator.alloc(domain.Entity, 0);
        var out: std.ArrayListUnmanaged(domain.Entity) = .empty;
        errdefer out.deinit(allocator);
        for (parsed.value.array.items) |item| {
            if (item != .string) continue;
            const owned_name = try allocator.dupe(u8, item.string);
            try out.append(allocator, try self.resolveEntity(allocator, .{
                .entity_type = "project",
                .name = owned_name,
                .scope = scope,
                .permissions_json = permissions_json,
                .actor_id = actor_id,
            }));
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn getMemoryAtom(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?domain.MemoryAtom {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json FROM memory_atoms WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgMemoryAtom(allocator, parsed.value.object);
    }

    pub fn patchMemoryAtomStatus(self: *PostgresStore, id: []const u8, status: []const u8, verified: bool) !bool {
        return self.patchMemoryAtomStatusActor(id, status, verified, null);
    }

    pub fn patchMemoryAtomStatusActor(self: *PostgresStore, id: []const u8, status: []const u8, verified: bool, actor_id: ?[]const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const verified_text = if (verified) "true" else "false";
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (UPDATE memory_atoms SET status = $1, last_verified_at_ms = CASE WHEN $2::boolean THEN $3::bigint ELSE last_verified_at_ms END WHERE id = $4 RETURNING id) SELECT count(*)::text FROM updated",
            &.{ status, verified_text, now_text, id },
        );
        const changed = (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
        if (changed) try self.insertAudit(self.allocator, "memory_atom.status", actor_id, "memory_atom", id);
        return changed;
    }

    pub fn patchArtifactStatusActor(self: *PostgresStore, id: []const u8, status: []const u8, actor_id: ?[]const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const verified = std.mem.eql(u8, status, "verified") or std.mem.eql(u8, status, "accepted");
        const verified_text = if (verified) "true" else "false";
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (UPDATE artifacts SET status = $1, updated_at_ms = $2::bigint, last_verified_at_ms = CASE WHEN $3::boolean THEN $2::bigint ELSE last_verified_at_ms END WHERE id = $4 RETURNING id) SELECT count(*)::text FROM updated",
            &.{ status, now_text, verified_text, id },
        );
        const changed = (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
        if (changed) try self.insertAudit(self.allocator, "artifact.status", actor_id, "artifact", id);
        return changed;
    }

    pub fn patchRelationStatusActor(self: *PostgresStore, id: []const u8, status: []const u8, actor_id: ?[]const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (UPDATE relations SET status = $1 WHERE id = $2 RETURNING id) SELECT count(*)::text FROM updated",
            &.{ status, id },
        );
        const changed = (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
        if (changed) try self.insertAudit(self.allocator, "relation.status", actor_id, "relation", id);
        return changed;
    }

    pub fn patchPrimitiveLifecycleActor(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, status: []const u8, actor_id: ?[]const u8, payload_json: []const u8) !bool {
        if (!primitiveLifecycleUsesOverlay(object_type)) return false;
        if (!try self.primitiveLifecycleTargetExists(allocator, object_type, object_id)) return false;
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "INSERT INTO primitive_lifecycle (object_type,object_id,status,actor_id,payload_json,updated_at_ms) VALUES ($1,$2,$3,$4,$5::jsonb,$6::bigint) " ++
                "ON CONFLICT(object_type, object_id) DO UPDATE SET status=excluded.status, actor_id=excluded.actor_id, payload_json=excluded.payload_json, updated_at_ms=excluded.updated_at_ms",
            &.{ object_type, object_id, status, actor_id, payload_json, now_text },
        );
        try self.insertAudit(self.allocator, "primitive_lifecycle.status", actor_id, object_type, object_id);
        return true;
    }

    pub fn primitiveLifecycleStatus(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) ![]const u8 {
        if (!primitiveLifecycleUsesOverlay(object_type)) return "active";
        const status = try self.queryParamsText(
            allocator,
            "SELECT coalesce((SELECT status FROM primitive_lifecycle WHERE object_type = $1 AND object_id = $2 LIMIT 1), 'active')",
            &.{ object_type, object_id },
        );
        defer allocator.free(status);
        return stableLifecycleStatus(status);
    }

    fn primitiveLifecycleTargetExists(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) !bool {
        if (std.mem.eql(u8, object_type, "source")) {
            var source = (try self.getSource(allocator, object_id)) orelse return false;
            defer deinitSource(allocator, &source);
            return true;
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            var entity = (try self.getEntity(allocator, object_id)) orelse return false;
            defer deinitEntity(allocator, &entity);
            return true;
        }
        if (std.mem.eql(u8, object_type, "context_pack")) return try self.contextPackExists(allocator, object_id);
        if (std.mem.eql(u8, object_type, "space")) {
            var space = (try self.getSpace(allocator, object_id)) orelse return false;
            defer deinitSpace(allocator, &space);
            return true;
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            var policy = (try self.getPolicyScope(allocator, object_id)) orelse return false;
            defer deinitPolicyScope(allocator, &policy);
            return true;
        }
        return false;
    }

    fn contextPackExists(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !bool {
        const text = try self.queryParamsText(allocator, "SELECT CASE WHEN EXISTS (SELECT 1 FROM context_packs WHERE id = $1) THEN 'true' ELSE 'false' END", &.{id});
        defer allocator.free(text);
        return std.mem.eql(u8, text, "true");
    }

    pub fn contextPackById(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?ContextPackResult {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT id,purpose,target,query_text,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated,generated_summary,sections_json,citations_json,forbidden_assumptions_json,suggested_next_steps_json,token_budget,created_at_ms FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgContextPackResult(allocator, parsed.value.object);
    }

    pub fn listContextPacks(self: *PostgresStore, allocator: std.mem.Allocator, limit: ?usize) ![]ContextPackResult {
        const parsed = if (limit) |value| blk: {
            const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{value});
            defer allocator.free(limit_text);
            break :blk try self.queryArrayParamsJson(
                allocator,
                "SELECT id,purpose,target,query_text,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated,generated_summary,sections_json,citations_json,forbidden_assumptions_json,suggested_next_steps_json,token_budget,created_at_ms FROM context_packs ORDER BY created_at_ms DESC LIMIT $1::bigint",
                &.{limit_text},
            );
        } else try self.queryArrayParamsJson(
            allocator,
            "SELECT id,purpose,target,query_text,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated,generated_summary,sections_json,citations_json,forbidden_assumptions_json,suggested_next_steps_json,token_budget,created_at_ms FROM context_packs ORDER BY created_at_ms DESC",
            &.{},
        );
        defer parsed.deinit();
        if (parsed.value != .array) return allocator.alloc(ContextPackResult, 0);
        var out: std.ArrayListUnmanaged(ContextPackResult) = .empty;
        errdefer {
            for (out.items) |*pack| deinitContextPackResult(allocator, pack);
            out.deinit(allocator);
        }
        for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            try out.append(allocator, try readPgContextPackResult(allocator, item.object));
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn contextPackLifecycleTarget(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !?PrimitiveLifecycleTarget {
        return self.contextPackVisibleTarget(allocator, id, actor_id, scopes_json, true);
    }

    pub fn contextPackVisibleTarget(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8, scopes_json: []const u8, include_deprecated: bool) !?PrimitiveLifecycleTarget {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT id,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        const obj = parsed.value.object;
        const sources = try rawJsonField(allocator, obj, "included_sources_json", "[]");
        defer allocator.free(sources);
        const artifacts = try rawJsonField(allocator, obj, "included_artifacts_json", "[]");
        defer allocator.free(artifacts);
        const atoms = try rawJsonField(allocator, obj, "included_memory_atoms_json", "[]");
        defer allocator.free(atoms);
        const refs = try rawJsonField(allocator, obj, "included_result_refs_json", "[]");
        defer allocator.free(refs);
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[\"admin\"]");
        defer allocator.free(required_scopes);
        const row_actor_id = try dupNullableStringField(allocator, obj, "actor_id");
        defer if (row_actor_id) |value| allocator.free(value);
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (!try self.contextPackVisible(allocator, sources, artifacts, atoms, refs, required_scopes, row_actor_id, actor_isolated, scopes_json, actor_id, include_deprecated)) return null;
        const object_id = try allocator.dupe(u8, id);
        errdefer allocator.free(object_id);
        const scope = try lifecycleScopeFromRequiredScopesJson(allocator, required_scopes);
        errdefer allocator.free(scope);
        const permissions_json = try allocator.dupe(u8, required_scopes);
        return .{
            .object_id = object_id,
            .scope = scope,
            .permissions_json = permissions_json,
        };
    }

    pub fn search(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput) ![]domain.SearchResult {
        const window_limit = searchCandidateWindowLimit(input);
        if (window_limit == 0) return allocator.alloc(domain.SearchResult, 0);
        const retrieval_input = searchRetrievalWindowInput(input);
        var plan = try retrieval_mod.buildPlanWithAdaptive(allocator, retrieval_input.query, retrieval_input.use_vector, retrieval_input.allow_reranker, adaptiveConfigFromSearchInput(retrieval_input));
        defer plan.deinit(allocator);
        var semantic_input = retrieval_input;
        semantic_input.query = plan.websearch_query;
        var graph_input = semantic_input;
        var exact_graph_query: ?[]u8 = null;
        if (retrieval_mod.queryHasEntityHint(retrieval_input.query)) {
            exact_graph_query = try retrieval_mod.buildExactWebsearchQuery(allocator, retrieval_input.query);
            graph_input.query = exact_graph_query.?;
        }
        defer if (exact_graph_query) |query| allocator.free(query);
        var keyword_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer keyword_results.deinit(allocator);

        if (plan.use_keyword) try self.searchPgKeywordCandidates(allocator, semantic_input, graph_input, &keyword_results);
        pgSortSearchResults(keyword_results.items);

        var vector_results: std.ArrayListUnmanaged(domain.SearchResult) = .empty;
        errdefer vector_results.deinit(allocator);
        if (plan.use_vector and retrieval_input.query.len > 0) {
            try self.searchPgVectorCandidates(allocator, retrieval_input, plan.expanded_query, &vector_results);
        }
        if (plan.use_graph or keyword_results.items.len > 0) {
            try self.expandPgGraphCandidates(allocator, retrieval_input, &keyword_results);
        }

        return try self.fusePgSearchResults(allocator, input, keyword_results.items, vector_results.items, window_limit);
    }

    fn searchPgKeywordCandidates(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput, graph_input: SearchInput, results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
        try self.searchPgMemoryAtoms(allocator, input, results);
        try self.searchPgSpaces(allocator, input, results);
        try self.searchPgPolicyScopes(allocator, input, results);
        try self.searchPgSources(allocator, input, results);
        try self.searchPgArtifacts(allocator, input, results);
        try self.searchPgEntities(allocator, graph_input, results);
        try self.searchPgRelations(allocator, graph_input, results);
        try self.searchPgContextPacks(allocator, input, results);
        try self.searchPgFeedEvents(allocator, input, results);
        try self.searchPgAgentMemories(allocator, input, results);
        if (input.include_sessions) try self.searchPgSessions(allocator, input, results);
    }

    fn fusePgSearchResults(self: *PostgresStore, allocator: std.mem.Allocator, input: SearchInput, keyword_results: []const domain.SearchResult, vector_results: []const domain.SearchResult, limit: usize) ![]domain.SearchResult {
        _ = self;
        return fuseRankedSearchResultLists(allocator, input, keyword_results, vector_results, limit);
    }

    fn recordVisibleWithPolicy(self: *PostgresStore, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8) !bool {
        if (!domain.recordVisible(scope, permissions_json, scopes_json)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn recordVisibleWithPolicyForActor(self: *PostgresStore, allocator: std.mem.Allocator, scope: []const u8, permissions_json: []const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        if (try self.recordVisibleWithPolicy(allocator, scope, permissions_json, scopes_json)) return true;
        const actor = actor_id orelse return false;
        if (!permissionsVisibleForActor(allocator, permissions_json, scopes_json, actor)) return false;
        if (!domain.scopeVisible(scope, scopes_json) and !domain.isActorOwnedAgentMemoryScope(scope, actor)) return false;
        const policy = try self.getPolicyScope(allocator, scope);
        if (policy) |p| return domain.recordVisible(p.scope, p.permissions_json, scopes_json);
        return true;
    }

    fn agentMemoryResultVisible(self: *PostgresStore, allocator: std.mem.Allocator, owner_actor_id: []const u8, scope: []const u8, permissions: []const u8, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) !bool {
        return access.agentMemoryVisible(allocator, .{
            .owner_actor_id = owner_actor_id,
            .scope = scope,
            .permissions_json = permissions,
            .session_id = session_id,
            .request_actor_id = actor_id,
            .request_scopes_json = scopes_json,
            .record_visible = try self.recordVisibleWithPolicy(allocator, scope, permissions, scopes_json),
            .session_visible = if (session_id) |sid| sessionVisibleForScopes(allocator, sid, scopes_json) else true,
        });
    }

    pub fn upsertVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorChunkInput) !VectorChunk {
        const parsed_embedding = try vector_mod.embeddingFromJson(allocator, input.embedding_json);
        defer allocator.free(parsed_embedding);
        if (!try self.vectorBackingObjectExists(allocator, input.object_type, input.object_id)) return error.InvalidVectorTarget;
        const id = try makeCanonicalVectorChunkId(allocator, input.object_type, input.object_id, input.chunk_ordinal);
        errdefer allocator.free(id);
        const now = ids.nowMs();
        const chunk_ordinal = try std.fmt.allocPrint(allocator, "{d}", .{input.chunk_ordinal});
        defer allocator.free(chunk_ordinal);
        const start_byte = try std.fmt.allocPrint(allocator, "{d}", .{input.start_byte});
        defer allocator.free(start_byte);
        const end_byte = try std.fmt.allocPrint(allocator, "{d}", .{input.end_byte});
        defer allocator.free(end_byte);
        const estimated_tokens = try std.fmt.allocPrint(allocator, "{d}", .{input.estimated_tokens});
        defer allocator.free(estimated_tokens);
        const dimensions = try std.fmt.allocPrint(allocator, "{d}", .{input.dimensions});
        defer allocator.free(dimensions);
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "INSERT INTO vector_chunks (id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,start_byte,end_byte,content_hash,chunk_strategy,estimated_tokens,transcript_timestamp,transcript_speaker,embedding_json,embedding,model,dimensions,created_at_ms,updated_at_ms) " ++
                "VALUES ($1,$2,$3,$4::bigint,$5,$6,$7::jsonb,$8::jsonb,$9::bigint,$10::bigint,$11,$12,$13::bigint,$14,$15,$16::jsonb,$17::vector,$18,$19::bigint,$20::bigint,$21::bigint) " ++
                "ON CONFLICT(id) DO UPDATE SET text=excluded.text, scope=excluded.scope, permissions_json=excluded.permissions_json, heading_path_json=excluded.heading_path_json, start_byte=excluded.start_byte, end_byte=excluded.end_byte, content_hash=excluded.content_hash, chunk_strategy=excluded.chunk_strategy, estimated_tokens=excluded.estimated_tokens, transcript_timestamp=excluded.transcript_timestamp, transcript_speaker=excluded.transcript_speaker, embedding_json=excluded.embedding_json, embedding=excluded.embedding, model=excluded.model, dimensions=excluded.dimensions, updated_at_ms=excluded.updated_at_ms",
            &.{ id, input.object_type, input.object_id, chunk_ordinal, input.text, input.scope, input.permissions_json, input.heading_path_json, start_byte, end_byte, input.content_hash, input.chunk_strategy, estimated_tokens, input.transcript_timestamp, input.transcript_speaker, input.embedding_json, input.embedding_json, input.model, dimensions, now_text, now_text },
        );
        const outbox_payload = try vectorUpsertPayloadJson(allocator, id);
        defer allocator.free(outbox_payload);
        _ = try self.enqueueVectorOutbox(.{ .action = "upsert", .object_type = input.object_type, .object_id = input.object_id, .payload_json = outbox_payload });
        try self.insertAudit(allocator, "vector_chunk.upserted", input.actor_id, "vector_chunk", id);
        return .{ .id = id, .object_type = input.object_type, .object_id = input.object_id, .chunk_ordinal = input.chunk_ordinal, .text = input.text, .scope = input.scope, .permissions_json = input.permissions_json, .heading_path_json = input.heading_path_json, .start_byte = input.start_byte, .end_byte = input.end_byte, .content_hash = input.content_hash, .chunk_strategy = input.chunk_strategy, .estimated_tokens = input.estimated_tokens, .transcript_timestamp = input.transcript_timestamp, .transcript_speaker = input.transcript_speaker, .embedding_json = input.embedding_json, .model = input.model, .dimensions = input.dimensions, .created_at_ms = now, .updated_at_ms = now };
    }

    pub fn getVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?VectorChunk {
        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,start_byte,end_byte,content_hash,chunk_strategy,estimated_tokens,transcript_timestamp,transcript_speaker,embedding_json,model,dimensions,created_at_ms,updated_at_ms FROM vector_chunks WHERE id = $1 LIMIT 1", &.{id});
        defer parsed.deinit();
        if (parsed.value != .array or parsed.value.array.items.len == 0) return null;
        const item = parsed.value.array.items[0];
        if (item != .object) return null;
        return try readPgVectorChunk(allocator, item.object);
    }

    pub fn listVectorChunks(self: *PostgresStore, allocator: std.mem.Allocator, limit: usize, offset: usize) ![]VectorChunk {
        const capped = @max(@as(usize, 1), @min(limit, 10000));
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{capped});
        defer allocator.free(limit_text);
        const offset_text = try std.fmt.allocPrint(allocator, "{d}", .{offset});
        defer allocator.free(offset_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,object_type,object_id,chunk_ordinal,text,scope,permissions_json,heading_path_json,start_byte,end_byte,content_hash,chunk_strategy,estimated_tokens,transcript_timestamp,transcript_speaker,embedding_json,model,dimensions,created_at_ms,updated_at_ms FROM vector_chunks ORDER BY updated_at_ms DESC, id LIMIT $1::bigint OFFSET $2::bigint",
            &.{ limit_text, offset_text },
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(VectorChunk) = .empty;
        errdefer out.deinit(allocator);
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try out.append(allocator, try readPgVectorChunk(allocator, item.object));
            }
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn deleteVectorChunk(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8) !bool {
        var chunk = (try self.getVectorChunk(allocator, id)) orelse return false;
        defer deinitVectorChunk(allocator, &chunk);
        const text = try self.queryParamsText(allocator, "WITH deleted AS (DELETE FROM vector_chunks WHERE id = $1 RETURNING 1) SELECT count(*)::text FROM deleted", &.{id});
        defer allocator.free(text);
        const changed = (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
        if (!changed) return false;
        const outbox_payload = try vectorUpsertPayloadJson(allocator, id);
        defer allocator.free(outbox_payload);
        _ = try self.enqueueVectorOutbox(.{
            .action = "delete",
            .object_type = chunk.object_type,
            .object_id = chunk.object_id,
            .payload_json = outbox_payload,
        });
        try self.insertAudit(allocator, "vector_chunk.deleted", actor_id, "vector_chunk", id);
        return true;
    }

    fn deleteVectorChunksForObject(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, actor_id: ?[]const u8) !usize {
        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id FROM vector_chunks WHERE object_type = $1 AND object_id = $2 ORDER BY id", &.{ object_type, object_id });
        defer parsed.deinit();
        var ids_to_delete: std.ArrayListUnmanaged([]const u8) = .empty;
        defer {
            for (ids_to_delete.items) |chunk_id| allocator.free(chunk_id);
            ids_to_delete.deinit(allocator);
        }
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try ids_to_delete.append(allocator, try dupStringField(allocator, item.object, "id", ""));
            }
        }
        var deleted: usize = 0;
        for (ids_to_delete.items) |chunk_id| {
            if (try self.deleteVectorChunk(allocator, chunk_id, actor_id)) deleted += 1;
        }
        return deleted;
    }

    pub fn vectorSearch(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorSearchInput) ![]vector_mod.VectorMatch {
        const query = try vector_mod.embeddingFromJson(allocator, input.embedding_json);
        defer allocator.free(query);
        if (query.len == 0) return allocator.alloc(vector_mod.VectorMatch, 0);
        {
            const candidate_limit = pgSearchCandidateLimit(input.limit, 20, 5000);
            const dimensions_text = try std.fmt.allocPrint(allocator, "{d}", .{query.len});
            defer allocator.free(dimensions_text);
            const candidate_limit_text = try std.fmt.allocPrint(allocator, "{d}", .{candidate_limit});
            defer allocator.free(candidate_limit_text);
            const ma_visible = try pgRecordVisibleSql(allocator, "ma.scope", "ma.permissions_json", input.scopes_json, input.actor_id);
            const source_visible = try pgRecordVisibleSql(allocator, "src.scope", "src.permissions_json", input.scopes_json, input.actor_id);
            const artifact_visible = try pgRecordVisibleSql(allocator, "art.scope", "art.permissions_json", input.scopes_json, input.actor_id);
            const entity_visible = try pgRecordVisibleSql(allocator, "ent.scope", "ent.permissions_json", input.scopes_json, input.actor_id);
            const relation_visible = try pgRecordVisibleSql(allocator, "rel.scope", "rel.permissions_json", input.scopes_json, input.actor_id);
            const relation_from_visible = try pgRecordVisibleSql(allocator, "rel_from.scope", "rel_from.permissions_json", input.scopes_json, input.actor_id);
            const relation_to_visible = try pgRecordVisibleSql(allocator, "rel_to.scope", "rel_to.permissions_json", input.scopes_json, input.actor_id);
            const agent_memory_visible = try pgRecordVisibleSql(allocator, "ami.scope", "ami.permissions_json", input.scopes_json, input.actor_id);
            const agent_memory_prefilter = try std.fmt.allocPrint(allocator, "(({s}) OR ($2::text IS NOT NULL AND ami.actor_id = $2))", .{agent_memory_visible});
            const space_visible = try pgRecordVisibleSql(allocator, "sp.scope", "sp.permissions_json", input.scopes_json, input.actor_id);
            const policy_visible = try pgRecordVisibleSql(allocator, "ps.scope", "ps.permissions_json", input.scopes_json, input.actor_id);
            const context_actor_filter = "(cp.actor_isolated = false OR ($2::text IS NOT NULL AND cp.actor_id = $2))";
            const ma_status_filter = if (input.include_deprecated) "" else " AND ma.status NOT IN ('rejected','deprecated','superseded')";
            const artifact_status_filter = if (input.include_deprecated) "" else " AND art.status NOT IN ('rejected','deprecated','superseded')";
            const relation_status_filter = if (input.include_deprecated) "" else " AND rel.status NOT IN ('rejected','deprecated','superseded')";
            const agent_status_filter = if (input.include_deprecated) "" else " AND agma.status NOT IN ('rejected','deprecated','superseded')";
            const inner = try std.fmt.allocPrint(
                allocator,
                "SELECT vc.id,vc.object_id,vc.object_type,vc.text,vc.scope,vc.permissions_json,vc.heading_path_json,vc.start_byte,vc.end_byte,vc.content_hash,vc.chunk_strategy,vc.estimated_tokens,vc.transcript_timestamp,vc.transcript_speaker,vc.embedding_json,(1 - (vc.embedding <=> $1::vector)) AS score " ++
                    "FROM vector_chunks vc " ++
                    "LEFT JOIN memory_atoms ma ON vc.object_type = 'memory_atom' AND ma.id = vc.object_id " ++
                    "LEFT JOIN sources src ON vc.object_type = 'source' AND src.id = vc.object_id " ++
                    "LEFT JOIN artifacts art ON vc.object_type = 'artifact' AND art.id = vc.object_id " ++
                    "LEFT JOIN entities ent ON vc.object_type = 'entity' AND ent.id = vc.object_id " ++
                    "LEFT JOIN relations rel ON vc.object_type = 'relation' AND rel.id = vc.object_id " ++
                    "LEFT JOIN entities rel_from ON rel_from.id = rel.from_entity_id " ++
                    "LEFT JOIN entities rel_to ON rel_to.id = rel.to_entity_id " ++
                    "LEFT JOIN context_packs cp ON vc.object_type = 'context_pack' AND cp.id = vc.object_id " ++
                    "LEFT JOIN agent_memory_items ami ON vc.object_type = 'agent_memory' AND ami.id = vc.object_id " ++
                    "LEFT JOIN memory_atoms agma ON agma.id = ami.memory_atom_id " ++
                    "LEFT JOIN spaces sp ON vc.object_type = 'space' AND sp.id = vc.object_id " ++
                    "LEFT JOIN policy_scopes ps ON vc.object_type = 'policy_scope' AND ps.scope = vc.object_id " ++
                    "WHERE vc.embedding IS NOT NULL AND vc.dimensions = $3::bigint AND ((" ++
                    "vc.object_type = 'memory_atom' AND ma.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'source' AND src.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'artifact' AND art.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'entity' AND ent.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'relation' AND rel.id IS NOT NULL{s} AND ({s}) AND rel_from.id IS NOT NULL AND ({s}) AND rel_to.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'context_pack' AND cp.id IS NOT NULL AND {s}) OR (" ++
                    "vc.object_type = 'agent_memory' AND ami.id IS NOT NULL AND agma.id IS NOT NULL{s} AND ({s})) OR (" ++
                    "vc.object_type = 'space' AND sp.id IS NOT NULL AND ({s})) OR (" ++
                    "vc.object_type = 'policy_scope' AND ps.scope IS NOT NULL AND ({s}))) " ++
                    "ORDER BY vc.embedding <=> $1::vector LIMIT $4::bigint",
                .{
                    ma_status_filter,
                    ma_visible,
                    source_visible,
                    artifact_status_filter,
                    artifact_visible,
                    entity_visible,
                    relation_status_filter,
                    relation_visible,
                    relation_from_visible,
                    relation_to_visible,
                    context_actor_filter,
                    agent_status_filter,
                    agent_memory_prefilter,
                    space_visible,
                    policy_visible,
                },
            );
            const parsed = try self.queryArrayParamsJson(allocator, inner, &.{ input.embedding_json, input.actor_id, dimensions_text, candidate_limit_text });
            defer parsed.deinit();
            var out: std.ArrayListUnmanaged(vector_mod.VectorMatch) = .empty;
            errdefer {
                vector_mod.deinitMatches(allocator, out.items);
                out.deinit(allocator);
            }
            if (parsed.value == .array) {
                for (parsed.value.array.items) |item| {
                    if (item != .object) continue;
                    const obj = item.object;
                    const scope = try dupStringField(allocator, obj, "scope", "");
                    const permissions = try rawJsonField(allocator, obj, "permissions_json", "[]");
                    defer allocator.free(permissions);
                    const object_id = try dupStringField(allocator, obj, "object_id", "");
                    const object_type = try dupStringField(allocator, obj, "object_type", "");
                    if (!try self.vectorChunkObjectVisibleForSearchInput(allocator, object_type, object_id, scope, permissions, input)) {
                        allocator.free(scope);
                        allocator.free(object_id);
                        allocator.free(object_type);
                        continue;
                    }
                    try out.append(allocator, .{
                        .id = try dupStringField(allocator, obj, "id", ""),
                        .object_id = object_id,
                        .object_type = object_type,
                        .text = try dupStringField(allocator, obj, "text", ""),
                        .scope = scope,
                        .heading_path_json = try rawJsonField(allocator, obj, "heading_path_json", "[]"),
                        .start_byte = json.intField(obj, "start_byte") orelse 0,
                        .end_byte = json.intField(obj, "end_byte") orelse 0,
                        .content_hash = try dupStringField(allocator, obj, "content_hash", ""),
                        .chunk_strategy = try dupStringField(allocator, obj, "chunk_strategy", "plain"),
                        .estimated_tokens = json.intField(obj, "estimated_tokens") orelse 0,
                        .transcript_timestamp = try dupNullableStringField(allocator, obj, "transcript_timestamp"),
                        .transcript_speaker = try dupNullableStringField(allocator, obj, "transcript_speaker"),
                        .score = @floatCast(json.floatField(obj, "score") orelse 0),
                    });
                    if (out.items.len >= vectorSearchResultLimit(input.limit)) break;
                }
            }
            const matches = try out.toOwnedSlice(allocator);
            return filterVectorMatchesByMinScore(allocator, matches, input);
        }
    }

    pub fn vectorSearchCandidates(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorSearchInput, candidates: []const vector_runtime.Candidate) ![]vector_mod.VectorMatch {
        var out: std.ArrayListUnmanaged(vector_mod.VectorMatch) = .empty;
        errdefer {
            vector_mod.deinitMatches(allocator, out.items);
            out.deinit(allocator);
        }
        const capped = vectorSearchResultLimit(input.limit);
        for (candidates) |candidate| {
            var chunk = (try self.getVectorChunk(allocator, candidate.vector_id)) orelse continue;
            defer deinitVectorChunk(allocator, &chunk);
            if (!try self.vectorChunkObjectVisibleForSearchInput(allocator, chunk.object_type, chunk.object_id, chunk.scope, chunk.permissions_json, input)) continue;
            if (!vectorScoreAllowedByMinScore(candidate.score, input)) continue;
            try out.append(allocator, try vectorMatchFromChunk(allocator, chunk, candidate.score));
            if (out.items.len >= capped) break;
        }
        return out.toOwnedSlice(allocator);
    }

    fn vectorChunkObjectVisibleForSearchInput(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, chunk_scope: []const u8, chunk_permissions: []const u8, input: VectorSearchInput) !bool {
        if (!try self.vectorChunkObjectVisible(allocator, object_type, object_id, chunk_scope, chunk_permissions, input.scopes_json, input.actor_id, input.include_deprecated)) return false;
        if (!std.mem.eql(u8, object_type, "agent_memory")) return true;
        var entry = (try self.agentMemoryById(allocator, object_id)) orelse return false;
        defer agent_memory_runtime.freeAgentMemory(allocator, &entry);
        return agentMemorySessionAllowedForSearch(input.session_id, input.include_sessions, entry.session_id);
    }

    fn vectorChunkObjectVisible(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, chunk_scope: []const u8, chunk_permissions: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        _ = chunk_scope;
        _ = chunk_permissions;
        if (std.mem.eql(u8, object_type, "memory_atom")) {
            var atom = (try self.getMemoryAtom(allocator, object_id)) orelse return false;
            defer deinitMemoryAtom(allocator, &atom);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(atom.status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, atom.scope, atom.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "source")) {
            var source = (try self.getSource(allocator, object_id)) orelse return false;
            defer deinitSource(allocator, &source);
            const status = try self.primitiveLifecycleStatus(allocator, "source", source.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, source.scope, source.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "artifact")) {
            var artifact = (try self.getArtifact(allocator, object_id)) orelse return false;
            defer deinitArtifact(allocator, &artifact);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(artifact.status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, artifact.scope, artifact.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            var entity = (try self.getEntity(allocator, object_id)) orelse return false;
            defer deinitEntity(allocator, &entity);
            const status = try self.primitiveLifecycleStatus(allocator, "entity", entity.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, entity.scope, entity.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "relation")) {
            return try self.vectorRelationVisible(allocator, object_id, scopes_json, actor_id, include_deprecated);
        }
        if (std.mem.eql(u8, object_type, "context_pack")) {
            return try self.vectorContextPackVisible(allocator, object_id, scopes_json, actor_id, include_deprecated);
        }
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            const status = (try self.agentMemoryStatusById(allocator, object_id)) orelse return false;
            defer allocator.free(status);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            var entry = (try self.agentMemoryById(allocator, object_id)) orelse return false;
            defer agent_memory_runtime.freeAgentMemory(allocator, &entry);
            return try self.agentMemoryResultVisible(allocator, entry.actor_id, entry.scope, entry.permissions_json, entry.session_id, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "space")) {
            var space = (try self.getSpace(allocator, object_id)) orelse return false;
            defer deinitSpace(allocator, &space);
            const status = try self.primitiveLifecycleStatus(allocator, "space", space.id);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, space.scope, space.permissions_json, scopes_json, actor_id);
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            var policy = (try self.getPolicyScope(allocator, object_id)) orelse return false;
            defer deinitPolicyScope(allocator, &policy);
            const status = try self.primitiveLifecycleStatus(allocator, "policy_scope", policy.scope);
            if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
            return try self.recordVisibleWithPolicyForActor(allocator, policy.scope, policy.permissions_json, scopes_json, actor_id);
        }
        return false;
    }

    fn vectorBackingObjectExists(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8) !bool {
        if (std.mem.eql(u8, object_type, "memory_atom")) {
            var atom = (try self.getMemoryAtom(allocator, object_id)) orelse return false;
            defer deinitMemoryAtom(allocator, &atom);
            return true;
        }
        if (std.mem.eql(u8, object_type, "source")) {
            var source = (try self.getSource(allocator, object_id)) orelse return false;
            defer deinitSource(allocator, &source);
            return true;
        }
        if (std.mem.eql(u8, object_type, "artifact")) {
            var artifact = (try self.getArtifact(allocator, object_id)) orelse return false;
            defer deinitArtifact(allocator, &artifact);
            return true;
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            var entity = (try self.getEntity(allocator, object_id)) orelse return false;
            defer deinitEntity(allocator, &entity);
            return true;
        }
        if (std.mem.eql(u8, object_type, "relation")) {
            var relation = (try self.getRelation(allocator, object_id)) orelse return false;
            defer deinitRelation(allocator, &relation);
            var from_entity = (try self.getEntity(allocator, relation.from_entity_id)) orelse return false;
            defer deinitEntity(allocator, &from_entity);
            var to_entity = (try self.getEntity(allocator, relation.to_entity_id)) orelse return false;
            defer deinitEntity(allocator, &to_entity);
            return true;
        }
        if (std.mem.eql(u8, object_type, "context_pack")) return try self.contextPackExists(allocator, object_id);
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            var entry = (try self.agentMemoryById(allocator, object_id)) orelse return false;
            defer agent_memory_runtime.freeAgentMemory(allocator, &entry);
            return true;
        }
        if (std.mem.eql(u8, object_type, "space")) {
            var space = (try self.getSpace(allocator, object_id)) orelse return false;
            defer deinitSpace(allocator, &space);
            return true;
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            var policy = (try self.getPolicyScope(allocator, object_id)) orelse return false;
            defer deinitPolicyScope(allocator, &policy);
            return true;
        }
        return false;
    }

    pub fn vectorObjectAcl(self: *PostgresStore, allocator: std.mem.Allocator, object_type: []const u8, object_id: []const u8, actor_id: ?[]const u8) !?VectorObjectAcl {
        if (std.mem.eql(u8, object_type, "memory_atom")) {
            var atom = (try self.getMemoryAtom(allocator, object_id)) orelse return null;
            defer deinitMemoryAtom(allocator, &atom);
            return try copyVectorObjectAcl(allocator, atom.scope, atom.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "source")) {
            var source = (try self.getSource(allocator, object_id)) orelse return null;
            defer deinitSource(allocator, &source);
            return try copyVectorObjectAcl(allocator, source.scope, source.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "artifact")) {
            var artifact = (try self.getArtifact(allocator, object_id)) orelse return null;
            defer deinitArtifact(allocator, &artifact);
            return try copyVectorObjectAcl(allocator, artifact.scope, artifact.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "entity")) {
            var entity = (try self.getEntity(allocator, object_id)) orelse return null;
            defer deinitEntity(allocator, &entity);
            return try copyVectorObjectAcl(allocator, entity.scope, entity.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "relation")) {
            var relation = (try self.getRelation(allocator, object_id)) orelse return null;
            defer deinitRelation(allocator, &relation);
            return try copyVectorObjectAcl(allocator, relation.scope, relation.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "context_pack")) {
            return try self.vectorContextPackAcl(allocator, object_id, actor_id);
        }
        if (std.mem.eql(u8, object_type, "agent_memory")) {
            var entry = (try self.agentMemoryById(allocator, object_id)) orelse return null;
            defer agent_memory_runtime.freeAgentMemory(allocator, &entry);
            return try copyVectorObjectAcl(allocator, entry.scope, entry.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "space")) {
            var space = (try self.getSpace(allocator, object_id)) orelse return null;
            defer deinitSpace(allocator, &space);
            return try copyVectorObjectAcl(allocator, space.scope, space.permissions_json);
        }
        if (std.mem.eql(u8, object_type, "policy_scope")) {
            var policy = (try self.getPolicyScope(allocator, object_id)) orelse return null;
            defer deinitPolicyScope(allocator, &policy);
            return try copyVectorObjectAcl(allocator, policy.scope, policy.permissions_json);
        }
        return null;
    }

    fn vectorRelationVisible(self: *PostgresStore, allocator: std.mem.Allocator, relation_id: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        var relation = (try self.getRelation(allocator, relation_id)) orelse return false;
        defer deinitRelation(allocator, &relation);
        if (!include_deprecated and !domain.isDefaultVisibleStatus(relation.status)) return false;
        if (!try self.recordVisibleWithPolicyForActor(allocator, relation.scope, relation.permissions_json, scopes_json, actor_id)) return false;
        var from_entity = (try self.getEntity(allocator, relation.from_entity_id)) orelse return false;
        defer deinitEntity(allocator, &from_entity);
        if (!try self.recordVisibleWithPolicyForActor(allocator, from_entity.scope, from_entity.permissions_json, scopes_json, actor_id)) return false;
        var to_entity = (try self.getEntity(allocator, relation.to_entity_id)) orelse return false;
        defer deinitEntity(allocator, &to_entity);
        if (!try self.recordVisibleWithPolicyForActor(allocator, to_entity.scope, to_entity.permissions_json, scopes_json, actor_id)) return false;
        return true;
    }

    fn vectorContextPackAcl(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, actor_id: ?[]const u8) !?VectorObjectAcl {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        const obj = parsed.value.object;
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[]");
        defer allocator.free(required_scopes);
        const row_actor = try dupNullableStringField(allocator, obj, "actor_id");
        defer if (row_actor) |value| allocator.free(value);
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (actor_isolated) {
            const actor = actor_id orelse return null;
            if (!actorMatches(actor_id, row_actor)) return null;
            const scope = try domain.defaultAgentMemoryScope(allocator, actor);
            errdefer allocator.free(scope);
            const permissions = try domain.actorGrantJson(allocator, actor);
            return .{ .scope = scope, .permissions_json = permissions };
        }
        return try vectorObjectAclFromRequiredAccessJson(allocator, required_scopes);
    }

    fn vectorContextPackVisible(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8, scopes_json: []const u8, actor_id: ?[]const u8, include_deprecated: bool) !bool {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated FROM context_packs WHERE id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return false;
        const obj = parsed.value.object;
        const source_ids = try rawJsonField(allocator, obj, "included_sources_json", "[]");
        defer allocator.free(source_ids);
        const artifact_ids = try rawJsonField(allocator, obj, "included_artifacts_json", "[]");
        defer allocator.free(artifact_ids);
        const atom_ids = try rawJsonField(allocator, obj, "included_memory_atoms_json", "[]");
        defer allocator.free(atom_ids);
        const result_refs = try rawJsonField(allocator, obj, "included_result_refs_json", "[]");
        defer allocator.free(result_refs);
        const required_scopes = try rawJsonField(allocator, obj, "required_scopes_json", "[]");
        defer allocator.free(required_scopes);
        const row_actor = try dupNullableStringField(allocator, obj, "actor_id");
        defer if (row_actor) |value| allocator.free(value);
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        if (!try self.contextPackVisible(allocator, source_ids, artifact_ids, atom_ids, result_refs, required_scopes, row_actor, actor_isolated, scopes_json, actor_id, include_deprecated)) return false;
        const status = try self.primitiveLifecycleStatus(allocator, "context_pack", id);
        if (!include_deprecated and !domain.isDefaultVisibleStatus(status)) return false;
        return true;
    }

    fn agentMemoryById(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?domain.AgentMemory {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json,ma.confidence AS score,ma.status " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id WHERE ami.id = $1 LIMIT 1",
            &.{id},
        );
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        return try readPgAgentMemory(allocator, parsed.value.object);
    }

    fn agentMemoryStatusById(self: *PostgresStore, allocator: std.mem.Allocator, id: []const u8) !?[]u8 {
        const text = try self.queryParamsText(
            allocator,
            "SELECT coalesce((SELECT ma.status FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id WHERE ami.id = $1 LIMIT 1), '')",
            &.{id},
        );
        if (text.len == 0) {
            allocator.free(text);
            return null;
        }
        return text;
    }

    pub fn enqueueVectorOutbox(self: *PostgresStore, input: VectorOutboxInput) !i64 {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const text = try self.queryParamsText(
            allocator,
            "INSERT INTO vector_outbox (action,object_type,object_id,status,attempts,payload_json,created_at_ms,updated_at_ms) VALUES ($1,$2,$3,$4,0,$5::jsonb,$6::bigint,$7::bigint) RETURNING id::text",
            &.{ input.action, input.object_type, input.object_id, input.status, input.payload_json, now_text, now_text },
        );
        const id = std.fmt.parseInt(i64, text, 10) catch 0;
        if (id > 0) try self.insertAudit(self.allocator, "vector_outbox.enqueued", null, "vector_outbox", input.object_id);
        return id;
    }

    pub fn listVectorOutbox(self: *PostgresStore, allocator: std.mem.Allocator, input: VectorOutboxListInput) ![]VectorOutboxEntry {
        try self.reclaimExpiredVectorOutbox(allocator);
        const capped = @max(@as(usize, 1), @min(input.limit, 1000));
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{capped});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,action,object_type,object_id,status,attempts,payload_json,created_at_ms,updated_at_ms,locked_until_ms,worker_id FROM vector_outbox " ++
                "WHERE ($1::text IS NULL OR action = $1) AND ($2::text IS NULL OR status = $2) ORDER BY id LIMIT $3::bigint",
            &.{ input.action, input.status, limit_text },
        );
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(VectorOutboxEntry) = .empty;
        errdefer {
            for (out.items) |*entry| freeVectorOutboxEntry(allocator, entry);
            out.deinit(allocator);
        }
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                try out.ensureUnusedCapacity(allocator, 1);
                out.appendAssumeCapacity(try readPgVectorOutboxEntry(allocator, item.object));
            }
        }
        return out.toOwnedSlice(allocator);
    }

    fn reclaimExpiredVectorOutbox(self: *PostgresStore, allocator: std.mem.Allocator) !void {
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "UPDATE vector_outbox SET status = 'pending', locked_until_ms = NULL, worker_id = NULL, updated_at_ms = $1::bigint WHERE status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $2::bigint",
            &.{ now_text, now_text },
        );
    }

    pub fn claimVectorOutbox(self: *PostgresStore, id: i64) !bool {
        return self.claimVectorOutboxAs(id, default_vector_outbox_worker_id);
    }

    pub fn claimVectorOutboxAs(self: *PostgresStore, id: i64, worker_id: []const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = ids.nowMs();
        const locked_until = try std.fmt.allocPrint(allocator, "{d}", .{time_math.deadlineMs(now, default_vector_outbox_lease_ms)});
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const id_text = try std.fmt.allocPrint(allocator, "{d}", .{id});
        const claim_worker_id = effectiveWorkerId(worker_id, default_vector_outbox_worker_id);
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (UPDATE vector_outbox SET status = 'running', attempts = attempts + 1, locked_until_ms = $1::bigint, worker_id = $2, updated_at_ms = $3::bigint WHERE id = $4::bigint AND (status = 'pending' OR (status = 'running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $5::bigint)) RETURNING 1) SELECT count(*)::text FROM updated",
            &.{ locked_until, claim_worker_id, now_text, id_text, now_text },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    pub fn heartbeatVectorOutboxAs(self: *PostgresStore, id: i64, worker_id: []const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
