            allocator,
            "WITH updated AS (UPDATE vector_outbox SET locked_until_ms = $1::bigint, updated_at_ms = $2::bigint WHERE id = $3::bigint AND status = 'running' AND worker_id = $4 RETURNING 1) SELECT count(*)::text FROM updated",
            &.{ locked_until, now_text, id_text, claim_worker_id },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
