    pub fn createLifecycleSnapshot(self: *PostgresStore, allocator: std.mem.Allocator, snapshot_type: []const u8, summary_json: []const u8) !LifecycleSnapshot {
        const id = try ids.make(allocator, "snap_");
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        try self.runParams(
            allocator,
            "WITH inserted AS (" ++
                "INSERT INTO lifecycle_snapshots (id,snapshot_type,summary_json,created_at_ms) VALUES ($1,$2,$3::jsonb,$4::bigint) RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'lifecycle.snapshot',NULL,'lifecycle_snapshot',id,'{}'::jsonb,$4::bigint FROM inserted RETURNING 1" ++
                ") SELECT 1",
            &.{ id, snapshot_type, summary_json, now_text },
        );
        return .{ .id = id, .snapshot_type = snapshot_type, .summary_json = summary_json, .created_at_ms = now };
    }

    pub fn lifecycleDiagnostics(self: *PostgresStore) !LifecycleDiagnostics {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()});
        const sql =
            "SELECT json_build_object(" ++
            "'total_memory_atoms',(SELECT count(*) FROM memory_atoms)," ++
            "'stale_memory_atoms',(SELECT count(*) FROM memory_atoms WHERE status='stale')," ++
            "'vector_outbox_pending',(SELECT count(*) FROM vector_outbox WHERE status='pending')," ++
            "'vector_outbox_running',(SELECT count(*) FROM vector_outbox WHERE status='running')," ++
            "'vector_outbox_failed',(SELECT count(*) FROM vector_outbox WHERE status IN ('failed_embedding','failed_external_index','failed_external_delete'))," ++
            "'vector_outbox_expired_running',(SELECT count(*) FROM vector_outbox WHERE status='running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $1::bigint)," ++
            "'lucid_projection_pending',(SELECT count(*) FROM jobs WHERE job_type='lucid_projection' AND (status='queued' OR status='running'))," ++
            "'lucid_projection_failed',(SELECT count(*) FROM jobs WHERE job_type='lucid_projection' AND status='failed')," ++
            "'graph_projection_pending',(SELECT count(*) FROM jobs WHERE job_type='graph_projection' AND (status='queued' OR status='running'))," ++
            "'graph_projection_failed',(SELECT count(*) FROM jobs WHERE job_type='graph_projection' AND status='failed')," ++
            "'response_cache_entries',(SELECT count(*) FROM response_cache)," ++
            "'semantic_cache_entries',(SELECT count(*) FROM semantic_cache)," ++
            "'embedding_cache_entries',(SELECT count(*) FROM embedding_cache)," ++
            "'expired_response_cache_entries',(SELECT count(*) FROM response_cache WHERE expires_at_ms > 0 AND expires_at_ms <= $1::bigint)," ++
            "'expired_semantic_cache_entries',(SELECT count(*) FROM semantic_cache WHERE expires_at_ms > 0 AND expires_at_ms <= $1::bigint)," ++
            "'cache_entries',(SELECT count(*) FROM response_cache)+(SELECT count(*) FROM semantic_cache)+(SELECT count(*) FROM embedding_cache)," ++
            "'queued_jobs',(SELECT count(*) FROM jobs WHERE status='queued')," ++
            "'running_jobs',(SELECT count(*) FROM jobs WHERE status='running')," ++
            "'failed_jobs',(SELECT count(*) FROM jobs WHERE status='failed')," ++
            "'expired_running_jobs',(SELECT count(*) FROM jobs WHERE status='running' AND locked_until_ms IS NOT NULL AND locked_until_ms <= $1::bigint)," ++
            "'pending_feed_events',(SELECT count(*) FROM memory_feed_events WHERE status='pending')," ++
            "'applying_feed_events',(SELECT count(*) FROM memory_feed_events WHERE status='applying')," ++
            "'open_conflicts',(SELECT count(*) FROM knowledge_conflicts WHERE status='open')," ++
            "'agent_memories',(SELECT count(*) FROM agent_memory_items)," ++
            "'memory_recall_signals',(SELECT count(*) FROM memory_recall_signals)," ++
            "'sessions',(SELECT count(*) FROM (SELECT session_id FROM session_messages WHERE role <> '" ++ domain.runtime_command_role ++ "' GROUP BY session_id) s))::text";
        const parsed = try self.queryParamsJson(allocator, sql, &.{now_text});
        defer parsed.deinit();
        const obj = parsed.value.object;
        return .{
            .total_memory_atoms = jsonCounterField(obj, "total_memory_atoms"),
            .stale_memory_atoms = jsonCounterField(obj, "stale_memory_atoms"),
            .vector_outbox_pending = jsonCounterField(obj, "vector_outbox_pending"),
            .vector_outbox_running = jsonCounterField(obj, "vector_outbox_running"),
            .vector_outbox_failed = jsonCounterField(obj, "vector_outbox_failed"),
            .vector_outbox_expired_running = jsonCounterField(obj, "vector_outbox_expired_running"),
            .lucid_projection_pending = jsonCounterField(obj, "lucid_projection_pending"),
            .lucid_projection_failed = jsonCounterField(obj, "lucid_projection_failed"),
            .graph_projection_pending = jsonCounterField(obj, "graph_projection_pending"),
            .graph_projection_failed = jsonCounterField(obj, "graph_projection_failed"),
            .cache_entries = jsonCounterField(obj, "cache_entries"),
            .response_cache_entries = jsonCounterField(obj, "response_cache_entries"),
            .semantic_cache_entries = jsonCounterField(obj, "semantic_cache_entries"),
            .embedding_cache_entries = jsonCounterField(obj, "embedding_cache_entries"),
            .expired_response_cache_entries = jsonCounterField(obj, "expired_response_cache_entries"),
            .expired_semantic_cache_entries = jsonCounterField(obj, "expired_semantic_cache_entries"),
            .queued_jobs = jsonCounterField(obj, "queued_jobs"),
            .running_jobs = jsonCounterField(obj, "running_jobs"),
            .failed_jobs = jsonCounterField(obj, "failed_jobs"),
            .expired_running_jobs = jsonCounterField(obj, "expired_running_jobs"),
            .pending_feed_events = jsonCounterField(obj, "pending_feed_events"),
            .applying_feed_events = jsonCounterField(obj, "applying_feed_events"),
            .open_conflicts = jsonCounterField(obj, "open_conflicts"),
            .agent_memories = jsonCounterField(obj, "agent_memories"),
            .sessions = jsonCounterField(obj, "sessions"),
            .memory_recall_signals = jsonCounterField(obj, "memory_recall_signals"),
        };
    }

    pub fn recordMemoryRecallSignal(self: *PostgresStore, allocator: std.mem.Allocator, input: MemoryRecallSignalInput) !void {
        const query = std.mem.trim(u8, input.query, " \t\r\n");
        if (query.len == 0) return;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const temp = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const now_text = try std.fmt.allocPrint(temp, "{d}", .{now});
        const score = cleanRecallScore(input.score);
        const score_text = try std.fmt.allocPrint(temp, "{d}", .{score});
        const query_hash = digest.sha256PartsHex(&.{query});
        const query_sample = query[0..@min(query.len, 512)];
        try self.runParams(
            temp,
            "INSERT INTO memory_recall_signals (object_type,object_id,object_key,scope,permissions_json,actor_id,session_id,store,query_hash,query_sample,first_recalled_at_ms,last_recalled_at_ms,recall_count,max_score,total_score) " ++
                "VALUES ($1,$2,$3,$4,$5::jsonb,$6,$7,$8,$9,$10,$11::bigint,$11::bigint,1,$12::double precision,$12::double precision) " ++
                "ON CONFLICT(object_type, object_id, actor_id, session_id, store, query_hash) DO UPDATE SET " ++
                "object_key=EXCLUDED.object_key, scope=EXCLUDED.scope, permissions_json=EXCLUDED.permissions_json, query_sample=CASE WHEN memory_recall_signals.query_sample = '' THEN EXCLUDED.query_sample ELSE memory_recall_signals.query_sample END, last_recalled_at_ms=EXCLUDED.last_recalled_at_ms, recall_count=memory_recall_signals.recall_count + 1, max_score=GREATEST(memory_recall_signals.max_score, EXCLUDED.max_score), total_score=memory_recall_signals.total_score + EXCLUDED.total_score",
            &.{ input.object_type, input.object_id, input.object_key, input.scope, input.permissions_json, input.actor_id orelse "", input.session_id orelse "", input.store orelse "", query_hash[0..], query_sample, now_text, score_text },
        );
    }

    pub fn listMemoryRecallCandidates(self: *PostgresStore, allocator: std.mem.Allocator, input: MemoryRecallCandidateQuery) ![]MemoryRecallCandidate {
        const capped = memoryRecallCandidateLimit(input.limit);
        const fetch_limit = memoryRecallCandidateFetchLimit(capped);
        const min_recall_count = try std.fmt.allocPrint(allocator, "{d}", .{input.min_recall_count});
        defer allocator.free(min_recall_count);
        const min_unique_queries = try std.fmt.allocPrint(allocator, "{d}", .{input.min_unique_queries});
        defer allocator.free(min_unique_queries);
        const min_score = try std.fmt.allocPrint(allocator, "{d}", .{input.min_score});
        defer allocator.free(min_score);
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{fetch_limit});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT object_type,object_id,object_key,scope,permissions_json,actor_id,session_id,store,SUM(recall_count)::bigint AS recall_count,COUNT(*)::bigint AS unique_queries,MAX(max_score)::double precision AS max_score,CASE WHEN SUM(recall_count) > 0 THEN SUM(total_score) / SUM(recall_count) ELSE 0 END AS avg_score,MIN(first_recalled_at_ms)::bigint AS first_recalled_at_ms,MAX(last_recalled_at_ms)::bigint AS last_recalled_at_ms " ++
                "FROM memory_recall_signals GROUP BY object_type,object_id,object_key,scope,permissions_json,actor_id,session_id,store " ++
                "HAVING SUM(recall_count) >= $1::bigint AND COUNT(*) >= $2::bigint AND MAX(max_score) >= $3::double precision " ++
                "ORDER BY SUM(recall_count) DESC, COUNT(*) DESC, MAX(last_recalled_at_ms) DESC LIMIT $4::bigint",
            &.{ min_recall_count, min_unique_queries, min_score, limit_text },
        );
        defer parsed.deinit();

        var out: std.ArrayListUnmanaged(MemoryRecallCandidate) = .empty;
        errdefer {
            for (out.items) |*candidate| freeMemoryRecallCandidate(allocator, candidate);
            out.deinit(allocator);
        }
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const obj = item.object;
            var candidate = MemoryRecallCandidate{
                .object_type = try dupStringField(allocator, obj, "object_type", ""),
                .object_id = try dupStringField(allocator, obj, "object_id", ""),
                .object_key = try dupStringField(allocator, obj, "object_key", ""),
                .scope = try dupStringField(allocator, obj, "scope", "workspace"),
                .permissions_json = try rawJsonField(allocator, obj, "permissions_json", "[]"),
                .actor_id = try dupStringField(allocator, obj, "actor_id", ""),
                .session_id = try dupStringField(allocator, obj, "session_id", ""),
                .store = try dupStringField(allocator, obj, "store", ""),
                .recall_count = jsonCounterField(obj, "recall_count"),
                .unique_queries = jsonCounterField(obj, "unique_queries"),
                .max_score = json.floatField(obj, "max_score") orelse 0,
                .avg_score = json.floatField(obj, "avg_score") orelse 0,
                .first_recalled_at_ms = json.intField(obj, "first_recalled_at_ms") orelse 0,
                .last_recalled_at_ms = json.intField(obj, "last_recalled_at_ms") orelse 0,
                .promotion_score = 0,
            };
            var kept = false;
            defer if (!kept) freeMemoryRecallCandidate(allocator, &candidate);
            if (!memoryRecallCandidateVisible(allocator, candidate, input.scopes_json, input.actor_id)) continue;
            candidate.promotion_score = recallPromotionScore(candidate);
            try out.append(allocator, candidate);
            kept = true;
            if (out.items.len >= capped) break;
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn countMemoryRecallSignalRows(self: *PostgresStore) !usize {
        const text = try self.queryText(self.allocator, "SELECT count(*)::text FROM memory_recall_signals");
        defer self.allocator.free(text);
        return std.fmt.parseInt(usize, text, 10) catch 0;
    }

    pub fn putResponseCache(self: *PostgresStore, input: ResponseCacheInput) !void {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const expires = cache_time.expiresAtMs(now, input.ttl_ms);
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const expires_text = try std.fmt.allocPrint(allocator, "{d}", .{expires});
        const token_text = try std.fmt.allocPrint(allocator, "{d}", .{@max(input.token_count, 0)});
        _ = try self.queryParamsText(
            allocator,
            "WITH upserted AS (" ++
                "INSERT INTO response_cache (cache_key,response_json,scopes_json,actor_id,created_at_ms,accessed_at_ms,expires_at_ms,hit_count,token_count) VALUES ($1,$2::jsonb,$3::jsonb,$4,$5::bigint,$5::bigint,$6::bigint,0,$7::bigint) " ++
                "ON CONFLICT(actor_id,cache_key) DO UPDATE SET response_json=excluded.response_json, scopes_json=excluded.scopes_json, created_at_ms=excluded.created_at_ms, accessed_at_ms=excluded.accessed_at_ms, expires_at_ms=excluded.expires_at_ms, hit_count=0, token_count=excluded.token_count RETURNING cache_key" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.response.put',$4,'response_cache',cache_key,'{}'::jsonb,$5::bigint FROM upserted RETURNING 1" ++
                ") SELECT count(*)::text FROM upserted",
            &.{ input.cache_key, input.response_json, input.scopes_json, input.actor_id, now_text, expires_text, token_text },
        );
        try self.evictResponseCacheLru(input.actor_id, input.max_entries);
    }

    pub fn getResponseCache(self: *PostgresStore, allocator: std.mem.Allocator, cache_key: []const u8, now_ms: i64, scopes_json: []const u8, actor_id: []const u8) !?ResponseCacheEntry {
        const inner = "SELECT cache_key,response_json,created_at_ms,accessed_at_ms,expires_at_ms,scopes_json,actor_id,hit_count,token_count FROM response_cache WHERE cache_key = $1 AND actor_id = $2 LIMIT 1";
        const parsed = try self.queryRowParamsJson(allocator, inner, &.{ cache_key, actor_id });
        defer parsed.deinit();
        if (parsed.value == .null) return null;
        const obj = parsed.value.object;
        const expires = json.intField(obj, "expires_at_ms") orelse 0;
        if (expires > 0 and expires <= now_ms) {
            try self.runParams(allocator, "DELETE FROM response_cache WHERE cache_key = $1 AND actor_id = $2", &.{ cache_key, actor_id });
            return null;
        }
        const entry_scopes = try rawJsonField(allocator, obj, "scopes_json", "[]");
        if (!domain.scopeListVisible(entry_scopes, scopes_json)) return null;
        const entry_actor = try dupStringField(allocator, obj, "actor_id", "");
        if (!cacheActorVisible(actor_id, entry_actor)) return null;
        try self.touchResponseCache(cache_key, actor_id, now_ms);
        return .{ .cache_key = try dupStringField(allocator, obj, "cache_key", ""), .response_json = try rawJsonField(allocator, obj, "response_json", "{}"), .scopes_json = entry_scopes, .actor_id = entry_actor, .created_at_ms = json.intField(obj, "created_at_ms") orelse 0, .accessed_at_ms = now_ms, .expires_at_ms = expires, .hit_count = (json.intField(obj, "hit_count") orelse 0) + 1, .token_count = json.intField(obj, "token_count") orelse 0 };
    }

    pub fn responseCacheStats(self: *PostgresStore, input: CacheStatsInput) !CacheEntryStats {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT count(*)::bigint AS entries, count(*) FILTER (WHERE expires_at_ms > 0 AND expires_at_ms <= $2::bigint)::bigint AS expired_entries, COALESCE(SUM(hit_count),0)::bigint AS hits, COALESCE(SUM(hit_count * token_count),0)::bigint AS tokens_saved FROM response_cache WHERE actor_id = $1",
            &.{ input.actor_id, now_text },
        );
        defer parsed.deinit();
        if (parsed.value != .object) return .{};
        const obj = parsed.value.object;
        return .{
            .entries = jsonCounterField(obj, "entries"),
            .expired_entries = jsonCounterField(obj, "expired_entries"),
            .hits = json.intField(obj, "hits") orelse 0,
            .tokens_saved = json.intField(obj, "tokens_saved") orelse 0,
        };
    }

    fn touchResponseCache(self: *PostgresStore, cache_key: []const u8, actor_id: []const u8, now_ms: i64) !void {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now_ms});
        try self.runParams(allocator, "UPDATE response_cache SET accessed_at_ms = $3::bigint, hit_count = hit_count + 1 WHERE cache_key = $1 AND actor_id = $2", &.{ cache_key, actor_id, now_text });
    }

    fn evictResponseCacheLru(self: *PostgresStore, actor_id: []const u8, max_entries: usize) !void {
        if (max_entries == 0) return;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const max_text = try std.fmt.allocPrint(allocator, "{d}", .{max_entries});
        _ = try self.queryParamsText(
            allocator,
            "WITH ranked AS (SELECT cache_key, row_number() OVER (ORDER BY accessed_at_ms DESC, created_at_ms DESC, cache_key DESC) AS rn FROM response_cache WHERE actor_id = $1), deleted AS (DELETE FROM response_cache rc USING ranked r WHERE rc.actor_id = $1 AND rc.cache_key = r.cache_key AND r.rn > $2::bigint RETURNING 1) SELECT count(*)::text FROM deleted",
            &.{ actor_id, max_text },
        );
    }

    pub fn clearResponseCache(self: *PostgresStore, input: CacheClearInput) !usize {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const now_param: []const u8 = now_text;
        const object_id = input.cache_key orelse input.actor_id;
        const sql = if (input.cache_key != null)
            if (input.expired_only)
                "WITH deleted AS (DELETE FROM response_cache WHERE actor_id = $1 AND cache_key = $2 AND expires_at_ms > 0 AND expires_at_ms <= $3::bigint RETURNING 1), audit AS (INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.response.clear',$1,'response_cache',$2,'{}'::jsonb,$3::bigint WHERE EXISTS (SELECT 1 FROM deleted) RETURNING 1) SELECT count(*)::text FROM deleted"
            else
                "WITH deleted AS (DELETE FROM response_cache WHERE actor_id = $1 AND cache_key = $2 RETURNING 1), audit AS (INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.response.clear',$1,'response_cache',$2,'{}'::jsonb,$3::bigint WHERE EXISTS (SELECT 1 FROM deleted) RETURNING 1) SELECT count(*)::text FROM deleted"
        else if (input.expired_only)
            "WITH deleted AS (DELETE FROM response_cache WHERE actor_id = $1 AND expires_at_ms > 0 AND expires_at_ms <= $2::bigint RETURNING 1), audit AS (INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.response.clear',$1,'response_cache',$3,'{}'::jsonb,$2::bigint WHERE EXISTS (SELECT 1 FROM deleted) RETURNING 1) SELECT count(*)::text FROM deleted"
        else
            "WITH deleted AS (DELETE FROM response_cache WHERE actor_id = $1 RETURNING 1), audit AS (INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.response.clear',$1,'response_cache',$2,'{}'::jsonb,$3::bigint WHERE EXISTS (SELECT 1 FROM deleted) RETURNING 1) SELECT count(*)::text FROM deleted";
        const params = if (input.cache_key) |cache_key|
            &.{ input.actor_id, cache_key, now_param }
        else if (input.expired_only)
            &.{ input.actor_id, now_param, object_id }
        else
            &.{ input.actor_id, object_id, now_param };
        const text = try self.queryParamsText(allocator, sql, params);
        return std.fmt.parseInt(usize, std.mem.trim(u8, text, " \t\r\n"), 10) catch 0;
    }

    pub fn responseCacheRevision(self: *PostgresStore, allocator: std.mem.Allocator) ![]u8 {
        const text = try self.queryText(allocator,
            \\WITH revision_values(v) AS (
            \\  SELECT COALESCE(MAX(imported_at_ms), 0) FROM sources
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM artifacts
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM entities
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM memory_atoms
            \\  UNION ALL SELECT COALESCE(MAX(last_verified_at_ms), 0) FROM memory_atoms
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM relations
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM spaces
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM policy_scopes
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM context_packs
            \\  UNION ALL SELECT COALESCE(MAX(timestamp_ms), 0) FROM agent_memory_items
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM session_messages
            \\  UNION ALL SELECT COALESCE(MAX(event_timestamp_ms), 0) FROM session_messages
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM vector_chunks
            \\  UNION ALL SELECT COALESCE(MAX(updated_at_ms), 0) FROM primitive_lifecycle
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM memory_feed_events
            \\  UNION ALL SELECT COALESCE(MAX(applied_at_ms), 0) FROM memory_feed_events
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM knowledge_conflicts
            \\  UNION ALL SELECT COALESCE(MAX(resolved_at_ms), 0) FROM knowledge_conflicts
            \\  UNION ALL SELECT COALESCE(MAX(created_at_ms), 0) FROM audit_events WHERE object_type NOT IN ('response_cache','semantic_cache','embedding_cache')
            \\)
            \\SELECT concat(
            \\  'db:',
            \\  COALESCE((SELECT MAX(v) FROM revision_values), 0)::text,
            \\  ':',
            \\  COALESCE((SELECT MAX(id) FROM audit_events WHERE object_type NOT IN ('response_cache','semantic_cache','embedding_cache')), 0)::text,
            \\  ':',
            \\  COALESCE((SELECT MAX(id) FROM memory_feed_events), 0)::text
            \\)
        );
        defer allocator.free(text);
        return allocator.dupe(u8, std.mem.trim(u8, text, " \t\r\n"));
    }

    pub fn putSemanticCache(self: *PostgresStore, input: SemanticCacheInput) !void {
        const parsed_embedding = try vector_mod.embeddingFromJson(self.allocator, input.embedding_json);
        defer self.allocator.free(parsed_embedding);
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const expires = cache_time.expiresAtMs(now, input.ttl_ms);
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const expires_text = try std.fmt.allocPrint(allocator, "{d}", .{expires});
        const token_text = try std.fmt.allocPrint(allocator, "{d}", .{@max(input.token_count, 0)});
        const dimensions_text = try std.fmt.allocPrint(allocator, "{d}", .{parsed_embedding.len});
        const provider = if (input.embedding_provider.len > 0) input.embedding_provider else "provided";
        _ = try self.queryParamsText(
            allocator,
            "WITH upserted AS (" ++
                "INSERT INTO semantic_cache (cache_key,query,response_json,embedding_json,embedding_provider,embedding_model,embedding_dimensions,scopes_json,actor_id,created_at_ms,accessed_at_ms,expires_at_ms,hit_count,token_count) VALUES ($1,$2,$3::jsonb,$4::jsonb,$5,$6,$7::bigint,$8::jsonb,$9,$10::bigint,$10::bigint,$11::bigint,0,$12::bigint) " ++
                "ON CONFLICT(actor_id,cache_key) DO UPDATE SET query=excluded.query, response_json=excluded.response_json, embedding_json=excluded.embedding_json, embedding_provider=excluded.embedding_provider, embedding_model=excluded.embedding_model, embedding_dimensions=excluded.embedding_dimensions, scopes_json=excluded.scopes_json, created_at_ms=excluded.created_at_ms, accessed_at_ms=excluded.accessed_at_ms, expires_at_ms=excluded.expires_at_ms, hit_count=0, token_count=excluded.token_count RETURNING cache_key" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'cache.semantic.put',$9,'semantic_cache',cache_key,'{}'::jsonb,$10::bigint FROM upserted RETURNING 1" ++
                ") SELECT count(*)::text FROM upserted",
            &.{ input.cache_key, input.query, input.response_json, input.embedding_json, provider, input.embedding_model, dimensions_text, input.scopes_json, input.actor_id, now_text, expires_text, token_text },
        );
        try self.evictSemanticCacheLru(input.actor_id, input.max_entries);
    }

    pub fn searchSemanticCache(self: *PostgresStore, allocator: std.mem.Allocator, input: SemanticCacheSearchInput) !?SemanticCacheMatch {
        const query = try vector_mod.embeddingFromJson(allocator, input.embedding_json);
        defer allocator.free(query);
        const query_dimensions = if (input.embedding_dimensions > 0) input.embedding_dimensions else query.len;
        if (query_dimensions != query.len) return null;
        const now = input.now_ms orelse ids.nowMs();
        const provider = input.embedding_provider;
        const dimensions_text = try std.fmt.allocPrint(allocator, "{d}", .{query_dimensions});
        defer allocator.free(dimensions_text);
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{semanticCacheCandidateLimit(input.candidate_limit)});
        defer allocator.free(limit_text);
        const prefix_upper = if (input.cache_key_prefix) |prefix| try semanticCachePrefixUpperBound(allocator, prefix) else null;
        defer if (prefix_upper) |upper| allocator.free(upper);
        const parsed = if (input.cache_key_prefix) |prefix|
            try self.queryArrayParamsJson(
                allocator,
                "SELECT cache_key,query,response_json,embedding_json,created_at_ms,accessed_at_ms,expires_at_ms,scopes_json,actor_id,hit_count,token_count,embedding_provider,embedding_model,embedding_dimensions FROM semantic_cache WHERE actor_id = $1 AND ($2 = '' OR embedding_provider = $2) AND (embedding_dimensions = $3::bigint OR embedding_dimensions = 0) AND cache_key >= $4 AND cache_key < $5 ORDER BY accessed_at_ms DESC, created_at_ms DESC LIMIT $6::bigint",
                &.{ input.actor_id, provider, dimensions_text, prefix, prefix_upper orelse prefix, limit_text },
            )
        else
            try self.queryArrayParamsJson(
                allocator,
                "SELECT cache_key,query,response_json,embedding_json,created_at_ms,accessed_at_ms,expires_at_ms,scopes_json,actor_id,hit_count,token_count,embedding_provider,embedding_model,embedding_dimensions FROM semantic_cache WHERE actor_id = $1 AND ($2 = '' OR embedding_provider = $2) AND (embedding_dimensions = $3::bigint OR embedding_dimensions = 0) ORDER BY accessed_at_ms DESC, created_at_ms DESC LIMIT $4::bigint",
                &.{ input.actor_id, provider, dimensions_text, limit_text },
            );
        defer parsed.deinit();
        var best: ?SemanticCacheMatch = null;
        var best_score = input.min_score;
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const obj = item.object;
            const expires = json.intField(obj, "expires_at_ms") orelse 0;
            if (expires > 0 and expires <= now) continue;
            const stored_model = json.stringField(obj, "embedding_model") orelse "";
            if (!semanticCacheModelVisible(input.embedding_model, stored_model)) continue;
            const stored_dimensions: usize = @intCast(@max(json.intField(obj, "embedding_dimensions") orelse 0, 0));
            if (stored_dimensions != 0 and stored_dimensions != query_dimensions) continue;
            const scopes_json = try rawJsonField(allocator, obj, "scopes_json", "[]");
            if (!domain.scopeListVisible(scopes_json, input.scopes_json)) continue;
            const entry_actor = try dupStringField(allocator, obj, "actor_id", "");
            if (!cacheActorVisible(input.actor_id, entry_actor)) continue;
            const embedding_json = try rawJsonField(allocator, obj, "embedding_json", "[]");
            defer allocator.free(embedding_json);
            const embedding = vector_mod.embeddingFromJson(allocator, embedding_json) catch continue;
            defer allocator.free(embedding);
            if (embedding.len != query_dimensions) continue;
            const score = vector_mod.cosine(query, embedding);
            if (score < best_score) continue;
            best_score = score;
            best = .{ .cache_key = try dupStringField(allocator, obj, "cache_key", ""), .query = try dupStringField(allocator, obj, "query", ""), .response_json = try rawJsonField(allocator, obj, "response_json", "{}"), .embedding_provider = try dupStringField(allocator, obj, "embedding_provider", "provided"), .embedding_model = try dupStringField(allocator, obj, "embedding_model", ""), .embedding_dimensions = query_dimensions, .scopes_json = scopes_json, .actor_id = entry_actor, .score = score, .created_at_ms = json.intField(obj, "created_at_ms") orelse 0, .accessed_at_ms = now, .expires_at_ms = expires, .hit_count = (json.intField(obj, "hit_count") orelse 0) + 1, .token_count = json.intField(obj, "token_count") orelse 0 };
        };
        if (best) |hit| try self.touchSemanticCache(hit.cache_key, input.actor_id, now);
        return best;
    }

    pub fn semanticCacheStats(self: *PostgresStore, input: CacheStatsInput) !CacheEntryStats {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT count(*)::bigint AS entries, count(*) FILTER (WHERE expires_at_ms > 0 AND expires_at_ms <= $2::bigint)::bigint AS expired_entries, COALESCE(SUM(hit_count),0)::bigint AS hits, COALESCE(SUM(hit_count * token_count),0)::bigint AS tokens_saved, count(*) FILTER (WHERE embedding_json <> '[]'::jsonb)::bigint AS embedding_entries FROM semantic_cache WHERE actor_id = $1",
            &.{ input.actor_id, now_text },
        );
        defer parsed.deinit();
        if (parsed.value != .object) return .{};
        const obj = parsed.value.object;
        return .{
            .entries = jsonCounterField(obj, "entries"),
            .expired_entries = jsonCounterField(obj, "expired_entries"),
            .hits = json.intField(obj, "hits") orelse 0,
            .tokens_saved = json.intField(obj, "tokens_saved") orelse 0,
            .embedding_entries = jsonCounterField(obj, "embedding_entries"),
        };
    }

    fn touchSemanticCache(self: *PostgresStore, cache_key: []const u8, actor_id: []const u8, now_ms: i64) !void {
