    }

    fn evictSemanticCacheLru(self: *PostgresStore, actor_id: []const u8, max_entries: usize) !void {
        if (max_entries == 0) return;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
