            "WITH deleted AS (DELETE FROM embedding_cache WHERE cache_key = $1 RETURNING 1) SELECT count(*)::text FROM deleted"
        else
            "WITH deleted AS (DELETE FROM embedding_cache RETURNING 1) SELECT count(*)::text FROM deleted";
