    pub fn runHygiene(self: *PostgresStore, input: HygieneRunInput) !HygieneRunResult {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const now = input.now_ms orelse ids.nowMs();
        var result = HygieneRunResult{};
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        const expired = try self.queryParamsText(
            allocator,
            "WITH r AS (DELETE FROM response_cache WHERE expires_at_ms > 0 AND expires_at_ms <= $1::bigint RETURNING 1), " ++
                "s AS (DELETE FROM semantic_cache WHERE expires_at_ms > 0 AND expires_at_ms <= $1::bigint RETURNING 1) " ++
                "SELECT ((SELECT count(*) FROM r) + (SELECT count(*) FROM s))::text",
            &.{now_text},
        );
        result.expired_cache_entries = std.fmt.parseInt(usize, expired, 10) catch 0;

        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id,status,last_verified_at_ms,created_at_ms,scope,permissions_json,predicate,object,text FROM memory_atoms ORDER BY created_at_ms ASC LIMIT 5000", &.{});
        defer parsed.deinit();
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const obj = item.object;
            const status = json.stringField(obj, "status") orelse "proposed";
            const predicate = json.stringField(obj, "predicate") orelse "fact";
            const object = json.stringField(obj, "object") orelse "";
            const text = json.stringField(obj, "text") orelse "";
            if (std.mem.eql(u8, predicate, "agent.memory") and domain.isInternalMemoryEntryKeyOrContent(object, text)) continue;
            result.checked += 1;
            const base_seen = json.intField(obj, "last_verified_at_ms") orelse (json.intField(obj, "created_at_ms") orelse now);
            const decision = lifecycle_mod.hygieneDecision(status, base_seen, now, input.stale_after_ms, input.archive_after_ms, input.purge_after_ms);
            const id_text = json.stringField(obj, "id") orelse continue;
            const scope = json.stringField(obj, "scope") orelse "workspace";
            const permissions = try rawJsonField(allocator, obj, "permissions_json", "[]");
            switch (decision) {
                .keep => {},
                .mark_stale => {
                    if (!hygieneCanVerify(input, scope, permissions)) continue;
                    if (!std.mem.eql(u8, status, "stale") and try self.patchMemoryAtomStatusActor(id_text, "stale", false, input.actor_id)) result.marked_stale += 1;
                },
                .archive => {
                    if (!hygieneCanVerify(input, scope, permissions)) continue;
                    if (!std.mem.eql(u8, status, "deprecated") and try self.patchMemoryAtomStatusActor(id_text, "deprecated", false, input.actor_id)) result.archived += 1;
                },
                .purge => if (input.hard_delete) {
                    if (!hygieneCanDelete(input, scope, permissions)) continue;
                    if (try self.hardDeleteMemoryAtom(id_text)) result.purged += 1;
                } else {
                    if (!hygieneCanVerify(input, scope, permissions)) continue;
                    if (!std.mem.eql(u8, status, "deprecated") and try self.patchMemoryAtomStatusActor(id_text, "deprecated", false, input.actor_id)) result.archived += 1;
                },
            }
        };
        if (input.dedupe_memory_atoms) try self.runMemoryAtomDedupe(allocator, input, &result);
        if (input.dedupe_agent_memory) try self.runAgentMemoryDedupe(allocator, input, &result);
        try self.insertAudit(self.allocator, "lifecycle.hygiene", null, "memory_atom", "bulk");
        return result;
    }

    fn runMemoryAtomDedupe(self: *PostgresStore, allocator: std.mem.Allocator, input: HygieneRunInput, result: *HygieneRunResult) !void {
        const limit = @max(@as(usize, 1), @min(input.dedupe_limit, @as(usize, 20_000)));
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{limit});
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT id,status,last_verified_at_ms,created_at_ms,scope,permissions_json,predicate,object,text FROM memory_atoms WHERE status NOT IN ('rejected','deprecated','superseded') ORDER BY created_at_ms DESC LIMIT $1::bigint",
            &.{limit_text},
        );
        defer parsed.deinit();

        var winners: std.StringHashMapUnmanaged(HygieneDedupeWinner) = .{};
        defer winners.deinit(allocator);

        if (parsed.value != .array) return;
        for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const obj = item.object;
            const id_text = json.stringField(obj, "id") orelse continue;
            const status = json.stringField(obj, "status") orelse "proposed";
            const last_verified = json.intField(obj, "last_verified_at_ms");
            const created = json.intField(obj, "created_at_ms") orelse 0;
            const scope = json.stringField(obj, "scope") orelse "workspace";
            const permissions = try rawJsonField(allocator, obj, "permissions_json", "[]");
            const predicate = json.stringField(obj, "predicate") orelse "fact";
            const object = json.stringField(obj, "object") orelse "";
            const text = json.stringField(obj, "text") orelse "";
            if (std.mem.eql(u8, predicate, "agent.memory") and domain.isInternalMemoryEntryKeyOrContent(object, text)) continue;
            result.dedupe_checked += 1;
            const key = (try hygieneAtomDedupeKey(allocator, scope, permissions, predicate, object, text, input.dedupe_normalized)) orelse continue;
            const entry = try winners.getOrPut(allocator, key);
            if (!entry.found_existing) {
                entry.key_ptr.* = key;
                entry.value_ptr.* = .{
                    .id = id_text,
                    .status = status,
                    .scope = scope,
                    .permissions_json = permissions,
                    .created_at_ms = created,
                    .last_verified_at_ms = last_verified,
                };
                continue;
            }
            if (!entry.value_ptr.seen_duplicate) {
                result.dedupe_groups += 1;
                entry.value_ptr.seen_duplicate = true;
            }
            const replace_winner = hygieneShouldReplaceWinner(status, created, last_verified, entry.value_ptr.*);
            if (replace_winner) {
                const duplicate = entry.value_ptr.*;
                if (hygieneCanDeprecateAtom(input, duplicate.status, duplicate.scope, duplicate.permissions_json)) {
                    if (input.hard_delete) {
                        if (try self.hardDeleteMemoryAtom(duplicate.id)) result.dedupe_purged += 1;
                    } else if (try self.patchMemoryAtomStatusActor(duplicate.id, "deprecated", false, input.actor_id)) {
                        result.dedupe_deprecated += 1;
                    }
                }
                entry.value_ptr.* = .{
                    .id = id_text,
                    .status = status,
                    .scope = scope,
                    .permissions_json = permissions,
                    .created_at_ms = created,
                    .last_verified_at_ms = last_verified,
                    .seen_duplicate = true,
                };
            } else if (hygieneCanDeprecateAtom(input, status, scope, permissions)) {
                if (input.hard_delete) {
                    if (try self.hardDeleteMemoryAtom(id_text)) result.dedupe_purged += 1;
                } else if (try self.patchMemoryAtomStatusActor(id_text, "deprecated", false, input.actor_id)) {
                    result.dedupe_deprecated += 1;
                }
            }
        }
    }

    fn deprecateAgentMemoryDuplicate(self: *PostgresStore, allocator: std.mem.Allocator, item_id: []const u8, atom_id: []const u8, input: HygieneRunInput) !bool {
        if (input.hard_delete) return self.hardDeleteMemoryAtom(atom_id);
        const text = try self.queryParamsText(
            allocator,
            "WITH item_deleted AS (" ++
                "DELETE FROM agent_memory_items WHERE id = $1 RETURNING 1" ++
                "), atom_updated AS (" ++
                "UPDATE memory_atoms SET status = 'deprecated' WHERE id = $2 AND status <> 'deprecated' RETURNING 1" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) " ++
                "SELECT 'agent_memory.deduped',$3,'agent_memory',$1,'{}'::jsonb,(extract(epoch from clock_timestamp()) * 1000)::bigint " ++
                "WHERE EXISTS (SELECT 1 FROM item_deleted) OR EXISTS (SELECT 1 FROM atom_updated) RETURNING 1" ++
                ") SELECT ((SELECT count(*) FROM item_deleted) + (SELECT count(*) FROM atom_updated))::text",
            &.{ item_id, atom_id, input.actor_id },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    fn runAgentMemoryDedupe(self: *PostgresStore, allocator: std.mem.Allocator, input: HygieneRunInput, result: *HygieneRunResult) !void {
        const limit = @max(@as(usize, 1), @min(input.dedupe_limit, @as(usize, 20_000)));
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{limit});
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT ami.id,ami.memory_atom_id,ma.status,ma.last_verified_at_ms,ami.timestamp_ms,ami.scope,ami.permissions_json,ami.category,ami.session_id,ami.key,ma.text " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
                "WHERE ma.status NOT IN ('rejected','deprecated','superseded') " ++
                "ORDER BY ami.timestamp_ms DESC LIMIT $1::bigint",
            &.{limit_text},
        );
        defer parsed.deinit();
        if (parsed.value != .array) return;

        var winners: std.StringHashMapUnmanaged(HygieneAgentMemoryDedupeWinner) = .{};
        defer winners.deinit(allocator);

        for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const obj = item.object;
            const item_id = json.stringField(obj, "id") orelse continue;
            const atom_id = json.stringField(obj, "memory_atom_id") orelse continue;
            const status = json.stringField(obj, "status") orelse "proposed";
            const last_verified = json.intField(obj, "last_verified_at_ms");
            const created = json.intField(obj, "timestamp_ms") orelse 0;
            const scope = json.stringField(obj, "scope") orelse "workspace";
            const permissions = try rawJsonField(allocator, obj, "permissions_json", "[]");
            const category = json.stringField(obj, "category") orelse "core";
            const session_id = json.nullableStringField(obj, "session_id");
            const item_key = json.stringField(obj, "key") orelse "";
            const text = json.stringField(obj, "text") orelse "";
            if (domain.isInternalMemoryEntryKeyOrContent(item_key, text)) continue;
            result.agent_memory_dedupe_checked += 1;
            const key = (try hygieneAgentMemoryDedupeKey(allocator, scope, permissions, category, session_id, text, input.dedupe_normalized)) orelse continue;
            const entry = try winners.getOrPut(allocator, key);
            if (!entry.found_existing) {
                entry.key_ptr.* = key;
                entry.value_ptr.* = .{
                    .item_id = item_id,
                    .atom_id = atom_id,
                    .status = status,
                    .scope = scope,
                    .permissions_json = permissions,
                    .created_at_ms = created,
                    .last_verified_at_ms = last_verified,
                };
                continue;
            }
            if (!entry.value_ptr.seen_duplicate) {
                result.agent_memory_dedupe_groups += 1;
                entry.value_ptr.seen_duplicate = true;
            }
            const replace_winner = hygieneShouldReplaceAgentMemoryWinner(status, created, last_verified, entry.value_ptr.*);
            if (replace_winner) {
                const duplicate = entry.value_ptr.*;
                if (hygieneCanDeprecateAtom(input, duplicate.status, duplicate.scope, duplicate.permissions_json)) {
                    if (try self.deprecateAgentMemoryDuplicate(allocator, duplicate.item_id, duplicate.atom_id, input)) {
                        if (input.hard_delete) result.agent_memory_dedupe_purged += 1 else result.agent_memory_dedupe_deprecated += 1;
                    }
                }
                entry.value_ptr.* = .{
                    .item_id = item_id,
                    .atom_id = atom_id,
                    .status = status,
                    .scope = scope,
                    .permissions_json = permissions,
                    .created_at_ms = created,
                    .last_verified_at_ms = last_verified,
                    .seen_duplicate = true,
                };
            } else if (hygieneCanDeprecateAtom(input, status, scope, permissions)) {
                if (try self.deprecateAgentMemoryDuplicate(allocator, item_id, atom_id, input)) {
                    if (input.hard_delete) result.agent_memory_dedupe_purged += 1 else result.agent_memory_dedupe_deprecated += 1;
                }
            }
        }
    }

    pub fn listMemoryAtomsVisible(self: *PostgresStore, allocator: std.mem.Allocator, input: MemoryAtomListInput) ![]domain.MemoryAtom {
        if (input.scope_filter_empty) return try allocator.alloc(domain.MemoryAtom, 0);
        const limit = primitiveListLimit(input.limit);
        if (limit == 0) return try allocator.alloc(domain.MemoryAtom, 0);
        const scan_limit = primitiveListScanLimit(limit);
        var out: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        errdefer {
            for (out.items) |*atom| deinitMemoryAtom(allocator, atom);
            out.deinit(allocator);
        }

        var offset: usize = 0;
        while (out.items.len < limit) {
            const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{scan_limit});
            defer allocator.free(limit_text);
            const offset_text = try std.fmt.allocPrint(allocator, "{d}", .{offset});
            defer allocator.free(offset_text);
            const parsed = try self.queryArrayParamsJson(
                allocator,
                "SELECT id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json " ++
                    "FROM memory_atoms WHERE predicate <> 'agent.memory' ORDER BY created_at_ms DESC, id DESC LIMIT $1::bigint OFFSET $2::bigint",
                &.{ limit_text, offset_text },
            );
            defer parsed.deinit();

            var scanned: usize = 0;
            if (parsed.value == .array) for (parsed.value.array.items) |item| {
                scanned += 1;
                if (item != .object) continue;
                var atom = try readPgMemoryAtom(allocator, item.object);
                if (!input.include_deprecated and !domain.isDefaultVisibleStatus(atom.status)) {
                    deinitMemoryAtom(allocator, &atom);
                    continue;
                }
                if (!try self.recordVisibleWithPolicyForActor(allocator, atom.scope, atom.permissions_json, input.scopes_json, input.actor_id)) {
                    deinitMemoryAtom(allocator, &atom);
                    continue;
                }
                try out.append(allocator, atom);
                if (out.items.len >= limit) break;
            };

            if (scanned < scan_limit or out.items.len >= limit) break;
            offset = bounded_int.saturatingUsizeAdd(offset, scanned);
        }
        return out.toOwnedSlice(allocator);
    }

    fn hardDeleteMemoryAtom(self: *PostgresStore, id_text: []const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        _ = try self.deleteVectorChunksForObject(allocator, "memory_atom", id_text, null);
        const text = try self.queryParamsText(
            allocator,
            "WITH agent_deleted AS (" ++
                "DELETE FROM agent_memory_items WHERE memory_atom_id = $1 RETURNING 1" ++
                "), deleted AS (" ++
                "DELETE FROM memory_atoms WHERE id = $1 RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) " ++
                "SELECT 'memory_atom.purged',NULL,'memory_atom',id,'{}'::jsonb,(extract(epoch from clock_timestamp()) * 1000)::bigint FROM deleted RETURNING 1" ++
                ") SELECT count(*)::text FROM deleted",
            &.{id_text},
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    fn insertContextPackRecord(
        self: *PostgresStore,
        allocator: std.mem.Allocator,
        id: []const u8,
        purpose: []const u8,
        target: []const u8,
        query: []const u8,
        included_sources_json: []const u8,
        included_artifacts_json: []const u8,
        included_memory_atoms_json: []const u8,
        included_result_refs_json: []const u8,
        required_scopes_json: []const u8,
        actor_id: ?[]const u8,
        actor_isolated: bool,
        generated_summary: []const u8,
        sections_json: []const u8,
        citations_json: []const u8,
        forbidden_assumptions_json: []const u8,
        suggested_next_steps_json: []const u8,
        token_budget: i64,
        created_at_ms: i64,
        audit_actor_id: ?[]const u8,
    ) !void {
        const token_budget_text = try std.fmt.allocPrint(allocator, "{d}", .{token_budget});
        defer allocator.free(token_budget_text);
        const created_at_text = try std.fmt.allocPrint(allocator, "{d}", .{created_at_ms});
        defer allocator.free(created_at_text);
        try self.runParams(
            allocator,
            "WITH inserted AS (" ++
                "INSERT INTO context_packs (id,purpose,target,query_text,included_sources_json,included_artifacts_json,included_memory_atoms_json,included_result_refs_json,required_scopes_json,actor_id,actor_isolated,generated_summary,sections_json,citations_json,forbidden_assumptions_json,suggested_next_steps_json,token_budget,created_at_ms) " ++
                "VALUES ($1,$2,$3,$4,$5::jsonb,$6::jsonb,$7::jsonb,$8::jsonb,$9::jsonb,$10,$11::boolean,$12,$13::jsonb,$14::jsonb,$15::jsonb,$16::jsonb,$17::bigint,$18::bigint) RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'context_pack.created',$19,'context_pack',id,'{}'::jsonb,$18::bigint FROM inserted RETURNING 1" ++
                ") SELECT count(*)::text FROM inserted",
            &.{ id, purpose, target, query, included_sources_json, included_artifacts_json, included_memory_atoms_json, included_result_refs_json, required_scopes_json, actor_id, if (actor_isolated) "true" else "false", generated_summary, sections_json, citations_json, forbidden_assumptions_json, suggested_next_steps_json, token_budget_text, created_at_text, audit_actor_id },
        );
    }

    pub fn createContextPack(self: *PostgresStore, allocator: std.mem.Allocator, input: ContextPackInput) !ContextPackResult {
        const search_results = input.preselected_results orelse try self.search(allocator, .{
            .query = input.query,
            .limit = input.retrieval_limit,
            .scopes_json = input.scopes_json,
            .include_deprecated = input.include_deprecated,
            .include_sessions = input.include_sessions,
            .session_id = input.session_id,
            .use_vector = input.use_vector,
            .adaptive_retrieval = input.adaptive_retrieval,
            .adaptive_keyword_max_tokens = input.adaptive_keyword_max_tokens,
            .adaptive_vector_min_tokens = input.adaptive_vector_min_tokens,
            .use_temporal_decay = input.use_temporal_decay,
            .use_mmr = input.use_mmr,
            .mmr_lambda = input.mmr_lambda,
            .mmr_candidate_multiplier = input.mmr_candidate_multiplier,
            .allow_reranker = input.allow_reranker,
            .rerank_candidate_limit = input.rerank_candidate_limit,
            .strict_reranker = input.strict_reranker,
            .min_relevance = input.min_relevance,
            .rrf_k = input.rrf_k,
            .rrf_weight = input.rrf_weight,
            .raw_score_weight = input.raw_score_weight,
            .rrf_window_multiplier = input.rrf_window_multiplier,
            .query_embedding_json = input.query_embedding_json,
            .query_embedding_provider = input.query_embedding_provider,
            .embedding_dimensions = input.embedding_dimensions,
            .actor_id = input.actor_id,
            .actor_capabilities_json = input.actor_capabilities_json,
            .agent_memory_route = input.agent_memory_route,
        });
        if (!input.preserve_result_order) context_pack.sortResults(search_results);
        const budgeted = try context_pack.budgetResults(allocator, search_results, input.token_budget);
        defer budgeted.deinit(allocator);
        const budgeted_results = budgeted.items;
        const id = try idOrMake(allocator, input.id, "ctx_");
        const now = ids.nowMs();
        const sources = try pgCollectResultIds(allocator, budgeted_results, "source", true);
        const artifacts = try pgCollectResultIds(allocator, budgeted_results, "artifact", false);
        const atoms = try pgCollectResultIds(allocator, budgeted_results, "memory_atom", false);
        const summary_full = try context_pack.buildSummary(allocator, input.query, budgeted_results);
        const summary = try context_pack.trimSummaryToBudget(allocator, summary_full, input.token_budget);
        const sections = try context_pack.buildSectionsJson(allocator, budgeted_results);
        const required_scopes = try context_pack.requiredScopesJson(allocator, budgeted_results);
        const result_refs = try context_pack.resultRefsJson(allocator, budgeted_results);
        const actor_isolated = context_pack.requiresActorIsolation(budgeted_results);
        if (input.persist) {
            try self.insertContextPackRecord(
                allocator,
                id,
                input.purpose,
                input.target,
                input.query,
                sources,
                artifacts,
                atoms,
                result_refs,
                required_scopes,
                input.actor_id,
                actor_isolated,
                summary,
                sections,
                sources,
                context_pack.forbidden_assumptions_json,
                context_pack.suggested_next_steps_json,
                input.token_budget,
                now,
                input.actor_id,
            );
        }
        return .{ .id = id, .purpose = input.purpose, .target = input.target, .query = input.query, .generated_summary = summary, .sections_json = sections, .citations_json = sources, .forbidden_assumptions_json = context_pack.forbidden_assumptions_json, .suggested_next_steps_json = context_pack.suggested_next_steps_json, .included_sources_json = sources, .included_artifacts_json = artifacts, .included_memory_atoms_json = atoms, .included_result_refs_json = result_refs, .required_scopes_json = required_scopes, .actor_id = input.actor_id, .actor_isolated = actor_isolated, .token_budget = input.token_budget, .created_at_ms = now, .persisted = input.persist };
    }

    pub fn importContextPackSnapshot(self: *PostgresStore, allocator: std.mem.Allocator, input: ContextPackSnapshotInput) !ContextPackResult {
        const id = try idOrMake(allocator, input.id, "ctx_");
        const now = ids.nowMs();
        try self.insertContextPackRecord(
            allocator,
            id,
            input.purpose,
            input.target,
            input.query,
            input.included_sources_json,
            input.included_artifacts_json,
            input.included_memory_atoms_json,
            input.included_result_refs_json,
            input.required_scopes_json,
            input.actor_id,
            input.actor_isolated,
            input.generated_summary,
            input.sections_json,
            input.citations_json,
            input.forbidden_assumptions_json,
            input.suggested_next_steps_json,
            input.token_budget,
            now,
            input.actor_id_for_audit orelse input.actor_id,
        );
        return .{
            .id = id,
            .purpose = input.purpose,
            .target = input.target,
            .query = input.query,
            .generated_summary = input.generated_summary,
            .sections_json = input.sections_json,
            .citations_json = input.citations_json,
            .forbidden_assumptions_json = input.forbidden_assumptions_json,
            .suggested_next_steps_json = input.suggested_next_steps_json,
            .included_sources_json = input.included_sources_json,
            .included_artifacts_json = input.included_artifacts_json,
            .included_memory_atoms_json = input.included_memory_atoms_json,
            .included_result_refs_json = input.included_result_refs_json,
            .required_scopes_json = input.required_scopes_json,
            .actor_id = input.actor_id,
            .actor_isolated = input.actor_isolated,
            .token_budget = input.token_budget,
            .created_at_ms = now,
            .persisted = true,
        };
    }

    pub fn agentMemoryStore(self: *PostgresStore, allocator: std.mem.Allocator, input: AgentMemoryInput) !domain.AgentMemory {
        const owner_actor_id = try requiredActorId(input.actor_id);
        const writer_actor_id = input.writer_actor_id orelse owner_actor_id;
        if (try self.agentMemoryEventOrderWouldRegress(allocator, input, owner_actor_id)) {
            if (try self.agentMemoryGet(allocator, input.key, input.session_id, owner_actor_id)) |entry| return entry;
            return ignoredAgentMemoryProjection(allocator, input, owner_actor_id, writer_actor_id);
        }
        var existing = try self.agentMemoryGet(allocator, input.key, input.session_id, owner_actor_id);
        defer if (existing) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
        const reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
        defer allocator.free(reduced_content);
        const stored_metadata_json = try agentMemoryStoredMetadataJson(allocator, input);
        defer allocator.free(stored_metadata_json);
        const source_title = try std.fmt.allocPrint(allocator, "Agent memory: {s}", .{input.key});
        defer allocator.free(source_title);
        const source_id = try ids.make(allocator, "src_");
        defer allocator.free(source_id);
        const atom_id = try ids.make(allocator, "mem_");
        defer allocator.free(atom_id);
        const item_id = try ids.make(allocator, "agm_");
        defer allocator.free(item_id);
        const source_ids = try singleJsonString(allocator, source_id);
        defer allocator.free(source_ids);
        const evidence = try evidenceRangeJson(allocator, source_id, reduced_content.len, "agent_memory");
        defer allocator.free(evidence);
        const now = if (input.event_order) |event_order| event_order.timestamp_ms else ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        const scope = try agentMemoryScope(allocator, owner_actor_id, input.session_id, input.scope);
        defer allocator.free(scope);
        const effective_permissions = try agentMemoryPermissions(allocator, owner_actor_id, input.scope, input.permissions_json);
        defer allocator.free(effective_permissions);
        const status = domain.defaultMemoryStatus("agent", scope);
        try self.runParams(
            allocator,
            "WITH matching_items AS (" ++
                "SELECT memory_atom_id FROM agent_memory_items WHERE key = $1 AND (($2::text IS NULL AND session_id IS NULL) OR session_id = $2) AND actor_id = $3" ++
                "), deprecated_atoms AS (" ++
                "UPDATE memory_atoms SET status = 'deprecated' WHERE id IN (SELECT memory_atom_id FROM matching_items) RETURNING 1" ++
                "), inserted_source AS (" ++
                "INSERT INTO sources (id,type,title,raw_content_uri,content,author,participants_json,permissions_json,scope,created_at_ms,imported_at_ms,checksum,language,related_entities_json,metadata_json) " ++
                "VALUES ($4,'agent_observation',$5,NULL,$6,NULL,'[]'::jsonb,$7::jsonb,$8,$9::bigint,$9::bigint,NULL,NULL,'[]'::jsonb,'{\"native\":\"agent_memory\"}'::jsonb) RETURNING id" ++
                "), inserted_atom AS (" ++
                "INSERT INTO memory_atoms (id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json) " ++
                "VALUES ($10,NULL,'agent.memory',$1,$6,$8,0.8,$11,$12::jsonb,$13::jsonb,'agent',$9::bigint,NULL,NULL,NULL,NULL,$7::jsonb,'[\"agent_memory\"]'::jsonb) RETURNING id" ++
                "), inserted_item AS (" ++
                "INSERT INTO agent_memory_items (id,key,session_id,actor_id,writer_actor_id,scope,permissions_json,memory_atom_id,category,timestamp_ms,metadata_json) " ++
                "VALUES ($14,$1,$2,$3,$15,$8,$7::jsonb,$10,$16,$9::bigint,$17::jsonb) " ++
                "ON CONFLICT (key, (coalesce(session_id, '')), actor_id) DO UPDATE SET " ++
                "id = EXCLUDED.id, writer_actor_id = EXCLUDED.writer_actor_id, scope = EXCLUDED.scope, permissions_json = EXCLUDED.permissions_json, memory_atom_id = EXCLUDED.memory_atom_id, category = EXCLUDED.category, timestamp_ms = EXCLUDED.timestamp_ms, metadata_json = EXCLUDED.metadata_json RETURNING id" ++
                "), audit_source AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'source.created',$15,'source',id,'{}'::jsonb,$9::bigint FROM inserted_source RETURNING 1" ++
                "), audit_atom AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'memory_atom.created',$15,'memory_atom',id,'{}'::jsonb,$9::bigint FROM inserted_atom RETURNING 1" ++
                "), audit_item AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'agent_memory.upserted',$15,'agent_memory',id,'{}'::jsonb,$9::bigint FROM inserted_item RETURNING 1" ++
                ") SELECT ((SELECT count(*) FROM inserted_item) + (SELECT count(*) FROM audit_source) + (SELECT count(*) FROM audit_atom) + (SELECT count(*) FROM audit_item))::text",
            &.{
                input.key,
                input.session_id,
                owner_actor_id,
                source_id,
                source_title,
                reduced_content,
                effective_permissions,
                scope,
                now_text,
                atom_id,
                status,
                source_ids,
                evidence,
                item_id,
                writer_actor_id,
                input.category,
                stored_metadata_json,
            },
        );
        return (try self.agentMemoryGet(allocator, input.key, input.session_id, owner_actor_id)).?;
    }

    fn agentMemoryEventOrderWouldRegress(self: *PostgresStore, allocator: std.mem.Allocator, input: AgentMemoryInput, owner_actor_id: []const u8) !bool {
        const event_order = input.event_order orelse return false;
        if (try self.agentMemoryTombstoneBlocksPut(allocator, input.key, input.session_id, owner_actor_id, event_order)) return true;
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT ami.timestamp_ms,ami.metadata_json FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id WHERE ami.key = $1 AND (($2::text IS NULL AND ami.session_id IS NULL) OR ami.session_id = $2) AND ami.actor_id = $3 AND ma.status NOT IN ('rejected','deprecated','superseded') ORDER BY ami.timestamp_ms DESC LIMIT 1",
            &.{ input.key, input.session_id, owner_actor_id },
        );
        defer parsed.deinit();
        if (parsed.value != .object) return false;
        const stored_timestamp_ms = json.intField(parsed.value.object, "timestamp_ms") orelse return false;
        const stored_metadata_json = try rawJsonField(allocator, parsed.value.object, "metadata_json", "{}");
        defer allocator.free(stored_metadata_json);
        return (try compareAgentMemoryInputToStoredMetadata(allocator, event_order, stored_timestamp_ms, stored_metadata_json)) <= 0;
    }

    fn agentMemoryTombstoneBlocksPut(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        const session_key = agentMemoryTombstoneSessionKey(session_id);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT timestamp_ms,origin_instance_id,origin_sequence FROM agent_memory_tombstones WHERE key = $1 AND actor_id = $2 AND ((tombstone_scope = 'scoped' AND session_key = $3) OR (tombstone_scope = 'all' AND session_key = '*'))",
            &.{ key, owner_actor_id, session_key },
        );
        defer parsed.deinit();
        if (parsed.value != .array) return false;
        for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const stored_timestamp_ms = json.intField(item.object, "timestamp_ms") orelse continue;
            const stored_origin_instance_id = json.stringField(item.object, "origin_instance_id") orelse "";
            const stored_origin_sequence = json.intField(item.object, "origin_sequence") orelse 0;
            if (compareAgentMemoryEventOrder(event_order, stored_timestamp_ms, stored_origin_instance_id, stored_origin_sequence) <= 0) return true;
        }
        return false;
    }

    pub fn agentMemoryTombstoneBlocksReplay(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        return self.agentMemoryTombstoneBlocksPut(allocator, key, session_id, owner_actor_id, event_order);
    }

    fn upsertAgentMemoryTombstone(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, owner_actor_id: []const u8, tombstone_scope: []const u8, session_id: ?[]const u8, event_order: AgentMemoryEventOrder) !void {
        const session_key = if (std.mem.eql(u8, tombstone_scope, "all")) "*" else agentMemoryTombstoneSessionKey(session_id);
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT timestamp_ms,origin_instance_id,origin_sequence FROM agent_memory_tombstones WHERE key = $1 AND actor_id = $2 AND tombstone_scope = $3 AND session_key = $4 LIMIT 1",
            &.{ key, owner_actor_id, tombstone_scope, session_key },
        );
        defer parsed.deinit();
        if (parsed.value == .object) {
            const stored_timestamp_ms = json.intField(parsed.value.object, "timestamp_ms") orelse 0;
            const stored_origin_instance_id = json.stringField(parsed.value.object, "origin_instance_id") orelse "";
            const stored_origin_sequence = json.intField(parsed.value.object, "origin_sequence") orelse 0;
            if (compareAgentMemoryEventOrder(event_order, stored_timestamp_ms, stored_origin_instance_id, stored_origin_sequence) <= 0) return;
        }
        const timestamp_text = try std.fmt.allocPrint(allocator, "{d}", .{event_order.timestamp_ms});
        defer allocator.free(timestamp_text);
        const origin_sequence_text = try std.fmt.allocPrint(allocator, "{d}", .{event_order.origin_sequence});
        defer allocator.free(origin_sequence_text);
        try self.runParams(
            allocator,
            "INSERT INTO agent_memory_tombstones (key,actor_id,tombstone_scope,session_key,session_id,timestamp_ms,origin_instance_id,origin_sequence) VALUES ($1,$2,$3,$4,$5,$6::bigint,$7,$8::bigint) " ++
                "ON CONFLICT (key, actor_id, tombstone_scope, session_key) DO UPDATE SET session_id = excluded.session_id, timestamp_ms = excluded.timestamp_ms, origin_instance_id = excluded.origin_instance_id, origin_sequence = excluded.origin_sequence",
            &.{ key, owner_actor_id, tombstone_scope, session_key, session_id, timestamp_text, event_order.origin_instance_id, origin_sequence_text },
        );
    }

    pub fn agentMemoryGet(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) !?domain.AgentMemory {
        const entries = try self.agentMemoryListInner(allocator, key, null, session_id, actor_id, 1, 0);
        if (entries.len == 0) {
            allocator.free(entries);
            return null;
        }
        const result = entries[0];
        allocator.free(entries);
        return result;
    }

    pub fn agentMemoryGetVisible(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        const entries = try self.agentMemoryListVisibleInner(allocator, key, null, session_id, actor_id, scopes_json, null, 0);
        if (entries.len == 0) {
            allocator.free(entries);
            return null;
        }
        const result = entries[0];
        for (entries[1..]) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
        allocator.free(entries);
        return result;
    }

    pub fn agentMemoryGetAnyVisible(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json,ma.confidence AS score,ma.status " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
                "WHERE ami.key = $1 AND ma.status NOT IN ('rejected','deprecated','superseded') " ++
                "ORDER BY CASE WHEN ami.actor_id = $2 THEN 0 WHEN ami.actor_id LIKE 'shared:%' THEN 1 ELSE 2 END, ami.timestamp_ms DESC",
            &.{ key, actor_id },
        );
        defer parsed.deinit();
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            var entry = try readPgAgentMemory(allocator, item.object);
            if (!try self.pgAgentMemoryResultVisible(allocator, entry.actor_id, entry.scope, entry.permissions_json, entry.session_id, scopes_json, actor_id)) {
                agent_memory_runtime.freeAgentMemory(allocator, &entry);
                continue;
            }
            return entry;
        };
        return null;
    }

    pub fn agentMemoryList(self: *PostgresStore, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        return self.agentMemoryListInner(allocator, null, category, session_id, actor_id, null, 0);
    }

    pub fn agentMemoryListWindow(self: *PostgresStore, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        return self.agentMemoryListInner(allocator, null, category, session_id, actor_id, limit, offset);
    }

    pub fn agentMemoryListVisible(self: *PostgresStore, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        return self.agentMemoryListVisibleInner(allocator, null, category, session_id, actor_id, scopes_json, null, 0);
    }

    pub fn agentMemoryListVisibleWindow(self: *PostgresStore, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const sql =
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json,ma.confidence AS score,ma.status " ++
            "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
            "WHERE ($1::text IS NULL OR ami.category = $1) " ++
            "AND ma.status NOT IN ('rejected','deprecated','superseded') " ++
            "AND (($2::text IS NULL AND ami.session_id IS NULL) OR ($2::text IS NOT NULL AND ami.session_id = $2)) " ++
            "ORDER BY CASE WHEN ami.actor_id = $3 THEN 0 WHEN ami.actor_id LIKE 'shared:%' THEN 1 ELSE 2 END, ami.timestamp_ms DESC LIMIT $4::bigint OFFSET $5::bigint";
        const fetch_limit = agentMemoryBackendWindowFetchLimit(limit);
        var raw_offset: usize = 0;
        var visible_seen: usize = 0;
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        while (true) {
            const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{fetch_limit});
            defer allocator.free(limit_text);
            const offset_text = try std.fmt.allocPrint(allocator, "{d}", .{agentMemoryBackendWindowOffsetI64(raw_offset)});
            defer allocator.free(offset_text);
            const parsed = try self.queryArrayParamsJson(allocator, sql, &.{ category, session_id, actor_id, limit_text, offset_text });
            defer parsed.deinit();
