    pub fn agentMemorySearch(self: *PostgresStore, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return try allocator.alloc(domain.AgentMemory, 0);
        const capped = agentMemorySearchResultLimit(limit);
        const request_actor = actor_id orelse return try allocator.alloc(domain.AgentMemory, 0);
        return self.agentMemorySearchVisibleScan(allocator, query, capped, session_id, false, request_actor, scopes_json);
    }

    pub fn agentMemorySearchAnyVisible(self: *PostgresStore, allocator: std.mem.Allocator, query: []const u8, limit: usize, scopes_json: []const u8, actor_id: []const u8) ![]domain.AgentMemory {
        if (limit == 0) return try allocator.alloc(domain.AgentMemory, 0);
        const capped = agentMemorySearchResultLimit(limit);
        return self.agentMemorySearchVisibleScan(allocator, query, capped, null, true, actor_id, scopes_json);
    }

    fn agentMemorySearchVisibleScan(self: *PostgresStore, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| agent_memory_runtime.freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        const candidate_limit = pgSearchCandidateLimit(limit, 20, 5000);
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{candidate_limit});
        defer allocator.free(limit_text);
        const sql = if (include_sessions)
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json, " ++
                "CASE WHEN $1::text = '' THEN ma.confidence ELSE (ts_rank_cd(ami.search_tsv, websearch_to_tsquery('simple',$1)) + ts_rank_cd(ma.search_tsv, websearch_to_tsquery('simple',$1)) + ma.confidence) END AS score, ma.status " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
                "WHERE ma.status NOT IN ('rejected','deprecated','superseded') " ++
                "AND ($1::text = '' OR ami.search_tsv @@ websearch_to_tsquery('simple',$1) OR ma.search_tsv @@ websearch_to_tsquery('simple',$1)) " ++
                "ORDER BY CASE WHEN $1::text = '' THEN 0 ELSE (ts_rank_cd(ami.search_tsv, websearch_to_tsquery('simple',$1)) + ts_rank_cd(ma.search_tsv, websearch_to_tsquery('simple',$1))) END DESC, ami.timestamp_ms DESC LIMIT $2::bigint"
        else
            "SELECT ami.id,ami.key,ma.text AS content,ami.category,ami.timestamp_ms,ami.session_id,ami.actor_id,ami.writer_actor_id,ami.scope,ami.permissions_json, " ++
                "CASE WHEN $2::text = '' THEN ma.confidence ELSE (ts_rank_cd(ami.search_tsv, websearch_to_tsquery('simple',$2)) + ts_rank_cd(ma.search_tsv, websearch_to_tsquery('simple',$2)) + ma.confidence) END AS score, ma.status " ++
                "FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id " ++
                "WHERE ma.status NOT IN ('rejected','deprecated','superseded') " ++
                "AND (($1::text IS NULL AND ami.session_id IS NULL) OR ($1::text IS NOT NULL AND ami.session_id = $1)) " ++
                "AND ($2::text = '' OR ami.search_tsv @@ websearch_to_tsquery('simple',$2) OR ma.search_tsv @@ websearch_to_tsquery('simple',$2)) " ++
                "ORDER BY CASE WHEN $2::text = '' THEN 0 ELSE (ts_rank_cd(ami.search_tsv, websearch_to_tsquery('simple',$2)) + ts_rank_cd(ma.search_tsv, websearch_to_tsquery('simple',$2))) END DESC, ami.timestamp_ms DESC LIMIT $3::bigint";
        const parsed = if (include_sessions)
            try self.queryArrayParamsJson(allocator, sql, &.{ query, limit_text })
        else
            try self.queryArrayParamsJson(allocator, sql, &.{ session_id, query, limit_text });
        defer parsed.deinit();
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            var entry = try readPgAgentMemory(allocator, item.object);
            var entry_owned = true;
            errdefer if (entry_owned) agent_memory_runtime.freeAgentMemory(allocator, &entry);
            if (!try self.pgAgentMemoryResultVisible(allocator, entry.actor_id, entry.scope, entry.permissions_json, entry.session_id, scopes_json, actor_id)) {
                agent_memory_runtime.freeAgentMemory(allocator, &entry);
                entry_owned = false;
                continue;
            }
            if (domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) {
                agent_memory_runtime.freeAgentMemory(allocator, &entry);
                entry_owned = false;
                continue;
            }
            if (query.len > 0 and (entry.score orelse 0) <= 0) {
                agent_memory_runtime.freeAgentMemory(allocator, &entry);
                entry_owned = false;
                continue;
            }
            try out.append(allocator, entry);
            entry_owned = false;
            sortAgentMemoryResults(out.items);
            trimAgentMemoryResults(allocator, &out, limit);
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn agentMemoryDelete(self: *PostgresStore, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const text = try self.queryParamsText(
            allocator,
            "WITH rows AS (" ++
                "DELETE FROM agent_memory_items WHERE key = $1 AND (($2::text IS NULL AND session_id IS NULL) OR session_id = $2) AND actor_id = $3 RETURNING memory_atom_id" ++
                "), upd AS (" ++
                "UPDATE memory_atoms SET status='deprecated' WHERE id IN (SELECT memory_atom_id FROM rows) RETURNING 1" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'agent_memory.deleted',$4,'agent_memory',$1,'{}'::jsonb,(extract(epoch from clock_timestamp()) * 1000)::bigint WHERE EXISTS (SELECT 1 FROM rows) RETURNING 1" ++
                ") SELECT count(*)::text FROM rows",
            &.{ key, session_id, actor_id, writer_actor_id orelse actor_id },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    fn agentMemoryDeleteOrdered(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        const order = event_order orelse return self.agentMemoryDelete(key, session_id, actor_id, writer_actor_id);
        const owner_actor = actor_id orelse return false;
        try self.upsertAgentMemoryTombstone(allocator, key, owner_actor, "scoped", session_id, order);
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT session_id,timestamp_ms,metadata_json FROM agent_memory_items WHERE key = $1 AND (($2::text IS NULL AND session_id IS NULL) OR session_id = $2) AND actor_id = $3",
            &.{ key, session_id, owner_actor },
        );
        defer parsed.deinit();
        var changed = false;
        if (parsed.value == .array) {
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                const stored_timestamp_ms = json.intField(item.object, "timestamp_ms") orelse continue;
                const stored_metadata_json = try rawJsonField(allocator, item.object, "metadata_json", "{}");
                defer allocator.free(stored_metadata_json);
                if ((try compareAgentMemoryInputToStoredMetadata(allocator, order, stored_timestamp_ms, stored_metadata_json)) < 0) continue;
                const row_session_id = json.nullableStringField(item.object, "session_id");
                changed = (try self.agentMemoryDelete(key, row_session_id, owner_actor, writer_actor_id)) or changed;
            }
        }
        return changed;
    }

    pub fn agentMemoryDeleteAll(self: *PostgresStore, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8) !bool {
        const owner_actor = actor_id orelse return false;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
