            allocator,
            "WITH rows AS (" ++
                "DELETE FROM agent_memory_items WHERE key = $1 AND actor_id = $2 RETURNING memory_atom_id" ++
                "), upd AS (" ++
                "UPDATE memory_atoms SET status='deprecated' WHERE id IN (SELECT memory_atom_id FROM rows) RETURNING 1" ++
