    pub fn patchAgentMemoryStatus(self: *PostgresStore, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8) !bool {
        return self.patchAgentMemoryStatusOrdered(self.allocator, key, session_id, actor_id, status, writer_actor_id, null);
    }

    pub fn patchAgentMemoryStatusOrdered(self: *PostgresStore, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        const owner_actor = actor_id orelse return false;
        var arena = std.heap.ArenaAllocator.init(allocator);
        defer arena.deinit();
        const scratch = arena.allocator();
        if (event_order) |order| {
            if (!domain.isDefaultVisibleStatus(status)) {
                try self.upsertAgentMemoryTombstone(scratch, key, owner_actor, "scoped", session_id, order);
            }
            const parsed = try self.queryArrayParamsJson(
                scratch,
                "SELECT ami.id,ami.memory_atom_id,ami.timestamp_ms,ami.metadata_json FROM agent_memory_items ami WHERE ami.key = $1 AND (($2::text IS NULL AND ami.session_id IS NULL AND ami.actor_id = $3) OR ($2::text IS NOT NULL AND ami.session_id = $2 AND ami.actor_id = $3))",
                &.{ key, session_id, owner_actor },
            );
            defer parsed.deinit();
            if (parsed.value != .array) return false;
            var saw_target = false;
            var changed = false;
            for (parsed.value.array.items) |item| {
                if (item != .object) continue;
                saw_target = true;
                const item_id = json.stringField(item.object, "id") orelse continue;
                const atom_id = json.stringField(item.object, "memory_atom_id") orelse continue;
                const stored_timestamp_ms = json.intField(item.object, "timestamp_ms") orelse continue;
                const stored_metadata_json = try rawJsonField(scratch, item.object, "metadata_json", "{}");
                if ((try compareAgentMemoryInputToStoredMetadata(scratch, order, stored_timestamp_ms, stored_metadata_json)) <= 0) continue;
                const next_metadata_json = try agentMemoryMetadataJsonWithEventOrder(scratch, order, stored_metadata_json);
                const verified_text = if (std.mem.eql(u8, status, "verified")) "true" else "false";
                const now_text = try std.fmt.allocPrint(scratch, "{d}", .{ids.nowMs()});
                try self.runParams(
                    scratch,
                    "UPDATE memory_atoms SET status = $1, last_verified_at_ms = CASE WHEN $2::boolean THEN $3::bigint ELSE last_verified_at_ms END WHERE id = $4",
                    &.{ status, verified_text, now_text, atom_id },
                );
                try self.runParams(
                    scratch,
                    "UPDATE agent_memory_items SET metadata_json = $1::jsonb WHERE id = $2",
                    &.{ next_metadata_json, item_id },
                );
                changed = true;
            }
            if (changed) try self.insertAudit(scratch, "agent_memory.status", writer_actor_id orelse owner_actor, "agent_memory", key);
            return saw_target;
        }
        const verified_text = if (std.mem.eql(u8, status, "verified")) "true" else "false";
        const now_text = try std.fmt.allocPrint(scratch, "{d}", .{ids.nowMs()});
        const text = try self.queryParamsText(
            scratch,
            "WITH updated AS (" ++
                "UPDATE memory_atoms SET status = $1, last_verified_at_ms = CASE WHEN $2::boolean THEN $3::bigint ELSE last_verified_at_ms END " ++
                "WHERE id IN (" ++
                "SELECT memory_atom_id FROM agent_memory_items WHERE key = $4 " ++
                "AND (($5::text IS NULL AND session_id IS NULL AND actor_id = $6) OR ($5::text IS NOT NULL AND session_id = $5 AND actor_id = $6))" ++
                ") RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'agent_memory.status',$7,'agent_memory',$4,'{}'::jsonb,(extract(epoch from clock_timestamp()) * 1000)::bigint WHERE EXISTS (SELECT 1 FROM updated) RETURNING 1" ++
                ") SELECT count(*)::text FROM updated",
            &.{ status, verified_text, now_text, key, session_id, owner_actor, writer_actor_id orelse owner_actor },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    fn deprecateRuntimeAgentMemoryMirrors(self: *PostgresStore, allocator: std.mem.Allocator, store_name: []const u8, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: ?[]const u8) !void {
        const text = try self.queryParamsText(
            allocator,
            "WITH updated AS (" ++
                "UPDATE memory_atoms ma SET status = 'deprecated' " ++
                "WHERE ma.predicate = 'agent.memory' AND ma.object = $1 AND ma.status NOT IN ('deprecated','superseded','rejected') " ++
                "AND EXISTS (" ++
                "SELECT 1 FROM jsonb_array_elements_text(ma.source_ids_json) sid(id) " ++
                "JOIN sources s ON s.id = sid.id " ++
                "WHERE s.metadata_json->>'native' = 'agent_memory_runtime' " ++
                "AND s.metadata_json->>'store' = $2 " ++
                "AND s.metadata_json->>'key' = $1 " ++
                "AND (($3::text IS NULL AND s.metadata_json->>'session_id' IS NULL) OR s.metadata_json->>'session_id' = $3) " ++
                "AND s.metadata_json->>'owner_id' = $4" ++
                ") RETURNING ma.id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'agent_memory.runtime_mirrors_deprecated',$5,'agent_memory',$1,'{}'::jsonb,(extract(epoch from clock_timestamp()) * 1000)::bigint WHERE EXISTS (SELECT 1 FROM updated) RETURNING 1" ++
                ") SELECT count(*)::text FROM updated",
            &.{ key, store_name, session_id, owner_actor_id, writer_actor_id },
        );
        allocator.free(text);
    }

