    pub fn agentMemoryCount(self: *PostgresStore, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const parsed = try self.queryArrayParamsJson(
            allocator,
            "SELECT ami.session_id,ami.actor_id,ami.scope,ami.permissions_json FROM agent_memory_items ami JOIN memory_atoms ma ON ma.id = ami.memory_atom_id WHERE ma.status NOT IN ('rejected','deprecated','superseded')",
            &.{},
        );
        defer parsed.deinit();
        var count: usize = 0;
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            const scope = json.stringField(item.object, "scope") orelse "";
            const permissions = try rawJsonField(allocator, item.object, "permissions_json", "[]");
            if (!try self.pgAgentMemoryResultVisible(allocator, json.stringField(item.object, "actor_id") orelse "", scope, permissions, json.stringField(item.object, "session_id"), scopes_json, actor_id)) continue;
            count += 1;
        };
        return count;
    }

    pub fn saveMessage(self: *PostgresStore, session_id: []const u8, role: []const u8, content: []const u8, actor_id: ?[]const u8) !void {
        return self.saveMessageAt(session_id, role, content, ids.nowMs(), actor_id);
    }

    pub fn saveMessageAt(self: *PostgresStore, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8) !void {
        const actor = try requiredActorId(actor_id);
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        const created_at_text = try std.fmt.allocPrint(allocator, "{d}", .{created_at_ms});
        try self.runParams(
            allocator,
            "INSERT INTO session_messages (session_id,actor_id,role,content,created_at_ms) VALUES ($1,$2,$3,$4,$5::bigint)",
            &.{ session_id, actor, role, content, created_at_text },
        );
    }

    pub fn saveMessageAtOrdered(self: *PostgresStore, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !void {
        const order = event_order orelse return self.saveMessageAt(session_id, role, content, created_at_ms, actor_id);
