    pub fn loadMessages(self: *PostgresStore, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        return try self.readMessagesArrayParams(
            allocator,
            "SELECT role,content,created_at_ms FROM session_messages WHERE session_id = $1 AND ($2::text IS NULL OR actor_id = $2) ORDER BY created_at_ms ASC, id ASC",
            &.{ session_id, actor_id },
        );
    }

    fn readMessagesArrayParams(self: *PostgresStore, allocator: std.mem.Allocator, inner: []const u8, params: []const ?[]const u8) ![]Message {
        const parsed = try self.queryArrayParamsJson(allocator, inner, params);
        defer parsed.deinit();
        var out: std.ArrayListUnmanaged(Message) = .empty;
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            try out.append(allocator, .{ .role = try dupStringField(allocator, item.object, "role", ""), .content = try dupStringField(allocator, item.object, "content", ""), .created_at_ms = json.intField(item.object, "created_at_ms") orelse 0 });
        };
        return out.toOwnedSlice(allocator);
    }

    pub fn clearMessages(self: *PostgresStore, session_id: []const u8, actor_id: ?[]const u8) !void {
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        try self.runParams(
            allocator,
            "WITH deleted_messages AS (" ++
                "DELETE FROM session_messages WHERE session_id = $1 AND ($2::text IS NULL OR actor_id = $2) RETURNING 1" ++
                "), deleted_usage AS (" ++
                "DELETE FROM session_usage WHERE session_id = $1 AND ($2::text IS NULL OR actor_id = $2) RETURNING 1" ++
                ") SELECT ((SELECT count(*) FROM deleted_messages) + (SELECT count(*) FROM deleted_usage))::text",
            &.{ session_id, actor_id },
        );
    }

    pub fn clearMessagesOrdered(self: *PostgresStore, session_id: []const u8, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !void {
        const order = event_order orelse return self.clearMessages(session_id, actor_id);
        const actor = actor_id orelse return error.MissingActorId;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        try self.upsertAgentSessionMessageTombstone(allocator, actor, session_id, order);
        const timestamp_text = try std.fmt.allocPrint(allocator, "{d}", .{order.timestamp_ms});
        const origin_sequence_text = try std.fmt.allocPrint(allocator, "{d}", .{order.origin_sequence});
        try self.runParams(
            allocator,
            "DELETE FROM session_messages WHERE session_id = $1 AND actor_id = $2 AND (" ++
                "(CASE WHEN event_timestamp_ms = 0 THEN created_at_ms ELSE event_timestamp_ms END < $3::bigint) OR " ++
                "(CASE WHEN event_timestamp_ms = 0 THEN created_at_ms ELSE event_timestamp_ms END = $3::bigint AND origin_instance_id < $4) OR " ++
                "(CASE WHEN event_timestamp_ms = 0 THEN created_at_ms ELSE event_timestamp_ms END = $3::bigint AND origin_instance_id = $4 AND origin_sequence <= $5::bigint))",
            &.{ session_id, actor, timestamp_text, order.origin_instance_id, origin_sequence_text },
        );
        _ = try self.deleteUsageOrdered(session_id, actor, order);
    }

    fn agentSessionMessageTombstoneBlocksPut(self: *PostgresStore, allocator: std.mem.Allocator, actor_id: []const u8, session_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT timestamp_ms,origin_instance_id,origin_sequence FROM agent_session_tombstones WHERE actor_id = $1 AND session_id = $2 AND tombstone_type = 'messages' LIMIT 1",
            &.{ actor_id, session_id },
        );
        defer parsed.deinit();
        if (parsed.value != .object) return false;
        const stored_timestamp_ms = json.intField(parsed.value.object, "timestamp_ms") orelse return false;
        const stored_origin_instance_id = json.stringField(parsed.value.object, "origin_instance_id") orelse "";
        const stored_origin_sequence = json.intField(parsed.value.object, "origin_sequence") orelse 0;
        return compareAgentMemoryEventOrder(event_order, stored_timestamp_ms, stored_origin_instance_id, stored_origin_sequence) <= 0;
    }

    fn upsertAgentSessionMessageTombstone(self: *PostgresStore, allocator: std.mem.Allocator, actor_id: []const u8, session_id: []const u8, event_order: AgentMemoryEventOrder) !void {
