    pub fn saveUsageOrdered(self: *PostgresStore, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !void {
        const order = event_order orelse return self.saveUsage(session_id, total_tokens, actor_id);
        const actor = try requiredActorId(actor_id);
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        if (try self.agentSessionUsageTombstoneBlocksPut(allocator, actor, session_id, order)) return;
        if (try self.agentSessionUsageEventOrderWouldRegress(allocator, actor, session_id, order)) return;
        const total_tokens_text = try sessionUsageDbTotalTokensText(allocator, total_tokens);
        const timestamp_text = try std.fmt.allocPrint(allocator, "{d}", .{order.timestamp_ms});
        const origin_sequence_text = try std.fmt.allocPrint(allocator, "{d}", .{order.origin_sequence});
        try self.runParams(
            allocator,
            "INSERT INTO session_usage (session_id,actor_id,total_tokens,updated_at_ms,event_timestamp_ms,origin_instance_id,origin_sequence) VALUES ($1,$2,$3::bigint,$4::bigint,$4::bigint,$5,$6::bigint) " ++
                "ON CONFLICT(session_id, actor_id) DO UPDATE SET total_tokens=excluded.total_tokens, updated_at_ms=excluded.updated_at_ms, event_timestamp_ms=excluded.event_timestamp_ms, origin_instance_id=excluded.origin_instance_id, origin_sequence=excluded.origin_sequence",
            &.{ session_id, actor, total_tokens_text, timestamp_text, order.origin_instance_id, origin_sequence_text },
        );
    }

