    pub fn deleteUsageOrdered(self: *PostgresStore, session_id: []const u8, actor_id: ?[]const u8, event_order: ?AgentMemoryEventOrder) !bool {
        const order = event_order orelse return self.deleteUsage(session_id, actor_id);
        const actor = actor_id orelse return false;
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const allocator = arena.allocator();
        try self.upsertAgentSessionUsageTombstone(allocator, actor, session_id, order);
        if (try self.agentSessionUsageEventOrderIsOlderThanStored(allocator, actor, session_id, order)) return false;
        const text = try self.queryParamsText(
            allocator,
            "WITH deleted AS (DELETE FROM session_usage WHERE session_id = $1 AND actor_id = $2 RETURNING 1) SELECT count(*)::text FROM deleted",
            &.{ session_id, actor },
        );
        return (std.fmt.parseInt(usize, text, 10) catch 0) > 0;
    }

    fn agentSessionUsageEventOrderWouldRegress(self: *PostgresStore, allocator: std.mem.Allocator, actor_id: []const u8, session_id: []const u8, event_order: AgentMemoryEventOrder) !bool {
        const parsed = try self.queryRowParamsJson(
            allocator,
            "SELECT CASE WHEN event_timestamp_ms = 0 THEN updated_at_ms ELSE event_timestamp_ms END AS event_timestamp_ms, origin_instance_id, origin_sequence FROM session_usage WHERE actor_id = $1 AND session_id = $2 LIMIT 1",
            &.{ actor_id, session_id },
        );
        defer parsed.deinit();
        if (parsed.value != .object) return false;
        const stored_timestamp_ms = json.intField(parsed.value.object, "event_timestamp_ms") orelse return false;
        const stored_origin_instance_id = json.stringField(parsed.value.object, "origin_instance_id") orelse "";
        const stored_origin_sequence = json.intField(parsed.value.object, "origin_sequence") orelse 0;
        return compareAgentMemoryEventOrder(event_order, stored_timestamp_ms, stored_origin_instance_id, stored_origin_sequence) <= 0;
    }

