    pub fn scanConflicts(self: *PostgresStore, allocator: std.mem.Allocator, input: ConflictListInput) ![]KnowledgeConflict {
        const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{conflictScanAtomLimit(input.limit)});
        defer allocator.free(limit_text);
        const parsed = try self.queryArrayParamsJson(allocator, "SELECT id,subject_entity_id,predicate,object,text,scope,confidence,status,source_ids_json,evidence_ranges_json,created_by,created_at_ms,valid_from_ms,valid_until_ms,last_verified_at_ms,owner,permissions_json,tags_json FROM memory_atoms ORDER BY created_at_ms DESC LIMIT $1::bigint", &.{limit_text});
        defer parsed.deinit();
        var atoms: std.ArrayListUnmanaged(domain.MemoryAtom) = .empty;
        defer {
            for (atoms.items) |*atom| deinitMemoryAtom(allocator, atom);
            atoms.deinit(allocator);
        }
        if (parsed.value == .array) for (parsed.value.array.items) |item| {
            if (item != .object) continue;
            var atom = try readPgMemoryAtom(allocator, item.object);
            errdefer deinitMemoryAtom(allocator, &atom);
            if (!try self.recordVisibleWithPolicy(allocator, atom.scope, atom.permissions_json, input.scopes_json)) {
                deinitMemoryAtom(allocator, &atom);
                continue;
            }
            try atoms.ensureUnusedCapacity(allocator, 1);
            atoms.appendAssumeCapacity(atom);
        };
        for (atoms.items, 0..) |a, i| {
            if (!domain.isDefaultVisibleStatus(a.status)) continue;
            for (atoms.items[i + 1 ..]) |b| {
                if (!domain.isDefaultVisibleStatus(b.status)) continue;
                if (!pgSameConflictSubject(a, b)) continue;
                if (std.mem.eql(u8, a.object, b.object)) continue;
                try self.insertPgConflict(allocator, a, b);
            }
        }
        return try self.listConflicts(allocator, input);
    }

    fn conflictVisible(self: *PostgresStore, allocator: std.mem.Allocator, conflict: KnowledgeConflict, scopes_json: []const u8) !bool {
        if (std.mem.eql(u8, conflict.object_a_type, "memory_atom") and std.mem.eql(u8, conflict.object_b_type, "memory_atom")) {
            var a = (try self.getMemoryAtom(allocator, conflict.object_a_id)) orelse return false;
            defer deinitMemoryAtom(allocator, &a);
            var b = (try self.getMemoryAtom(allocator, conflict.object_b_id)) orelse return false;
            defer deinitMemoryAtom(allocator, &b);
            return (try self.recordVisibleWithPolicy(allocator, a.scope, a.permissions_json, scopes_json)) and
                (try self.recordVisibleWithPolicy(allocator, b.scope, b.permissions_json, scopes_json));
        }
        return try self.recordVisibleWithPolicy(allocator, conflict.scope, conflict.permissions_json, scopes_json);
    }

