    fn insertPgConflict(self: *PostgresStore, allocator: std.mem.Allocator, a: domain.MemoryAtom, b: domain.MemoryAtom) !void {
        const a_id = if (std.mem.lessThan(u8, a.id, b.id)) a.id else b.id;
        const b_id = if (std.mem.lessThan(u8, a.id, b.id)) b.id else a.id;
        const summary = try std.fmt.allocPrint(allocator, "Potential conflicting {s}: {s} vs {s}", .{ a.predicate, a.object, b.object });
        defer allocator.free(summary);
        const permissions = try combinedPermissionsJson(allocator, a.permissions_json, b.permissions_json);
        defer allocator.free(permissions);
        const id = try ids.make(allocator, "cnf_");
        defer allocator.free(id);
        const now = ids.nowMs();
        const now_text = try std.fmt.allocPrint(allocator, "{d}", .{now});
        defer allocator.free(now_text);
        const changed_text = try self.queryParamsText(
            allocator,
            "WITH inserted AS (" ++
                "INSERT INTO knowledge_conflicts (id,conflict_type,object_a_type,object_a_id,object_b_type,object_b_id,scope,permissions_json,status,summary,created_at_ms,resolved_at_ms) " ++
                "VALUES ($1,'memory_atom_conflict','memory_atom',$2,'memory_atom',$3,$4,$5::jsonb,'open',$6,$7::bigint,NULL) " ++
                "ON CONFLICT(conflict_type,object_a_id,object_b_id) DO NOTHING RETURNING id" ++
                "), audit AS (" ++
                "INSERT INTO audit_events (event_type,actor,object_type,object_id,payload_json,created_at_ms) SELECT 'conflict.detected',NULL,'knowledge_conflict',id,'{}'::jsonb,$7::bigint FROM inserted RETURNING 1" ++
                ") SELECT count(*)::text FROM inserted",
            &.{ id, a_id, b_id, a.scope, permissions, summary, now_text },
        );
        defer allocator.free(changed_text);
    }
};

fn pgScoreText(query: []const u8, text: []const u8) f64 {
    return retrieval_mod.lexicalScore(query, text);
}

const contextPackHasEvidence = store_context_pack.hasEvidence;
const contextPackRequiredScopesCoverRecord = store_context_pack.requiredScopesCoverRecord;
const validateContextPackResultRefs = store_context_pack.validateResultRefs;

fn appendOwnedSearchResultList(allocator: std.mem.Allocator, lists: *std.ArrayListUnmanaged([]domain.SearchResult), results: []domain.SearchResult) !void {
    if (results.len == 0) {
        allocator.free(results);
        return;
    }
    errdefer allocator.free(results);
    try lists.append(allocator, results);
}

fn appendCollectedSearchResultList(allocator: std.mem.Allocator, lists: *std.ArrayListUnmanaged([]domain.SearchResult), results: *std.ArrayListUnmanaged(domain.SearchResult)) !void {
    if (results.items.len == 0) {
        results.deinit(allocator);
        return;
    }
    const owned = try results.toOwnedSlice(allocator);
    try appendOwnedSearchResultList(allocator, lists, owned);
}

fn jsonArrayTextHasItems(value: []const u8) bool {
    const trimmed = std.mem.trim(u8, value, " \t\r\n");
    return trimmed.len > 2 and !std.mem.eql(u8, trimmed, "[]");
}

fn resultActorIsolatedGlobal(allocator: std.mem.Allocator, result_type: []const u8, scope: []const u8, permissions_json: []const u8, actor_id: ?[]const u8) bool {
    if (std.mem.eql(u8, result_type, "session_message")) return true;
    const actor = actor_id orelse return false;
    return domain.isActorOwnedAgentMemoryScope(scope, actor) or domain.permissionsContainActorGrant(allocator, permissions_json, actor);
}

fn pgSortSearchResults(items: []domain.SearchResult) void {
    var i: usize = 0;
    while (i < items.len) : (i += 1) {
        var best = i;
        var j = i + 1;
        while (j < items.len) : (j += 1) {
            if (items[j].score > items[best].score) best = j;
        }
        if (best != i) std.mem.swap(domain.SearchResult, &items[i], &items[best]);
    }
}

