    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.append(allocator, '[');
    var count: usize = 0;
    for (results) |result| {
        if (collect_citations) {
            const parsed = std.json.parseFromSlice(std.json.Value, allocator, result.source_ids_json, .{}) catch continue;
            defer parsed.deinit();
            if (parsed.value != .array) continue;
            for (parsed.value.array.items) |item| {
                if (item != .string) continue;
                try appendUniqueJsonStringGlobal(allocator, &out, &count, item.string);
            }
        } else if (std.mem.eql(u8, result.result_type, result_type)) {
            try appendUniqueJsonStringGlobal(allocator, &out, &count, result.id);
        }
    }
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn appendUniqueJsonStringGlobal(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), count: *usize, value: []const u8) !void {
    const needle = try json.stringLiteral(allocator, value);
    defer allocator.free(needle);
    if (std.mem.indexOf(u8, out.items, needle) != null) return;
    if (count.* > 0) try out.append(allocator, ',');
    try json.appendString(out, allocator, value);
    count.* += 1;
}

fn singleJsonString(allocator: std.mem.Allocator, value: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '[');
    try json.appendString(&out, allocator, value);
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn freeMemoryRecallCandidate(allocator: std.mem.Allocator, candidate: *MemoryRecallCandidate) void {
    allocator.free(candidate.object_type);
    allocator.free(candidate.object_id);
    allocator.free(candidate.object_key);
    allocator.free(candidate.scope);
    allocator.free(candidate.permissions_json);
    allocator.free(candidate.actor_id);
    allocator.free(candidate.session_id);
    allocator.free(candidate.store);
}

const memory_recall_default_candidate_limit: usize = 20;
const memory_recall_candidate_limit_max: usize = 100;
const memory_recall_candidate_fetch_multiplier: usize = 8;
const memory_recall_candidate_fetch_limit_max: usize = 1000;

fn memoryRecallCandidateLimit(limit: usize) usize {
    if (limit == 0) return memory_recall_default_candidate_limit;
    return @min(limit, memory_recall_candidate_limit_max);
}

fn memoryRecallCandidateFetchLimit(limit: usize) usize {
    const expanded = bounded_int.saturatingUsizeMul(limit, memory_recall_candidate_fetch_multiplier);
    return @min(@max(expanded, limit), memory_recall_candidate_fetch_limit_max);
}

fn cleanRecallScore(score: f64) f64 {
    if (score != score or score < 0) return 0;
    return score;
}

fn jsonCounterField(obj: std.json.ObjectMap, field: []const u8) usize {
    return nonNegativeIntToUsize(json.intField(obj, field) orelse 0);
}

const nonNegativeIntToUsize = bounded_int.nonNegativeI64ToUsize;
const nonNegativeIntToU64 = bounded_int.nonNegativeI64ToU64;
const saturatingCounterSum = bounded_int.saturatingUsizeSum;

fn sessionUsageDbTotalTokens(total_tokens: u64) i64 {
    return bounded_int.u64ToI64Saturating(total_tokens);
}

fn sessionUsageDbTotalTokensText(allocator: std.mem.Allocator, total_tokens: u64) ![]u8 {
    return std.fmt.allocPrint(allocator, "{d}", .{sessionUsageDbTotalTokens(total_tokens)});
}

fn sqliteChangesToUsize(changes: c_int) usize {
    return bounded_int.nonNegativeCIntToUsize(changes);
}

