test "memory recall candidate limits bound fetch windows without overflow" {
    try std.testing.expectEqual(@as(usize, memory_recall_default_candidate_limit), memoryRecallCandidateLimit(0));
    try std.testing.expectEqual(@as(usize, 42), memoryRecallCandidateLimit(42));
