    try std.testing.expectEqual(@as(usize, 0), memoryRecallCandidateFetchLimit(0));
    try std.testing.expectEqual(@as(usize, 80), memoryRecallCandidateFetchLimit(10));
    try std.testing.expectEqual(@as(usize, memory_recall_candidate_fetch_limit_max), memoryRecallCandidateFetchLimit(200));
    try std.testing.expectEqual(@as(usize, memory_recall_candidate_fetch_limit_max), memoryRecallCandidateFetchLimit(std.math.maxInt(usize)));
