fn memoryRecallCandidateVisible(allocator: std.mem.Allocator, candidate: MemoryRecallCandidate, request_scopes_json: []const u8, request_actor_id: ?[]const u8) bool {
    const actor = request_actor_id orelse return false;
    const same_owner = candidate.actor_id.len > 0 and std.mem.eql(u8, candidate.actor_id, actor);
    const permissions_visible = permissionsVisibleForActor(allocator, candidate.permissions_json, request_scopes_json, request_actor_id);
    const record_visible = domain.scopeVisible(candidate.scope, request_scopes_json) and permissions_visible;
    const actor_private_scope = same_owner and (domain.isActorOwnedAgentMemoryScope(candidate.scope, actor) or
        (candidate.session_id.len > 0 and std.mem.startsWith(u8, candidate.scope, "session:")));
    if (!(record_visible or (actor_private_scope and permissions_visible))) return false;
    if (candidate.session_id.len > 0 and !sessionVisibleForScopes(allocator, candidate.session_id, request_scopes_json)) return false;
    return true;
}

fn recallPromotionScore(candidate: MemoryRecallCandidate) f64 {
    return recallPromotionScoreAt(candidate, ids.nowMs());
}

fn recallPromotionScoreAt(candidate: MemoryRecallCandidate, now_ms: i64) f64 {
    const count_signal = clamp01(@as(f64, @floatFromInt(candidate.recall_count)) / 5.0);
    const query_signal = clamp01(@as(f64, @floatFromInt(candidate.unique_queries)) / 3.0);
    const score_signal = clamp01(candidate.max_score);
    const age_ms = time_math.elapsedSinceMs(now_ms, candidate.last_recalled_at_ms);
    const age_days = @as(f64, @floatFromInt(age_ms)) / 86_400_000.0;
    const recency_signal = 1.0 / (1.0 + age_days / 14.0);
    return 0.45 * count_signal + 0.25 * query_signal + 0.20 * score_signal + 0.10 * recency_signal;
}

fn clamp01(value: f64) f64 {
    if (value != value or value <= 0) return 0;
    if (value >= 1) return 1;
    return value;
}

test "memory recall promotion score age is overflow safe" {
    const base = MemoryRecallCandidate{
        .object_type = "agent_memory",
        .object_id = "mem",
        .object_key = "pref",
        .scope = "public",
        .permissions_json = "[]",
        .actor_id = "agent:a",
        .session_id = "",
        .store = "scratch",
        .recall_count = 5,
        .unique_queries = 3,
        .max_score = 1.0,
        .avg_score = 1.0,
        .first_recalled_at_ms = 0,
        .last_recalled_at_ms = 1_000,
        .promotion_score = 0,
    };

    try std.testing.expectApproxEqAbs(@as(f64, 1.0), recallPromotionScoreAt(base, 1_000), 0.000001);

    var future = base;
    future.last_recalled_at_ms = 2_000;
    try std.testing.expectApproxEqAbs(@as(f64, 1.0), recallPromotionScoreAt(future, 1_000), 0.000001);

    var ancient = base;
    ancient.last_recalled_at_ms = std.math.minInt(i64);
    const ancient_score = recallPromotionScoreAt(ancient, std.math.maxInt(i64));
    try std.testing.expect(std.math.isFinite(ancient_score));
    try std.testing.expect(ancient_score >= 0.9);
    try std.testing.expect(ancient_score < 1.0);
}

test "json string helpers escape ids before dedupe" {
    const allocator = std.testing.allocator;
    const escaped_array = try singleJsonString(allocator, "src_\"quoted\\id");
    defer allocator.free(escaped_array);

    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, escaped_array, .{});
    defer parsed.deinit();
    try std.testing.expectEqualStrings("src_\"quoted\\id", parsed.value.array.items[0].string);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    defer out.deinit(allocator);
    try out.append(allocator, '[');
    var count: usize = 0;
    try appendUniqueJsonStringGlobal(allocator, &out, &count, "src_\"quoted\\id");
    try appendUniqueJsonStringGlobal(allocator, &out, &count, "src_\"quoted\\id");
    try out.append(allocator, ']');

    var deduped = try std.json.parseFromSlice(std.json.Value, allocator, out.items, .{});
    defer deduped.deinit();
    try std.testing.expectEqual(@as(usize, 1), deduped.value.array.items.len);
    try std.testing.expectEqualStrings("src_\"quoted\\id", deduped.value.array.items[0].string);
}

test "required access fails closed for malformed permissions json" {
    const allocator = std.testing.allocator;

    const not_json = try requiredAccessJsonGlobal(allocator, "public", "not-json", null);
    defer allocator.free(not_json);
    try std.testing.expect(std.mem.indexOf(u8, not_json, access.malformed_permissions_required_gate) != null);
    try std.testing.expect(!requiredScopesVisible(not_json, "[\"public\"]"));
    try std.testing.expect(requiredScopesVisible(not_json, "[\"admin\"]"));

    const object_json = try requiredAccessJsonGlobal(allocator, "public", "{\"permission\":\"public\"}", null);
    defer allocator.free(object_json);
    try std.testing.expect(std.mem.indexOf(u8, object_json, access.malformed_permissions_required_gate) != null);
    try std.testing.expect(!requiredScopesVisible(object_json, "[\"public\"]"));

    const mixed_array = try requiredAccessJsonGlobal(allocator, "public", "[\"public\",42]", null);
    defer allocator.free(mixed_array);
    try std.testing.expect(std.mem.indexOf(u8, mixed_array, access.malformed_permissions_required_gate) != null);
    try std.testing.expect(!requiredScopesVisible(mixed_array, "[\"public\"]"));
}

fn entityIdsJson(allocator: std.mem.Allocator, entities: []const domain.Entity) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '[');
    for (entities, 0..) |entity, i| {
        if (i > 0) try out.append(allocator, ',');
        try json.appendString(&out, allocator, entity.id);
    }
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn appendUniqueEntity(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.Entity), entity: domain.Entity) !void {
    for (out.items) |existing| {
        if (std.mem.eql(u8, existing.id, entity.id)) return;
    }
    try out.append(allocator, entity);
}

fn evidenceRangeJson(allocator: std.mem.Allocator, source_id: []const u8, text_len: usize, kind: []const u8) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.appendSlice(allocator, "[{\"source_id\":");
    try json.appendString(&out, allocator, source_id);
    try out.appendSlice(allocator, ",\"start\":0,\"end\":");
    try out.print(allocator, "{d}", .{text_len});
    try out.appendSlice(allocator, ",\"kind\":");
    try json.appendString(&out, allocator, kind);
    try out.appendSlice(allocator, "}]");
    return out.toOwnedSlice(allocator);
}

fn testingSqliteCount(store: *Store, sql: [*:0]const u8) !i64 {
    return switch (store.backend) {
        .sqlite => |*s| s.countSql(sql),
        .postgres => error.UnsupportedBackend,
    };
}

fn testingSqliteExec(store: *Store, sql: [*:0]const u8) !void {
    return switch (store.backend) {
        .sqlite => |*s| s.exec(sql),
        .postgres => error.UnsupportedBackend,
    };
}

fn testingSqliteSetOrderMs(
    store: *Store,
    allocator: std.mem.Allocator,
    table: []const u8,
    order_column: []const u8,
    id_column: []const u8,
    id: []const u8,
    order_ms: i64,
) !void {
    const sql_text = try std.fmt.allocPrint(
        allocator,
        "UPDATE {s} SET {s} = {d} WHERE {s} = '{s}'",
        .{ table, order_column, order_ms, id_column, id },
    );
    const sql = try allocator.dupeZ(u8, sql_text);
    try testingSqliteExec(store, sql);
}

fn testingRebuildSqliteFtsIndexes(store: *Store) !void {
    return switch (store.backend) {
        .sqlite => |*s| s.rebuildSqliteFtsIndexes(),
        .postgres => error.UnsupportedBackend,
    };
}

fn testingRunQueuedAgentMemoryMirrorJobs(store: *Store, allocator: std.mem.Allocator) !usize {
    const jobs = try store.listJobs(allocator, .{ .scopes_json = "[\"admin\"]", .status = "queued", .limit = 100 });
    defer freeLoadedJobs(allocator, jobs);
    var mirrored: usize = 0;
    for (jobs) |job| {
        if (!std.mem.eql(u8, job.job_type, "agent_memory_mirror")) continue;
        const result_json = try store.runAgentMemoryMirrorJob(allocator, job);
        defer allocator.free(result_json);
        mirrored += 1;
    }
    return mirrored;
}

fn testingRawSqliteExec(db: *c.sqlite3, sql: [*:0]const u8) !void {
    var err_msg: [*c]u8 = null;
    const rc = c.sqlite3_exec(db, sql, null, null, &err_msg);
    if (rc != c.SQLITE_OK) {
        if (err_msg) |msg| c.sqlite3_free(msg);
        return error.SqlExecFailed;
    }
}

