            .to_entity_id = hidden_to.id,
            .scope = "project:secret",
            .permissions_json = "[\"project:secret\"]",
            .status = "verified",
        });
        try testingSqliteSetOrderMs(&store, alloc, "relations", "created_at_ms", "id", hidden_relation_id, @as(i64, 1000) + @as(i64, @intCast(i)));

        const hidden_pack_id = try std.fmt.allocPrint(alloc, "ctx_hidden_primitive_window_{d}", .{i});
        _ = try store.importContextPackSnapshot(alloc, .{
            .id = hidden_pack_id,
            .query = "hidden context pack before visible",
            .generated_summary = "hidden context pack summary",
            .required_scopes_json = "[\"project:secret\"]",
            .suppress_feed = true,
        });
        try testingSqliteSetOrderMs(&store, alloc, "context_packs", "created_at_ms", "id", hidden_pack_id, @as(i64, 1000) + @as(i64, @intCast(i)));
    }

    const input: PrimitiveListInput = .{ .limit = 1, .scopes_json = "[\"public\"]" };

    const sources = try store.listSourcesVisible(alloc, input);
    try std.testing.expectEqual(@as(usize, 1), sources.len);
    try std.testing.expectEqualStrings(visible_source.id, sources[0].id);

    const artifacts = try store.listArtifactsVisible(alloc, input);
    try std.testing.expectEqual(@as(usize, 1), artifacts.len);
    try std.testing.expectEqualStrings(visible_artifact.id, artifacts[0].id);

    const entities = try store.listEntitiesVisible(alloc, input);
    try std.testing.expectEqual(@as(usize, 1), entities.len);
    try std.testing.expectEqualStrings(visible_entity.id, entities[0].id);

    const relations = try store.listRelationsVisible(alloc, input);
    try std.testing.expectEqual(@as(usize, 1), relations.len);
    try std.testing.expectEqualStrings(visible_relation.id, relations[0].id);

    const packs = try store.listContextPacksVisible(alloc, input);
    try std.testing.expectEqual(@as(usize, 1), packs.len);
    try std.testing.expectEqualStrings(visible_pack.id, packs[0].id);
}

