test "sqlite vector search honors minimum score threshold" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const query_json = try vector_mod.embeddingToJson(alloc, &[_]f32{ 1, 0, 0 });
    const weak_json = try vector_mod.embeddingToJson(alloc, &[_]f32{ 0.5, 0.8660254, 0 });
    const atom_strong = try store.createMemoryAtom(alloc, .{ .text = "strong vector memory", .scope = "public", .created_by = "human" });
    const atom_weak = try store.createMemoryAtom(alloc, .{ .text = "weak vector memory", .scope = "public", .created_by = "human" });
    const strong_chunk = try store.upsertVectorChunk(alloc, .{ .object_id = atom_strong.id, .text = atom_strong.text, .scope = atom_strong.scope, .embedding_json = query_json, .dimensions = 3 });
    const weak_chunk = try store.upsertVectorChunk(alloc, .{ .object_id = atom_weak.id, .text = atom_weak.text, .scope = atom_weak.scope, .embedding_json = weak_json, .dimensions = 3 });

    const unfiltered = try store.vectorSearch(alloc, .{ .embedding_json = query_json, .scopes_json = "[\"public\"]", .limit = 10 });
    try std.testing.expectEqual(@as(usize, 2), unfiltered.len);

    const filtered = try store.vectorSearch(alloc, .{ .embedding_json = query_json, .scopes_json = "[\"public\"]", .limit = 10, .min_score = 0.75 });
    try std.testing.expectEqual(@as(usize, 1), filtered.len);
    try std.testing.expectEqualStrings(strong_chunk.id, filtered[0].id);

    const hydrated = try store.vectorSearchCandidates(alloc, .{ .embedding_json = query_json, .scopes_json = "[\"public\"]", .limit = 10, .min_score = 0.75 }, &[_]vector_runtime.Candidate{
        .{ .vector_id = weak_chunk.id, .score = 0.5 },
        .{ .vector_id = strong_chunk.id, .score = 0.99 },
    });
    try std.testing.expectEqual(@as(usize, 1), hydrated.len);
    try std.testing.expectEqualStrings(strong_chunk.id, hydrated[0].id);
}

test "sqlite vector ann side index tracks chunk lifecycle and search falls back" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{ .vector_backend = .{
        .sqlite_ann_candidate_multiplier = 9,
        .sqlite_ann_min_candidates = 77,
    } });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const first_embedding = try vector_mod.embeddingToJson(alloc, &[_]f32{ 1, 0, 0, 0 });
    const second_embedding = try vector_mod.embeddingToJson(alloc, &[_]f32{ 0, 1, 0, 0 });
    const atom = try store.createMemoryAtom(alloc, .{ .text = "ann indexed memory", .scope = "public", .created_by = "human" });
    const first_chunk = try store.upsertVectorChunk(alloc, .{
        .object_id = atom.id,
        .text = atom.text,
        .scope = atom.scope,
        .embedding_json = first_embedding,
        .dimensions = 4,
    });
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunk_ann"));
    var ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expect(ann_stats.enabled);
    try std.testing.expectEqual(@as(u32, 9), ann_stats.candidate_multiplier);
    try std.testing.expectEqual(@as(u32, 77), ann_stats.min_candidates);
    try std.testing.expectEqual(@as(usize, 1), ann_stats.indexed_chunks);
    try std.testing.expectEqual(@as(usize, 0), ann_stats.missing_chunks);
    try std.testing.expectEqual(@as(usize, 0), ann_stats.stale_chunks);

    const updated_chunk = try store.upsertVectorChunk(alloc, .{
        .object_id = atom.id,
        .text = "ann indexed memory updated",
        .scope = atom.scope,
        .embedding_json = second_embedding,
        .dimensions = 4,
    });
    try std.testing.expectEqualStrings(first_chunk.id, updated_chunk.id);
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunk_ann"));
    try testingSqliteExec(&store, "UPDATE vector_chunk_ann SET source_updated_at_ms = 0");
    ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expectEqual(@as(usize, 1), ann_stats.stale_chunks);

    switch (store.backend) {
        .sqlite => |*sqlite| try sqlite.rebuildSqliteVectorAnnIndex(),
        .postgres => unreachable,
    }
    ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expectEqual(@as(usize, 0), ann_stats.stale_chunks);

    const indexed_matches = try store.vectorSearch(alloc, .{ .embedding_json = second_embedding, .scopes_json = "[\"public\"]", .limit = 5 });
    try std.testing.expectEqual(@as(usize, 1), indexed_matches.len);
    try std.testing.expectEqualStrings(updated_chunk.id, indexed_matches[0].id);

    try testingSqliteExec(&store, "DELETE FROM vector_chunk_ann");
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunk_ann"));
    ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expectEqual(@as(usize, 0), ann_stats.indexed_chunks);
    try std.testing.expectEqual(@as(usize, 1), ann_stats.missing_chunks);
    const fallback_matches = try store.vectorSearch(alloc, .{ .embedding_json = second_embedding, .scopes_json = "[\"public\"]", .limit = 5 });
    try std.testing.expectEqual(@as(usize, 1), fallback_matches.len);
    try std.testing.expectEqualStrings(updated_chunk.id, fallback_matches[0].id);

    switch (store.backend) {
        .sqlite => |*sqlite| try sqlite.rebuildSqliteVectorAnnIndex(),
        .postgres => unreachable,
    }
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunk_ann"));
    ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expectEqual(@as(usize, 1), ann_stats.indexed_chunks);
    try std.testing.expectEqual(@as(usize, 0), ann_stats.missing_chunks);
    try std.testing.expect(try store.deleteVectorChunk(alloc, updated_chunk.id, "agent:vector"));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store, "SELECT COUNT(*) FROM vector_chunk_ann"));
    ann_stats = try store.sqliteVectorAnnStats();
    try std.testing.expectEqual(@as(usize, 0), ann_stats.indexed_chunks);
    try std.testing.expectEqual(@as(usize, 0), ann_stats.missing_chunks);
}

