test "sqlite search and context packs expose matched vector section metadata" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const embedding = try vector_mod.embeddingToJson(alloc, &[_]f32{ 1, 0 });
    const artifact = try store.createArtifact(alloc, .{
        .title = "Sectioned Product Spec",
        .body = "# Product\nLarge unrelated intro that should not replace the matched vector chunk.\n## Storage\nCanonical storage section.",
        .scope = "public",
        .status = "published",
    });
    _ = try store.upsertVectorChunk(alloc, .{
        .object_type = "artifact",
        .object_id = artifact.id,
        .text = "## Storage\nMatched vector chunk only.",
        .scope = artifact.scope,
        .permissions_json = artifact.permissions_json,
        .heading_path_json = "[\"# Product\",\"## Storage\"]",
        .embedding_json = embedding,
        .dimensions = 2,
    });

    const results = try store.search(alloc, .{
        .query = "vector section metadata",
        .query_embedding_json = embedding,
        .scopes_json = "[\"public\"]",
        .limit = 5,
        .use_temporal_decay = false,
        .use_mmr = false,
    });
    try std.testing.expectEqual(@as(usize, 1), results.len);
    try std.testing.expectEqualStrings("artifact", results[0].result_type);
    try std.testing.expectEqualStrings("## Storage\nMatched vector chunk only.", results[0].text);
    try std.testing.expectEqualStrings("[\"# Product\",\"## Storage\"]", results[0].heading_path_json);

    var encoded: std.ArrayListUnmanaged(u8) = .empty;
    try results[0].writeJson(alloc, &encoded);
    const result_json = try encoded.toOwnedSlice(alloc);
    try std.testing.expect(std.mem.indexOf(u8, result_json, "\"heading_path\":[\"# Product\",\"## Storage\"]") != null);

    const pack = try store.createContextPack(alloc, .{
        .query = "vector section metadata",
        .query_embedding_json = embedding,
        .scopes_json = "[\"public\"]",
        .retrieval_limit = 5,
        .persist = true,
        .use_temporal_decay = false,
        .use_mmr = false,
    });
    try std.testing.expect(std.mem.indexOf(u8, pack.sections_json, "\"heading_path\":[\"# Product\",\"## Storage\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, pack.included_result_refs_json, "\"heading_path\":[\"# Product\",\"## Storage\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, pack.generated_summary, "[# Product > ## Storage] ## Storage\nMatched vector chunk only.") != null);
    try std.testing.expect(std.mem.indexOf(u8, pack.generated_summary, "Large unrelated intro") == null);

    const persisted = (try store.contextPackById(alloc, pack.id)).?;
    try std.testing.expectEqualStrings(pack.sections_json, persisted.sections_json);
    try std.testing.expectEqualStrings(pack.citations_json, persisted.citations_json);
    try std.testing.expectEqualStrings(pack.forbidden_assumptions_json, persisted.forbidden_assumptions_json);
    try std.testing.expectEqualStrings(pack.suggested_next_steps_json, persisted.suggested_next_steps_json);
    try std.testing.expect(std.mem.indexOf(u8, persisted.sections_json, "\"heading_path\":[\"# Product\",\"## Storage\"]") != null);
}

test "lancedb external vector index runs through canonical outbox and ACL hydration" {
    if (builtin.os.tag == .windows) return error.SkipZigTest;

    const tmp_random = try ids.make(std.testing.allocator, "");
    defer std.testing.allocator.free(tmp_random);
    const tmp_name = try std.fmt.allocPrint(std.testing.allocator, "np_lancedb_e2e_{d}_{s}", .{ std.c.getpid(), tmp_random });
    defer std.testing.allocator.free(tmp_name);
    const tmp_path = try std.fmt.allocPrint(std.testing.allocator, ".zig-cache/tmp/{s}", .{tmp_name});
    defer std.testing.allocator.free(tmp_path);
    try std.Io.Dir.cwd().createDirPath(compat.io(), tmp_path);
    defer std.Io.Dir.cwd().deleteTree(compat.io(), tmp_path) catch {};

    const command = try std.fmt.allocPrint(std.testing.allocator, "{s}/lancedb-adapter", .{tmp_path});
    defer std.testing.allocator.free(command);
    const lancedb_uri = try std.fmt.allocPrint(std.testing.allocator, "{s}/lancedb", .{tmp_path});
    defer std.testing.allocator.free(lancedb_uri);
    const script =
        \\#!/bin/sh
        \\payload="$(cat)"
        \\if [ "$1" = "upsert" ]; then
        \\  echo "$payload" | grep '"rows"' >/dev/null || exit 2
        \\  echo "$payload" | grep '"vector_id":"vec:11:memory_atom:mem_lancedb_e2e:0"' >/dev/null || exit 3
        \\  echo '{"status":"ok"}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "search" ]; then
        \\  echo "$payload" | grep '\[1,0\]' >/dev/null || exit 4
        \\  echo '{"matches":[{"id":"vec:11:memory_atom:mem_lancedb_e2e:0","score":0.99},{"id":"vec_missing","score":1.0}]}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "delete" ]; then
        \\  echo "$payload" | grep '"vector_id":"vec:11:memory_atom:mem_lancedb_e2e:0"' >/dev/null || exit 5
        \\  echo '{"status":"ok"}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "reset" ]; then
        \\  echo '{"status":"ok"}'
        \\  exit 0
        \\fi
        \\exit 1
        \\
    ;
    var file = try std.Io.Dir.cwd().createFile(compat.io(), command, .{ .read = true });
    var buffer: [1024]u8 = undefined;
    var writer: std.Io.File.Writer = .init(file, compat.io(), &buffer);
    try writer.interface.writeAll(script);
    try writer.interface.flush();
    try file.setPermissions(compat.io(), .executable_file);
    file.close(compat.io());

    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{ .vector_backend = .{
        .backend = .lancedb,
        .lancedb_uri = lancedb_uri,
        .lancedb_command = command,
        .collection = "vectors",
        .timeout_secs = 10,
    } });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const embedding = try vector_mod.embeddingToJson(alloc, &[_]f32{ 1, 0 });
    const atom = try store.createMemoryAtom(alloc, .{ .id = "mem_lancedb_e2e", .text = "lancedb external memory", .scope = "public", .created_by = "human" });
    const chunk = try store.upsertVectorChunk(alloc, .{ .object_id = atom.id, .text = atom.text, .scope = atom.scope, .embedding_json = embedding, .dimensions = 2 });
    try std.testing.expectEqualStrings("vec:11:memory_atom:mem_lancedb_e2e:0", chunk.id);
    try std.testing.expectEqual(@as(usize, 1), try store.countVectorOutbox("pending"));

    const indexed = try store.runVectorOutbox(10);
    try std.testing.expectEqual(@as(usize, 1), indexed.processed);
    try std.testing.expectEqual(@as(usize, 1), try store.countVectorOutbox("indexed_external"));

    const matches = try store.vectorSearch(alloc, .{ .embedding_json = embedding, .scopes_json = "[\"public\"]", .limit = 10, .strict_external = true });
    try std.testing.expectEqual(@as(usize, 1), matches.len);
    try std.testing.expectEqualStrings(chunk.id, matches[0].id);
    try std.testing.expectApproxEqAbs(@as(f32, 0.99), matches[0].score, 0.0001);

    try std.testing.expect(try store.deleteVectorChunk(alloc, chunk.id, "agent:vector"));
    const deleted = try store.runVectorOutbox(10);
    try std.testing.expectEqual(@as(usize, 1), deleted.processed);
    try std.testing.expectEqual(@as(usize, 1), try store.countVectorOutbox("deleted_external"));

    const after_delete = try store.vectorSearch(alloc, .{ .embedding_json = embedding, .scopes_json = "[\"public\"]", .limit = 10, .strict_external = true });
    try std.testing.expectEqual(@as(usize, 0), after_delete.len);
}

fn multiVectorAdapterScript(
    allocator: std.mem.Allocator,
    vector_id: []const u8,
    score: []const u8,
    upsert_marker: []const u8,
    delete_marker: []const u8,
    reset_marker: []const u8,
) ![]u8 {
    return std.fmt.allocPrint(allocator,
        \\#!/bin/sh
        \\payload="$(cat)"
        \\if [ "$1" = "upsert" ]; then
        \\  echo "$payload" | grep '"vector_id":"{s}"' >/dev/null || exit 3
        \\  touch "{s}"
        \\  echo '{{"status":"ok"}}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "search" ]; then
        \\  echo '{{"matches":[{{"id":"{s}","score":{s}}},{{"id":"missing_from_canonical","score":1.0}}]}}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "delete" ]; then
        \\  echo "$payload" | grep '"vector_id":"{s}"' >/dev/null || exit 4
        \\  touch "{s}"
        \\  echo '{{"status":"ok"}}'
        \\  exit 0
        \\fi
        \\if [ "$1" = "reset" ]; then
        \\  touch "{s}"
        \\  echo '{{"status":"ok"}}'
        \\  exit 0
        \\fi
        \\exit 1
        \\
    , .{ vector_id, upsert_marker, vector_id, score, vector_id, delete_marker, reset_marker });
}

fn writeExecutableTestFile(path: []const u8, content: []const u8) !void {
    var file = try std.Io.Dir.cwd().createFile(compat.io(), path, .{ .read = true });
    var buffer: [1024]u8 = undefined;
    var writer: std.Io.File.Writer = .init(file, compat.io(), &buffer);
    try writer.interface.writeAll(content);
    try writer.interface.flush();
    try file.setPermissions(compat.io(), .executable_file);
    file.close(compat.io());
}

fn expectFileExists(path: []const u8) !void {
    const bytes = try std.Io.Dir.cwd().readFileAlloc(compat.io(), path, std.testing.allocator, .limited(16));
    std.testing.allocator.free(bytes);
}

