test "sqlite primary runtime primitive mirror is durable job based" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{ .backend = .memory_lru },
    });
    defer store.deinit();
    const allocator = std.testing.allocator;

    const source = try store.createSource(allocator, .{
        .title = "Runtime mirrored source",
        .content = "runtime mirror should own and release temporary slices",
        .scope = "public",
        .actor_id = "agent:mirror-owner",
    });
    defer {
        allocator.free(source.id);
        allocator.free(source.related_entities_json);
    }

    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store, "SELECT COUNT(*) FROM jobs WHERE job_type = 'agent_memory_mirror' AND object_type = 'source'"));
    const before_jobs = try store.agentMemoryListVisibleRouted(allocator, "primitive:source", null, "agent:mirror-reader", "[\"public\"]", .{ .target = .runtime });
    defer freeAgentMemorySlice(allocator, before_jobs);
    try std.testing.expectEqual(@as(usize, 0), before_jobs.len);
    try std.testing.expectEqual(@as(usize, 1), try testingRunQueuedAgentMemoryMirrorJobs(&store, allocator));

    const mirrors = try store.agentMemoryListVisibleRouted(allocator, "primitive:source", null, "agent:mirror-reader", "[\"public\"]", .{ .target = .runtime });
    defer freeAgentMemorySlice(allocator, mirrors);
    try std.testing.expectEqual(@as(usize, 1), mirrors.len);
    try std.testing.expectEqualStrings("primitive:source", mirrors[0].category);
    try std.testing.expectEqualStrings("public", mirrors[0].scope);

    const actorless = try store.createSource(allocator, .{
