    const applied = try store.applyFeedMemoryAtomAtomic(allocator, .{
        .event = .{
            .event_type = "memory_atom.put",
            .operation = "put",
            .object_type = "memory_atom",
            .object_id = "feed-memory-atom",
            .scope = "public",
            .permissions_json = "[]",
            .actor_id = "agent:feed-mirror",
            .payload_json = "{\"text\":\"feed mirror atom\"}",
        },
        .prepared = .{ .atom = .{
            .text = "feed mirror atom",
            .scope = "public",
            .actor_id = "agent:feed-mirror",
            .storage_route = .{ .target = .runtime },
        } },
    });
