test "sqlite context pack preserves reranked preselected order when requested" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    var reranked_results = [_]domain.SearchResult{
        .{ .id = "src_first", .result_type = "source", .title = "Source First", .text = "Source was selected first by rerank", .scope = "public", .status = "active", .score = 0.2, .source_ids_json = "[\"src_first\"]", .created_at_ms = 1, .confidence = 0.6 },
        .{ .id = "mem_decision", .result_type = "memory_atom", .title = "Decision", .text = "Decision: deterministic context pack sort would normally promote this", .scope = "public", .status = "verified", .score = 0.9, .source_ids_json = "[]", .created_at_ms = 2, .confidence = 0.9 },
    };
    const preserved = try store.createContextPack(alloc, .{
        .query = "reranked order",
        .scopes_json = "[\"public\"]",
        .persist = false,
        .preselected_results = reranked_results[0..],
        .preserve_result_order = true,
    });
    const preserved_source_pos = std.mem.indexOf(u8, preserved.included_result_refs_json, "src_first") orelse return error.TestExpectedEqual;
    const preserved_decision_pos = std.mem.indexOf(u8, preserved.included_result_refs_json, "mem_decision") orelse return error.TestExpectedEqual;
    try std.testing.expect(preserved_source_pos < preserved_decision_pos);

    var sorted_results = [_]domain.SearchResult{
        .{ .id = "src_first", .result_type = "source", .title = "Source First", .text = "Source was selected first by rerank", .scope = "public", .status = "active", .score = 0.2, .source_ids_json = "[\"src_first\"]", .created_at_ms = 1, .confidence = 0.6 },
        .{ .id = "mem_decision", .result_type = "memory_atom", .title = "Decision", .text = "Decision: deterministic context pack sort should promote this", .scope = "public", .status = "verified", .score = 0.9, .source_ids_json = "[]", .created_at_ms = 2, .confidence = 0.9 },
    };
    const sorted = try store.createContextPack(alloc, .{
        .query = "default order",
        .scopes_json = "[\"public\"]",
        .persist = false,
        .preselected_results = sorted_results[0..],
    });
    const sorted_source_pos = std.mem.indexOf(u8, sorted.included_result_refs_json, "src_first") orelse return error.TestExpectedEqual;
    const sorted_decision_pos = std.mem.indexOf(u8, sorted.included_result_refs_json, "mem_decision") orelse return error.TestExpectedEqual;
    try std.testing.expect(sorted_decision_pos < sorted_source_pos);
}

test "sqlite runtime agent memory mirrors deprecate stale versions per named store" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory_stores = &.{
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
            .{ .name = "archive", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    const scratch = AgentMemoryStorageRoute.parse("scratch");
    const archive = AgentMemoryStorageRoute.parse("archive");

    _ = try store.agentMemoryStoreRouted(alloc, .{ .key = "pref.lifecycle", .content = "scratch-v1", .actor_id = "agent:lifecycle" }, scratch);
    _ = try store.agentMemoryStoreRouted(alloc, .{ .key = "pref.lifecycle", .content = "archive-v1", .actor_id = "agent:lifecycle" }, archive);
    try std.testing.expectEqual(@as(i64, 2), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.owner_id') = 'agent:lifecycle'
        \\)
    ));

    _ = try store.agentMemoryStoreRouted(alloc, .{ .key = "pref.lifecycle", .content = "scratch-v2", .actor_id = "agent:lifecycle" }, scratch);
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.store') = 'scratch'
        \\    AND json_extract(s.metadata_json, '$.owner_id') = 'agent:lifecycle'
        \\)
    ));
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.store') = 'archive'
        \\    AND json_extract(s.metadata_json, '$.owner_id') = 'agent:lifecycle'
        \\)
    ));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.text = 'scratch-v1' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.store') = 'scratch'
        \\)
    ));

    try std.testing.expect(try store.agentMemoryDeleteRouted("pref.lifecycle", null, "agent:lifecycle", "agent:lifecycle", scratch));
    try std.testing.expectEqual(@as(i64, 0), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.store') = 'scratch'
        \\    AND json_extract(s.metadata_json, '$.owner_id') = 'agent:lifecycle'
        \\)
    ));
    try std.testing.expectEqual(@as(i64, 1), try testingSqliteCount(&store,
        \\SELECT COUNT(*) FROM memory_atoms ma
        \\WHERE ma.predicate = 'agent.memory' AND ma.object = 'pref.lifecycle' AND ma.status <> 'deprecated'
        \\AND EXISTS (
        \\  SELECT 1 FROM json_each(ma.source_ids_json) sid
        \\  JOIN sources s ON s.id = sid.value
        \\  WHERE json_extract(s.metadata_json, '$.native') = 'agent_memory_runtime'
        \\    AND json_extract(s.metadata_json, '$.store') = 'archive'
        \\    AND json_extract(s.metadata_json, '$.owner_id') = 'agent:lifecycle'
        \\)
    ));
}

