    const session_count: usize = 10_005;

    for (0..session_count) |i| {
        const session_id = try std.fmt.allocPrint(alloc, "paged-session-{d}", .{i});
        try store.saveMessageRoutedAtSuppressFeed(session_id, "user", "paged session marker", @intCast(i + 1), actor, scratch);
    }

    const scratch_feed = try (try store.namedAgentMemoryRuntime(scratch)).listFeedEventsByInput(alloc, .{
        .since_id = 0,
        .limit = 1,
        .actor_id = actor,
        .scopes_json = "[\"actor:agent:session-page\"]",
    });
    defer {
        for (scratch_feed) |*event| event.deinit(alloc);
        alloc.free(scratch_feed);
    }
    try std.testing.expectEqual(@as(usize, 0), scratch_feed.len);

    const all_page = try store.listSessionsRouted(alloc, 3, 10_000, actor, AgentMemoryStorageRoute.parse("all"));
    defer {
        for (all_page.sessions) |*session| freeSessionInfoOwned(alloc, session);
        alloc.free(all_page.sessions);
    }
    try std.testing.expectEqual(@as(u64, session_count), all_page.total);
    try std.testing.expectEqual(@as(usize, 3), all_page.sessions.len);

    const subset_page = try store.listSessionsRouted(alloc, 3, 10_000, actor, subset);
    defer {
        for (subset_page.sessions) |*session| freeSessionInfoOwned(alloc, session);
        alloc.free(subset_page.sessions);
    }
    try std.testing.expectEqual(@as(u64, session_count), subset_page.total);
    try std.testing.expectEqual(@as(usize, 3), subset_page.sessions.len);
}

