    const atom = try store.createMemoryAtom(alloc, .{ .text = "diagnostic memory", .scope = "public", .created_by = "human" });
    _ = try store.agentMemoryStore(alloc, .{ .key = "diagnostic.agent", .content = "diagnostic agent memory", .actor_id = "agent:diagnostics" });
    try std.testing.expect(try store.patchMemoryAtomStatus(atom.id, "stale", false));
    _ = try store.enqueueVectorOutbox(.{ .action = "upsert", .object_type = "memory_atom", .object_id = atom.id });
    _ = try store.enqueueVectorOutbox(.{ .action = "upsert", .object_type = "memory_atom", .object_id = "failed", .status = "failed_embedding" });
    _ = try store.enqueueVectorOutbox(.{ .action = "upsert", .object_type = "memory_atom", .object_id = "running", .status = "running" });
    try testingSqliteExec(&store, "UPDATE vector_outbox SET locked_until_ms = 1 WHERE object_id = 'running'");
    try store.putResponseCache(.{ .cache_key = "diagnostic:response", .response_json = "{\"ok\":true}", .ttl_ms = 1, .now_ms = 1 });
    try store.putSemanticCache(.{ .cache_key = "diagnostic:semantic", .query = "diagnostic", .response_json = "{\"ok\":true}", .embedding_json = "[1,0]", .embedding_dimensions = 2, .ttl_ms = 1, .now_ms = 1 });
    try store.putEmbeddingCache(.{ .cache_key = "diagnostic:embedding", .provider = "test", .dimensions = 2, .embedding_json = "[1,0]", .now_ms = 1 });
    const job = try store.createJob(alloc, .{ .job_type = "diagnostics" });
    try std.testing.expect(try store.claimJob(job.id));
    try testingSqliteExec(&store, "UPDATE jobs SET locked_until_ms = 1 WHERE job_type = 'diagnostics'");

    const diag = try store.lifecycleDiagnostics();
    try std.testing.expectEqual(@as(usize, 2), diag.total_memory_atoms);
    try std.testing.expectEqual(@as(usize, 1), diag.stale_memory_atoms);
    try std.testing.expectEqual(@as(usize, 1), diag.vector_outbox_pending);
    try std.testing.expectEqual(@as(usize, 1), diag.vector_outbox_running);
    try std.testing.expectEqual(@as(usize, 1), diag.vector_outbox_failed);
    try std.testing.expectEqual(@as(usize, 1), diag.vector_outbox_expired_running);
    try std.testing.expectEqual(@as(usize, 3), diag.cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.response_cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.semantic_cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.embedding_cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.expired_response_cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.expired_semantic_cache_entries);
    try std.testing.expectEqual(@as(usize, 1), diag.running_jobs);
    try std.testing.expectEqual(@as(usize, 1), diag.expired_running_jobs);
    try std.testing.expectEqual(@as(usize, 1), diag.agent_memories);
}

