test "api agent memory routes delegate missing lifecycle targets" {
    var store = try Store.initSQLiteWithOptions(std.testing.allocator, ":memory:", .{
        .agent_memory = .{
            .backend = .api,
            .api = .{ .base_url = "https://pantry.example/v1" },
        },
        .agent_memory_stores = &.{
            .{
                .name = "remote",
                .config = .{
                    .backend = .api,
                    .api = .{ .base_url = "https://pantry.example/v1" },
                },
            },
            .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
        },
    });
    defer store.deinit();

    try std.testing.expect(try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(.{ .target = .primary }));
    try std.testing.expect(try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(.{ .target = .runtime }));
    try std.testing.expect(try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(AgentMemoryStorageRoute.parse("remote")));
    try std.testing.expect(!try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(.{ .target = .native }));
    try std.testing.expect(try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(.{ .target = .all }));

    try std.testing.expect(try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(.{ .target = .runtime }));
    try std.testing.expect(try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(AgentMemoryStorageRoute.parse("remote")));
    try std.testing.expect(!try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(AgentMemoryStorageRoute.parse("scratch")));
    try std.testing.expect(!try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(.{ .target = .all }));

    const remote_only_stores = [_][]const u8{"remote"};
    try std.testing.expect(try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(AgentMemoryStorageRoute.fromStores(&remote_only_stores)));
    const mixed_stores = [_][]const u8{ "remote", "scratch" };
    try std.testing.expect(try store.agentMemoryLifecycleCanDelegateMissingTargetRouted(AgentMemoryStorageRoute.fromStores(&mixed_stores)));
    try std.testing.expect(!try store.agentMemoryLifecycleRequiresRemoteTargetLookupRouted(AgentMemoryStorageRoute.fromStores(&mixed_stores)));
}

