    const key = "fanin.same";
    _ = try store.agentMemoryStoreRouted(alloc, .{
        .key = key,
        .content = "multi store same key native value",
        .actor_id = "agent:fanin",
    }, .{ .target = .native });
    _ = try store.agentMemoryStoreRouted(alloc, .{
        .key = key,
        .content = "multi store same key runtime value",
        .actor_id = "agent:fanin",
    }, .{ .target = .runtime });
    _ = try store.agentMemoryStoreRouted(alloc, .{
        .key = key,
        .content = "multi store same key scratch value",
        .actor_id = "agent:fanin",
    }, AgentMemoryStorageRoute.parse("scratch"));
    _ = try store.agentMemoryStoreRouted(alloc, .{
        .key = key,
        .content = "multi store same key archive value",
        .actor_id = "agent:fanin",
    }, AgentMemoryStorageRoute.parse("archive"));

    const listed = try store.agentMemoryListAnyVisibleRouted(alloc, null, "agent:fanin", "[]", .{ .target = .all });
    try expectSameKeyStores(listed, key, &.{ "native", "runtime", "scratch", "archive" });

    const subset_stores = [_][]const u8{ "scratch", "archive" };
    const subset = try store.agentMemoryListAnyVisibleRouted(alloc, null, "agent:fanin", "[]", AgentMemoryStorageRoute.fromStores(&subset_stores));
    try expectSameKeyStores(subset, key, &.{ "scratch", "archive" });

    const searched = try store.agentMemorySearchAnyVisibleRouted(alloc, "multi store same key", 10, "[]", "agent:fanin", .{ .target = .all });
    try expectSameKeyStores(searched, key, &.{ "native", "runtime", "scratch", "archive" });

    const search_results = try store.search(alloc, .{
        .query = "multi store same key",
        .scopes_json = "[]",
        .limit = 20,
        .use_vector = false,
        .actor_id = "agent:fanin",
        .agent_memory_route = .{ .target = .all },
    });
    var seen: usize = 0;
    var saw_native = false;
    var saw_runtime = false;
    var saw_scratch = false;
    var saw_archive = false;
    for (search_results) |result| {
        if (!std.mem.eql(u8, result.result_type, "agent_memory")) continue;
        if (!std.mem.eql(u8, result.title, key) and std.mem.indexOf(u8, result.title, key) == null) continue;
        seen += 1;
        if (std.mem.eql(u8, result.store, "native")) saw_native = true;
        if (std.mem.eql(u8, result.store, "runtime")) saw_runtime = true;
        if (std.mem.eql(u8, result.store, "scratch")) saw_scratch = true;
        if (std.mem.eql(u8, result.store, "archive")) saw_archive = true;
    }
    try std.testing.expectEqual(@as(usize, 4), seen);
    try std.testing.expect(saw_native);
    try std.testing.expect(saw_runtime);
    try std.testing.expect(saw_scratch);
    try std.testing.expect(saw_archive);
}

test "agent memory delete does not mutate when existing lookup fails" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();

    var saved = try store.agentMemoryStoreRouted(std.testing.allocator, .{
        .key = "delete.preflight",
        .content = "delete preflight must preserve this value",
        .actor_id = "agent:delete-preflight",
    }, .{ .target = .native });
    defer agent_memory_runtime.freeAgentMemory(std.testing.allocator, &saved);

    const original_allocator = store.allocator;
    var failing_allocator = std.testing.FailingAllocator.init(original_allocator, .{ .fail_index = 0 });
    store.allocator = failing_allocator.allocator();
    const delete_result = store.agentMemoryDeleteRouted(
        "delete.preflight",
        null,
        "agent:delete-preflight",
        "agent:delete-preflight",
        .{ .target = .native },
    );
    store.allocator = original_allocator;
    try std.testing.expectError(error.OutOfMemory, delete_result);

    var still_present = (try store.agentMemoryGetRouted(std.testing.allocator, "delete.preflight", null, "agent:delete-preflight", .{ .target = .native })).?;
    defer agent_memory_runtime.freeAgentMemory(std.testing.allocator, &still_present);
    try std.testing.expectEqualStrings("delete preflight must preserve this value", still_present.content);
}

