fn expectSameKeyStores(entries: []const domain.AgentMemory, key: []const u8, expected_stores: []const []const u8) !void {
    var actual_count: usize = 0;
    for (entries) |entry| {
        if (std.mem.eql(u8, entry.key, key)) actual_count += 1;
    }
    try std.testing.expectEqual(expected_stores.len, actual_count);

    for (expected_stores) |expected_store| {
        var saw_store = false;
        for (entries) |entry| {
            if (!std.mem.eql(u8, entry.key, key)) continue;
            if (!std.mem.eql(u8, entry.store, expected_store)) continue;
            saw_store = true;
            break;
        }
        try std.testing.expect(saw_store);
    }
}

