test "sqlite context pack visibility releases temporary acl records" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const setup = arena.allocator();

    const source = try store.createSource(setup, .{
        .id = "src_ctx_visibility_owned",
        .title = "Context Visibility Source",
        .content = "owned source fields must be released after visibility checks",
        .scope = "public",
    });
    const source_ids = try std.fmt.allocPrint(setup, "[\"{s}\"]", .{source.id});

    const artifact = try store.createArtifact(setup, .{
        .id = "art_ctx_visibility_owned",
        .title = "Context Visibility Artifact",
        .body = "owned artifact fields must be released after visibility checks",
        .status = "verified",
        .scope = "public",
        .source_ids_json = source_ids,
    });
    const artifact_ids = try std.fmt.allocPrint(setup, "[\"{s}\"]", .{artifact.id});

    const atom = try store.createMemoryAtom(setup, .{
        .id = "mem_ctx_visibility_owned",
        .text = "owned atom fields must be released after visibility checks",
        .scope = "public",
        .status = "verified",
        .created_by = "human",
        .source_ids_json = source_ids,
    });
    const atom_ids = try std.fmt.allocPrint(setup, "[\"{s}\"]", .{atom.id});

    _ = try store.importContextPackSnapshot(setup, .{
        .id = "ctx_visibility_owned",
        .query = "context visibility owned records",
        .generated_summary = "context visibility owned records summary",
        .included_sources_json = source_ids,
        .included_artifacts_json = artifact_ids,
        .included_memory_atoms_json = atom_ids,
        .included_result_refs_json = "[{\"id\":\"ref_ctx_visibility_owned\",\"type\":\"source\",\"required_scopes\":[\"public\"],\"actor_isolated\":false}]",
        .required_scopes_json = "[\"public\"]",
        .suppress_feed = true,
    });

    const visible_packs = try store.listContextPacksVisible(std.testing.allocator, .{ .limit = 5, .scopes_json = "[\"public\"]" });
    defer {
        for (visible_packs) |*pack| deinitContextPackResult(std.testing.allocator, pack);
        std.testing.allocator.free(visible_packs);
    }
    try std.testing.expectEqual(@as(usize, 1), visible_packs.len);
    try std.testing.expectEqualStrings("ctx_visibility_owned", visible_packs[0].id);

    const sanitized = switch (store.backend) {
        .sqlite => |*sqlite| try sqlite.sanitizeSourceIdsForActor(std.testing.allocator, source_ids, "[\"public\"]", null),
        .postgres => unreachable,
    };
    defer std.testing.allocator.free(sanitized);
    try std.testing.expectEqualStrings(source_ids, sanitized);

    const hidden_source = try store.createSource(setup, .{
        .id = "src_ctx_visibility_hidden_owned",
        .title = "Hidden Context Visibility Source",
        .content = "hidden source fields must be released after sanitizer checks",
        .scope = "project:secret",
        .permissions_json = "[\"project:secret\"]",
    });
    const hidden_source_ids = try std.fmt.allocPrint(setup, "[\"{s}\"]", .{hidden_source.id});
    const sanitized_hidden = switch (store.backend) {
        .sqlite => |*sqlite| try sqlite.sanitizeSourceIdsForActor(std.testing.allocator, hidden_source_ids, "[\"public\"]", null),
        .postgres => unreachable,
    };
    defer std.testing.allocator.free(sanitized_hidden);
    try std.testing.expectEqualStrings("[]", sanitized_hidden);
}

