    const results = try store.agentMemorySearch(alloc, "Deprecated FTS Marker", 10, "s-1", "[\"project:nullpantry\",\"session:s-1\"]", "agent:hygiene");
    defer {
        for (results) |*entry| agent_memory_runtime.freeAgentMemory(alloc, entry);
        alloc.free(results);
    }
    try std.testing.expectEqual(@as(usize, 0), results.len);
}

