test "postgres storage contract covers primitives when configured" {
    const require_postgres = compat.process.getEnvVarOwned(std.testing.allocator, "NULLPANTRY_REQUIRE_POSTGRES_TEST") catch null;
    if (require_postgres) |value| std.testing.allocator.free(value);
    const url = compat.process.getEnvVarOwned(std.testing.allocator, "NULLPANTRY_TEST_POSTGRES_URL") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => if (require_postgres != null) return error.MissingPostgresTestUrl else return error.SkipZigTest,
        else => return err,
    };
    defer std.testing.allocator.free(url);

    var store = try Store.initPostgres(std.testing.allocator, url);
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();

    const unique = try ids.make(alloc, "pgcontract");
    const rollback_source_id = try ids.make(alloc, "pgrollbacksrc");
    const failing_import = [_]PreparedMemoryImport{.{
        .atom = .{
            .text = "postgres atomic import rollback atom",
            .scope = "public",
            .created_by = "human",
            .tags_json = "{not-json",
        },
        .generated_source = .{
            .id = rollback_source_id,
            .source_type = "manual",
            .title = "Postgres rollback source",
            .content = "this generated source must roll back with the failed atom",
            .scope = "public",
        },
    }};
    try std.testing.expectError(error.PostgresCommandFailed, store.importMemoryAtomsAtomic(alloc, &failing_import));
    try std.testing.expect((try store.getSource(alloc, rollback_source_id)) == null);

    const source = try store.createSource(alloc, .{
        .source_type = "manual",
        .title = unique,
        .content = "Postgres contract source for NullPantry",
        .scope = "public",
    });
    const loaded_source = (try store.getSource(alloc, source.id)).?;
    try std.testing.expectEqualStrings(source.id, loaded_source.id);

    const artifact = try store.createArtifact(alloc, .{
        .artifact_type = "decision",
        .title = unique,
        .body = "Decision: Postgres contract must work.",
        .status = "accepted",
        .source_ids_json = try singleJsonString(alloc, source.id),
    });
    const loaded_artifact = (try store.getArtifact(alloc, artifact.id)).?;
    try std.testing.expectEqualStrings("accepted", loaded_artifact.status);

    const atom = try store.createMemoryAtom(alloc, .{
        .text = unique,
        .scope = "public",
        .created_by = "human",
        .source_ids_json = try singleJsonString(alloc, source.id),
    });
    const found = try store.search(alloc, .{ .query = unique, .scopes_json = "[\"public\"]", .limit = 50, .use_vector = false });
    var saw_atom = false;
    for (found) |result| {
        if (std.mem.eql(u8, result.id, atom.id)) saw_atom = true;
    }
    try std.testing.expect(saw_atom);

    _ = try store.agentMemoryStore(alloc, .{ .key = unique, .content = "postgres native agent memory", .category = "core", .session_id = "pg-session", .actor_id = "agent:postgres" });
    const agent_entry = (try store.agentMemoryGet(alloc, unique, "pg-session", "agent:postgres")).?;
    try std.testing.expectEqualStrings("postgres native agent memory", agent_entry.content);
    const shared_key = try std.fmt.allocPrint(alloc, "{s}.shared", .{unique});
    _ = try store.agentMemoryStore(alloc, .{ .key = shared_key, .content = "postgres shared team agent memory", .category = "core", .scope = "team:pg", .actor_id = "shared:team:pg" });
    const pg_shared = (try store.agentMemoryGetVisible(alloc, shared_key, null, "agent:pg-a", "[\"team:pg\"]")).?;
    try std.testing.expectEqualStrings("postgres shared team agent memory", pg_shared.content);
    try std.testing.expect((try store.agentMemoryGetVisible(alloc, shared_key, null, "agent:pg-c", "[\"public\"]")) == null);
    const pg_agent_list = try store.agentMemoryList(alloc, "core", "pg-session", "agent:postgres");
    try std.testing.expectEqual(@as(usize, 1), pg_agent_list.len);
    try std.testing.expectEqualStrings(unique, pg_agent_list[0].key);
    const pg_visible_list = try store.agentMemoryListVisible(alloc, "core", null, "agent:pg-b", "[\"team:pg\"]");
    var saw_pg_visible_shared = false;
    for (pg_visible_list) |entry| {
        if (std.mem.eql(u8, entry.key, shared_key)) saw_pg_visible_shared = true;
    }
    try std.testing.expect(saw_pg_visible_shared);
    const pg_shared_search = try store.search(alloc, .{ .query = "postgres shared team", .scopes_json = "[\"team:pg\"]", .limit = 10, .use_vector = false, .actor_id = "agent:pg-b" });
    var saw_pg_shared = false;
    for (pg_shared_search) |result| {
        if (std.mem.eql(u8, result.result_type, "agent_memory") and std.mem.indexOf(u8, result.text, "postgres shared team agent memory") != null) saw_pg_shared = true;
    }
    try std.testing.expect(saw_pg_shared);
    const pg_rank_high_key = try std.fmt.allocPrint(alloc, "{s}.rank.high", .{unique});
    const pg_rank_low_key = try std.fmt.allocPrint(alloc, "{s}.rank.low", .{unique});
    _ = try store.agentMemoryStore(alloc, .{ .key = pg_rank_high_key, .content = "alpha beta gamma", .category = "core", .actor_id = "agent:postgres" });
    _ = try store.agentMemoryStore(alloc, .{ .key = pg_rank_low_key, .content = "alpha", .category = "core", .actor_id = "agent:postgres" });
    const pg_ranked = try store.agentMemorySearch(alloc, "alpha beta gamma", 1, null, "[]", "agent:postgres");
    try std.testing.expectEqual(@as(usize, 1), pg_ranked.len);
    try std.testing.expectEqualStrings(pg_rank_high_key, pg_ranked[0].key);
    const pg_zero_limit = try store.agentMemorySearch(alloc, "alpha", 0, null, "[]", "agent:postgres");
    try std.testing.expectEqual(@as(usize, 0), pg_zero_limit.len);

    const pg_dedupe_scope = try std.fmt.allocPrint(alloc, "team:pg-dedupe-{s}", .{unique});
    const pg_dedupe_permissions = try std.fmt.allocPrint(alloc, "[\"{s}\"]", .{pg_dedupe_scope});
    const pg_dedupe_a_key = try std.fmt.allocPrint(alloc, "{s}.dedupe.a", .{unique});
    const pg_dedupe_b_key = try std.fmt.allocPrint(alloc, "{s}.dedupe.b", .{unique});
    const pg_dedupe_base_ms = ids.nowMs();
    _ = try store.agentMemoryStore(alloc, .{
        .key = pg_dedupe_a_key,
        .content = "Postgres Agent Memory Duplicate Fact",
        .category = "prefs",
        .session_id = "pg-dedupe-session",
        .actor_id = "agent:pg-dedupe",
        .scope = pg_dedupe_scope,
        .permissions_json = pg_dedupe_permissions,
        .event_order = .{ .timestamp_ms = pg_dedupe_base_ms, .origin_instance_id = "postgres-contract", .origin_sequence = 1 },
    });
    _ = try store.agentMemoryStore(alloc, .{
        .key = pg_dedupe_b_key,
        .content = "postgres   agent memory duplicate fact",
        .category = "prefs",
        .session_id = "pg-dedupe-session",
        .actor_id = "agent:pg-dedupe",
        .scope = pg_dedupe_scope,
        .permissions_json = pg_dedupe_permissions,
        .event_order = .{ .timestamp_ms = pg_dedupe_base_ms + 1, .origin_instance_id = "postgres-contract", .origin_sequence = 2 },
    });
    const pg_dedupe_denied = try store.runHygiene(.{
        .stale_after_ms = 365 * 24 * 60 * 60 * 1000,
        .archive_after_ms = 365 * 24 * 60 * 60 * 1000,
        .dedupe_agent_memory = true,
        .scopes_json = try std.fmt.allocPrint(alloc, "[\"{s}\"]", .{pg_dedupe_scope}),
        .capabilities_json = "[\"verify\"]",
    });
    try std.testing.expect(pg_dedupe_denied.agent_memory_dedupe_groups >= 1);
    try std.testing.expectEqual(@as(usize, 0), pg_dedupe_denied.agent_memory_dedupe_deprecated);
    const pg_dedupe_allowed = try store.runHygiene(.{
        .stale_after_ms = 365 * 24 * 60 * 60 * 1000,
        .archive_after_ms = 365 * 24 * 60 * 60 * 1000,
        .dedupe_agent_memory = true,
        .scopes_json = try std.fmt.allocPrint(alloc, "[\"{s}\",\"verify:{s}\"]", .{ pg_dedupe_scope, pg_dedupe_scope }),
        .capabilities_json = "[\"verify\"]",
    });
    try std.testing.expect(pg_dedupe_allowed.agent_memory_dedupe_checked >= 2);
    try std.testing.expect(pg_dedupe_allowed.agent_memory_dedupe_groups >= 1);
    try std.testing.expectEqual(@as(usize, 1), pg_dedupe_allowed.agent_memory_dedupe_deprecated);
    try std.testing.expect((try store.agentMemoryGet(alloc, pg_dedupe_a_key, "pg-dedupe-session", "agent:pg-dedupe")) == null);
    try std.testing.expect((try store.agentMemoryGet(alloc, pg_dedupe_b_key, "pg-dedupe-session", "agent:pg-dedupe")) != null);

    try store.saveMessage(unique, "user", "hello postgres history", "agent:postgres");
    const history_result = try store.history(alloc, unique, 10, 0, "agent:postgres");
    try std.testing.expectEqual(@as(u64, 1), history_result.total);

    const pack = try store.createContextPack(alloc, .{ .query = unique, .scopes_json = "[\"public\"]" });
    try std.testing.expect(std.mem.indexOf(u8, pack.generated_summary, unique) != null);

    const snapshot = try store.createLifecycleSnapshot(alloc, "postgres-contract", "{\"memory_atoms\":1}");
    try std.testing.expect(std.mem.startsWith(u8, snapshot.id, "snap_"));
    const audit_events = try store.listAuditEvents(alloc, 0, 5000);
    var saw_snapshot_audit = false;
    for (audit_events) |event| {
        if (std.mem.eql(u8, event.event_type, "lifecycle.snapshot") and
            std.mem.eql(u8, event.object_type, "lifecycle_snapshot") and
            std.mem.eql(u8, event.object_id, snapshot.id))
        {
            saw_snapshot_audit = true;
        }
    }
    try std.testing.expect(saw_snapshot_audit);

    try std.testing.expectEqual(migrations.expected_schema_version, try store.schemaVersion());

    const cursor_connector = try std.fmt.allocPrint(alloc, "{s}.connector", .{unique});
    const cursor = try store.upsertConnectorCursor(alloc, .{
        .connector = cursor_connector,
        .scope = "team:pg",
        .cursor = "cursor-1",
        .config_json = "{\"kind\":\"postgres-contract\"}",
        .permissions_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
    });
    try std.testing.expectEqualStrings("cursor-1", cursor.cursor);
    const loaded_cursor = (try store.getConnectorCursor(alloc, cursor_connector, "team:pg")).?;
    try std.testing.expectEqualStrings("{\"kind\":\"postgres-contract\"}", loaded_cursor.config_json);
    const visible_cursors = try store.listConnectorCursors(alloc, .{ .connector = cursor_connector, .scopes_json = "[\"team:pg\"]", .limit = 10 });
    try std.testing.expectEqual(@as(usize, 1), visible_cursors.len);
    const hidden_cursors = try store.listConnectorCursors(alloc, .{ .connector = cursor_connector, .scopes_json = "[\"public\"]", .limit = 10 });
    try std.testing.expectEqual(@as(usize, 0), hidden_cursors.len);

    _ = try store.createMemoryAtom(alloc, .{
        .predicate = "decision.postgres.conflict",
        .object = "sqlite",
        .text = "Postgres contract conflict says SQLite.",
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .created_by = "human",
    });
    _ = try store.createMemoryAtom(alloc, .{
        .predicate = "decision.postgres.conflict",
        .object = "postgres",
        .text = "Postgres contract conflict says Postgres.",
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .created_by = "human",
    });
    const pg_conflicts = try store.scanConflicts(alloc, .{ .scopes_json = "[\"team:pg\"]", .status = "open", .limit = 20 });
    var saw_pg_conflict = false;
    for (pg_conflicts) |conflict| {
        if (std.mem.indexOf(u8, conflict.summary, "decision.postgres.conflict") != null) saw_pg_conflict = true;
    }
    try std.testing.expect(saw_pg_conflict);
    const hidden_pg_conflicts = try store.listConflicts(alloc, .{ .scopes_json = "[\"public\"]", .status = "open", .limit = 20 });
    for (hidden_pg_conflicts) |conflict| {
        try std.testing.expect(std.mem.indexOf(u8, conflict.summary, "decision.postgres.conflict") == null);
    }

    const cache_key = try std.fmt.allocPrint(alloc, "{s}.response-cache", .{unique});
    try store.putResponseCache(.{
        .cache_key = cache_key,
        .response_json = "{\"ok\":true}",
        .scopes_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
        .ttl_ms = 60_000,
    });
    try std.testing.expect((try store.getResponseCacheForScopes(alloc, cache_key, ids.nowMs(), "[\"team:pg\"]", "agent:pg-a")) != null);
    try std.testing.expect((try store.getResponseCacheForScopes(alloc, cache_key, ids.nowMs(), "[\"team:pg\"]", "agent:pg-b")) == null);
    try std.testing.expect((try store.getResponseCacheForScopes(alloc, cache_key, ids.nowMs(), "[\"public\"]", "agent:pg-a")) == null);

    const semantic_key = try std.fmt.allocPrint(alloc, "{s}.semantic-cache", .{unique});
    try store.putSemanticCache(.{
        .cache_key = semantic_key,
        .query = "postgres semantic cache",
        .response_json = "{\"semantic\":true}",
        .embedding_json = "[1,0,0]",
        .scopes_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
        .ttl_ms = 60_000,
    });
    try std.testing.expect((try store.searchSemanticCache(alloc, .{ .embedding_json = "[1,0,0]", .scopes_json = "[\"team:pg\"]", .actor_id = "agent:pg-a", .min_score = 0.99 })) != null);
    try std.testing.expect((try store.searchSemanticCache(alloc, .{ .embedding_json = "[1,0,0]", .scopes_json = "[\"team:pg\"]", .actor_id = "agent:pg-b", .min_score = 0.99 })) == null);

    const expired_response_key = try std.fmt.allocPrint(alloc, "{s}.expired-response-cache", .{unique});
    const expired_semantic_key = try std.fmt.allocPrint(alloc, "{s}.expired-semantic-cache", .{unique});
    try store.putResponseCache(.{
        .cache_key = expired_response_key,
        .response_json = "{\"expired\":true}",
        .scopes_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-expired-cache",
        .ttl_ms = 10,
        .now_ms = 100,
    });
    try store.putSemanticCache(.{
        .cache_key = expired_semantic_key,
        .query = "expired postgres semantic cache",
        .response_json = "{\"expired\":true}",
        .embedding_json = "[0,1,0]",
        .scopes_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-expired-cache",
        .ttl_ms = 10,
        .now_ms = 100,
    });
    const pg_hygiene = try store.runHygiene(.{ .now_ms = 111 });
    try std.testing.expect(pg_hygiene.expired_cache_entries >= 2);
    try std.testing.expect((try store.getResponseCacheForScopes(alloc, expired_response_key, 112, "[\"team:pg\"]", "agent:pg-expired-cache")) == null);
    try std.testing.expect((try store.searchSemanticCache(alloc, .{ .embedding_json = "[0,1,0]", .scopes_json = "[\"team:pg\"]", .actor_id = "agent:pg-expired-cache", .min_score = 0.99, .now_ms = 112 })) == null);

    const vector = try store.upsertVectorChunk(alloc, .{
        .object_type = "memory_atom",
        .object_id = atom.id,
        .chunk_ordinal = 0,
        .text = "postgres pgvector contract chunk",
        .scope = "public",
        .embedding_json = "[1,0,0]",
        .dimensions = 3,
        .actor_id = "agent:postgres",
    });
    const matches = try store.vectorSearch(alloc, .{ .embedding_json = "[1,0,0]", .scopes_json = "[\"public\"]", .limit = 5 });
    var saw_vector = false;
    for (matches) |match| {
        if (std.mem.eql(u8, match.id, vector.id)) saw_vector = true;
    }
    try std.testing.expect(saw_vector);

    const pg_private_vector_entry = try store.agentMemoryStore(alloc, .{
        .key = try std.fmt.allocPrint(alloc, "{s}.private-vector", .{unique}),
        .content = "postgres private agent vector memory",
        .category = "core",
        .actor_id = "agent:pg-vector",
    });
    _ = try store.upsertVectorChunk(alloc, .{
        .object_type = "agent_memory",
        .object_id = pg_private_vector_entry.id,
        .chunk_ordinal = 0,
        .text = pg_private_vector_entry.content,
        .scope = pg_private_vector_entry.scope,
        .permissions_json = pg_private_vector_entry.permissions_json,
        .embedding_json = "[1,0,0]",
        .dimensions = 3,
        .actor_id = "agent:pg-vector",
    });
    const private_vector_matches = try store.vectorSearch(alloc, .{ .embedding_json = "[1,0,0]", .scopes_json = "[]", .limit = 20, .actor_id = "agent:pg-vector" });
    var saw_private_agent_vector = false;
    for (private_vector_matches) |match| {
        if (std.mem.eql(u8, match.object_type, "agent_memory") and std.mem.eql(u8, match.object_id, pg_private_vector_entry.id)) saw_private_agent_vector = true;
    }
    try std.testing.expect(saw_private_agent_vector);
    const denied_private_vector_matches = try store.vectorSearch(alloc, .{ .embedding_json = "[1,0,0]", .scopes_json = "[]", .limit = 20, .actor_id = "agent:pg-other" });
    for (denied_private_vector_matches) |match| {
        try std.testing.expect(!std.mem.eql(u8, match.object_id, pg_private_vector_entry.id));
    }

    try std.testing.expect((try store.countVectorOutbox("pending")) > 0);
    const outbox = try store.listVectorOutbox(alloc, .{ .action = "upsert", .status = "pending", .limit = 10 });
    try std.testing.expect(outbox.len > 0);
    try std.testing.expect(try store.claimVectorOutbox(outbox[0].id));
    try std.testing.expect(!(try store.claimVectorOutbox(outbox[0].id)));
    try std.testing.expect(!try store.heartbeatVectorOutboxAs(outbox[0].id, "worker:pg-vector-other"));
    try std.testing.expect(try store.heartbeatVectorOutboxAs(outbox[0].id, default_vector_outbox_worker_id));
    try std.testing.expect(try store.finishVectorOutbox(outbox[0].id, "indexed_local"));

    const feed_key = try std.fmt.allocPrint(alloc, "{s}.feed", .{unique});
    const feed_id = try store.appendFeedEvent(.{
        .event_type = "contract.memory.put",
        .operation = "put",
        .object_type = "memory_atom",
        .object_id = atom.id,
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
        .dedupe_key = feed_key,
        .payload_json = "{\"text\":\"postgres feed contract\"}",
        .status = "applied",
    });
    try std.testing.expectEqual(feed_id, try store.appendFeedEvent(.{
        .event_type = "contract.memory.put",
        .operation = "put",
        .object_type = "memory_atom",
        .object_id = atom.id,
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
        .dedupe_key = feed_key,
        .payload_json = "{\"text\":\"postgres feed contract\"}",
        .status = "applied",
    }));
    try std.testing.expectError(error.FeedDedupeMismatch, store.appendFeedEvent(.{
        .event_type = "contract.memory.put",
        .operation = "put",
        .object_type = "memory_atom",
        .object_id = atom.id,
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
        .dedupe_key = feed_key,
        .payload_json = "{\"text\":\"postgres feed contract retry\"}",
        .status = "applied",
    }));
    const visible_feed = try store.listFeedEvents(alloc, .{ .since_id = feed_id - 1, .scopes_json = "[\"team:pg\"]", .limit = 10 });
    var saw_feed = false;
    for (visible_feed) |event| {
        if (event.id == feed_id) saw_feed = true;
    }
    try std.testing.expect(saw_feed);

    const direct_source = try store.createSource(alloc, .{
        .title = "Postgres direct feed source",
        .content = "postgres direct feed source content",
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .actor_id = "agent:pg-a",
    });
    const direct_feed = try store.listFeedEvents(alloc, .{ .since_id = feed_id - 1, .scopes_json = "[\"team:pg\"]", .limit = 20 });
    var saw_direct_source = false;
    for (direct_feed) |event| {
        if (std.mem.eql(u8, event.object_id, direct_source.id)) {
            saw_direct_source = true;
            try std.testing.expectEqualStrings("source.put", event.event_type);
            try std.testing.expect(event.dedupe_key != null);
            try std.testing.expect(std.mem.startsWith(u8, event.dedupe_key.?, "direct:source:"));
        }
    }
    try std.testing.expect(saw_direct_source);
    const direct_search = try store.search(alloc, .{ .query = "postgres direct feed source", .scopes_json = "[\"team:pg\"]", .limit = 20, .use_vector = false });
    for (direct_search) |result| {
        if (!std.mem.eql(u8, result.result_type, "feed_event")) continue;
        try std.testing.expect(std.mem.indexOf(u8, result.text, direct_source.id) == null);
        try std.testing.expect(std.mem.indexOf(u8, result.text, "Postgres direct feed source") == null);
    }

    const private_scope = try domain.defaultAgentMemoryScope(alloc, "agent:pg-private");
    const private_permissions = try domain.actorGrantJson(alloc, "agent:pg-private");
    const private_feed_id = try store.appendFeedEvent(.{
        .event_type = "agent_memory.put",
        .operation = "put",
        .object_type = "agent_memory",
        .object_id = try std.fmt.allocPrint(alloc, "{s}.pg.private", .{unique}),
        .scope = private_scope,
        .permissions_json = private_permissions,
        .actor_id = "agent:pg-private",
        .payload_json = "{\"key\":\"pg.private\",\"content\":\"postgres private feed\"}",
        .status = "applied",
    });
    const private_visible = try store.listFeedEvents(alloc, .{ .since_id = private_feed_id - 1, .scopes_json = "[]", .actor_id = "agent:pg-private", .limit = 10 });
    var saw_private = false;
    for (private_visible) |event| {
        if (event.id == private_feed_id) saw_private = true;
    }
    try std.testing.expect(saw_private);
    const private_status = try store.feedStatus(alloc, .{ .scopes_json = "[]", .actor_id = "agent:pg-private" });
    try std.testing.expect(private_status.visible_events >= 1);
    try std.testing.expect(private_status.applied_events >= 1);
    const private_hidden = try store.listFeedEvents(alloc, .{ .since_id = private_feed_id - 1, .scopes_json = "[]", .actor_id = "agent:pg-other", .limit = 10 });
    for (private_hidden) |event| {
        try std.testing.expect(event.id != private_feed_id);
    }

    const hidden_feed = try store.listFeedEvents(alloc, .{ .since_id = feed_id - 1, .scopes_json = "[\"public\"]", .limit = 10 });
    for (hidden_feed) |event| {
        try std.testing.expect(event.id != feed_id);
        try std.testing.expect(!std.mem.eql(u8, event.object_id, direct_source.id));
    }
    const compacted = try store.compactFeed(feed_id, "agent:pg-a");
    try std.testing.expect(compacted.cursor_floor >= feed_id);
    try std.testing.expectError(error.CursorExpired, store.listFeedEvents(alloc, .{ .since_id = feed_id - 1, .scopes_json = "[\"team:pg\"]", .limit = 10 }));

    const job = try store.createJob(alloc, .{
        .job_type = "postgres-contract",
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .object_type = "memory_atom",
        .object_id = atom.id,
        .input_json = "{\"contract\":true}",
        .actor_id = "agent:pg-a",
    });
    try std.testing.expect(try store.claimJob(job.id));
    try std.testing.expect(!(try store.claimJob(job.id)));
    const claimed_pg_job = (try store.getJob(alloc, job.id)).?;
    try std.testing.expectEqual(@as(i64, 1), claimed_pg_job.attempts);
    try std.testing.expect(!try store.heartbeatJobAs(job.id, "worker:pg-other"));
    try std.testing.expect(try store.heartbeatJobAs(job.id, default_job_worker_id));
    try std.testing.expect(try store.finishJob(job.id, "succeeded", "{\"done\":true}", null));

    const expired_job = try store.createJob(alloc, .{
        .job_type = "postgres-contract-expired",
        .scope = "team:pg",
        .permissions_json = "[\"team:pg\"]",
        .object_type = "memory_atom",
        .object_id = atom.id,
        .input_json = "{\"contract\":true}",
        .actor_id = "agent:pg-a",
    });
    try std.testing.expect(try store.claimJob(expired_job.id));
    switch (store.backend) {
        .postgres => |*pg| try pg.runSql(try std.fmt.allocPrint(alloc, "UPDATE jobs SET locked_until_ms = 1 WHERE id = '{s}'", .{expired_job.id})),
        else => unreachable,
    }
    const queued_only = try store.listJobs(alloc, .{ .scopes_json = "[\"team:pg\"]", .status = "queued" });
    for (queued_only) |queued_job| try std.testing.expect(!std.mem.eql(u8, queued_job.id, expired_job.id));
    const runnable = try store.listJobs(alloc, .{ .scopes_json = "[\"team:pg\"]", .status = "queued", .include_expired_running = true });
    var saw_expired = false;
    for (runnable) |runnable_job| {
        if (std.mem.eql(u8, runnable_job.id, expired_job.id)) {
            saw_expired = true;
            try std.testing.expectEqualStrings("running", runnable_job.status);
        }
    }
    try std.testing.expect(saw_expired);
    try std.testing.expect(try store.heartbeatJobAs(expired_job.id, default_job_worker_id));
    try std.testing.expect(!(try store.claimJobAs(expired_job.id, "worker:pg-reclaim")));
    switch (store.backend) {
        .postgres => |*pg| try pg.runSql(try std.fmt.allocPrint(alloc, "UPDATE jobs SET locked_until_ms = 1 WHERE id = '{s}'", .{expired_job.id})),
        else => unreachable,
    }
    try std.testing.expect(try store.claimJob(expired_job.id));
    const reclaimed_pg_job = (try store.getJob(alloc, expired_job.id)).?;
    try std.testing.expectEqual(@as(i64, 2), reclaimed_pg_job.attempts);
}
